-- reputation, objectives, description, and giver name + coordinates. The
-- detail panel reads this when live/harvested data isn't present.
--   d[id] = { r={{n}...}, mo, rep, o=objectives, de=description, g={n,x,y,loc} }
local _, DT = ...
DT.WikiDetails = DT.WikiDetails or {}
local d = DT.WikiDetails
d[10106]={r={{n="Mark of Honor Hold x3"}},mo=7000,rep="+150 Honor Hold",o="Capture the Overlook, the Stadium and Broken Hill, then return to Warrant Officer Tracy Proudwell in Honor Hold. *Capture The Overlook *Capture the Stadium *Capture Broken Hill",de="The Hellfire Citadel wages constant battles with our forces. We are holding our own so far, but we can't yet launch a real offensive against them. To do that, we need forward staging areas. Our scouts identified three fortifications near Hellfire Citadel. We want you to help secure these forts. Capture each fort, and then report back to me. May fortune shine upon you in the conflicts ahead, , for you will no doubt clash with Horde forces eager to gain these same fortifications.",g={n="Warrant Officer Tracy Proudwell",x=0.564,y=0.628,loc="Honor Hold, Hellfire Peninsula"}}
d[10110]={r={{n="Mark of Thrallmar x3"}},mo=7000,rep="+150 Thrallmar",o="Capture the Overlook, the Stadium and Broken Hill, then return to Battlecryer Blackeye in Thrallmar. *Capture The Overlook *Capture the Stadium *Capture Broken Hill",de="The fel orcs of Hellfire Citadel must be scoured from our birthland! To attack them, we must first secure forward staging points near the Citadel. Our outrunners found three fortifications that will suit this purpose, but the Alliance has the same idea and even now sends forces to take them! We want you to stop the Alliance and capture these forts. Aid in the capture of each fort and then return to me. For the Horde!",g={n="Battlecryer Blackeye",x=0.558,y=0.392,loc="Thrallmar, Hellfire Peninsula"}}
d[11008]={mo=119900,rep="Sha'tari Skyguard +350",o="Seek out Monstrous Kaliri Eggs on the tops of Skettis dwellings and use the Skyguard Blasting Charges on them. Return to Sky Sergeant Doryn.",de="You think you have what it takes to be part of the Skyguard? We'll have to see how you handle yerself in the air. The arakkoa are breeding a gargantuan variety of their attack pets and are using it against our scouts. I want you to take these blasting charges and use them to destroy hatcheries above the arakkoa's dwellings. Avoid the monstrous kaliri guarding the hatcheries. They'll knock you off your mount before you know what hit you.",g={n="Sky Sergeant Doryn",x=0.645,y=0.666,loc="Blackwind Landing, Terokkar Forest"}}
d[11015]={mo=119900,rep="Netherwing +250",o="Taskmaster Varkule Dragonbreath at Dragonmaw Base Camp in Shadowmoon Valley wants you to bring him 30 Netherwing Crystals. *Netherwing Crystal (30)",de="No good at nothin'? That's fine. Even lunkheads like you can be used around here. Just find creatures on the ledge and kill 'em. Sometimes they'll have nether crystals on their carcasses. Gather those and bring 'em back to me and I'll consider your work order for the day complete.",g={n="Taskmaster Varkule Dragonbreath",x=0.660,y=0.864,loc="Dragonmaw Base Camp, Shadowmoon Valley"}}
d[11016]={mo=44000,rep="Netherwing +250",o="Taskmaster Varkule Dragonbreath at Dragonmaw Base Camp in Shadowmoon Valley wants you to bring him 35 Nethermine Flayer Hide. *Nethermine Flayer Hide (35)",de="A skinner, eh? Well you'll find plenty to skin here! You gotta search for flayers around crystal formations. Take 'em down and take their hides. Sometimes they'll have a hide worth keepin'. Bring those to me.",g={n="Taskmaster Varkule Dragonbreath",x=0.660,y=0.864,loc="Dragonmaw Base Camp, Shadowmoon Valley"}}
d[11017]={mo=44000,rep="Netherwing +250",o="Taskmaster Varkule Dragonbreath at Dragonmaw Base Camp in Shadowmoon Valley wants you to bring him 40 Netherdust Pollen. *Netherdust Pollen (40)",de="A flower picker?! Hilarious... Unfortunately, our mages and shaman need your services. The netherdust bushes that grow on this ledge have special pollen that is apparently very useful in their magical dealings. Bring me that stuff and I'll consider your work order complete.",g={n="Taskmaster Varkule Dragonbreath",x=0.660,y=0.864,loc="Dragonmaw Base Camp, Shadowmoon Valley"}}
d[11018]={mo=44000,rep="Netherwing +250",o="Taskmaster Varkule Dragonbreath at Dragonmaw Base Camp in Shadowmoon Valley wants you to bring him 40 Nethercite Ore. *Nethercite Ore (40)",de="A miner! An orc after my own heart! That's how Varkule got his start - minin'! There ain't nothin' better than getting down and dirty in the mines, is there? Now get out there and find those nethercite deposits. Strip 'em for all their worth and bring me back the ore.",g={n="Taskmaster Varkule Dragonbreath",x=0.660,y=0.864,loc="Dragonmaw Base Camp, Shadowmoon Valley"}}
d[11020]={mo=79250,rep="+250 Netherwing",o="Yarzill the Merc at Dragonmaw Base Camp in Shadowmoon Valley wants you to use Yarzill's Mutton in conjunction with Fel Glands to poison 12 Dragonmaw Peon Camps. *Dragonmaw Peon Camp Poisoned (12) *Yarzill's Mutton (provided)",de="The Dragonmaw have peons stationed at nearly every crystal formation up here. While the outright slaying of them would draw far too much unwanted attention to you, there is a way that we can thin their numbers and remain below the suspicious eyes of Mor'ghor. Venture into the wilds of Shadowmoon Valley and slay the tainted wildlife. Take from them their corrupt fel glands. Use those fel glands with this mutton that I'll give you near the peons. They'll take one bite and fall deathly ill!",g={n="Yarzill the Merc",x=0.660,y=0.864,loc="Dragonmaw Base Camp, Shadowmoon Valley"}}
d[11023]={r={{n="15x Apexis Shard"}},mo=119900,rep="Sha'tari Skyguard +500Ogri'la +500",o="Sky Sergeant Vanderlip has tasked you with the bombing of 15 Fel Cannonball Stacks. Return to her at the Skyguard Outpost atop the Blade's Edge Mountains once you have done so.",de="We're still having problems with those flak cannons, . Don't get me wrong—I think that you did an outstanding job the last time out—but, that doesn't change the fact that those damned demons seem to be replenishing their ammo supplies faster than we can knock them out. And that means we're having a hell of a time getting our people through there, not to mention the risk those demons pose to Ogri'la. What do you say? Want to take another shot at it?",g={n="Sky Sergeant Vanderlip",x=0.276,y=0.529,loc="Skyguard Outpost, Blade's Edge Mountains"}}
d[11035]={mo=119900,rep="Netherwing +250",o="Yarzill the Merc at Dragonmaw Base Camp in Shadowmoon Valley wants you to recover 10 Netherwing Relics. *Netherwing Relic (10)",de="On the northeast edge of this island exists a dock used for the packaging and transport of Netherwing crystals and relics. Dragonmaw Transporters transport the goods from the dock to Dragonmaw Fortress while Dragonmaw Ascendants guard the ground from any would-be attackers. This leaves one opening for you to make a strike at the Dragonmaw: The Dragonmaw Skyway. Fly to the shattered islands of the Dragonmaw Skyway and ambush the transporters that use the route. Recover our stolen relics!",g={n="Yarzill the Merc",x=0.660,y=0.864,loc="Dragonmaw Base Camp, Shadowmoon Valley"}}
d[11051]={r={{n="Kronk's Grab Bag"},{n="15xApexis Shard"}},mo=119900,rep="+350 Ogri'la",o="Kronk has asked you to use the Banishing Crystal to banish 15 demons at Forge Camp: Wrath or Forge Camp: Terror atop the Blade's Edge Mountains. Return it to him once you have done so. * Banishing Crystal (provided)",de="If we know the demons, and we do because we've studied them extensively, they're fast at work repairing any damage that has been done to their precious transporter. So, if you want a chance at another darkrune, take our banishing crystal back out there and eliminate more demons. Besides, you want to help us to lessen the threat that the demons pose, yes? We said \"chance\" because the process we use yields mixed results. You might get a darkrune, or you might get something else entirely.",g={n="Kronk",x=0.285,y=0.585,loc="Ogri'la, Blade's Edge Mountains"}}
d[11055]={mo=119900,rep="Netherwing +350",o="Chief Overseer Mudlump at the Dragonmaw Base Camp in Shadowmoon Valley wants you to discipline 20 lazy Dragonmaw Peons. You will also need to return your Booterang. *Dragonmaw Peon Disciplined (20) *Booterang (Provided)",de="This is your booterang. There are many like it but this one is yours. As an overseer you will use this booterang to sow terror into the hearts of defiant peons. Proper use of the booterang will instill obedience and ensure subservience. Venture forth to the crystal fields and discipline any peons that you see slacking off. Show them the might of the booterang!",g={n="Chief Overseer Mudlump",x=0.668,y=0.860,loc="Dragonmaw Base Camp, Shadowmoon Valley"}}
d[11066]={mo=119900,rep="+350 Sha'tari Skyguard+350 Ogri'la",o="Skyguard Khatie has asked you to wrangle 5 Aether Rays. After you have done so, return them to her at the Skyguard Outpost atop the Blade's Edge Mountains. *Aether Rays wrangled (5) *Wrangling Rope (provided)",de="So, I hope that you're up to helping us wrangle up even more aether rays! From what I can see, you're a natural with the rope! And it's for a good cause, because not only do we get fresh mounts, but it helps us to protect Ogri'la, which the ogres appreciate. Remember, the aether rays fly around Vortex Pinnacle, and the Crystal Spine to the northeast. Think you can wrangle me up some more?",g={n="Skyguard Khatie",x=0.279,y=0.515,loc="Blade's Edge Mountains"}}
d[11076]={mo=182800,rep="Netherwing +350",o="The Mistress of the Mines at the Netherwing Mines in Shadowmoon Valley wants you to recover 15 Nethermine Cargo crates. *Nethermine Cargo (15)",de="Much of our hard work lies scattered about in these mines. Carts full of cargo are littered across every inch of this mine! We just can't get to any of it with the current infestation. That's where you come in, . Your daily duty here at this mine is to collect the cargo left behind by the miners and deep mine workers. Gather the nethermine cargo and return it to me or my sister.",g={n="Mistress of the Mines",x=0.654,y=0.902,loc="Netherwing Mines, Shadowmoon Valley"}}
d[11077]={mo=119900,rep="Netherwing +350",o="The Dragonmaw Foreman at the Netherwing Mines in Shadowmoon Valley wants you to kill 15 Nethermine Flayers and 5 Nethermine Ravagers. *Nethermine Flayer slain (15) *Nethermine Ravager slain (5)",de="That dragon waking up riled up a host of other nasty creatures in these mines. Two types are proving to be a thorn in the side of the Dragonmaw: Nethermine flayers and Nethermine ravagers. You must help us by killing them off. All I ask is your involvement once per day. Get in there and kill as many as you can!",g={n="Dragonmaw Foreman",x=0.634,y=0.874,loc="Netherwing Mines, Shadowmoon Valley"}}
d[11080]={r={{n="15x Apexis Shard"}},mo=91000,rep="Ogri'la +350",o="Chu'a'lor has asked you to return to him at Ogri'la atop the Blade's Edge Mountains after you have gained Apexis Emanations from an Apexis Relic. *Apexis Emanations attained",de="Now that you have felt the enlightening vibrations of the apexis relics, it is time for you to further your understanding of their workings. We are very eager to benefit from your observations! As you progress in your ability to attune to the relics, you will gain a higher level of knowledge. This recognition will come in the form of an emanation from the relic. Return to us when you have attained such an emanation.",g={n="Chu'a'lor",x=0.288,y=0.574,loc="Ogri'la, Blade's Edge Mountains"}}
d[11085]={mo=91000,rep="Sha'tari Skyguard +150",o="Escort the to safety and report to . *Rescue the Skyguard Prisoner",de="Hail, . I thank you for coming to my aid. The arakkoa's monstrous birds knocked me from my nether ray while on a scouting mission. Let's get out of here, while we can.",g={n="Skyguard Prisoner",x=0.600,y=0.720,loc="Skettis, Terokkar Forest"}}
d[11086]={mo=119900,rep="+500 Netherwing",o="Overlord Mor'ghor at Dragonmaw Base Camp in Shadowmoon Valley wants you to kill 20 Deathshadow Agents. *Deathshadow Agent slain (20)",de="One of your responsibilities as a captain of Dragonmaw is to snuff out Burning Legion activity in Outland. It is your duty to silence those that defy Lord Illidan! The demons foolishly attempt to stabilize the portal found on the Twilight Ridge of western Nagrand. They must pay for their treachery, and you will be the orc that collects on their debt. Travel to the Twilight Ridge and lay waste to its inhabitants. You will be responsible for making at least one attack per day on their fortifications.",g={n="Overlord Mor'ghor",x=0.662,y=0.856,loc="Dragonmaw Base Camp, Shadowmoon Valley"}}
d[11097]={mo=85000,rep="Netherwing + 500",o="Assist Commander Hobb and the Scryers in defending the Sanctum of the Stars. Once all of the Dragonmaw forces have been defeated, return to Overlord Mor'ghor at Dragonmaw Base Camp with the Scryer Medals. *Dragonmaw Forces Defeated *Scryer Medals (provided) Suggested Players [3]",de="Take these Scryer medals. Mor'ghor will need proof of \"victory\" once this is over. He will recognize them as coming from the corpses of fallen Scryer soldiers. Now all that remains is to use the signal flare to alert the Dragonmaw raiders. We will crush them when you are ready. Just give me the word.",g={n="Commander Hobb",x=0.560,y=0.570,loc="Sanctum of the Stars, Shadowmoon Valley"}}
d[11101]={mo=182800,rep="Netherwing + 500",o="Assist Commander Arcus and the Aldor in defending the Altar of Sha'tar. Once all of the Dragonmaw forces have been defeated, return to Overlord Mor'ghor at Dragonmaw Base Camp with the Aldor Medals. * Dragonmaw Forces Defeated * Aldor Medals (provided) * Suggested Players [3]",de="Take these Aldor medals. Mor'ghor will need proof of \"victory\" once this is over. He will recognize them as coming from the corpses of fallen Aldor soldiers. Now all that remains is to use the signal flare to alert the Dragonmaw raiders. We will crush them when you are ready. Just give me the word.",g={n="Commander Arcus",x=0.620,y=0.300,loc="Altar of Sha'tar, Shadowmoon Valley"}}
d[11131]={r={{n="Hallow's End Pumpkin Treat (3) and"},{n="Weighted Jack-o'-Lantern"}},mo=3500,rep="+75 Stormwind",o="The Costumed Orphan Matron wants you to help put out all the village fires (already burning). When they are out, speak again to the Costumed Orphan Matron. *Put Out the Fires",de="You must help us! The Headless Horseman is attacking the village. Fires are everywhere! The children aren't safe! Please, , join the fire brigade. Grab a bucket and toss it on the fires, or pass it to a friend who's closer to the blaze. Put out all the fires and we may yet be saved!",g={n="Costumed Orphan Matron",loc="Azuremyst Isle; Dun Morogh; Elwynn Forest"}}
d[11153]={mo=47000,rep="+250 Valiance Expedition",o="Take Petrov's Cluster Bombs and drop them on enough pirates to kill or destroy 25 Blockade Pirates and 10 Blockade Cannons. Once you've accomplished that, return to Bombardier Petrov at Westguard Keep. * Blockade Pirate slain (25) * Blockade Cannon destroyed (10) * Petrov's Cluster Bombs (provided)",de="All of our ships are sunk! We need your help to break the pirate blockade below in the Shattered Straits! Take these cluster bombs and hitch a ride on the zeppelin that Harrowmeiser has 'loaned' to us. He'll fly you over the decks of those pirate bastards, and you make sure to give it to them good! If you can't bomb them to smithereens, I'm afraid we'll never be able to break the blockade.",g={n="Bombardier Petrov",x=0.29,y=0.42,loc="Westguard Keep, Howling Fjord"}}
d[11219]={r={{n="Hallow's End Pumpkin Treat (3) and"},{n="Weighted Jack-o'-Lantern"}},mo=3500,o="The Masked Orphan Matron wants you to help put out all the village fires (already burning). When they are out, speak again to the Masked Orphan Matron in town. *Put Out the Fires",de="The Horde's children need you, . The Headless Horseman, once a human paladin and now an insane fiend, has set fire to our village! You must put out those fires! Grab a bucket and throw it onto the blaze, or toss it to an ally who is closer to the flames. Extinguish all the fires and thwart the Headless Horseman!",g={n="Masked Orphan Matron",loc="Durotar; Eversong Woods; Tirisfal Glades"}}
d[11293]={r={{n="15xBrewfest Prize Token"}},o="Spread the word about Brewfest at the flags outside the bank, in the Military Ward, in the Hall of Explorers and in the Mystic Ward. * Bark Outside the Bank * Bark in the Military Ward * Bark in the Hall of Explorers * Bark in the Mystic Ward * Ram Racing Reins (provided)",de="We need to get the word out about the Barleybrews at Brewfest. You need to shout at the flags outside the bank, in the Military Ward, in the Hall of Explorers and in the Mystic Ward. I'll make things easy though, I'll lend you a racing ram for 4 minutes. Use the reins to let him go, but try not to tire him out.",g={n="Becan Barleybrew",loc="Dun Morogh"}}
d[11294]={r={{n="15xBrewfest Prize Token"}},o="Spread the word about Brewfest at the flags outside the bank, in the Military Ward, in the Hall of Explorers and in the Mystic Ward. * Bark Outside the Bank * Bark in the Military Ward * Bark in the Hall of Explorers * Bark in the Mystic Ward * Ram Racing Reins (provided)",de="It's time to let people know that the Thunderbrew have heard their cries for good brew. You need to shout at the flags outside the bank, in the Military Ward, in the Hall of Explorers and in the Mystic Ward. We'll make it easy though. We'll lend you a ram for 4 minutes. Be careful with going too fast though since you won't find any apple crates in Ironforge... We can't take the chance of helping out the Barleybrew messengers.",g={n="Daran Thunderbrew",x=0.494,y=0.386,loc="Dun Morogh"}}
d[11335]={r={{n="up to +"}},mo=119900,o="Win an Arathi Basin battleground match and return to an Alliance Brigadier General at any Alliance capital city or Shattrath. * Victory in Arathi Basin",de="The reality of fighting on multiple fronts, , is that we cannot spread our forces too thin or we risk losing it all! Critical troop deployments are necessary on a day by day basis. Today it is the battle of Arathi Basin that demands immediate reinforcements. Return to me with news of victory, . We cannot allow the Horde scum to secure the resources that are rightfully ours!"}
d[11336]={r={{n="+"}},mo=119900,o="Win an Alterac Valley battleground match and return to an Alliance Brigadier General at any Alliance capital city or Shattrath. * Victory in Alterac Valley",de="The reality of fighting on multiple fronts, , is that we cannot spread our forces too thin or we risk losing it all! Critical troop deployments are necessary on a day by day basis. Today it is the battle for Alterac Valley that's in most need of brave combatants. Go now, , and aid the Stormpike Expedition. We cannot allow the Frostwolf Clan to get away with the violence they've inflicted on our brethren!"}
d[11337]={r={{n="+"}},mo=119900,o="Win an Eye of the Storm battleground match and return to an Alliance Brigadier General at any Alliance capital city or Shattrath. * Victory in the Eye of the Storm",de="The fight against the Horde knows no boundaries, . Even in Outland, territorial disputes and old hatreds are enough to tip the scales in favor of war. Go into the Eye of the Storm and make sure the Alliance prevails in Outland just like it has in Azeroth."}
d[11338]={r={{n="up to +"}},mo=119900,o="Win a Warsong Gulch battleground match and return to an Alliance Brigadier General at any Alliance capital city or Shattrath. * Victory in Warsong Gulch",de="The Silverwing Sentinels fight to protect the forest in Warsong Gulch. We aid them, not because we're tree-lovers, but because the forest forms a natural protective barrier for Alliance territory. Their need is greater today than it's ever been. We need to deploy reinforcements right away unless we want to see Ashenvale annexed to the Barrens!"}
d[11339]={r={{n="up to +"}},mo=119900,de="Arathi Basin is on the verge of being lost to Alliance forces. We must send reinforcements at this very moment or all our efforts will have been in vain. Do not delay, , go to Arathi Basin and crush the enemy. Victory to the Horde!"}
d[11340]={r={{n="+"}},mo=119900,o="Win an Alterac Valley battleground match and return to a Horde Warbringer at any Horde capital city or Shattrath. * Victory in Alterac Valley",de="We've recently come extremely close to driving the Stormpike invaders from Alterac Valley. As a result we're redirecting all our reinforcements to aid the Frostwolf Clan. A decisive victory there would free up the resources we need to crush the Alliance scum on all the other battlefronts. Go, . Earn great honor by heeding the call of the brave Frostwolf warriors."}
d[11341]={r={{n="+"}},mo=119900,o="Win an Eye of the Storm battleground match and return to a Horde Warbringer at any Horde capital city, Wintergrasp, Dalaran, or Shattrath. * Victory in Eye of the Storm",de="We will fight and crush the enemy wherever we find them. Azeroth, Outland, the place makes no difference. We cannot allow the Alliance to establish superiority in the Eye of the Storm. Take the battle to them today... tomorrow it might be too late!"}
d[11342]={r={{n="up to +"}},mo=119900,o="Win a Warsong Gulch battleground match and return to a Horde Warbringer at any Horde capital city, Wintergrasp, Dalaran, or Shattrath. * Victory in Warsong Gulch",de="The Alliance is an insidious enemy, . They claim to defend the Ashenvale forests to justify their acts of aggression against our territories in the Barrens. Today we have an opportunity to drive the enemy from our lands once and for all. Go to Warsong Gulch and take back what is rightfully ours!"}
d[11377]={r={{n="Barrel of Fish or Crate of Meat"}},mo=75900,o="The Rokk in Lower City has asked you to cook up some Kaliri Stew using his cooking pot. Return to him when it's done. *Kaliri Stew *Cooking Pot (Kaliri Stew) (provided)",de="I'm providing the catering for some unusual party guests tonight. One of these fellows was flying around in Skettis and got knocked to the ground by a monstrous kaliri--his leg was broken badly. They've requested something special for his get well party: Kaliri Stew. I can loan you my cooking pot so you can whip up a batch of stew for me. The recipe itself is simple, but you'll need to get a giant kaliri wing and some cooked warp burgers.",g={n="The Rokk",x=0.62,y=0.16,loc="Lower City, Shattrath City"}}
d[11379]={r={{n="Barrel of Fish or Crate of Meat"}},mo=75900,o="The Rokk in Lower City has asked you to cook up some Demon Broiled Surprise using his cooking pot. Return to him when it's done. * Demon Broiled Surprise * Cooking Pot (Demon Broiled Surprise) (provided)",de="I'm trying to invent something with some real zing. But to be honest, I'm more of an idea goblin these days. I've lost my sense of adventure. But you... remind me of my younger days; ready to take on the world with a sword in one hand and a skillet in the other. I want you to take my beloved cooking pot and head out to Blade's Edge. Throw in some shortribs and crunchy serpent--already cooked for extra flavor--and broil it over an abyssal's corpse, the only thing hot enough to do the trick.",g={n="The Rokk",x=0.62,y=0.16,loc="Lower City, Shattrath City"}}
d[11380]={r={{n="Barrel of Fish or Crate of Meat"}},mo=75900,o="The Rokk in Lower City has asked you to collect 15 Mana Berries from the Eco-Domes in Netherstorm. * Mana Berry 0/15",de="Wouldn't you know it, I think my foodstuffs are up to date and someone comes along and request the unusual: Mana Berry Delight. Unfortunately, mana berries are only found in the eco-domes of Netherstorm. Just don't bother looking around Stormspire--it's picked clean. I could only trust someone trained in the culinary arts to pick the best berries, so don't let me down!",g={n="The Rokk",x=0.62,y=0.16,loc="Lower City, Shattrath City"}}
d[11381]={r={{n="Barrel of Fish or Crate of Meat"}},mo=75900,o="The Rokk in Lower City has asked you to cook up some Spiritual Soup using his cooking pot. Return to him when it's done. * Spiritual Soup * Cooking Pot (Spiritual Soup) (provided)",de="Death is in the air. I've never had so many orders for my famous soup—it lifts your spirits and soothes the soul. And I know a fellow cook when I see one! Would you like to help me out and get a cut of the profits? Here, take my cooking pot, gather some and I'll let you in on a little secret. What makes my soup so good for the soul? It's not chicken—I cook it at the Ancestral Grounds in Nagrand to soak up all that spiritual stuff there.",g={n="The Rokk",x=0.62,y=0.16,loc="Lower City, Shattrath City"}}
d[11391]={r={{n="Super Healing Potion (2)"}},mo=47000,rep="+250 Explorers' League",o="You're Steel Gate's ace pilot now, so the Steel Gate Chief Archaeologist wants you to keep patrol around the dig site and fight off anything that attacks. Report back to him when you're done with your patrol. * Gjalerbron Gargoyle slain (8)",de="Eh? Yer back for another day's work? Well, alright, here's the keys. We don't need any haulin' today, so just keep an eye out for anything suspicious, okay? I've hooked her up with some rockets and a machine gun - just in case.",g={n="Steel Gate Chief Archaeologist",x=0.308,y=0.286,loc="Steel Gate, Howling Fjord"}}
d[11405]={o="Take a Dreary Candle to the Loosely Turned Soil. * Dreary Candle (provided) * Suggested Players [5]",de="Many dreary candles adorn this pumpkin shrine, which grins, taunting...",g={n="Pumpkin Shrine"}}
d[11407]={r={{n="15x Brewfest Prize Token"}},o="Spread the word about Brewfest at the flags outside the auction house in the Valley of Strength, in the Valley of Honor, in the Valley of Wisdom and in the Valley of Spirits. *Ram Racing Reins (provided)",de="So, do you want to help bring strength and honor to Brewfest? We need you to shout at the flags outside the auction house in the Valley of Strength, in the Valley of Honor, in the Valley of Wisdom and in the Valley of Spirits. We'll lend you a racing ram for 4 minutes and also give you these racing reins. Be careful though, the cheap goblins didn't put any apple crates along the way.",g={n="Cort Gorestein",x=0.443,y=0.178,loc="Durotar"}}
d[11408]={r={{n="15xBrewfest Prize Token"}},o="Spread the word about Brewfest at the flags outside the auction house in the Valley of Strength, in the Valley of Honor, in the Valley of Wisdom and in the Valley of Spirits. *Ram Racing Reins (provided)",de="We need to spread the word about the trolls at Brewfest. Ya need to shout at the flags outside the auction house in the Valley of Strength, in the Valley of Honor, in the Valley of Wisdom and in the Valley of Spirits. But I'll make it easy for ya, I'll lend you a racing ram for 4 minutes. I'll also give you these racing reins. Be careful though, the goblins didn't put any apple crates along the way. They are cheap like that.",g={n="Ja'ron",x=0.437,y=0.175,loc="Durotar"}}
d[11472]={mo=47000,rep="+500 The Kalu'ak",o="Toss Tasty Reef Fish at a Reef Bull to lead it to a Reef Cow. Once you have helped the two find true love, return to Anuniaq at Kamagua. * Reef Bull led to a Reef Cow",de="The Northsea Pirates slaughtered the isles' alpha sea lion bull. They did this to clean the decks of their ships! Now the sea lions won't mate. Help me to repopulate their numbers. The reef bulls can be found at the Twin Shores to the southeast. They crave the tasty reef fish that can be found on the east and west sides of the isles. Take this net and gather enough fish, at least a dozen—maybe more, to lure a bull across the strait to a reef cow. * Anuniaq's Net (provided)",g={n="Anuniaq",x=0.246,y=0.588,loc="Kamagua, Howling Fjord"}}
d[11496]={mo=34000,o="Captain Theris Dawnhearth at the Shattered Sun Staging Area wants you to obtain 4 Mana Remnants from Wretched Fiends and Wretched Devourers and use them to energize one of the Crystal Wards surrounding the Sun's Reach Sanctum to the north. *Mana Remnants (4) *Energize a Crystal Ward",de="Our first priority is to capture the Sun's Reach Sanctum. Once we've secured it, we'll be able to use its energy to open a portal from Shattrath. The sanctum is overrun with the Wretched - former blood elves who've devolved into mindless husks of their former selves. Its defenses would've normally prevented this intrusion, but the Wretched have stolen the power sources from the protective wards. Hunt down the Wretched and get the mana remnants they carry. Use them to energize the sanctum wards.",g={n="Captain Theris Dawnhearth",x=0.474,y=0.306,loc="Shattered Sun Staging Area, Isle of Quel'Danas"}}
d[11502]={r={{n="209 honor"}},rep="+500 Kurenai",o="Defeat 10 enemy players in Halaa and return to Lakoor in Telaar. *Halaa Enemy Combatant slain (10)",de="We are not a warlike race, . However when war comes to our lands, we do not run away from it. The Alliance and the Horde wage war in the city of Halaa, to the northwest. We do not know what the blood elves are scheming, but any victory for the Horde would be disastrous. The history between our people and the orcs is one of bloodshed and betrayal. Go and slay the enemy in Halaa and you will be rewarded in coin, honor and renown.",g={n="Lakoor",x=0.558,y=0.736,loc="Telaar, Nagrand"}}
d[11503]={r={{n="209 honor"}},rep="+500 The Mag'har",o="Defeat 10 enemy players in Halaa and return to Karrtog in Garadar. *Halaa Enemy Combatant slain (10)",de="Our ancient enemy, the draenei, have returned with powerful allies. They wage war in Halaa, southwest of here. We cannot allow them a victory there as Garadar would be next without a doubt. Go and slay those who would aid our ancient enemy.",g={n="Karrtog",x=0.528,y=0.36,loc="Garadar, Nagrand"}}
d[11505]={r={{n="+209 honor (620 honor at 80)"}},o="Help the Alliance secure a tower in the Bone Wastes. *Secure a Spirit Tower",de="Auchindoun's spirits have no stake in the conflict between the Alliance and the Horde, but incurring their favor will give our side an edge in the region. Ancient custom directs the living to pay their respects at spirit towers in the Bone Wastes - though only at specific times of the day. If you can help secure a tower during these times, you will have helped bring the spirits to our side. Should we succeed in gaining the spirits' favor, they will grant us a boon that will aid us in our endeavors.",g={n="Exorcist Sullivan",x=0.558,y=0.538,loc="Allerian Stronghold, Terokkar Forest"}}
d[11506]={r={{n="+209 honor"}},o="Help the Horde secure a tower in the Bone Wastes. *Secure a Spirit Tower",de="The draenei might be our enemies, but the spirits of their ancestors in Auchindoun are restless and have no allegiance. The draenei's custom required them to pay their respects at spirit towers at various times during the day. If you can help secure a tower during these times, you will help the spirits return to peace in Auchindoun. The Alliance will try to capture the towers in order to secure the dead's favor. We must ensure that our side succeeds instead.",g={n="Exorcist Vaisha",x=0.493,y=0.459,loc="Stonebreaker Hold, Terokkar Forest"}}
d[11514]={r={{n="Shattered Sun Supplies"}},mo=44000,rep="+250 Shattered Sun Offensive",o="Obtain 10 Smuggled Mana Cells and return them to Exarch Nasuun on the Terrace of Light in Shattrath City. *Smuggled Mana Cell (10)",de="We must maintain the energy to our portal or it will collapse. The mana cells that the ethereal at Bash'ir Landing have hidden will continue to serve our purposes. The landing sits atop the northwestern corner of the Blade's Edge Mountains, far to the north. Remember, acquire a phase device from one of the ethereal and then use it to locate the smuggled goods. Just be cautious of the phase wyrms that they use to guard the mana cells.",g={n="Exarch Nasuun",x=0.492,y=0.424,loc="Terrace of Light, Shattrath City"}}
d[11515]={r={{n="5x Mark of Sargeras or 5x Sunfury Signet"}},mo=51500,rep="+250 Shattered Sun Offensive",o="Magistrix Seyla at the Throne of Kil'jaeden wants you to kill 4 Emaciated Felbloods by using the Fel Siphon on them. You will need Demonic Blood from nearby Wrath Heralds to power the Fel Siphon. *Emaciated Felblood slain (4) *Fel Siphon (provided)",de="When Kael's forces retreated through that portal, his most loyal lackeys were rewarded with an abominable gift. They stayed behind and gorged themselves on the blood of demons for days. The blood has changed them, given them new powers. It will also prove their undoing. Obtain blood samples from other demons. Use them to power this fel siphon and deprive these arrogant fools of their new powers. Slay them in their weakened state and return to me.",g={n="Magistrix Seyla",x=0.582,y=0.176,loc="Throne of Kil'jaeden, Hellfire Peninsula"}}
d[11516]={r={{n="Shattered Sun Supplies"}},mo=44000,rep="+250 Shattered Sun Offensive",o="Magistrix Seyla at the Throne of Kil'jaeden wants you to use the Sizzling Embers to summon a Living Flare and slay Incandescent Fel Sparks near it until it becomes an Unstable Living Flare. Return to the Legion Gateway with the Unstable Fel Spark to destroy it. *Legion Gateway Destroyed *Sizzling Embers (provided)",de="We have to shut down this gateway to stop Legion reinforcements to the Isle of Quel'Danas. Take these embers, they contain one of my creations: a living flare. It is designed to act as a powerful destructive force - as long as it has been provided enough energy. Find the fel sparks that wander the area and slay them near the living flare. The flare will grow in power each time, until it becomes unstable. Once you've achieved this bring the flare to the gateway. It will know what to do.",g={n="Magistrix Seyla",x=0.582,y=0.176,loc="Throne of Kil'jaeden, Hellfire Peninsula"}}
d[11523]={mo=91000,rep="+150 Shattered Sun Offensive",o="Captain Theris Dawnhearth at the Shattered Sun Staging Area wants you to obtain 4 Mana Remnants from Wretched Fiends and Wretched Devourers and use them to energize one of the Crystal Wards surrounding the Sun's Reach Sanctum to the north. *Mana Remnants (4) *Energize a Crystal Ward",de="We've succeeded in reactivating the crystal wards around the sanctum, but why stop there? We'll build defenses around the other structures, but the Wretched are stubborn and continue to steal power from the crystal wards. Hunt them down and get the mana remnants they carry. Use the remnants to energize the sanctum wards; the safety of our operation depends on it.",g={n="Captain Theris Dawnhearth",x=0.474,y=0.306,loc="Shattered Sun Staging Area, Isle of Quel'Danas"}}
d[11524]={mo=91000,rep="+150 Shattered Sun Offensive",o="Vindicator Xayann at the Shattered Sun Staging Area wants you to place the Attuned Crystal Cores inside 5 defeated Arcane Sentries to turn them into friendly units. * Converted Sentry Deployed (5) * Attuned Crystal Cores (provided)",de="We lack the numbers to capture the Sanctum at Sun's Reach, but I've a plan that will tip the scales in our favor. The loose energy from the Sunwell has caused the sentries that patrol this island to malfunction. The crystal cores that control their behavior are damaged beyond repair. I've crafted new crystals that will bring them under our control; place them inside the hulls of defeated sentries. Once the golems are converted, take them to the sanctum. We need all the help we can get.",g={n="Vindicator Xayann",x=0.47,y=0.3,loc="Shattered Sun Staging Area, Isle of Quel'Danas"}}
d[11532]={mo=34000,rep="+150 Shattered Sun Offensive",o="Battlemage Arynna wants you to speak to Ayren Cloudbreaker when you're ready to fly over the Dead Scar. Once there, use the Arcane Charges to kill 2 Pit Overlords, 3 Eredar Sorcerers and 12 Wrath Enforcers. * Pit Overlord slain (2) * Eredar Sorcerer slain (3) * Wrath Enforcer slain (12) * Arcane Charges (quest item) (provided)",de="The Legion will move against us as soon as their forces to the south are freed up. The Scourge at the Dead Scar are keeping their forces occupied at the moment. It won't last long, however. I want yout to fly a dragonhawk over to the scar and put a dent in the demons' numbers with these arcane charges. If all goes well, they won't even notice us taking the armory from Kael's lackeys. Talk to Ayren, the dragonhawk master in the west part of the harbor, when you're ready to fly there.",g={n="Battlemage Arynna",x=0.474,y=0.352,loc="Sun's Reach Sanctum, Isle of Quel'Danas"}}
d[11535]={mo=44000,rep="+250 Shattered Sun Offensive",o="Smith Hauthaa in Sun's Reach Armory wants you to kill Darkspine Myrmidon to the east and use their keys to steal three pieces of the ore from their chests. *Darkspine Iron Ore (3)",de="Supplies are inbound, or so I'm told. Regardless, we can ill afford to wait around hoping that help arrives before our offensive stalls. We must make the best of what we have. As for me, I need ore to fashion an anvil so I can begin to upgrade our armor and weapons. There are a group of naga on the coast to the east of here collecting ore and placing it in chests for shipment to the Legion. Relieving them of their ore will help our efforts in more ways than one....",g={n="Smith Hauthaa",x=0.506,y=0.408,loc="Sun's Reach Armory, Isle of Quel'Danas"}}
d[11537]={mo=44000,rep="+250 Shattered Sun Offensive",o="Harbinger Inuuro wants you to slay 6 Burning Legion Demons and the Emissary of Hate in Dawning Square. Use the Shattered Sun Banner to impale the Emissary of Hate's corpse. *Burning Legion Demon slain (6) * Emissary of Hate Implaled * Shattered Sun Banner (provided)",de="We must continue to defeat and demoralize the armies of the Legion. The emissaries of hate are Legion shocktroopers sent to reinforce tactical Legion positions. The enemy rallies upon their arrival for they fear them more than they fear us. Today we will change that. Take this banner and slay the demons at Dawning Square. When the emissary is sent, slay and impale him.",g={n="Harbinger Inuuro",x=0.476,y=0.352,loc="Sun's Reach Sanctum, Isle of Quel'Danas"}}
d[11538]={mo=44000,rep="+250 Shattered Sun Offensive",o="Harbinger Inuuro wants you to slay 6 Burning Legion Demons and the Emissary of Hate in Dawning Square or the Sun's Reach Armory. Use the Shattered Sun Banner to impale the Emissary of Hate's corpse. *Burning Legion Demon Slain (6) *Emissary of Hate Impaled *Shattered Sun Banner (provided)",de="The Burning Legion holds the Sun's Reach Armory, which is of tactical importance to our operation. As long as their morale remains high we will not wrest the building from their control. The emissaries of hate are Legion shocktroopers sent whenever their forces suffer significant losses. The enemy rallies upon their arrival for they fear them more than they fear us. Today we will change that. Take this banner and slay the demons of the Legion. When the emissary is sent, slay and impale him.",g={n="Harbinger Inuuro",x=0.476,y=0.352,loc="Sun's Reach Sanctum, Isle of Quel'Danas"}}
d[11539]={mo=44000,rep="+250 Shattered Sun Offensive",o="Magister Ilastar at Sun's Reach Armory wants you to slay 6 Dawnblade Summoners, 6 Dawnblade Blood Knights and 3 Dawnblade Marksmen. *Dawnblade Summoner slain (6) *Dawnblade Blood Knight slain (6) *Dawnblade Marksman slain (3)",de="One of Kael's most elite forces, the Dawnblade army, has been stationed at the Sun's Reach Harbor and Dawnstar Village. The harbor is of critical importance to our plans, so any Dawnblade casualties you inflict will be of tremendous help. Kael'thas will rue the day that he turned his back on his people and sided with the Burning Legion.",g={n="Magister Ilastar",x=0.494,y=0.404,loc="Sun's Reach Armory, Isle of Quel'Danas"}}
d[11542]={rep="+250 Shattered Sun Offensive",o="Vindicator Kaalan at the Sun's Reach Armory wants you to speak to Ayren Cloudbreaker and fly over the Dawnblade reinforcement fleet. Use the Flaming Oil to set the ship sails on fire as you fly and once you land, slay 6 Dawnblade Reservists. *Sin'loren sails burned *Bloodoath sails burned *Dawnchaser sails burned *Dawnblade Reservist slain (6) *Flaming Oil (provided)",de="We're making a push to solidify our control of Sun's Reach by capturing the harbor next. Unfortunately a fleet of Dawnblade reservists is on its way to reinforce Kael's forces there. Take this oil and secure a dragonhawk from Ayren Cloudbreaker. You should be able to fly within reach of the ships' sails; once you're close enough, set them on fire. Land in one of the ships and attack the reservists. With their ship sails on fire they won't be able to mount much of a defense.",g={n="Vindicator Kaalan",x=0.504,y=0.390,loc="Sun's Reach Armory, Isle of Quel'Danas"}}
d[11513]={g={n="Exarch Nasuun",x=0.492,y=0.424,loc="Terrace of Light, Shattrath City"}}
d[11520]={g={n="Mar'nah",x=0.515,y=0.326,loc="Sun's Reach Harbor, Isle of Quel'Danas"}}
d[11521]={g={n="Mar'nah",x=0.515,y=0.326,loc="Sun's Reach Harbor, Isle of Quel'Danas"}}
d[11875]={g={n="Emissary Mordin",loc="Shattrath City"}}
d[11545]={rep="+150 Shattered Sun Offensive",o="Anchorite Ayuri at Sun's Reach in Sunwell Isle wants you to donate 10 gold. *Required Money:",de="We've taken Sun's Reach from the enemy and our final victory is at hand. The cost was high and many brave combatants gave their lives so we could achieve this. It is my goal to ensure that those who perished in combat are not forgotten. I ask that you take a moment to consider making a donation towards a memorial fund. Any leftover gold will go to the widows and orphans of the fallen.",g={n="Anchorite Ayuri",x=0.48,y=0.37,loc="Sun's Reach Sanctum, Isle of Quel'Danas"}}
d[11548]={rep="+150 Shattered Sun Offensive",o="Anchorite Ayuri at Sun's Reach in Sunwell Isle wants you to donate 10 gold. * Required Money:",de="We've built a memorial to honor those slain in battle. It's but a small consolation to the families that lost their loved ones. I am taking up a collection to aid the orphans and spouses of our war heroes. If you can spare a small donation it would go a long way.",g={n="Anchorite Ayuri",x=0.48,y=0.37,loc="Sun's Reach Sanctum, Isle of Quel'Danas"}}
d[11666]={r={{n="Bag of Fishing Treasures"}},o="Bring a Blackfin Darter to Old Man Barlo. You can find him fishing northeast of Shattrath City by Silmyr Lake.",de="You probably know all about the Golden Darter--they're fairly common in the rivers of Terokkar Forest and a delicacy for priests. But here's one you haven't heard of: the blackfin darter. The fish is notoriously crafty and difficult to catch. You have to pull your line at the last possible second, because they nibble at the bait before they take it. Drop your line in the rivers of Terokkar and bring me a black darter. Avoid the lakes, as the blackfin only thrive in moving water.",g={n="Old Man Barlo",x=0.38,y=0.12,loc="Silmyr Lake, Terokkar Forest"}}
d[11667]={r={{n="Bag of Fishing Treasures"}},o="Catch the World's Largest Mudfish and bring it to Old Man Barlo. You can find him fishing northeast of Shattrath City by Silmyr Lake. * World's Largest Mudfish",de="Figluster's Mudfish is a surprisingly quick bottom feeder found in the waters of Nagrand. They grow their entire lives and are well known as fighters. Years ago, I caught what I'm certain was the world's biggest mudfish... until it snapped my line and escaped. A fisherman of your caliber doesn't need to be told what to do—your destiny awaits in the lakes of Nagrand.",g={n="Old Man Barlo",x=0.38,y=0.12,loc="Silmyr Lake, Terokkar Forest"}}
d[11691]={mo=44000,o="Bring the Earthen Ring Magma Totem to the Ice Stone, north of Luma Skymother. *Earthen Ring Magma Totem (provided) * Suggested Players: [5]",de="I and my Shamans have gathered our powers for the coming battle with the Lord of Frost. , you will be the fist of the Earthmother. Take this magma totem. Use it against the Ice Stone, to the north. Ahune is channeling his power through this stone; it is our hope that the totem will disrupt him and cut off his link to the elemental planes. If fortune is with us, then, perhaps, we can defeat him. Prepare yourself, . If Ahune comes to face us, then his fury will be great.",g={n="Luma Skymother",loc="Slave Pens, Coilfang Reservoir"}}
d[11877]={r={{n="Shattered Sun Supplies"}},mo=44000,rep="+250 Shattered Sun Offensive",o="Lord Torvos in Shattrath wants you to capture the Sunfury Attack Plans. * Sunfury Attack Plans",de="As we press the offensive on Quel'Danas, we've discovered that Kael'thas' minions are planning a counterattack. By ordering the Sunfury blood elves, based in Netherstorm, to attack our operations in Outland, he hopes to draw troops and attention away from the Sunwell. We must not allow this to happen, . Each and every blade is needed on the front lines. Go to Netherstorm and capture their attack plans. Any of the Sunfury blood elves up there could be in possession of the plans. Good luck, .",g={n="Lord Torvos",loc="Terrace of Light, Shattrath City"}}
d[11921]={r={{n="Burning Blossom x5"}},o="Win the torch tossing game, then speak with the Master Fire Eater. *Hit 20 braziers. You have 1.5 minutes from time you hit Accept and receive the torches. *Practice Torches (provided)",de="Hello, fire juggler! Are you having fun and making fiery mayhem? That's what I like to hear! Now, do you think you're an expert at torch tossing? Then I have a test for you... You know the rules: toss torches at the marked braziers. This time, however, you have a little more time and a LOT more braziers to hit. Ready?",g={n="Master Fire Eater",loc="Alliance capital cities"}}
d[11924]={r={{n="Burning Blossom x5"}},o="Catch 10 torches in a row, then speak with the Master Fire Eater. *Catch 10 torches in a row. *Unlit Torches (provided)",de="Torch catching sure keeps you on your toes. Think you can keep it up for a long time? Let's see...",g={n="Master Fire Eater",loc="Alliance capital cities"}}
d[11925]={r={{n="Burning Blossom x5"}},o="Catch 10 torches in a row, then speak with the Master Flame Eater. *Catch 10 torches in a row. *Return to Master Flame Eater. *Unlit Torches (provided)",de="Torch catching sure keeps you on your toes. Think you can keep it up for a long time? Let's see...",g={n="Master Flame Eater",loc="Horde capital cities"}}
d[11926]={r={{n="Burning Blossom x5"}},o="Win the torch tossing game, then speak with the Master Flame Eater. *Hit 20 braziers. *Return to Master Flame Eater. *Practice Torches (provided)",de="Hello, fire juggler! Are you having fun and making fiery mayhem? That's what I like to hear! Now, do you think you're an expert at torch tossing? Then I have a test for you... You know the rules: toss torches at the marked braziers. This time, however, you have a little more time and a LOT more braziers to hit. Ready?",g={n="Master Flame Eater",loc="Horde capital cities"}}
d[11940]={mo=47000,rep="+325 Wyrmrest Accord",o="Raelorasz wants you to use the Blood-tipped Spear to subdue a Nexus Drake Hatchling and return it to him at the Transitus Shield. * Captured Nexus Drake * Raelorasz's Spear (provided)",de="I need more drake hatchlings to continue researching the runes covering their bodies. They can be found around the northwest edge of the valley.... Take this and use it on one of them. Wait for it to become subdued, then bring it here to me before it expires.",g={n="Raelorasz",loc="Transitus Shield, Borean Tundra"}}
d[11945]={mo=50000,rep="+500 The Kalu'ak",o="Utaik wants you to gather 8 Kaskala Supplies in Kaskala. *Kaskala Supplies (8)",de="Dark times are upon us. Karkut's spirit walks the earth and gathers the spirits of dead tuskarr. The sons of the mist have taken many of our brethren. Soon dear Kaskala will be reduced to ashes. There is hope yet. Not for us, perhaps, but we've sent our families to Unu'pe. Salvage any supplies before it's too late for our families.",g={n="Utaik",x=0.64,y=0.458,loc="Kaskala, Borean Tundra"}}
d[11960]={mo=50000,rep="+500 The Kalu'ak",o="Collect 12 Snowfall Glade Pups. Deliver them to Trapper Mau'i at Moa'ki Harbor. * Snowfall Glade Pup (item) (12)",de="We must move decisively against the wolvar if we're to have a chance of survival. However, I worry that in our zeal, too many of them will be slain. The Snowfall Glade wolvar have as much right to exist as do we. You and I will see to it that they get that chance. If Elder Ko'nani hasn't asked you already, he will ask you to deal with them. While you're upon the glade to the north, I'd like you to bag up their pups and bring them to me.",g={n="Trapper Mau'i",loc="Moa'ki Harbor, Dragonblight"}}
d[12020]={r={{n="10x Brewfest Prize Token"},{n="Down With The Dark Iron"}},o="Talk to Boxey Boltspinner in the Brewfest camp.",de="The Dark Irons took a beating! As they rushed back to the Grim Guzzler, a portion of their transport fell off. More importantly, you managed to keep the camp safe... today. Head over to Boxey and explain your heroic triumph over the Dark Iron dwarves.",g={n="Dark Iron Mole Machine Wreckage"}}
d[12038]={mo=50000,o="Mack at Granite Springs wants you to use his grog to burn 30 Famished Scourge Trolls. * Scourge Trolls Burned (30) * Mack's Dark Grog (provided)",de="Whatcha waitin' fer, ? Them shcourged trolls ain't gunna kill themselves! You know the drill. Take shome o thish here grog and hurl it at 'em from a distance.... Then jusht sit back an' watch 'em burn.",g={n="Mack Fearsen",x=0.712,y=0.682,loc="Various"}}
d[12062]={o="Speak with Coren Direbrew. *Suggested Players [5]",de="Coren Direbrew is in the next room, riling up Dark Iron dwarves for another attack on Brewfest. Defeat him! Go to Coren and pick a fight. Tell him his beer isn't fit for pigs. When you do that, be ready for a fight. The last person who insulted his brew... was fed to dire boars.",g={n="Brewfest Spy",loc="Blackrock Depths"}}
d[12133]={o="Give the Scorched Holy Symbol to the . *Scorched Holy Symbol (provided)",de="This large jack-o'-lantern rests in the middle of the village. It eyes those who look upon it, betraying a dark menace within. Smashing the pumpkin reveals an old, scorched holy symbol.",g={n="Large Jack-o'-Lantern"}}
d[12135]={r={{n="Tricky Treat and"},{n="Weighted Jack-o'-Lantern"}},mo=234000,o="The Costumed Orphan Matron wants you to help put out all the village fires after the Headless Horseman lights them. When they are out, speak again to the Costumed Orphan Matron. *Put Out the Fires",de="You must help us! The Headless Horseman will attack the village at any moment! Fires will be everywhere! The children aren't safe! Please, , will you face the fires of the Headless Horseman? When he comes, you must join the fire brigade. Grab a bucket and toss it on the fires, or pass it to a friend who's closer to the blaze. If you put out all the fires then we may yet be saved!",g={n="Costumed Orphan Matron",loc="Azuremyst Isle; Dun Morogh; Elwynn Forest"}}
d[12139]={r={{n="Tricky Treat"},{n="Weighted Jack-o'-Lantern"}},mo=3500,o="The wants you to help put out all the village fires after the Headless Horseman lights them. When they are out, speak again to the . *Put Out the Fires",de="The Headless Horseman will attack the village at any moment! Fires will be everywhere! , will you face the fires of the Headless Horseman? When he comes, you must join the fire brigade. Grab a and toss it on the fires, or pass it to a friend who's closer to the blaze. If you put out all the fires then we may yet be saved!"}
d[12155]={o="Give the Scorched Holy Symbol to the . *Scorched Holy Symbol (provided)",de="This large jack-o'-lantern rests in the middle of the village. It eyes those who look upon it, betraying a dark menace within. Smashing the pumpkin reveals an old, scorched holy symbol.",g={n="Large Jack-o'-Lantern"}}
d[12170]={mo=56000,rep="+250 with Horde Expedition",o="Raider Captain Kronn wants you to slay 10 Alliance units or players at the Blackriver Logging Camp. *Alliance in Blackriver slain (10)",de="The Venture Company abandoned operations shortly after we showed up. Clearly they were afraid of what we were going to do to their greedy little hides. With them gone, their logging camps are up for grabs. Our war machine is a hungry beast... without renewing our supplies we won't make it to Icecrown. Unfortunately the Alliance seems to have the same idea and we must make sure we're the ones that prevail. Head into the logging camp and help us fight the Alliance scum.",g={n="Raider Captain Kronn",x=0.265,y=0.658,loc="Blackriver Logging Camp, Grizzly Hills"}}
d[12192]={r={{n="10x Brewfest Prize Token"},{n="Down With The Dark Iron"}},o="Talk to Bizzle Quicklift in the Brewfest camp.",de="The Dark Irons took a beating! As they rushed back to the Grim Guzzler, a portion of their transport fell off. More importantly, you managed to keep the camp safe... today. Head over to Bizzle and explain your heroic triumph over the Dark Iron dwarves.",g={n="Dark Iron Mole Machine Wreckage"}}
d[12244]={r={{n="Key to Refurbished Shredder"}},mo=56000,o="Synipus at Blue Sky Logging Grounds wants you to bring 3 Broken-down Shredders back to him. *Shredder Delivered (3)",de="Listen, pal. Why don't ya roll up your sleeves and grab a wrench? There's work to be done! They need these shredders refurbished and sent down to Venture Bay, and they need it done yesterday.... No wrench? Well what good are ya then? May as well go down with the rest of the lugheads and play with the Horde! While you're there, see if you can drive some of those broken-down shredders up here for repairs. Be careful! They're in pretty bad shape.",g={n="Synipus",x=0.395,y=0.436,loc="Blue Sky Logging Grounds, Grizzly Hills"}}
d[12268]={mo=56000,o="Pipthwack in Blue Sky Logging Grounds wants you to collect 4 Grooved Cogs, 3 Notched Sprockets, and 2 High Tension Springs. *Grooved Cog (4) *Notched Sprocket (3) *High Tension Spring (2)",de="Ack! This thing's a mess! Goblin engineering leaves a great deal to be desired, believe you me. Just look at this! It's a wonder it ever worked to begin with. Give me a hand, will ya? To get this even close to operable specifications I'll need to replace a few cogs, sprockets, and springs. You should have no trouble finding them down around the sawmill.",g={n="Pipthwack",x=0.396,y=0.434,loc="Blue Sky Logging Grounds, Grizzly Hills"}}
d[12270]={r={{n="Key to Refurbished Shredder"}},mo=56000,rep="+250 Warsong Offensive",o="Grekk at Blue Sky Logging Grounds wants you to acquire 3 shredders and return to him with them. *Shredder Delivered (3)",de="Read my lips, - I need those shredders! Just as important - I need to keep them out of the hands of the alliance! They've been refurbishing the shredders and using them against our brothers in Venture Bay. Now we're going to give them a taste of their own medicine! You see a shredder out there, grab it! You see one of the alliance scum on one, kill 'em and then grab it! Once you have one, drive it back here to me and we'll get to work on it. Dismissed!",g={n="Grekk",x=0.346,y=0.325,loc="Blue Sky Logging Grounds, Grizzly Hills"}}
d[12280]={rep="+250 with Warsong Offensive",o="Lurz at Blue Sky Logging Grounds wants you to collect 4 Grooved Cog, 3 Notched Sprocket, and 2 High Tension Spring. * Grooved Cog (4) * Notched Sprocket (3) * High Tension Spring (2)",de="Twenty shredders by noon tomorrow! Who makes these schedules, anyway? No one who ever put one of these garbage cans back together, that's who.... If I'm going to hit my quota, I'll need a hand. Help me out and I'll share my commission with you - fair enough? I need cogs, sprockets and springs. They're littered across the ground down by the shredders.",g={n="Lurz",x=0.344,y=0.326,loc="Blue Sky Logging Grounds, Grizzly Hills"}}
d[12284]={rep="Warsong Offensive +250",o="Commander Bargok wants you to kill 15 Alliance units or players in Blue Sky Logging Ground. * Alliance units eliminated (15)",de="We've suffered heavy casualties here, . The only good news is that we've given as much as we've taken. I've requested more troops, but the bulk of our forces are bogged down in Venture Bay. It looks like we're on our own for now. No matter how bad it gets, we MUST stand our ground! The precious resources of this region are essential to the Horde's long-term success in Northrend. We've got to keep the Alliance on their heels until help arrives. Get out there and give 'em something to think about.",g={n="Commander Bargok",x=0.345,y=0.33,loc="Blue Sky Logging Grounds, Grizzly Hills"}}
d[12288]={rep="+250 Warsong Offensive",o="Aumana at Blue Sky Logging Grounds wants you to use the Renewing Tourniquet on 10 Wounded Skirmishers. * Wounded Skirmishers Healed (10) * Renewing Tourniquet (provided)",de="You there, ! Help me! We're losing valuable lives! There are simply too many wounded for me to tend to alone. If we can't get our soldiers healed we could be run out of Grizzly Hills altogether! Take this tourniquet and use it on the wounded down on the battlefield. Hurry, ! They're dyyying!!",g={n="Aumana",x=0.339,y=0.327,loc="Blue Sky Logging Grounds, Grizzly Hills"}}
d[12289]={mo=56000,rep="+125 Alliance Vanguard +250 Valiance Expedition",o="Sergeant Hartsman wants you to defeat 15 Horde units or players in Blue Sky Logging Grounds. *Horde units eliminated (15)",de="It is a dark day for the Alliance. Many good men lay dead or dying here. Our only consolation is that they fought well and brought down many of the enemy with them. With the bulk of our forces committed to Venture Bay we stand alone to weather this storm. The resources in this region are vital to the Alliance and may well make the difference in our struggle against the Horde. We must not fail! Go, . Strike at them while they lick their wounds. Avenge your fallen brothers and keep our hopes alive!",g={n="Sergeant Hartsman",x=0.394,y=0.438,loc="Blue Sky Logging Grounds, Grizzly Hills"}}
d[12296]={mo=56000,rep="+125 Alliance Vanguard+250 Valiance Expedition",o="Rheanna at Blue Sky Logging Grounds wants you to use the Renewing Bandage on 10 Wounded Westfall Infantry units. *Westfall Infantry Healed (10) *Renewing Bandage (provided)",de="Oh, the carnage.... I've been through many battles, , and this one was more brutal than any I've seen. Our fight with the Horde has become more intense than ever. It's them or us here in Northrend - life or death. If we are to survive here another day we'll need to mend our wounded. There are too many for me to rescue alone. I've prepared special bandages that will enable you to assist me. Take one and tend to those who have not yet succumbed to their wounds.",g={n="Rheanna",x=0.405,y=0.425,loc="Blue Sky Logging Grounds, Grizzly Hills"}}
d[12314]={mo=56000,o="Slay Captain Zorna and report to Baron Freeman in Venture Bay. * Captain Zorna slain * Suggested Players [3]",de="The Horde's forces are poised to break through our lines and complete their conquest of Venture Bay if we do not act. The Horde's forces in the port are commanded by Captain Zorna, near the ship on the far side of the bay. If you can defeat her, the Horde's offensive will falter and we can seize the chance to capture the port. Beware, , for Zorna is a fierce fighter. It may take several people to defeat her, or if you have access to a repaired shredder, you might try using it to your advantage.",g={n="Baron Freeman",x=0.222,y=0.812,loc="Venture Bay, Grizzly Hills"}}
d[12315]={mo=56000,o="Slay Captain Brightwater and report to General Khazgar at Venture Bay. * Captain Brightwater slain * Suggested Players [3]",de="With every advance, our men are met by fresh Alliance reinforcements. It's almost as though their commander anticipates my every move! The time has come for good Captain Brightwater to meet his end. He commands his troops from aboard an Alliance destroyer at the far end of the bay. This will be no easy fight, . Take along a couple of trusted friends, or if you have a key to one of those repaired shredders, use it to disembowel Brightwater! Either way, he must fall!",g={n="General Khazgar",x=0.101,y=0.772,loc="Venture Bay, Grizzly Hills"}}
d[12317]={mo=56000,o="Defeat 10 Alliance units or players in Venture Bay and return to Centurion Kaggrum. *Alliance killed in Venture Bay (10)",de="This wretched Westfall Brigade is proving a tougher opponent than we'd thought. Though few in number, they fight well and bravely, but we cannot afford to wait them out. Conqueror Krenna's orders were to capture the port quickly. You must break the stalemate, . Find the enemy's marines and slaughter them until the resistance ceases. Only then will we be able to claim ownership of the port. Go quickly. We don't want to keep Conqueror Krenna waiting.",g={n="Centurion Kaggrum",x=0.101,y=0.773,loc="Venture Bay, Grizzly Hills"}}
d[12323]={mo=56000,o="Use the Smoke Bomb to drive 20 Venture Company Stragglers from their buildings and then report to Sergeant Downey. *Venture Company Stragglers smoked out (20) *Smoke Bomb (quest item) (provided)",de="There are still pockets of cowardly Venture Company men holed up in some of the buildings at the center of Venture Bay. I need every man I can spare out there fighting against the Horde, but we can't allow those Venture Company stragglers to camp out in those buildings, either. Maybe we can \"convince\" them to make for their ship. Take this smoke bomb and use it to smoke out the stragglers from their places in the bunkhouse, sawmill, or stables. Don't get too close, though; they probably bite.",g={n="Sergeant Downey",x=0.22,y=0.808,loc="Venture Bay, Grizzly Hills"}}
d[12324]={mo=56000,o="Use the Smoke Bomb to drive 20 Venture Company Stragglers from their buildings and then report to Stone Guard Ragetotem. * Venture Company Stragglers smoked out (20) * Smoke Bomb (quest item) (provided)",de="Not only is this port infested with sniveling Alliance cowards, but to make matters worse, there are still Venture Company employees holed up in some of the buildings. They're not worth the time it takes to kill and I can't spare the warriors anyway. Maybe we can \"convince\" them to make for their ship. Take this smoke bomb and use it to smoke out the stragglers from their places in the bunkhouse, sawmill, or stables. Don't get too close, though; there's no telling what diseases they're carrying.",g={n="Stone Guard Ragetotem",x=0.113,y=0.769,loc="Venture Bay, Grizzly Hills"}}
d[12372]={mo=56000,rep="+325 The Wyrmrest Accord",o="Devrestrasz at Wyrmrest Temple has asked you to slay 3 Azure Dragons, slay 5 Azure Drakes, and to destabilize the Azure Dragonshrine while riding a Wyrmrest Defender into battle. * Azure Dragon slain (3) * Azure Drake slain (5) * Destabilize the Azure Dragonshrine",de="Emboldened by the overabundance of magic now flowing through the Azure Dragonshrine, the blue dragonflight has dared to attack Wyrmrest Temple itself! I ask that you ride one of our defenders into battle to slay their dragons and drakes, and to attack the eruption of ley line energies at the dragonshrine itself in order to destabilize it. Outside on the east and west terraces are wyrmrest defenders. Speak with one to ride it into battle. Without your help, , we will surely lose.",g={n="Lord Devrestrasz",x=0.592,y=0.542,loc="Various"}}
d[12432]={mo=56000,o="General Gorlok at the lighthouse in Venture Bay wants you to destroy the Alliance Lumber Boat. General Gorlok will only be present at the lighthouse when the Horde has it in their possession. *Destroyed Alliance Lumber Shipment",de="You there, ! Get your lousy carcass over here! The Alliance have a shipment of lumber all ready for transport just northeast of here. Since getting our hands on that wood is out of the question, there's only one thing to do - destroy it! The goblin at the end of the dock here has some torpedoes all ready to go. He's got all the fuel for them on the docked goblin ship. Get some fuel, then commandeer one of the torpedoes and ride it into their ship. Dismissed!",g={n="General Gorlok",x=0.146,y=0.865,loc="Venture Bay, Grizzly Hills"}}
d[12437]={mo=56000,o="Commander Howser at the lighthouse in Venture Bay wants you to destroy the Horde lumber shipment. Commander Howser will only be present at the lighthouse when the Alliance has it in their possession. *Horde Lumberboat destroyed",de="Listen, . This battle is as much over resources as tactical supremacy. I have a mission that could turn the tide in our struggle against the Horde here. We have a chance to strike a critical blow against them and the window could close at any moment. There are torpedoes at the end of the dock that we can use to take down the Horde's lumber ship to the northwest. You'll need to get some of the fuel that's stored on the docked goblin ship, then ride one of the torpedoes into their transport!",g={n="Commander Howser",x=0.148,y=0.866,loc="Venture Bay, Grizzly Hills"}}
d[12444]={mo=56000,rep="+125 Alliance Vanguard+250 Valiance Expedition",o="Scout Captain Carter wants you to kill 10 Horde units or players in the Blackriver Logging Camp. *Horde in Blackriver slain (10)",de="The Venture Company's on its way out of Grizzly Hills. They used to run logging operations here, but things got a little too dangerous for them. Their abandoned sites are up for grabs and we sure as hell can't let the Horde get their hands on them. The Blackriver Logging Camp is the smallest of the three logging sites in this zone, but we still need it. Do your part and fend off the Horde forces. Any lumber they get here will be made into weapons to be used against us elsewhere.",g={n="Scout Captain Carter",x=0.3,y=0.598,loc="Blackriver Logging Camp, Grizzly Hills"}}
d[12502]={mo=15800,o="Captain Brandon wants you to place the Argent Crusade Banner in the Drakkari Pedestals at Drak'Sotra * Argent Crusade Banner South * Argent Crusade Banner North * Argent Crusade Banner East *Argent Crusade Banner (provided)",de="Listen, . This is the Argent Crusade. Our men will fight to the end and never complain no matter what the conditions. That said, we've taken some heavy casualties in this campaign and we've been hitting it hard with little or no sleep for months. That all takes a toll on morale, whether we admit it or not. It may not seem like much, but seeing our standard raised over the battlefield is of considerable comfort to a soldier. Take these banners and raise them at the pedestals in Drak'Sotra.",g={n="Captain Brandon",x=0.488,y=0.789,loc="Various"}}
d[12509]={mo=15800,o="Captain Rupert in Drak'Sotra wants you to restore courage to the cowering Crusade Recruits. * Recruit's Courage Restored (5)",de="Finally, the patrol arrives! Here's the situation, . We've lost many of our finest soldiers in this campaign and have had to call upon our recruits to fill in the gaps. We've just fought one of our fiercest battles and many of the recruits were simply not prepared to face this enemy. There are more fights ahead, and I need them ready to follow orders. If there's one thing I can't stomach, it's cowardice. Perhaps you can help them find the courage to continue.",g={n="Captain Rupert",x=0.58,y=0.72,loc="Various"}}
d[12519]={mo=15800,o="Captain Grondel outside the Coliseum wants you to gather 7 Drakkari Medallions from the nearby Drakkari Corpses. * Drakkari Medallion: (7)",de="Look at me, . Do I look like I have time fer fillin' out reports? It be all I can do to keep this post free o' the bloody Scourge, and they want me to mess with paperwork! No sense in complainin'. I need to get the commander some kinda kill count from the last skirmish. You wanna be helpful? Go and get me all the medals you can find from the dead trolls around here. That'll hafta be close enough.",g={n="Captain Grondel",x=0.481,y=0.638,loc="Various"}}
d[12541]={mo=15800,o="Alchemist Finklestein at Heb'Valok wants you to assist him in the creation of a truth serum. When you are ready to begin, you are to speak to him and follow his instructions. * Truth Serum Created",de="Ahh, you must be the promised patrol. Your timing couldn't be better. I have urgent need of an extra pair of hands. We have a Drakkari prisoner who's been sent here to undergo questioning. Before the interrogation begins, I require assistance in the creation of a truth serum. Creating a truth serum is tricky business, demanding keen instincts, perfect timing, and improvisation at every step. Let me know when you're ready, . And remember, timing is everything!",g={n="Alchemist Finklestein",x=0.35,y=0.52,loc="Heb'Valok, Zul'Drak;Light's Hammer, Icecrown Citadel"}}
d[12564]={mo=15800,o="Captain Brandon at Drak'Sotra wants you to collect 5 Mature Water-Poppies from Drak'Sotra Fields. * Mature Water-Poppy (5)",de="Gritty as my men are, they're still mortal. Wounds and pain diminish their ability to perform their missions. No amount of training changes that simple fact of life. Thankfully, one of our alchemists has developed a recipe for a salve that binds to our bandages and greatly reduces the pain our soldiers experience. The salve requires a special poppy these trolls cultivate just west of here. Go to Drak'Sotra Fields and harvest some of them to keep our stockpiles from running out.",g={n="Captain Brandon",x=0.488,y=0.789,loc="Various"}}
d[12568]={mo=15800,o="Captain Rupert wants you to use the Incinerating Oil on 5 Defeated Argent Footmen in Drak'Sotra. * Argent Footman Corpse Incinerated (5)",de="Trust me, . I know.... The smell of burnt flesh has become sickening to even me, a Forsaken. Nevertheless, it is our solemn duty to ensure that our brethren never walk with the Scourge. Pour this oil on the corpses of our fallen to ensure that we never face them on the battlefield as enemies.",g={n="Captain Rupert",x=0.58,y=0.72,loc="Various"}}
d[12585]={mo=15800,o="Captain Grondel at Drak'Agal wants you to bring him 20 pieces of Dead Thornwood. * Dead Thornwood (20)",de="Well, it ain't glamorous, but it needs doin'. My troops have been fightin' their hearts out while knee-deep in stagnant water for days on end. That just can't be good fer ya. What they need is a nice fire to dry 'em out and lighten their spirits. This part of the city's soaked, but the dead roots of these thornwood trees have a way of resistin' the moisture. Round us up some fuel for burnin' and we'll be mighty grateful.",g={n="Captain Grondel",x=0.481,y=0.638,loc="Various"}}
d[12588]={mo=15800,o="Captain Bran in Drak'Sotra wants you to use the Steel Spade on the nearby Ancient Dirt Mounds to recover the Ancient Drakkari Relic. * Ancient Dirt Mounds Investigtated (5) *Steel Spade (provided)",de="One of our troops came across an old treasure map during our last offensive. If what it shows is true, then there are priceless troll artifacts nearby. My soldiers have their hands full, pressed between the Drakkari and the Scourge. I need you to follow up on this intelligence. Take this shovel and use it at the loose dirt mounds to the southwest. Return to me after a diligent search has been conducted.",g={n="Captain Brandon",x=0.488,y=0.789,loc="Various"}}
d[12591]={mo=15800,o="Captain Rupert at Drak'Sotra wants you to use High Impact Grenade near 5 Nethurbian Craters. * Nerubian Tunnels Collapsed (5) * High Impact Grenade (provided)",de="Clever... Just when it seemed we were getting things under control, they tunneled right underneath us and secured the shrine! Now we're caught between two nethurbian armies and our predicament is worsening by the minute. As our first course of action, we must stop them from reinforcing. Their tunnels must be sealed. Take these grenades and throw them down their craters to the northwest.",g={n="Captain Rupert",x=0.58,y=0.72,loc="Various"}}
d[12594]={mo=15800,o="Captain Grondel wants you to kill 7 Mossy Rampagers in Drak'Agal. * Mossy Rampagers Slain: (7)",de="Of all the posts, they throw me in this one. The place is flooded with putrid, stagnant water and now it's host to sewage elementals! I don't really know what they are or why they're here, and frankly I couldn't care less. What I do know is they're making a mess of my sector! How am I supposed to conduct any dignified military operations with those foul things roaming around? Get out there, , and don't come back 'til you've cleared your share of 'em off of my battlefield!",g={n="Captain Grondel",x=0.481,y=0.638,loc="Various"}}
d[12689]={g={n="Jaloot",x=0.725,y=0.575,loc="Sholazar Basin"}}
d[12702]={rep="Frenzyheart Tribe +250",o="Capture 12 Chicken Escapees for Elder Harkek at Frenzyheart Hill. * Captured Chicken (12) * Chicken Net (provided)",de="I bet you not guess what happen again. Nope, not Goregek or chickens. Okay, I lie. Goregek let chickens out again. Dumb Goregek and rumbly belly. Let me know if you need help from any of the hunters... they around here somewhere.",g={n="Elder Harkek",loc="Frenzyheart Hill; Sholazar Basin"}}
d[12703]={rep="Frenzyheart Tribe +350",o="Bring a pure sample of :Oracle Blood to the Altar of Kartak to summon Kartak the Abomination. With the aid of Kartak's shared powers, slaughter 50 of the nearby Sparktouched Gorlocs for Shaman Jakjek in Kartak's Hold. * Sparktouched Gorloc (50)",de="You the great Lich Hunter, eh? Good to have such strong Frenzyheart ally for battle. Maybe you strong enough to call Kartak even. Big battle at Kartak's Hold to southwest. Go kill spark big-tongues until you get good bit of Oracle Blood. Bring blood to altar in Kartak's Hold to call Kartak for delicious feast of big-tongue. Kartak take your body if you worthy... with Kartak's powers, you slaughter more big-tongues than even best dreams. Go kill lots, hunter!",g={n="Vekgar",loc="Frenzyheart Hill, Sholazar Basin"}}
d[12704]={rep="+500 The Oracles",o="Soo-say in Rainspeaker Canopy wants you to take a companion to dig up and collect 6 Shiny Treasures. Be sure to speak to Soo-say in Rainspeaker Canopy about securing the aid of one of your previous companions. *Shiny Treasures (6)",de="Since mosswalker been attacked I worried maybe we not good to Great Rain Stone... we maybe too greedy. We need more treasures to offer! You good at finding shinies last time... maybe you go look more around village for shinies? You maybe need one of good Rainspeakers for help. Just tell us who.",g={n="High-Oracle Soo-say",loc="Sholazar Basin"}}
d[12726]={r={{n="or at 80."}},rep="+500 The Oracles",o="Soo-nee wants you to use the Tempest Drums at the Stormwright's Shelf and help Haiphoon devour 3 Storm Revenants and 3 Aqueous Spirits. * Aqueous Spirit Devoured (4) * Storm Revenant Devoured (4) * Drums of the Tempest (provided)",de="Listen to storm, yes? The Stormwright's Shelf echoes with ancient song.... the Song of Wind and Water. The great tempest devours the sons of typhoons and storms. Take this drum and play his song... play Haiphoon's song. Help him feed on wind and water so tempest can continue.",g={n="Oracle Soo-nee",x=0.532,y=0.569,loc="Sholazar Basin"}}
d[12732]={rep="Frenzyheart Tribe +250",o="Bring a vial of Suntouched Heartblood to Rejek at Frenzyheart Hill. * Suntouched Heartblood * Rejek's Vial (provided)",de="One day, Rejek will be mighty warrior. Blood and skyfire will make Rejek strong. You see soon. Rejek give you vial, you take to very top of Suntouched Pillar, far to west. Put waters there in vial. Then go to north edge of basin, to ledge north of Bonefields. You find and kill goretalon matriarch. Take heartblood. You combine heartblood and water, bring to Rejek. Rejek drink, make strong.",g={n="Rejek",x=0.557,y=0.695,loc="Frenzyheart Hill, Sholazar Basin"}}
d[12734]={rep="Frenzyheart Tribe +250",o="Blood Rejek's Blade on the corpses of a Sapphire Hive Wasp, a Hardknuckle Charger, and 3 members of the Mistwhisper Tribe. You may blood the sword on either Mistwhisper Oracles or Mistwhisper Warriors. Return to Rejek at Frenzyheart Hill when your task is complete. * Blade blooded on Sapphire Hive Wasp * Blade blooded on Hardknuckle Charger * Blade Blooded on Mistwhisper members (3) * Rejek's Blade (Provided)",de="Rejek just became youngest warrior in all of Frenzyheart tribe. Father gave Rejek a mighty sword to defeat Frenzyheart enemies, but old tradition say sword need to be blooded first. Older warrior usually do that. You do this honor for Rejek? Take blade, put in corpses of all Frenzyheart foes: wasps and hardknuckles to southwest, and the big-tongues. Maybe blood blade on Mistwhispers, far to northwest near Bittertide Lake.",g={n="Rejek",x=0.557,y=0.695,loc="Frenzyheart Hill, Sholazar Basin"}}
d[12735]={r={{n="or at 80."}},o="Soo-nee, at the Rainspeaker Canopy, wants you to play the Cleansing Chime at Bittertide Lake, Wintergrasp River and River's Heart and slay the evil spirits that plague the waters there. *Kill Spirit of Ha-Khalan *Kill Spirit of Atha *Kill Spirit of Koosu *Chime of Cleansing (provided)",de="Earth in Sholazar is pure. The pillars have protected the land for centuries. Water, not as pure, it comes from outside Sholazar.... from oceans, from lakes, from rivers. Water sometimes bring bad spirits - need to be cleansed. You take this chime and play at Bittertide Lake, Wintergrasp River and River's Heart. It make bad spirit angry... and then you must kill it.",g={n="Oracle Soo-nee",x=0.532,y=0.569,loc="Sholazar Basin"}}
d[12736]={r={{n="or at 80."}},rep="+500 The Oracles",o="Soo-nee at Rainspeaker Canopy wants you to use the Didgeridoo of Contemplation at the top of the Glimmering Pillar, the Suntouched Pillar, the Mosslight Pillar and the Skyreach Pillar. * Contemplation at Glimmering Pillar * Contemplation at Suntouched Pillar * Contemplation at Mosslight Pillar * Contemplation at Skyreach Pillar * Didgeridoo of Contemplation (provided)",de="Of course you not as smart as gorloc! You just simple . You not without hope, though! You show you can learn. Maybe crystals make you smart like crystals make us smart! I teach you to play song to clear your mind. You play song by crystals then crystals make your mind better... not as good as gorloc's but better than you have now. Lifeblood Pillar is broken, but other pillars still good!",g={n="Oracle Soo-nee",x=0.532,y=0.569,loc="Sholazar Basin"}}
d[12737]={r={{n="or at 80."}},rep="+500 The Oracles",o="Soo-nee at Rainspeaker Canopy wants you to go to the Stormwright's Shelf, northwest of the Maker's Perch, and play the Horn of Fecundity near 8 piles Soaked Fertile Dirt. * Song of Fecundity played (8) * Horn of Fecundity (provided)",de="The storm is a destructive force. Storm burns trees. Storm floods houses. But storm can also be life force if you know right song. In Stormwright Shelf, above Maker's Perch, you can find small dirt mounds. They very fertile—they carry inside a strong seed. All they wait for is the right song. You take this horn and play song for them.",g={n="Oracle Soo-nee",x=0.532,y=0.569,loc="Sholazar Basin"}}
d[12741]={rep="Frenzyheart Tribe +250",o="Gather 3 Essence of the Monsoon and 3 Essence of the Storm (Sholazar Basin) and take them to the Shrine of the Tempest. Return to Rejek at Frenzyheart Hill with the True Power of the Tempest. * True Power of the Tempest",de="Silly big-tongues think singing to the clouds give them power. Rejek show big-tongues how to get power by taking it! Far to northwest, there is large, flat area the big-tongues call 'Stormwright's Shelf.' Rejek is sure you can only get there by flying like bird. On this shelf, Rejek has heard of mighty forces of wind and water. Kill them for their badness, then take it to the big-tongue 'Shrine of the Tempest' at shelf's western side. Rejek will await your return with ultimate power.",g={n="Rejek",x=0.557,y=0.695,loc="Frenzyheart Hill, Sholazar Basin"}}
d[12758]={o="Get Venture Co. Explosives from any of the Venture Company units at Swindlegrin's Dig and use them to obtain a Stormwatcher's Head. Bring the Stomwatcher's Head to Rejek at Frenzyheart Hill. * Stormwatcher's Head",de="Rejek hears tales of giant metal men on faraway Stormwright's Shelf. Far to northwest, outside Basin's lip, you will find it. Imagine Rejek using heads of giant metal men as helmet. Make Rejek unstoppable! Make Rejek mighty! You get for Rejek, but metal head might not come off metal body easy. Maybe steal bombs from little green men and their friends at Swindlegrin's Dig near Suntouched Pillar? Use bombs to get head off metal body, then bring to Rejek.",g={n="Rejek",x=0.557,y=0.695,loc="Frenzyheart Hill, Sholazar Basin"}}
d[12759]={rep="Frenzyheart Tribe +350",o="Retrieve some of Zepik's traps from his stash in Kartak's Hold. Using the traps, slaughter 50 of the nearby Sparktouched Gorlocs, and then return to Shaman Jakjek in Kartak's Hold. * Sparktouched Gorloc (50)",de="Zepik tell me that you maybe the best gorloc hunter he met... other than Zepik. Still big battle to southwest - you go help. Zepik keeps some of biggest, baddest traps in his stash at Kartak's Hold... told Vekgar to use them for battle, so you use them too. Go pick out any traps you want and kill lots of big-tongues. Lots and lots!",g={n="Vekgar",loc="Frenzyheart Hill, Sholazar Basin"}}
d[12760]={rep="Frenzyheart Tribe +350",o="Using the secret Frenzyheart drink, slaughter 30 of the Sparktouched Gorlocs around Kartak's Hold and then speak to Shaman Jakjek. *Sparktouched Gorloc (30) *Secret Strength of the Frenzyheart (provided)",de="Battle still going at Kartak's Hold... I think it time for you to learn big secret of Frenzyheart. We have berries we keep from other lands we came from... they not so special on their own, but mix them with drunk drinks and they make Frenzyheart super strong. You a Frenzyheart now... it time you get to be strong too. I give some drink, then you be super strong and you go smash all the spark big-tongues.",g={n="Vekgar",loc="Frenzyheart Hill, Sholazar Basin"}}
d[12813]={rep="+325 Knights of the Ebon Blade",o="Setaal Darkmender at Death's Rise has given you the Darkmender's Tincture. Apply it to the corpses of 10 of any of the Scarlet Onslaught units found there. * Scarlet Onslaught corpse transformed (10)",de="How kind... how generous our lord-commander is. Where he is flowers and sunshine, I am filled only with hatred. It is not enough to end their miserable lives... I want them humiliated... debased! What could be more unspeakable than to be turned into that which you hate? To dedicate your existence to eradicating a thing, and then in the end to become it? How sad. Take this tincture northwest to Onslaught Harbor. Apply it to their still corpses and watch what happens, but avoid the cathedral.",g={n="Setaal Darkmender",x=0.19,y=0.48,loc="Various"}}
d[12815]={rep="+325 Knights of the Ebon Blade",o="Uzo Deathcaller at Death's Rise wants you to kill 10 Onslaught Gryphon Riders. * Onslaught Gryphon Rider slain (10) * Bone Gryphon (provided)",de="Now that you got your bone gryphon, I wantcha to take it back down there everyday and make a no fly zone over Onslaught Harbor. I gotta admit, mon, I don't really care if you use the bone gryphon to kill them gryphon riders or not. But I'm guessin' that if you do, you'll find it much easier to get to 'em. Besides, its got lots of neat tricks you can use.",g={n="Uzo Deathcaller",x=0.19,y=0.47,loc="Death's Rise, Icecrown"}}
d[12833]={mo=68000,o="Ricket at K3 wants you to use :Improved Land Mines at Garm's Bane to fend off the attackers from Garm. Both Garm Invaders and Snowblind Followers will count towards this goal. * Garm Invader slain (12)",de="Hey there again! You didn't run off like all the other adventurers did? Well, you're just a peach, aren't ya? I was beginning to think I smelled funny or something! We could still use a bit of a hand around here, and you have just the right experience. Remember those magnataur? Well apparently the cave didn't completely collapse... there are still quite a few left. So much for Gino taking care of them eh? Fortunately, Jeer made way more than enough mines. You've got this!",g={n="Ricket",x=0.409,y=0.854,loc="Various"}}
d[12838]={rep="+325 Knights of the Ebon Blade",o="Aurochs Grimbane at Death's Rise wants you to collect 5 Onslaught Intel Documents. * Onslaught Intel Documents (5)",de="I need to know what the Scarlet Onslaught is planning today. You will be my instrument in this task. Fly to Onslaught Harbor and rifle through their baggage trunks for documents. The trunks will be locked, so you'll have to take the keys from the Scarlet Onslaught members by whatever means.",g={n="Aurochs Grimbane",loc="Death's Rise, Icecrown"}}
d[12869]={rep="+250 The Frostborn",o="Fjorlin Frostbrow at Frosthold wants you to ride with a Stormcrest Eagle and kill 16 Stormpeak Wyrms in the Foot Steppes. * Stormpeak Wyrm slain (16) * Storm Hammer (provided)",de="You were there with Loken, weren't you? The iron dwarves captured Veranus, the brood mother of the proto-drakes. The drakes don't seem even a little bit happy about the situation... they've gotten very aggressive. They've pushed into stormcrest territory and the eagles have taken to an all out fight with them. It's time to return the favor. We're riding to the Foot Steppes and slaughtering them there. King Stormheart left this hammer to me - make good use and see to it that I get it back.",g={n="Fjorlin Frostbrow",x=0.298,y=0.757,loc="Frosthold, Storm Peaks"}}
d[12958]={r={{n="Dalaran Jewelcrafter's Token"}},mo=74000,rep="Kirin Tor +32.5",o="Combine a Vrykul Amulet, a Dark Jade and a Bloodstone to make a Blood Jade Amulet and bring it to Timothy Jones in Dalaran. You can find a Vrykul Amulet on any Northrend Vrykul. * Blood Jade Amulet",de="A wealthy shipping concern has requested a collection of Blood Jade Amulets to sell at Undermine. If you can bring me the materials to make one, I can reward you with a :Dalaran Jewelcrafter's Token.",g={n="Timothy Jones",x=0.408,y=0.345,loc="Cartier & Co. Fine Jewelry, Magus Commerce Exchange, Dalaran"}}
d[12959]={r={{n="Dalaran Jewelcrafter's Token"}},mo=74000,rep="Kirin Tor +25",o="Combine a Northern Ivory, a Chalcedony and a Shadow Crystal to craft a :Glowing Ivory Figurine and bring it to Timothy Jones in Dalaran. *Northern Ivory *Chalcedony *Shadow Crystal",de="A wealthy shipping concern has requested a collection of Glowing Ivory Figurines to sell at Undermine. If you can bring me the materials to make one, I can reward you with a :Dalaran Jewelcrafter's Token.",g={n="Timothy Jones",x=0.408,y=0.345,loc="Cartier & Co. Fine Jewelry, Magus Commerce Exchange, Dalaran"}}
d[12960]={r={{n="Dalaran Jewelcrafter's Token"}},mo=74000,rep="Kirin Tor +25",o="Combine an Iron Dwarf Brooch, a :Huge Citrine and a :Sun Crystal to craft a Wicked Sun Brooch and bring it to Timothy Jones in Dalaran. *Iron Dwarf Brooch *Wicked Sun Brooch",de="A wealthy shipping concern has requested a collection of Wicked Sun Brooches to sell at Undermine. If you can bring me one, I can reward you with a Dalaran Jewelcrafter's Token.",g={n="Timothy Jones",x=0.408,y=0.345,loc="Cartier & Co. Fine Jewelry, Magus Commerce Exchange, Dalaran"}}
d[12961]={r={{n="Dalaran Jewelcrafter's Token"}},mo=74000,rep="Kirin Tor +25",o="Combine a Proto Dragon Bone, a Sun Crystal and a Dark Jade to craft an :Intricate Bone Figurine and bring it to Timothy Jones in Dalaran. * Proto Dragon Bone * Sun Crystal * Dark Jade",de="A wealthy shipping concern has requested a collection of Intricate Bone Figurines to sell at Undermine. If you can bring me the materials to make one, I can reward you with a Dalaran Jewelcrafter's Token.",g={n="Timothy Jones",x=0.408,y=0.345,loc="Cartier & Co. Fine Jewelry, Magus Commerce Exchange, Dalaran"}}
d[12962]={r={{n="Dalaran Jewelcrafter's Token"}},mo=74000,rep="Kirin Tor +32.5",o="Combine an :Elemental Armor Scrap, a :Bloodstone and a :Huge Citrine to craft a Bright Armor Relic and bring it to Timothy Jones in Dalaran. You can find an Elemental Armor Scrap on any Northrend Revenant. *Bright Armor Relic",de="A wealthy shipping concern has requested a collection of Bright Armor Relics to sell at Undermine. If you can bring me one, I can reward you with a Dalaran Jewelcrafter's Token.",g={n="Timothy Jones",x=0.408,y=0.345,loc="Cartier & Co. Fine Jewelry, Magus Commerce Exchange, Dalaran"}}
d[12963]={r={{n="Dalaran Jewelcrafter's Token"}},mo=65000,rep="Kirin Tor +32.5",o="Combine a Scourge Curio, a Sun Crystal and a Shadow Crystal to craft a :Shifting Sun Curio and bring it to Timothy Jones in Dalaran. *Scourge Curio *Sun Crystal *Shadow Crystal",de="A wealthy shipping concern has requested a collection of Shifting Sun Curios to sell at Undermine. If you can bring me one, I can reward you with a :Dalaran Jewelcrafter's Token.",g={n="Timothy Jones",x=0.408,y=0.345,loc="Cartier & Co. Fine Jewelry, Magus Commerce Exchange, Dalaran"}}
d[12977]={mo=74000,rep="+455 The Sons of Hodir",o="You are to defeat 5 Niffelem Forefathers and 5 Restless Frostborn at Thunderfall. You are then to blow Hodir's Horn over their corpses, then return to :Hodir's Horn in Dun Niffelem. *Niffelem Forefather freed (5) *Restless Frostborn freed (5) *Hodir's Horn (provided)",de="You have done a great service to the giants of Dun Niffelem. Without your aid, this monument would not exist. As you silently ponder its significance, feelings begin to flood your heart. The feelings fill your mind with thoughts and images... as well as a sense of urgency. The sensations fade and leave you with a knowledge of what you must do. The restless spirits at Thunderfall must be put to rest. As you set off, you find that your hands have been filled with an ethereal horn.",g={n="Hodir's Horn",x=0.64,y=0.647}}
d[12981]={rep="+455 The Sons of Hodir",o="You are to go to Frostfield Lake, kill the Brittle Revenants there and use the Essence of Ice on the Smoldering Scraps at Fjorn's Anvil. You are then to collect 6 of the Frozen Iron scraps and return to Fjorn's Anvil in Dun Niffelem. * Frozen Iron Scrap (6)",de="As you stare at the anvil you relive your recent accomplishments, particularly those which brought this artifact to rest here. It suddenly occurs to you that more remains to be done. To the east, smoldering scraps clutter the landscape - shrapnel from the battle fought there. If they could be cooled and gathered somehow, the frost giants would have an abundant supply of metal and the region would be cleared of these remnants of war.",g={n="Fjorn's Anvil",x=0.631,y=0.628}}
d[12994]={rep="+455 The Sons of Hodir",o="You must defeat 3 Stormforged Spies in the Valley of Ancient Winters. Using the Ethereal Worg's Fang at the Corpse of the Fallen Worg will summon an Ethereal Frostworg, which will expose hidden enemies. You are to return to the Frostworg Denmother in Dun Niffelem when the valley has been cleansed of spies. * Stormforged Infiltrators Slain (3) * Ethereal Worg's Fang (provided)",de="The rapport you've developed with the inhabitants of Dun Niffelem has yielded some unexpected discoveries. For example, you somehow find yourself able to understand the denmother's guttural growls and sharp quips - at least you think you do. It would seem that she senses danger outside the stronghold and wants you to do something about it. With her forepaw, she removes the chain from around her neck and lets it drop at your feet. As you pick it up you notice an aged fang attached to it....",g={n="Frostworg Denmother",x=0.63,y=0.6,loc="Dun Niffelem, Storm Peaks"}}
d[12995]={rep="+325 Knights of the Ebon Blade",o="Baron Sliver at The Shadow Vault wishes you to plant 15 Ebon Blade Banners within the corpses of vrykul found within the greater Jotunheim region. *Vrykul corpses impaled with Ebon Blade banners (15) *Ebon Blade Banner (quest item) (provided)",de="We must attack the vrykul of Jotunheim on many levels. Brute force, of course, is good, but I prefer a more cerebral approach. I want you to demoralize them. My men here have forged a number of banners for you. I would like for you to take and plant them within the corpses of fallen vrykul. Let the banners serve as a constant reminder to them that they face a more immediate threat than the wrath of the Lich King.",g={n="Baron Sliver",x=0.42,y=0.24,loc="Various"}}
d[13003]={mo=165300,rep="+650 The Sons of Hodir",o="You are to use Hodir's Spear to challenge a Wild Wyrm in the Valley of Ancient Winters. Once in its grip, you are to fight to the death. * Wild Wyrm Slain",de="Hodir's Spear is an icon of great prowess in battle. Its mere presence instills a deep hunger for glory in all who enter Dun Niffelem. In fact, simply being near it has compelled you to test your own abilities. Scanning the horizon, your vision locks on a wild wyrm as it flies nearby. It is decided. Of you and he, only one shall see the next sunrise....",g={n="Hodir's Spear"}}
d[13006]={rep="+455 The Sons of Hodir",o="You are to enter Hibernal Cavern west of Dun Niffelem and collect 5 units of Viscous Oil from the Viscous Oils there. You are then to return to Dun Niffelem and apply the oil to Hodir's Helm. * Viscous Oil (5)",de="As you draw near the helm, you notice that the frigid environment is already taking its toll on the artifact's surface. What is now just a thin layer of ice will surely grow to envelop it entirely. Not about to let your hard efforts go to waste, you resolve to scour the region in search of a solution. Just as you set off, the eyes of the helm flash and an image of the nearby Hibernal Cavern enters your mind.",g={n="Hodir's Helm",x=0.641,y=0.593}}
d[13046]={rep="+455 The Sons of Hodir",o="You are to feed Arngrim 5 Disembodied Jormungar, then return to Arngrim's frozen image in Dun Niffelem. You must go to the Valley of Ancient Winters and use Arngrim's Tooth on the Roaming Jormungar there. Once they have become disembodied, you must fight them until they are weakened. * Arngrim's spirit fed (5) * Arngrim's Tooth (provided)",de="Arngrim's hunger was legendary. Even in death, his expression is one of famished yearning. You find that just looking at him is making your stomach growl. It is said that throughout his life he was never truly sated, and that there was absolutely nothing he wouldn't eat. You wonder to yourself if there might be a way to feed the old king. No sooner does the thought enter your mind than one of the massive frozen teeth falls from Arngrim's head, bounces off of his beard and lands in your hand.",g={n="Arngrim the Insatiable",x=0.66,y=0.6,loc="Dun Niffelem, Storm Peaks"}}
d[13069]={rep="+325 Knights of the Ebon Blade",o="The Leaper at The Shadow Vault wants you to use a Jotunheim Rapid-Fire Harpoon to shoot down 20 Jotunheim Proto-Drakes and their riders. *Jotunheim Proto-Drakes & their riders shot down (20)",de="Jotunheim has aerial defenses, both in terms of proto-drake riders and harpoon guns. They've concentrated these on their northern and western facings where they are most vulnerable. Let's use their defenses against them! Take control of a harpoon gun on the platforms that overhang the cliffs on either side of Valhalas to the southwest. Take out the proto-drakes and their riders. Shoot 'em up!",g={n="The Leaper",x=0.436,y=0.251,loc="Shadow Vault, Icecrown"}}
d[13071]={mo=37000,rep="+325 Knights of the Ebon Blade",o="Vile at The Shadow Vault wants you to steal a Njorndar Proto-Drake and use it to set fire to 10 vrykul buildings in the greater Jotunheim region. Balargarde Fortress, due to its nature, cannot be set ablaze. *Vrykul buildings set ablaze (8)",de="Vile like fire! Vile like proto-drakes! Little go to Jotunheim and steal a pretty proto-drake in Njorndar Village. Make proto-drake make pretty fires on Jotunheim buildings!",g={n="Vile",x=0.435,y=0.245,loc="Shadow Vault, Icecrown"}}
d[13100]={r={{n="Epicurean's Award"},{n="Small Spice Bag"}},mo=58000,rep="+195 Kirin Tor",o="Use your Meatloaf Pan to cook 4 Infused Mushrooms and 2 Chilled Meats and bring the finished Mushroom Meatloaf to Orton Bennet in Curiosities & Moore, located in Runeweaver Square in Dalaran. * Infused Mushroom Meatloaf * Meatloaf Pan (provided)",de="We have an important order that needs to go out! Orton Bennet in Curiosities & Moore needs a mushroom meatloaf. Get 4 Infused Mushrooms that are found in the Dalaran sewers and 2 Chilled Meats and cook them in the pot at any fire and deliver it to Orton.",g={n="Katherine Lee",loc="A Hero's Welcome, Dalaran"}}
d[13100]={r={{n="Epicurean's Award"},{n="Small Spice Bag"}},mo=58000,rep="+150 Kirin Tor",o="Cook 4 Crystalsong Carrots from Crystalsong Forest with 4 Chilled Meat in the Cookpot. Then bring the Vegetable Stew to the Dalaran sewers Innkeeper Ajay Green. * Vegetable Stew * Stew Cookpot (provided)",de="We be havin' another order to fill. Da innkeeper in da Dalaran sewers needs a vegetable stew as his customers dey don't have so much to eat, mon. He asked for a vegetable stew as he didn't appreciate da gnome that was in the last stew I sent. Get 4 Crystalsong Carrots from the Crystalsong Forest and cook them together with 4 Chilled Meat and bring it to Ajay. You can be gettin' to da Forest from da portal chamber in da eastern corner of Runeweaver Square.",g={n="Awilo Lon'gomba",loc="Filthy Animal, Dalaran"}}
d[13101]={r={{n="Epicurean's Award Small Spice Bag"}},mo=58000,rep="+195 Kirin Tor",o="Bring 4 Northern Stew that you use your cooking skill to make and a Jug of Wine from the cheese shop in Dalaran to Arille Azuregaze at the Legerdemain Lounge found in Runeweaver Square in Dalaran. *Northern Stew (4) *Jug of Wine",de="Arille Azuregaze at the Legerdemain Lounge has a convention coming in and needs a feast pronto! You need to provide 4 Northern Stew and a Jug of Wine from the cheese shop \"One More Glass\" in central Dalaran. The owner of the cheese shop, owes me the wine and you should find it somewhere around the shop. Bring the wine and stews to Arille.",g={n="Katherine Lee",loc="A Hero's Welcome, Dalaran"}}
d[13102]={r={{n="Epicurean's Award Small Spice Bag"}},mo=58000,rep="+150 Kirin Tor",o="Cook 4 Crystalsong Carrot from Crystalsong Forest with 4 Chilled Meat in the Cookpot. Once it is ready bring the Vegetable Stew to the Dalaran sewers Innkeeper Ajay Green. * Vegetable Stew (1) * Stew Cookpot (provided)",de="Ajay Green the innkeeper in the Dalaran sewers needs a vegetable stew for his customers as they are running low on food down there. Collect 4 Crystalsong Carrots from the Crystalsong Forest and cook them together with 4 Chilled Meat. You can get to the Crystalsong Forest from the portal chamber in the eastern corner of Runeweaver Square. Once the vegetable stew is ready, bring it to Ajay.",g={n="Katherine Lee",loc="A Hero's Welcome, Dalaran"}}
d[13107]={r={{n="2x Epicurean's Award"},{n="Small Spice Bag"}},mo=58000,rep="+195 Kirin Tor",o="Fill the Empty Picnic Basket with 4 Rhino Dogs that you use your Cooking skill to make and 4 Wild Mustard that you find in the grassy areas of Dalaran. Bring the Picnic Basket to Archmage Pentarus at Krasus' Landing in Dalaran. * Mustard Dog Basket * Empty Picnic Basket (provided)",de="Archmage Pentarus likes to watch the occasional game of battle ball and is preparing to go, but needs food for the trip. You need to fill his picnic basket with 4 rhino dogs that you cook and then 4 wild mustard that are found in grassy areas of the city. Bring him his picnic basket so he can be ready to go see the big game.",g={n="Katherine Lee",loc="A Hero's Welcome, Dalaran"}}
d[13112]={r={{n="Epicurean's Award"},{n="Small Spice Bag"}},mo=58000,rep="+195 Kirin Tor",o="Cook 4 Infused Mushrooms from the Dalaran sewers with 2 Chilled Meats in your Meatloaf Pan and bring them to Orton Bennet in Curiosities & Moore located in Runeweaver Square in Dalaran. * Infused Mushroom Meatloaf * Meatloaf Pan (provided)",de="Orton Bennet in Curiosities & Moore be needin' a mushroom meatloaf. Get 4 Infused Mushrooms dat be found in the Dalaran sewers and 2 Chilled Meats and cook dem in the pot at any fire and deliver it to Orton. If only de council would let me serve me gnome specialty, I would show dem a real treat!",g={n="Awilo Lon'gomba",loc="Filthy Animal, Dalaran"}}
d[13113]={r={{n="Epicurean's Award"},{n="Small Spice Bag"}},mo=58000,rep="+195 Kirin Tor",o="Bring 4 Northrend Stews and a Jug of Wine from the cheese shop in Dalaran to Arrille Azuregaze at the Legerdemain Lounge found in Runeweaver Square in Dalaran. *Northern Stew (4) *Jug of Wine",de="Can you believe da horde has outlawed cannibalism...it just ain't right I tell ya! I guess I should keep me mind on me work when we gots an order to fill. Arrille Azuregaze at the Legerdemain Lounge has many a guest a'comin to his place, mon. You gots to be providin' 4 Northern Stew and a Jug of Wine from the cheese shop in central Dalaran. Bring the wine and stew to Arrille.",g={n="Awilo Lon'gomba",loc="Filthy Animal, Dalaran"}}
d[13115]={r={{n="Epicurean's Award Small Spice Bag Eversong Party Platter"}},mo=58000,rep="+195 Kirin Tor",o="Combine the empty cheese platter with Aged Dalaran Limburger from the cheese shop \"One More Glass\" and with 6 Half Full Dalaran Wine Glasses found on tables around Dalaran. Bring the Wine and Cheese platter to Ranid Glowergold at the Leatherworkers in the Magus Commerce Exchange. * Wine and Cheese Platter * Empty Cheese Serving Platter (provided)",de="Ranid Glowergold in da Leatherworkers shop in be havin' a need for wine and cheese. Why he don't want some tasty Gnome is beyond me. Collect da cheese from da cheese shop in central Dalaran and da half full wine glasses found on tables around da city. Bring da wine and serve it with the cheese to Ranid. You can call da wine a Wine Medley, mon'.",g={n="Awilo Lon'gomba",loc="Filthy Animal, Dalaran"}}
d[13115]={r={{n="Epicurean's Award Small Spice Bag Eversong Party Platter"}},mo=58000,rep="+195 Kirin Tor",o="Combine the empty cheese platter with Aged Dalaran Limburger from the cheese shop \"One More Glass\" and with 6 Half Full Dalaran Wine Glasses found on tables around Dalaran. Bring the Wine and Cheese platter to Ranid Glowergold at Legendary Leathers in the Magus Commerce Exchange. * Wine and Cheese Platter * Empty Cheese Serving Platter (provided)",de="Ranid Glowergold in the Leatherworkers shop in Dalaran has had a sudden craving for wine and cheese. Collect cheese which is on the shelf at \"One More Glass\" in central Dalaran and half full wine glasses found on tables all over the city. Pour the wine together into a bottle and serve it with the cheese to Ranid. We don't think he will know the difference.",g={n="Katherine Lee",loc="A Hero's Welcome, Dalaran"}}
d[13116]={r={{n="2x Epicurean's Award"},{n="Small Spice Bag"}},mo=58000,rep="+195 Kirin Tor",o="Fill the Empty Picnic Basket with 4 Rhino Dogs that you be cookin' with your skill and 4 Wild Mustard that you find in the grassy areas of Dalaran. Bring the Picnic Basket to Archmage Pentarus at Krasus' Landing in Dalaran. * Mustard Dog Basket * Empty Picnic Basket (provided)",de="Da Archmage Pentarus likes to be watchin' his crazy battle ball game, but he be needin' some food for da game. You be needin' to fill his picnic basket with 4 cooked rhino dogs and then 4 wild mustard that are found in da grassy corners of de city. Fill up his basket with the mustard dog goodies, mon'.",g={n="Awilo Lon'gomba",loc="Filthy Animal, Dalaran"}}
d[13233]={r={{n="+200 honor at 80"}},mo=74000,o="High Captain Justin Bartlett aboard the Skybreaker wants you to kill 15 Horde Players.",de="It is as I told you. They were not merely idle words spoken in a fit of anger. Time and again, the Horde have demonstrated their disdain for everything we hold dear and holy. They must pay with their lives for their transgressions against the light. All of them. Just imagine a world free of their stain, . Envision the joy our children will know. Think of the reverence your descendants will have for your memory, knowing they owe their happiness to you. Now go, and make that vision a reality!",g={n="High Captain Justin Bartlett",loc="Skybreaker, Icecrown"}}
d[13234]={mo=74000,o="Sky-Reaver Korm Blackscar wants you to kill 15 Alliance Players in Icecrown. *Alliance Players Slain (15)",de="The time has come! Too long have we suffered the company of the self-righteous Alliance! Too long have we stayed our hand from cleansing our world of the weak and the desperate. Now, we bring an end to our humiliation! Now, we show them the true meaning of fear! Now, we bring honor to the Horde! Here, at Icecrown, we break the Alliance! Go, . Hunt them down. Break them. Take their will to live!",g={n="Sky-Reaver Korm Blackscar",loc="Orgrim's Hammer, Icecrown"}}
d[13240]={r={{n="Choose one of:"},{n="Kirin Tor Commendation Badge"},{n="Argent Crusade Commendation Badge"},{n="Ebon Blade Commendation Badge"},{n="Wyrmrest Commendation Badge"},{n="Sons of Hodir Commendation Badge"}},mo=148000,rep="+75 Kirin Tor",o="Archmage Timear in Dalaran has foreseen that you must destroy 10 Centrifuge Constructs. * Centrifuge Construct slain (10)",de="It is into the Oculus floating above Coldarra that you must travel, . I have foreseen a situation in which you must destroy the centrifuge constructs therein. I can assure you that if you do not first eliminate these magical creations, you and your friends will fail. Thus I have seen, thus you must do.",g={n="Archmage Timear",loc="Violet Hold, Dalaran"}}
d[13241]={r={{n="Choose one of:"},{n="Kirin Tor Commendation Badge"},{n="Argent Crusade Commendation Badge"},{n="Ebon Blade Commendation Badge"},{n="Wyrmrest Commendation Badge"},{n="Sons of Hodir Commendation Badge"}},mo=148000,rep="+75 Kirin Tor",o="Archmage Timear in Dalaran wants you to slay 7 Ymirjar Berserkers. *Ymirjar Berserker slain (7)",de="King Ymiron's champions stand between you and victory in the not-to-distant future. You will travel to the fortress known as Utgarde Pinnacle nestled deep within the woods of the Howling Fjord. I cannot stress how important it is that you and your traveling companions deal with the ymirjar berserkers therein. Failure to do so may very well doom you, !",g={n="Archmage Timear",loc="Violet Hold, Dalaran"}}
d[13243]={r={{n="Choose one of:"},{n="Kirin Tor Commendation Badge"},{n="Argent Crusade Commendation Badge"},{n="Ebon Blade Commendation Badge"},{n="Wyrmrest Commendation Badge"},{n="Sons of Hodir Commendation Badge"}},mo=148000,rep="+75 Kirin Tor",o="Archmage Timear in Dalaran has foreseen that you must slay 4 Infinite Agents. * Infinite Agent slain (4)",de="The timeline is in danger from the Infinite dragonflight. Without your intervention, all of time will unravel! You must travel to a point in time known as the Culling of Stratholme within the Caverns of Time. It gives me a migraine just to attempt to see into all of the possible pasts, but I do know that it is crucial for you to kill the Infinite agents. Only by slaying them will the true past be preserved and the present and future kept from being undone forever!",g={n="Archmage Timear",loc="Violet Hold, Dalaran"}}
d[13244]={r={{n="Choose one of:"},{n="Kirin Tor Commendation Badge"},{n="Argent Crusade Commendation Badge"},{n="Ebon Blade Commendation Badge"},{n="Wyrmrest Commendation Badge"},{n="Sons of Hodir Commendation Badge"}},mo=148000,rep="+75 Kirin Tor",o="Archmage Timear in Dalaran has foreseen that you must slay 7 Titanium Vanguards. * Titanium Vanguard slain (7)",de="The entirety of Azeroth is in peril. The mad god Loken has it within his power to put an end to everything! Within the Terrestrial Watchtower at the Halls of Lightning, the titanium vanguards stand poised to execute Loken's dread will upon countless unknowing victims. I have looked into the future, . You are the one to see that this does not come to pass!",g={n="Archmage Timear",loc="Violet Hold, Dalaran"}}
d[13248]={r={{n="2x Emblem of Triumph"}},mo=222000,rep="+75 Kirin Tor",o="Archmage Lan'dalock in Dalaran wants you to return with the :Locket of the Deceased Queen. This quest may only be completed on Heroic difficulty. * Locket of the Deceased Queen",de="King Ymiron of Utgarde Pinnacle is the favored vrykul of the Lich King. That alone is reason enough to put an end to him. But should he blow the horns and call for all of the leaders of the ymirjar and mjordin alike, the vrykul will become a force more powerful than any other within the Scourge! It is up to you, , to see to it that this does not come to pass. Bring me the locket from around his neck so that I will know that Ymiron no longer poses a threat.",g={n="Archmage Lan'dalock",x=0.576,y=0.666,loc="Various"}}
d[13261]={mo=74000,o="Chief Engineer Copperclaw aboard Orgrim's Hammer wants you to use Copperclaw's Volatile Oil at the Broken Front to attract 3 Frostbrood Skytalons. To use the oil, you must collect a Pile of Bones, an Abandoned Helm, and Abandoned Armor from the battlefield there. * Field Tests Conducted (3) * Copperclaw's Volatile Oil (provided)",de="Wahooo! It works! Not that I had any doubts in my supernatural ingenuity, only that I wasn't quite sure what kind of explosion to expect - let's just say I'm glad to see that you didn't get your eyebrows singed off. So now I just need to show ol' Korm how ya thaw out one 'a them wyrms. He'll hafta promote me to... to... to whatever comes after Chief Engineer! Here, you take another batch of the stuff and head back out to the front and I'll go get Korm... Well? Move out!",g={n="Chief Engineer Copperclaw",loc="Orgrim's Hammer, Icecrown"}}
d[13276]={mo=74000,o="Koltira Deathweaver on Orgrim's Hammer wants you to use the Abomination Reanimation Kit to create a Reanimated Abomination, which you are to use to kill 15 Icy Ghouls, 15 Vicious Geists, and 15 Risen Alliance Soldiers. * Icy Ghouls Exploded (15) * Vicious Geists Exploded (15) * Risen Alliance Soldier Exploded (15)",de="You know what to do, . Take this kit and use the guts from their abominations to create one of your own, then command it to attack the enemy forces at the gate. You would do well to refine this tactic for when we make another assault on the gate.",g={n="Koltira Deathweaver",x=0.73,y=0.526,loc="Various"}}
d[13280]={rep="+250 Valiance Expedition+125 Alliance Vanguard",o="Frazzle Geargrinder (coords 57.0, 62.6) in Ymirheim wants you to use her Geargrinder's Jumpbot to plant the Alliance Battle Standard in the skulls at the top of the mountain. * Alliance Battle Standard planted",de="You've just got to get my jumpbot to the tippy top of the mountain to the northwest here at Ymirheim pronto, ! That dastardly, no-good Blast Thunderbomb is working on his own bot, and I'm afraid he almost has it completed. We're in a race to see who's gonna be king of the mountain! Once you jump up there, plant our battle standard in the pile of bones and show everyone that the Alliance, and my engineering skills, are the best!",g={n="Frazzle Geargrinder",loc="Ymirheim, Icecrown"}}
d[13283]={rep="+250 Warsong Offensive+125 Horde Expedition",o="Blast Thunderbomb in Ymirheim wants you to use his Thunderbomb's Jumpbot to plant the Horde Battle Standard in the skulls at the top of the mountain. * Horde Battle Standard planted",de="Yo, , I need you to get my jumpbot to the top of this mountain to the southeast, like yesterday! That girly, self-righteous Frazzle Geargrinder thinks that her jumpbot's better than mine. Hah! We're in a race to see who's gonna be king of the mountain! Once you jump up there, plant our battle standard in the pile of bones and show everyone that the Horde, and my mad engineering skills, are the best!",g={n="Blast Thunderbomb",x=0.519,y=0.576,loc="Ymirheim, Icecrown"}}
d[13284]={rep="+150 Valiance Expedition",o="Escort the Skybreaker troops to the gates of Ymirheim. Return to Ground Commander Koup at the edge of the glacier east of Ymierheim for compensation after the task is complete. * Alliance troops escorted to Ymirheim (4)",de="Greetings . Our troops have been attempting to storm Ymirheim for some time, but these Vrykul are far more vicious than any we've faced before. They've been ambushing us repeatedly as we try to make it up the pass, and we've lost a lot of men. If you want to lend yourself to the battle and help get my squad to the gates of Ymirheim safely, we will gladly reward you for your efforts. Once at the gates, we'll dig in and wait for reinforcements to catch up to us.",g={n="Skybreaker Squad Leader",loc="Bombardment, Icecrown"}}
d[13289]={mo=74000,o="Thassarian on the Skybreaker wants you to use the Abomination Reanimation Kit to create a Reanimated Abomination, which you are to use to kill 15 Icy Ghouls, 15 Vicious Geists, and 15 Risen Alliance Soldiers. *Icy Ghouls Exploded (15) *Vicious Geists Exploded (15) *Risen Alliance Soldier Exploded (15)",de="You know what to do, . Take this kit and use the guts from their abominations to create one of your own, then command it to attack the enemy forces at the gate. You would do well to refine this tactic for when we make another assault on the gate.",g={n="Thassarian",x=0.73,y=0.526,loc="Various"}}
d[13292]={o="Chief Engineer Boltwrench aboard the Skybreaker wants you to use the Smuggled Solution at the Broken Front. Using the solution will require an Abandoned Helm, Abandoned Armor, and a Pile of Bones (Icecrown), all found at the Broken Front. *Frostbrood Skytalons Destroyed (3)",de="Oh, yes, yes. Back again, are we? Never enough practice, I suppose. Here we are, the solution to that pesky frostwyrm problem. Make them scarce, . The more you take out now, the less we face when we are again ready to attempt our march on the citadel. Best of luck, now. And do bring back whatever you don't use. * Smuggled Solution (provided)",g={n="Chief Engineer Boltwrench",loc="Skybreaker, Icecrown"}}
d[13300]={mo=74000,rep="+250 Argent Crusade",o="Absalan the Pious aboard the Skybreaker wants you to rescue 10 Saronite Mine Slaves. * Saronite Mine Slave rescued (10)",de="Our people are being captured and put to work as slaves in the saronite mines of Ymirheim, the vrykul stronghold in the middle of Icecrown. The Lich King has them mining that unholy ore day and night. I made a promise to Highlord Fordring that we would get those wretches out of there alive, and that's exactly what we will do. Unfortunately, I've been ordered to stay on this gunship and serve as an ambassador to the Valiance Expedition. Will you please rescue them in my stead, ?",g={n="Absalan the Pious",loc="Skybreaker, Icecrown"}}
d[13301]={rep="Warsong Offensive +250",o="Escort the Kor'kron troops to the gates of Ymirheim. Return to Ground Commander Xutjja at the edge of the glacier north of Ymirheim for compensation after the task is complete. *Horde troops escorted to Ymirheim (4)",de="Greetings . Our troops have been attempting to Storm Ymirheim for some time, but these Vrykul are far more vicious than any we've faced before. They've been ambushing us repeatedly as we try to make it up the pass, and we've lost a lot of men. If you want to lend yourself to the battle and help get my squad to the gates of Ymirheim safely, we will gladly reward you for your efforts. Once at the gates, we'll dig in and wait for reinforcements to catch up to us.",g={n="Kor'kron Squad Leader",x=0.58,y=0.47,loc="Ymirheim, Icecrown"}}
d[13302]={rep="Argent Crusade +250",o="Brother Keltan aboard Orgrim's Hammer wants you to rescue 10 Saronite Mine Slaves. * Saronite Mine Slave rescued (10)",de="Our people are being captured and put to work as slaves in the saronite mines of Ymirheim, the vrykul stronghold in the middle of Icecrown. The Lich King has them mining that unholy ore day and night. I made a promise to Highlord Fordring that we would get those wretches out of there alive, and that's exactly what we will do. Unfortunately, I've been ordered to stay on this gunship and serve as an ambassador to the Warsong Offensive. Will you please rescue them in my stead, ?",g={n="Brother Keltan",loc="Orgrim's Hammer, Icecrown"}}
d[13310]={rep="Warsong Offensive +250",o="Ground Commander Xutjja at the edge of the glacier north of Ymirheim has ordered you to use the Kor'kron Suppression Turret to keep the Kor'kron Troop Transport alive long enough to make all of its drops. * Kor'kron Infiltrators dropped (4)",de="Alright scrub, I've got something to keep you from being a complete waste. A unit of highly trained infiltrators is ready to be dropped inside of Ymirheim. The vrykul inside have automated spear guns that have been ripping our transports to shreds, so we had the engineers on Orgrim's Hammer whip us up a suppression turret. You're the gunner. Launch rounds at their spear guns to obscure their vision and clog their gears. See to it that my men all make their drops and the transport stays in one piece.",g={n="Ground Commander Xutjja",x=0.583,y=0.46,loc="Ymirheim, Icecrown"}}
d[13322]={o="Chief Engineer Boltwrench aboard the Skybreaker wants you to drink the Diluted Cult Tonic, kill any Cultists at Aldur'thar and take their Tainted Essences. You are then to combine 10 of the essences into a Writhing Mass and throw it into any of their cauldrons. *Writhing Mass Banished *Diluted Cult Tonic (provided)",de="Those twisted cultists are looking for souls to put in their crazy-juice? Then let's help 'em out a bit! Take a swig of this - don't worry, I've diluted it plenty... I'm almost positive that its only effect will be to detect any cultist's essence. Once you've collected a bunch of 'em, throw the writhing mass of twisted souls in one of their cauldrons. Let's see how they like a taste of their own medicine!",g={n="Chief Engineer Boltwrench",loc="Skybreaker, Icecrown"}}
d[13323]={o="Thassarian, aboard the Skybreaker, wants you to collect Orbs of Illusion from Bitter Initiates at Aldur'thar and use them on 3 Dark Subjugators there. *Dark Subjugators Dragged and Dropped (3)",de="Looks like those initiates are increasing in number again. You know what to do... At the southern portion of the gate, the new cultists are being trained. They're certain to be holding a special item given to all initiates - an Orb of Illusion. These artifacts are used to disguise a cult member, allowing them to gain safe passage, infiltrate, or simply blend in with an enemy. Slay the fools until you find some, then use them on the Subjugators there.",g={n="Thassarian",x=0.73,y=0.526,loc="Various"}}
d[13330]={rep="Warsong Offensive +250",o="Warbringer Davos Rioht on Orgrim's Hammer has sent you to kill 20 vrykul in Ymirheim. * Ymirheim Vrykul slain (20)",de="Those vrykul that have gained the favor of the Lich King call themselves the Ymirjar. They inhabit a city in the center of Icecrown. We have a lot of preparations to make before we assault Icecrown Citadel, and the one that stands before us now is routing these so-called \"Chosen\" of the Lich King. Go to their city, Ymirheim, and slaughter them in their home. Let there be no questions as to who the stronger combatants are here.",g={n="Warbringer Davos Rioht",loc="Orgrim's Hammer, Icecrown"}}
d[13331]={rep="Warsong Offensive +250 Horde Expedition +125",o="Use the SGM-3 to destroy 6 Skybreaker Recon Fighters, then report back to Sky-Reaver Korm Blackscar aboard Orgrim's Hammer. * Skybreaker Recon Fighter (6) * SGM-3 (provided)",de="The Alliance is tenacious, I'll give them that, but it'll take more than that to stop us. Take this :SGM-3 with you and shoot down the Skybreaker's recon fighters once again. I doubt the message will get through their thick skulls, but there are enough missiles to keep trying to get our point across. Go and find their fighters flying above the Valley of Fallen Heroes, west of Aldur'thar, and don't come back until you've made wreckage of them.",g={n="Sky-Reaver Korm Blackscar",loc="Orgrim's Hammer, Icecrown"}}
d[13336]={rep="+250 Valiance Expedition",o="Knight-Captain Drosche on the Skybreaker has sent you to kill 20 vrykul in Ymirheim. * Ymirheim Vrykul (20)",de="Those vrykul of that have gained the favor of the Lich King call themselves the Ymirjar. They inhabit a city in the center of Icecrown. We have a lot of preparations to make before we assault Icecrown Citadel, and the one that stands before us now is routing these so-called \"Chosen\" of the Lich King. Go to their city, Ymirheim, and slaughter them in their home. Let there be no questions as to who the stronger combatants are here.",g={n="Knight-Captain Drosche",loc="Skybreaker, Icecrown"}}
d[13344]={mo=74000,o="Thassarian, aboard the Skybreaker, wants you to collect 5 Dark Matters and summon a Dark Messenger at Aldur'thar. *Dark Messenger summoned *Rod of Siphoning (provided)",de="The cultists have discovered the last messenger you summoned, . While it was quite informative, it's important that we continue to monitor their every move. Use this rod to siphon the dark matter from the corpses of enslaved minions at Aldur'thar. Then use their summoning crystal to bring another dark messenger into being. Until it is discovered, the messenger will serve as our eyes and ears, discreetly observing the actions of our enemy.",g={n="Thassarian",x=0.73,y=0.526,loc="Various"}}
d[13353]={r={{n="(or at max level)"}},o="Koltira, aboard Orgrim's Hammer, wants you to collect Orbs of Illusion from Bitter Initiates at Aldur'thar and use them on 3 Dark Subjugators there. *Dark Subjugator Dragged and Dropped (3)",de="Looks like those initiates are increasing in number again. You know what to do... At the southern portion of the gate, the new cultists are being trained. They're certain to be holding a special item given to all initiates - an Orb of Illusion. These artifacts are used to disguise a cult member, allowing them to gain safe passage, infiltrate, or simply blend in with an enemy. Slay the fools until you find some, then use them on the subjugators there.",g={n="Koltira Deathweaver",x=0.73,y=0.526,loc="Various"}}
d[13368]={mo=222000,o="Koltira, aboard Orgrim's Hammer, wants you to slay Alumeth the Ascended at Aldur'thar. *Alumeth the Ascended Defeated Suggested Players [5]",de="It's Alumeth... He's growing in power again. I can sense it. Again his underlings are channeling power to his soul. If he's allowed to rest, their efforts will soon transform him into a mighty adversary. Return to his chamber in the north portion of Aldur'thar. Combine his , , and , then use his on the crystal there. Hurry, ! Destroy him while there's still time!",g={n="Koltira Deathweaver",x=0.73,y=0.526,loc="Various"}}
d[13376]={o="Fringe Engineer Tezzla wants you to kill Bombardment Infantry, Gargoyle Ambushers, Frostbrood Sentries and Scourge War Machines. *Bombardment Infantry slain (50) *Gargoyle Ambusher slain (20) *Scourge War Machine slain (12) *Frostbrood Sentry slain (12)",de=", the struggle continues. Lucky for us, we're stocked up on bombs and rockets! Time for another bombing mission—this one's a long one, through the Bombardment and into the Valley of Lost Hope. Head back out with an infra-green bomber and blow those Scourge into little scourge-lets!",g={n="Fringe Engineer Tezzla",x=0.54,y=0.369,loc="Aldur'thar, Icecrown"}}
d[13382]={o="Kibli Killohertz wants you to kill Bombardment Infantry, Gargoyle Ambushers, Frostbrood Sentries and Scourge War Machines. * Bombardment Infantry slain (50) * Gargoyle Ambusher slain (20) * Scourge War Machine slain (12) * Frostbrood Sentry slain (12)",de="The fight goes on! Your new orders arrived for a long-range bombing mission through the Bombardment and into the Valley of Lost Hope -- when you're ready, ask Karen for a bomber and pour those bombs and rockets onto the Scourge!",g={n="Kibli Killohertz",x=0.54,y=0.429,loc="Aldur'thar: The Desolation Gate, Icecrown"}}
d[13404]={o="Kibli Killohertz wants you to kill Bombardment Infantry, Bombardment Captains and Gargoyle Ambushers. * Bombardment Infantry slain (50) * Bombardment Captain slain (10) * Gargoyle Ambusher slain (20)",de="This is a short-ranged mission, over The Bombardment. A good warm up. Ready?",g={n="Kibli Killohertz",x=0.54,y=0.429,loc="Aldur'thar: The Desolation Gate, Icecrown"}}
d[13406]={o="Fringe Engineer Tezzla wants you to kill Bombardment Infantry, Bombardment Captains and Gargoyle Ambushers. *Bombardment Infantry slain (50) *Bombardment Captain slain (10) *Gargoyle Ambusher slain (20)",de="Ready to warm up with a short bombing mission? You have your orders, and we have our bombers stocked and ready.",g={n="Fringe Engineer Tezzla",x=0.54,y=0.369,loc="Aldur'thar, Icecrown"}}
d[13414]={rep="+250 with Wyrmrest Accord",o="Corastrasza on the upper ring of the Nexus in Coldarra wants you to ride her drake and kill 5 Scalesworn Elites. * Scalesworn Elites Slain (5)",de="Again we meet, . I confess, your presence is beginning to grow on me. Am I correct in assuming that you've come to hone your aerial combat skills? As always, my pets stand ready to bring fiery destruction to the enemy. Speak, and they shall be at your disposal.",g={n="Corastrasza",x=0.296,y=0.248,loc="Various"}}
d[13422]={mo=55000,o="Gretta the Arbiter in Brunnhildar Village wants you to use the Disciplining Rod on 6 Exhausted Vrykul inside the Forlorn Mine. *Exhausted Vrykul Disciplined (6) *Disciplining Rod (provided)",de="You've succeeded where others have failed. Yet you cannot rest on your laurels. You must show others what strength and commitment really mean. The male insubordinates inside the Forlorn Mine need to be disciplined once again. Show them sister... show them what it means to disobey us.",g={n="Gretta the Arbiter",x=0.51,y=0.66,loc="Brunnhildar Village, The Storm Peaks"}}
d[13423]={r={{n="Hyldnir Spoils"}},mo=74000,o="Gretta the Arbiter in Brunnhildar Village wants you to defeat 6 Victorious Challengers. * Victorious Challenger slain (6)",de="Everyone's impressed by your performance, sister. But do not let your guard down—every new challenger with delusions of grandeur is going to come out swinging for your title of Hyldskvinnar. Show these upstarts what you're made of.",g={n="Gretta the Arbiter",x=0.51,y=0.66,loc="Brunnhildar Village, The Storm Peaks"}}
d[13424]={r={{n="Hyldnir Spoils"}},mo=74000,o="Gretta the Arbiter, in Brunnhildar Village, wants you to use the Reins of the Warbear Matriarch inside the Pit of the Fang and defeat 6 Hyldsmeet Warbears. *Hyldsmeet Warbear slain (6) *Reins of the Warbear Matriarch (Brunnhildar Village) (provided)",de="To truly stay in your best riding shape you'll want to test yourself against the other Hyldnir every day. Head back into the Pit of the Fang and show them what you're capable of. They'll appreciate suffering defeat to one as skilled as yourself.",g={n="Gretta the Arbiter",x=0.51,y=0.66,loc="Brunnhildar Village, The Storm Peaks"}}
d[13425]={mo=74000,o="Gretta the Arbiter in Brunnhildar Village wants you to go to Valkyrion and obtain Vials of Frost Oil from the Valkyrion Aspirants. Use the Vials of Frost Oil to destroy 30 Plagued Proto-Drake Eggs. * Plagued Proto-Drake Eggs destroyed (30)",de="It is not enough to demonstrate your prowess among your peers. You must also fight our enemies, dear sister. The Valkyrion traitors continue to mock our noble drake-riding traditions by rearing plagued proto-drakes. Seize the frost oil they wield and use it to freeze their abominable plagued eggs.",g={n="Gretta the Arbiter",x=0.51,y=0.66,loc="Brunnhildar Village, The Storm Peaks"}}
d[13479]={r={{n="Blossoming Branch"}},mo=74000,o="The Spring Gatherer wants you to get 20 shell fragments. * Brightly Colored Shell Fragment (20)",de="Noblegarden, celebration of life and spring! I hope you've been enjoying the egg hunt, friend, because I could use the services of a capable individual like you. I'm not certain what form of magic was used in the creation of the eggs, and the druids aren't keen on explaining it to me. Perhaps you could collect some shell fragments for me during your egg collection. You can keep the contents of the eggs; all I require is a sufficient sample of the eggs themselves.",g={n="Spring Gatherer",loc="Brill, Tirisfal Glades; Razor Hill, Durotar; Bloodhoof Village, Mulgore; Falconwing Square, Eversong Woods"}}
d[13480]={r={{n="Blossoming Branch"}},mo=74000,o="The Spring Collector wants you to get 20 shell fragments. * Brightly Colored Shell Fragment (20)",de="Noblegarden, celebration of life and spring! I hope you've been enjoying the egg hunt, friend, because I could use the services of a capable individual like you. I'm not certain what form of magic was used in the creation of the eggs, and the druids aren't keen on explaining it to me. Perhaps you could collect some shell fragments for me during your egg collection. You can keep the contents of the eggs; all I require is a sufficient sample of the eggs themselves.",g={n="Spring Collector",x=0.428,y=0.654,loc="Various"}}
d[13625]={r={{n="2x Aspirant's Seal"}},rep="+250 The Silver Covenant",o="Strike a Melee Target with Thrust 5 times, use Shield-Breaker on 2 vulnerable Ranged Targets, use Charge on 2 vulnerable Charge Targets and then return to Scout Shalyndria at the Argent Tournament Grounds. If you lose your lance, you can get another from any of the Lance Racks near the stables or the Silver Covenant Pavilion. * Use Thrust on Melee Target (5) * Use Shield-Breaker on vulnerable Ranged Target (2) * Use Charge on vulnerable Charge Target (2)",de="Most of the tournament's competitions require competitors to master the command of a mount in battle. In order to familiarize you with mounted combat, we've put up training dummies all over the northern part of the tournament grounds. Visit the stables on the southern side of the grounds, near the main ring and mount up on the Quel'dorei steed. Familiarize yourself with the tactics available to you and use them to defeat the three different kinds of training dummies.",g={n="Scout Shalyndria",loc="Silver Covenant Pavilion, Icecrown"}}
d[13627]={o="Bring 12 Rough Hewn Planks to Bezzle Blastbolt at the Argent Tournament Grounds *Rough Hewn Plank (12)",de="Come closer. No, not too close. Don't want any unnecessary suspicion now, do we? This coliseum requires more lumber than we've stockpiled and there's no way I'm going to pay to have it shipped in from Grizzly Hills. At the western end of Crystalsong Forest, by the Great Tree, grow a number of young Crystalsong oaks. They'd provide just the kind of planking we need for building and scaffolding. Take this axe, use it to fell the trees and then hew them into planks, but don't let anyone see you!",g={n="Bezzle Blastbolt",loc="Argent Tournament Grounds, Icecrown"}}
d[13666]={r={{n="2x Aspirant's Seal"}},rep="+250 The Silver Covenant",o="Retrieve the Ashwood Brand and bring it to Arcanist Taelis at the Argent Tournament Grounds. *Ashwood Brand *Warts-B-Gone Lip Balm (provided)",de="Some of the champions believe an ancient weapon born of Northrend will bring them luck in the tourney. I have agreed to help them search for these weapons. There's an old legend from Grizzly Hills about a maiden cursed with a frog's form to protect the blade she has long guarded. She lives among the lake frogs on the shore of Ashwood Lake, just east of Ashwood Post. The only thing said to break the curse is a /kiss, freely given. Apply this balm before kissing anything, . Otherwise, you'll catch warts.",g={n="Arcanist Taelis",loc="Silver Covenant Pavilion, Icecrown"}}
d[13669]={r={{n="2x Aspirant's Seal"}},rep="+250 The Silver Covenant",o="Bring the Blade of Drak'Mar to Arcanist Taelis at the Argent Tournament Grounds. *Blade of Drak'Mar",de="Our champions have taken a liking to ancient weapons produced here in Northrend. I've heard the bards telling tales of travelers offering winter hyacinths to a lonely maiden in return for gifts. Those hyacinths grow only on the ice flowing from the Ironwall Dam, northwest on the border between Icecrown and Crystalsong. Gather the flowers and take them to the circle of lamps in Drak'Mar Lake in northeastern Dragonblight, near Zul'Drak and Grizzly Hills. Ask the lonely maiden for a worthy blade.",g={n="Arcanist Taelis",loc="Silver Covenant Pavilion, Icecrown"}}
d[13670]={r={{n="2x Aspirant's Seal"}},mo=132300,rep="+250 The Silver Covenant",o="Arcanist Taelis at the Argent Tournament Grounds wants you to bring him Winter's Edge. *Winter's Edge",de="The Ironforge grand champion's squire told me an intriguing story. In the center of Winter's Breath Lake in northern Howling Fjord, you will find a maiden encased in ice. She is the guardian of an ancient sword and waits there for the blade's new bearer to free her. South of here, overlooking the exit to the Crystal Vice, you will find Lord Everblaze. Kill him, take his everburning ember, and use it to set the maiden free. Prove your worth and earn the weapon that she has guarded for so long, .",g={n="Arcanist Taelis",loc="Silver Covenant Pavilion, Icecrown"}}
d[13671]={r={{n="Aspirant's Seal"}},rep="+250 The Silver Covenant",o="Avareth Swiftstrike at the Argent Tournament Grounds wants you to kill 8 Icecrown Scourge. You may kill Scourge in any part of Icecrown except the Bombardment. *Icecrown Scourge slain (8)",de="The tournament is a time for testing your skills against your peers, but we must not forget that the real enemy, the Scourge, will not wait. As you learn to master mounted combat, do not forget to practice the skills that have served you well all these years. Show us that you can face the Scourge with honor and bravery, and you will earn your right to compete in this tournament. Travel to Icecrown and slay any Scourge you see there, but stay clear of the Bombardment, where you would be overwhelmed.",g={n="Avareth Swiftstrike",loc="Silver Covenant Pavilion, Icecrown"}}
d[13673]={r={{n="2x Aspirant's Seal"}},mo=59440,rep="+250 The Sunreavers",o="Retrieve the Ashwood Brand and bring it to Magister Edien Sunhollow at the Argent Tournament Grounds. * Ashwood Brand * Warts-B-Gone Lip Balm (provided)",de="Some of the champions believe an ancient weapon born of Northrend will bring them luck in the tourney. I have agreed to help them search for these weapons. There is an old legend about a maiden in Grizzly Hills, who guarded a powerful blade. She is said to have been cursed and turned into a frog, so that none would eve wield the blade. She lives among the frogs on the shore of Ashwood Lake, just east of Ashwood Post. It is said the only thing that can break the curse is a kiss, freely given. Apply this balm before kissing anything, . Otherwise, you'll catch warts.",g={n="Magister Edien Sunhollow",loc="Various"}}
d[13674]={r={{n="2x Aspirant's Seal"}},mo=59440,rep="+250 The Sunreavers",o="Bring the Blade of Drak'Mar to Magister Edien Sunhollow at the Argent Tournament Grounds. * Blade of Drak'Mar",de="Our champions have taken a liking to ancient weapons produced here in Northrend. I've heard the bards telling tales of travelers offering winter hyacinths to a lonely maiden in return for gifts. Those hyacinths grow only on the ice flowing from the Ironwall Dam, northwest on the border between Icecrown and Crystalsong. Gather the flowers and take them to the circle of lamps in Drak'Mar Lake in northeastern Dragonblight, near Zul'Drak and Grizzly Hills. Ask the lonely maiden for a worthy blade.",g={n="Magister Edien Sunhollow",loc="Various"}}
d[13676]={r={{n="Aspirant's Seal"}},mo=58000,rep="+250 The Sunreavers",o="Amariel Sunsworn at the Argent Tournament Grounds wants you to kill 8 Icecrown Scourge. You may kill Scourge in any part of Icecrown except the Bombardment. *Icecrown Scourge slain (8)",de="The tournament is a time for testing your skills against your peers, but we must not forget that the real enemy, the Scourge, will not wait. As you learn to master mounted combat, do not forget to practice the skills that have served you well all these years. Show us that you can face the Scourge with honor and bravery, and you will earn your right to compete in this tournament. Travel to Icecrown and slay any Scourge you see there, but stay clear of the Bombardment, where you would be overwhelmed.",g={n="Amariel Sunsworn",x=0.7631,y=0.2438,loc="Various"}}
d[13677]={r={{n="2x Aspirant's Seal"}},mo=58000,rep="+250 The Sunreavers",o="Strike a Melee Target with Thrust 5 times, use Shield-Breaker on 2 vulnerable Ranged Targets, use Charge on 2 vulnerable Charge Targets, and then return to Galathia Brightdawn at the Argent Tournament Grounds. If you lose your lance, you can get another from any of the Lance Racks near the stables or the Sunreaver Pavilion. * Use Thrust on Melee Target (5) * Use Shield-Breaker on vulnerable Ranged Target (2) * Use Charge on vulnerable Charge Target (2)",de="Most of the tournament's competitions require competitors to master the command of a mount in battle. In order to familiarize you with mounted combat, we've put up training dummies all over the northern part of the tournament grounds. Visit the stables outside the pavilion, equip your lance, and mount up on the Sunreaver hawkstrider. Familiarize yourself with the mount and use its abilities to defeat the three different kinds of training dummies.",g={n="Galathia Brightdawn",x=0.762,y=0.244,loc="Sunreaver Pavilion, Icecrown"}}
d[13681]={o="Bring 15 Small Stone Blocks to Bozzle Blastbolt at the Argent Tournament Grounds. *Small Stone Block (15)",de="Getting stone for this job has been a nightmare, I tell ya! There are tones of stone available from ruins in safe places, but those holier-than-thou paladins won't go for it. Something about 'priceless artifacts.' Anyway, whining about that isn't going to get this place built. There are tons of crumbling titan ruins in the Foot Steppes and at the Inventor's Library in Storm Peaks. Take my, uh, 'chisel' with you and see if you can break those huge blocks into useful pieces.",g={n="Bozzle Blastbolt",loc="Argent Tournament Grounds, Icecrown"}}
d[13830]={r={{n="Bag of Fishing Treasures (Dalaran)"}},rep="+325 Kirin Tor",o="Marcia Chase in Dalaran City wants you to discover the mystery of the Phantom Ghostfish. * Discover the Ghostfish mystery",de="Any Northrend angler worth salt knows about the pygmy suckerfish. It's not edible, but sometimes useful to alchemists. There is, however, a stealthy fish that hides among the suckerfish in the River's Heart of Sholazar Basin. The phantom ghostfish. When out of water, they become increasingly translucent until they fade away completely. Some hypothesize they return to Sholazar, and others are more... superstitious. I want you to catch this fish and discover its secret by any means!",g={n="Marcia Chase",x=0.526,y=0.656,loc="Various"}}
d[13832]={r={{n="Bag of Fishing Treasures (Dalaran)"}},rep="+325 Kirin Tor",o="Marcia Chase in Dalaran City wants you to bring her a piece of Corroded Jewelry. * Corroded Jewelry",de="Hard to believe that most people fish in the Dalaran Sewers for giant rats and mutated fish. Especially when those waters are filled with priceless jewelry - discarded by broken hearted fools, thieves, and careless drunks. The trick is to let your hook drag the bottom and don't pull up too hard when get something. Try it out, . I'd be willing to trade whatever you find for a few trinkets of my own.",g={n="Marcia Chase",x=0.526,y=0.656,loc="Various"}}
d[13833]={r={{n="Bag of Fishing Treasures (Dalaran)"}},rep="+325 Kirin Tor",o="Marcia Chase in Dalaran City wants you to bring her 5 Bloodtooth Frenzies. * Bloodtooth Frenzy (5)",de="The bloodtooth is a fiesty little fish used in a recipe to cure infected wounds. We could use some of them, if you're up to it. As the name suggests, they've a hunger for blood. The only way I know how to catch the little devils is by creating a blood pool and fishing in it. Get yourself covered in blood - just slaughter a beast in the Borean Tundra - and then jump in the water. It'll wash right off and create the perfect fishing spot.",g={n="Marcia Chase",x=0.526,y=0.656,loc="Various"}}
d[13834]={r={{n="Bag of Fishing Treasures (Dalaran)"}},rep="+325 Kirin Tor",o="Marcia Chase in Dalaran City wants you to bring her 10 Terrorfish. * Terrorfish (10)",de="The best fishing is often the most dangerous. Wintergrasp boasts a bountiful catch for the brazen. In fact, it's the only place to catch the fabled Terrorfish - a fish both lethal and delicious. Bring me some, and we'll have something to discuss.",g={n="Marcia Chase",x=0.526,y=0.656,loc="Various"}}
d[13836]={r={{n="Bag of Fishing Treasures (Dalaran)"}},rep="+325 Kirin Tor",o="in Dalaran City wants you to return the Severed Arm to her. * Severed Arm",de="I've received word of an unfortunate accident at the Dalaran prison; a guard had his arm severed and thrown into the water by a particularly vicious inmate. Our first aid clinic promises they can reattach the arm if we bring it back. You fish long enough in the water outside the prison, and I'd bet my favorite fishing pole that arm will surface. Find that arm, and bring it to Olisarra the Kind here in Dalaran. She'll know what to do.",g={n="Marcia Chase",x=0.526,y=0.656,loc="Various"}}
d[13836]={r={{n="Bag of Fishing Treasures (Dalaran)"}},rep="+325 Kirin Tor",o="Olisarra the Kind in Dalaran City wants you to return the Severed Arm to her. * Severed Arm",de="It seems a recent deep sea fishing trip went very wrong. The boat capsized, and one of the fisherman lost an arm to a hungry monsterbelly. Our first aid clinic promises they can reattach the arm if we can bring it back. You fish long enough where monsterbellies are found, and I'd bet my favorite fishing pole our little monsterbelly will show his ugly face. Find that arm, and bring it to Olisarra the Kind here in Dalaran. She'll know what to do.",g={n="Marcia Chase",x=0.526,y=0.656,loc="Various"}}
d[13846]={rep="+130 Argent Crusade",o="Speak with Squire Artie to contribute 10 gold to the Argent Crusade's cause. * Required money:",de="The bestest of the champions come to the chapel to hear the argent confessor speak every day. You should see how much she inspires them, . Not only do they fight for the Argent Crusade, but they put a lot of money into the collection basket when I take it around. Maybe you'd like to contribute too?",g={n="Squire Artie",loc="Argent Pavilion, Argent Tournament Grounds"}}
d[14076]={r={{n="Champion's Seal"}},mo=74000,o="Acquire 4 Jormungar Egg Sacs and bring them to Savinia Loresong at the Argent Tournament Grounds. *Jormungar Egg Sac (4) *Earthshaker Drum (provided)",de="Now that the coliseum is complete, the Argent Crusade has asked us to help look after the creatures that champions will be fighting. The giant jormungar have perhaps the strangest diet; they grow strong by eating the eggs of their own kind and the best eggs come from deep jormungar. Take this drum to the Foot Steppes in central Storm Peaks and play them near the snow mounds you see there. Rouse the deep jormungar, kill them, and gather their egg sacs.",g={n="Savinia Loresong",x=0.762,y=0.196,loc="Various"}}
d[14077]={r={{n="Champion's Seal"}},mo=74000,o="Use the Confessor's Prayer Book to perform last rites for 8 Slain Tualiq Villagers and then return to Narasi Snowdawn at the Argent Tournament Grounds. *Last Rites Administrated (8) *Confessor's Prayer Book (provided)",de="I've been listening to Confessor Paletress speak, and I must tell you, her words have given me much to consider. It is not enough to fight beside the crusaders; we must take up their mission. Off the north coast is Hrothgar's Landing, where the seagoing Kvaldir have overrun an old tuskarr settlement and slain the villagers. Take this book and read the rites for the dead near the corpses of the villagers. It will allow their spirit to escape the mists engulfing the island and find peace.",g={n="Narasi Snowdawn",x=0.762,y=0.196,loc="Various"}}
d[14080]={r={{n="Champion's Seal"}},mo=74000,o="Narasi Snowdawn at the Argent Tournament Grounds wants you to kill 10 Kvaldir. *Kvaldir slain (10)",de="The Kvaldir, fearsome vrykul raiders, have disrupted our shipments and murdered the tuskarr inhabitants of an island to the north, renaming it Hrothgar's Landing. If they are allowed to get a foothold there, there is no doubt that we will be their next target. The crusade's forces have their hands full dealing with the Scourge, and we must defend the tournament grounds. Fly north from the grounds until you reach the island and take on the Kvaldir before they can destroy anything else.",g={n="Narasi Snowdawn",x=0.762,y=0.196,loc="Various"}}
d[14090]={r={{n="Champion's Seal"}},mo=74000,o="Use the Weighted Net to capture 8 Snowblind Followers and bring them to Savinia Loresong at the Argent Tournament Grounds. *Snowblind Follower captured x8 *Weighted Net (provided)",de="Two of my men have already been killed trying to confine the magnataur called Gormok the Impaler, yet the creature still rages. It howls for hours about being without its favorite snobold. If the Argent Crusade didn't wish to use this monster in the coliseum, I'd slay it myself. Perhaps it's time to bring the beast its playthings. Take this net and travel to Garm's Bane in southeast Storm Peaks. It's just northeast of K3. Capture some of those snobolds and pray to the Light you've found the right one.",g={n="Savinia Loresong",x=0.762,y=0.196,loc="Various"}}
d[14092]={r={{n="Champion's Seal"}},mo=74000,o="Acquire 4 Jormungar Egg Sacs and bring them to Tylos Dawnrunner at the Argent Tournament Grounds. *Jormungar Egg Sac (4) *Earthshaker Drum (provided)",de="Now that the coliseum is complete, the Argent Crusade has asked us to help look after the creatures that champions will be fighting. The giant jormungar have perhaps the strangest diet; they grow strong by eating the eggs of their own kind and the best eggs come from deep jormungar. Take this drum to the Foot Steppes in central Storm Peaks and play them near the snow mounds you see there. The sound will rouse the deep jormungar. Kill them, collect their egg sacs, and return to the tournament grounds.",g={n="Tylos Dawnrunner",loc="Sunreaver Pavilion, Icecrown"}}
d[14095]={mo=74000,o="Take the Kraken Tooth to as proof of your victory. * Kraken Tooth (Provided)",de="A whole tooth from a dead Kraken is a rare find indeed. will want to see this.",g={n="Kraken Tooth"}}
d[14096]={r={{n="Champion's Seal"}},mo=74000,o="Rescue Kul the Reckless and 4 Captive Aspirants from Deathspeaker's Watch and return to Narasi Snowdawn at the Argent Tournament Grounds. *Kul the Reckless rescued *Captive Aspirant rescued (4)",de="Crusader Kul has gone and gotten himself into trouble again, only this time he's not alone. When he saw the cultists making camp at Deathspeaker's Watch, west of the tournament grounds, Kul gathered the aspirants for an assault. Without reinforcements, Kul and his followers were easily captured. I have no doubt that the cult will sacrifice the prisoners unless we can mount a rescue. Any of those cultists could carry keys to the black cages. Find the keys and free Kul and the captive aspirants.",g={n="Narasi Snowdawn",x=0.762,y=0.196,loc="Various"}}
d[14101]={r={{n="Champion's Seal"}},mo=74000,o="High Crusader Adelard at the Argent Tournament Grounds wants you to kill Deathspeaker Kharos. *Deathspeaker Kharos slain",de="The Cult of the Damned has redoubled its efforts to see us destroyed. They have grown bold and are massing their strength at Deathspeaker's Watch on the ridge west of the tournament grounds. The ruthless Deathspeaker Kharos has his men fortifying their positions, preparing to unleash all of the cult's weapons. My men are preparing themselves and the valiants to defend the grounds, but I want champions like you, , to lead our effort to blunt the attack. Find Deathspeaker Kharos and slay him.",g={n="High Crusader Adelard",loc="Argent Pavilion, Icecrown"}}
d[14101]={r={{n="Champion's Seal"}},mo=74000,o="High Crusader Adelard at the Argent Tournament Grounds wants you to defeat Drottinn Hrothgar. *Drottinn Hrothgar slain * Kvaldir War Horn (provided)",de="The kvaldir, seafaring vrykul who raid ships and coastal settlements, have overrun a tuskarr island across the strait to the north. Their leader is a veteran raider, Drottinn Hrothgar, who seeks to control these seas. With him in power, our ships and troop transports will never be safe. We will be stranded here at the Lich King's mercy. Take this captured kvaldir war horn to the circle of tuskarr statues on the eastern part of Hrothgar's Landing and use it to challenge the kvaldir leader.",g={n="High Crusader Adelard",loc="Argent Pavilion, Icecrown"}}
d[14102]={r={{n="Champion's Seal"}},mo=74000,o="High Crusader Adelard at the Argent Tournament Grounds wants you to kill Mistcaller Yngvar. *Mistcaller Yngvar slain * Mistcaller's Charm (provided)",de="The kvaldir have returned to the coasts of Northrend and if left unchecked, they will prevent our supplies and reinforcements from arriving. One of them, known as Mistcaller Yngvar, has taken up residence in a cave on the western side of Hrothgar's Landing. There, he manipulates the mists to conceal the kvaldir and the sea beasts they command. Take this charm and travel across the strait north of the tournament grounds, to Hrothgar's Landing. Find the mistcaller's cave and use the charm to reveal him.",g={n="High Crusader Adelard",loc="Argent Pavilion, Icecrown"}}
d[14104]={r={{n="Champion's Seal"}},mo=74000,o="High Crusader Adelard at the Argent Tournament Grounds wants you to kill Ornolf the Scarred. *Ornolf the Scarred slain * Captured Kvaldir Banner (provided)",de="Ornolf the Scarred is a fearsome raider renowned among his Kvaldir brethren for raiding and capturing ships. From aboard Bor's Fury, he and his crew attack our ships and steal our goods. Ornolf and his men are among those who slaughtered the inhabitants of a tuskarr island to the north and renamed it Hrothgar's Landing. His ship sits at anchor at the eastern end of the island's harbor. Take this captured banner and display it on the ship to provoke him into facing you in battle.",g={n="High Crusader Adelard",loc="Argent Pavilion, Icecrown"}}
d[14107]={r={{n="Champion's Seal"}},mo=74000,o="Crusader Silverdawn wants you to bring peace to 6 Fallen Hero's Spirits. *Fallen Hero's Spirit blessed x6 *Light-Blessed Relic (provided)",de="The Argent Crusade is hardly the first force to challenge the Lich King. Our enemy turns spirits of the fallen against us. Their spirits wander the Valley of Fallen Heroes southwest of the grounds between Aldur'thar and the Ironwall Rampart. The area is littered with discarded soul crystals, used by the Scourge to control the spirits. Gather those soul crystals and use them with this Light-blessed relic to bestow the blessing of peace upon the spirits. They have more than earned their rest.",g={n="Crusader Silverdawn",loc="Argent Pavilion, Icecrown"}}
d[14108]={r={{n="Champion's Seal"}},mo=74000,o="Crusader Silverdawn wants you to mount an Argent Hippogryph, throw 8 Flaming Spears at the North Sea Kraken and take out 6 Kvaldir Deepcallers. You can find the Argent Hippogryphs right outside the Argent Crusade tent at the Tournament Grounds. *Hurl Spears at North Sea Kraken (8) *Kvaldir Deepcaller slain (6) *Flaming Spears (provided)",de="The Sunreavers and Silver Covenant sent ships north to engage the Kvaldir at Hrothgar's Landing, but were intercepted and detained by a Kvaldir Raiding vessel. To make matters worse, the Kvaldir have found a way to call forth the dreaded Kraken that lives beneath the North Sea. If anyone on board is to get out alive, that Kraken must be driven away and the Kvaldir's summoning ritual ... disrupted. Crusader, take these spears and an Argent Hippogryph will take you to the battle.",g={n="Crusader Silverdawn",loc="Argent Pavilion, Icecrown"}}
d[14112]={r={{n="Champion's Seal"}},mo=74000,o="Savinia Loresong at the Argent Tournament Grounds wants you to bring her 3 pieces of North Sea Shark Meat. *North Sea Shark Meat x3",de="The crusaders have captured a yeti that they're calling Icehowl. He's to be a participant in the Crusaders' Coliseum battles and we've been asked to help with his training and upkeep. The crusaders weren't fond of my suggestion that we feed the beast surplus Sunreavers. The creature has a predilection for shark meat, so I want you to fly down to the Silver Blade, floating in the strait to the north. Get some fresh chum from one of the buckets on the boat, then spread it in the water to attract sharks.",g={n="Savinia Loresong",x=0.762,y=0.196,loc="Various"}}
d[14136]={r={{n="Champion's Seal"}},mo=58000,o="Girana the Blooded at the Argent Tournament Grounds would like you to kill 8 Kvaldir Berserkers and 3 Kvaldir Harpooners aboard The Firehawk. *Kvaldir Berserker slain (8) *Kvaldir Harpooner slain (3)",de="The Kvaldir have set up camp at Hrothgar's Landing, the small island to the North. We sent Captain Aerthas Firehawk to the area, but they ran into a Kvaldir Raiding party heading to the Tournament Grounds! The Firehawk is now under attack by the raiders and is vastly outnumbered. Get out there and show those Kvaldir why attacking the Sunreavers is a poor plan indeed. The Firehawk is between Hrothgar's Landing to the north and the Tournament Grounds, on the western side of The Sea Reaver's Run.",g={n="Girana the Blooded",loc="Various"}}
d[14144]={r={{n="Champion's Seal"}},mo=74000,o="Use the Confessor's Prayer Book to perform last rites for 8 Slain Tualiq Villagers and then return to Girana the Blooded at the Argent Tournament Grounds. *Last Rites Administrated (8) *Confessor's Prayer Book (provided)",de="I've been listening to Confessor Paletress speak, and I must tell you, her words have made me think. We fight beside the crusaders, but we can learn from them, too. Off the north coast is Hrothgar's Landing, where the seagoing Kvaldir have overrun an old tuskarr settlement and slain the villagers. Take this book and read the rites for the dead near the corpses of the villagers. It will allow their spirit to escape the mists engulfing the island and find peace.",g={n="Girana the Blooded",loc="Various"}}
d[14145]={r={{n="Champion's Seal"}},mo=74000,o="Tylos Dawnrunner at the Argent Tournament Grounds wants you to bring him 3 pieces of North Sea Shark Meat. *North Sea Shark Meat (3)",de="The crusaders have captured a yeti that they're calling Icehowl. He's to be a participant in the Crusaders' Coliseum battles and we've been asked to help with his training and upkeep. The crusaders weren't fond of my suggestion that we feed some Silver Covenant members to the beast. The creature prefers shark meat, so I want you to fly down to the Crimson Dawn, floating in the strait to the north. Get some fresh chum from one of the buckets on the boat, then spread it in the water to attract sharks.",g={n="Tylos Dawnrunner",loc="Sunreaver Pavilion, Icecrown"}}
d[14152]={r={{n="Champion's Seal"}},mo=58000,o="Head out to The North Sea and kill 8 Vrykul Berserkers and 3 Vrykul Harpooners attacking The Wavecrest. *Kvaldir Berserker slain (8) *Kvaldir Harpooner slain (3)",de="Champion, Captain Wavecrest and her ship were sent north to disrupt the Kvaldir in Hrothgar's Landing when they were intercepted by a Kvaldir raiding party headed to the Tournament Grounds. Unfortunately, the Kvaldir far outnumber the crew on board and are slowly taking over the ship. We need you to go north to The Wavecrest in Hrothgar's Run, between the Tournament Grounds and Hrothgar's Landing and help the crew fend off the attack. You should see the ship on the east side of Hrothgar's Run.",g={n="Narasi Snowdawn",x=0.762,y=0.196,loc="Various"}}
d[14488]={mo=74000,o="Serve the Court Subpoena to Apothecary Hummel in Shadowfang Keep. *Court Subpoena *Standard Apothecary Serving Kit (provided)",de="You made it, huh? Good. I've been waiting for help. No time like the present to act, right? Take this kit and head deeper inside to serve papers to the leader of that scumbag chemical company, Hummel. The paper's inside. So's a little something to protect you from any chemical tricks they might pull. Use one of the neutralizers when the time comes, all right?",g={n="Investigator Fezzen Brasstacks"}}
d[24597]={r={{n="Lovely Stormwind Card and 5x Love Token"}},o="Present a Lovely Charm Bracelet to Emissary Audwin Alston in Stormwind. *Lovely Charm Bracelet *Lovely Charm Collector's Kit (provided)",de="Did you want to make a Lovely Charm Bracelet for the Emissary of Stormwind? I'm sure he'd be thrilled. Do you already have a Lovely Charm Collector's Kit?",g={n="Kwee Q. Peddlefeet",x=0.54,y=0.71,loc="During Love is in the Air event: Darnassus; Ironforge; Stormwind City; Exodar; Orgrimmar; Thunder Bluff; Undercity; Silvermoon City"}}
d[24597]={r={{n="Lovely Stormwind Card and 5x Love Token"}},o="Present a Lovely Charm Bracelet to King Anduin Wrynn in Stormwind. * Lovely Charm Bracelet * Lovely Charm Collector's Kit (provided)",de="Did you want to make a Lovely Charm Bracelet for the King of Stormwind? I'm sure he'd be thrilled. Do you already have a Lovely Charm Collector's Kit?",g={n="Kwee Q. Peddlefeet",x=0.54,y=0.71,loc="During Love is in the Air event: Darnassus; Ironforge; Stormwind City; Exodar; Orgrimmar; Thunder Bluff; Undercity; Silvermoon City"}}
d[24609]={r={{n="Lovely Ironforge Card"},{n="5x Love Token"}},mo=58500,o="Present a Lovely Charm Bracelet to Muradin Bronzebeard in Ironforge. * Lovely Charm Bracelet * Lovely Charm Collector's Kit (provided)",de="Did you want to make a Lovely Charm Bracelet for Muradin Bronzebeard? I'm sure he'd be thrilled. Do you already have a Lovely Charm Collector's Kit?",g={n="Kwee Q. Peddlefeet",x=0.54,y=0.71,loc="During Love is in the Air event: Darnassus; Ironforge; Stormwind City; Exodar; Orgrimmar; Thunder Bluff; Undercity; Silvermoon City"}}
d[24610]={r={{n="Lovely Darnassus Card and 5x Love Token"}},mo=48500,o="Present a Lovely Charm Bracelet to Tyrande Whisperwind in Darnassus. * Lovely Charm Bracelet * Lovely Charm Collector's Kit (provided)",de="Did you want to make a Lovely Charm Bracelet for the High Priestess of Elune? I'm sure she'd be thrilled. Do you already have a Lovely Charm Collector's Kit?",g={n="Kwee Q. Peddlefeet",x=0.54,y=0.71,loc="During Love is in the Air event: Darnassus; Ironforge; Stormwind City; Exodar; Orgrimmar; Thunder Bluff; Undercity; Silvermoon City"}}
d[24611]={r={{n="Lovely Exodar Card and 5x Love Token"}},o="Present a Lovely Charm Bracelet to Prophet Velen in Exodar. * Lovely Charm Bracelet * Lovely Charm Collector's Kit (provided)",de="Did you want to make a Lovely Charm Bracelet for the Prophet of the Exodar? I'm sure he'd be thrilled. Do you already have a Lovely Charm Collector's Kit?",g={n="Kwee Q. Peddlefeet",x=0.54,y=0.71,loc="During Love is in the Air event: Darnassus; Ironforge; Stormwind City; Exodar; Orgrimmar; Thunder Bluff; Undercity; Silvermoon City"}}
d[24612]={r={{n="Lovely Orgrimmar Card"},{n="5x Love Token"}},mo=15,o="Present a Lovely Charm Bracelet to Emissary Drunzek Skullband in Orgrimmar. *Lovely Charm Bracelet *Lovely Charm Collector's Kit (provided)",de="Did you want to make a Lovely Charm Bracelet for the Orgrimmar Emissary? I'm sure he'd be thrilled. Do you already have a Lovely Charm Collector's Kit?",g={n="Kwee Q. Peddlefeet",x=0.54,y=0.71,loc="During Love is in the Air event: Darnassus; Ironforge; Stormwind City; Exodar; Orgrimmar; Thunder Bluff; Undercity; Silvermoon City"}}
d[24613]={o="Present a Lovely Charm Bracelet to Lady Sylvanas Windrunner in Undercity. * Lovely Charm Bracelet * Lovely Charm Collector's Kit (provided)",de="Did you want to make a Lovely Charm Bracelet for the Banshee Queen? I'm sure she'd be thrilled. Do you already have a Lovely Charm Collector's Kit?",g={n="Kwee Q. Peddlefeet",x=0.54,y=0.71,loc="During Love is in the Air event: Darnassus; Ironforge; Stormwind City; Exodar; Orgrimmar; Thunder Bluff; Undercity; Silvermoon City"}}
d[24614]={o="Present a Lovely Charm Bracelet to Cairne Bloodhoof in Thunder Bluff. * Lovely Charm Bracelet * Lovely Charm Collector's Kit (provided)",de="Did you want to make a Lovely Charm Bracelet for the High Chieftian? I'm sure he'd be thrilled. Do you already have a Lovely Charm Collector's Kit?",g={n="Kwee Q. Peddlefeet",x=0.54,y=0.71,loc="During Love is in the Air event: Darnassus; Ironforge; Stormwind City; Exodar; Orgrimmar; Thunder Bluff; Undercity; Silvermoon City"}}
d[24614]={o="Present a Lovely Charm Bracelet to Baine Bloodhoof in Thunder Bluff. *Lovely Charm Bracelet *Lovely Charm Collector's Kit (provided)",de="Did you want to make a Lovely Charm Bracelet for the High Chieftain? I'm sure he'd be thrilled. Do you already have a Lovely Charm Collector's Kit?",g={n="Kwee Q. Peddlefeet",x=0.54,y=0.71,loc="During Love is in the Air event: Darnassus; Ironforge; Stormwind City; Exodar; Orgrimmar; Thunder Bluff; Undercity; Silvermoon City"}}
d[24615]={o="Present a Lovely Charm Bracelet to Lor'themar Theron in Silvermoon City. *Lovely Charm Bracelet *Lovely Charm Collector's Kit (provided)",de="Did you want to make a Lovely Charm Bracelet for the Regent Lord of Quel'Thalas? I'm sure he'd be thrilled. Do you already have a Lovely Charm Collector's Kit?",g={n="Kwee Q. Peddlefeet",x=0.54,y=0.71,loc="During Love is in the Air event: Darnassus; Ironforge; Stormwind City; Exodar; Orgrimmar; Thunder Bluff; Undercity; Silvermoon City"}}
d[24629]={r={{n="5x Love Token"}},mo=2100,o="Spray 10 people with the Crown Perfume Sprayer. * Crown Perfume Sprayer (provided)",de="You look like a real go-getter, . How about we work out a little win-win scenario? Crown's looking to offer samples of our latest holiday-themed products to as many potential customers as possible. Help us share the love, and we'll give you discounts on some great Crown merchandise! Your time, our money, friend. We do you say?",g={n="Public Relations Agent",x=0.53,y=0.66,loc="Various"}}
d[24635]={r={{n="5x Love Token"}},o="Spray 10 people with the Crown Cologne Sprayer. *Samples Given (10)",de="You seem like the enterprising sort, . How about we make a little deal? Crown wants to offer samples of our latest holiday-themed products to as many potential customers as we can. Help us share the love while earning some fantastic Crown merchandise! Your time, our money, friend. What do you think?",g={n="Public Relations Agent",x=0.53,y=0.66,loc="Various"}}
d[24636]={r={{n="5x Love Token"}},mo=165400,o="Toss 10 people samples from the Crown Chocolate Sampler. * Samples Given (10) * Crown Chocolate Sampler (provided)",de="I can see you've got an eye for opportunity, . What do you say we make a little coin together? Crown needs to push samples of our latest holiday-themed products to every potential customer in the city. Help us share the love, and we'll share some of that amazing Crown merchandise with you! Your time, our money, friend. We got a deal?",g={n="Public Relations Agent",x=0.53,y=0.66,loc="Various"}}
d[24651]={r={{n="Love Token x5"}},mo=29000,o="Kill 5 Crown Sprayers and use Snagglebolt's Khorium Bomb to destroy one chemical wagon east of Shattrath in Terokkar Forest, then return to Detective Snap Snagglebolt in Orgrimmar. * Chemical Wagon Destroyed * Crown Underling slain (5) * Snagglebolt's Khorium Bomb (provided)",de="This ledger is full of locations, and I need you to investigate and take action, pal. This has gone on long enough. Here's an entry I want you to check out: it looks like it's just east of Shattrath in Terokkar Forest. Get out there and rough 'em up. Oh, and if you see something big and dangerous enough that it needs destroying, toss this bomb at it.",g={n="Detective Snap Snagglebolt",loc="Durotar"}}
d[24664]={r={{n="Love Token x5"}},mo=74000,o="Kill 5 Crown Sprinklers and use Snagglebolt's Khorium Bomb to destroy one chemical wagon east of Everlook in Winterspring, then return to Inspector Snip Snagglebolt in Stormwind. * Chemical Wagon Destroyed * Crown Sprinkler slain x5 * Snagglebolt's Khorium Bomb (provided)",de="This ledger is full of locations, and I need you to investigate and take action, pal. This has gone on long enough. Here's an entry I want you to check out: it's in Winterspring, just east of Everlook. Oh, now this is personal. Get out there and rough 'em up. Oh, and if you see something big and dangerous enough that it needs destroying, toss this bomb at it.",g={n="Inspector Snip Snagglebolt",loc="Stormwind Gate, Elwynn Forest"}}
d[24666]={r={{n="Love Token x5"}},mo=132300,o="Kill 5 Crown Sprayers and use Snagglebolt's Khorium Bomb to destroy one chemical wagon in the Forlorn Woods of Crystalsong Forest, then return to Detective Snap Snagglebolt in Orgrimmar. * Chemical Wagon Destroyed * Crown Sprayer slain x5 * Snagglebolt's Khorium Bomb (provided)",de="This ledger is full of locations, and I need you to investigate and take action, pal. This has gone on long enough. Here's an entry I want you to check out: it looks like it's in the Forlorn Woods of Crystalsong, northwest of the Mirror of Twilight. Get out there and rough 'em up. Oh, and if you see something big and dangerous enough that it needs destroying, toss this bomb at it.",g={n="Detective Snap Snagglebolt",loc="Durotar"}}
d[24666]={r={{n="Love Token x5"}},mo=132300,o="Kill 5 Crown Sprayers and use Snagglebolt's Khorium Bomb to destroy one chemical wagon in the Forlorn Woods of Crystalsong Forest, then return to Inspector Snip Snagglebolt in Stormwind. * Chemical Wagon Destroyed * Crown Sprayer slain x5 * Snagglebolt's Khorium Bomb (provided)",de="This ledger is full of locations, and I need you to investigate and take action, pal. This has gone on long enough. Here's an entry I want you to check out: it looks like it's in the Forlorn Woods of Crystalsong, northwest of the Mirror of Twilight. Get out there and rough 'em up. Oh, and if you see something big and dangerous enough that it needs destroying, toss this bomb at it.",g={n="Inspector Snip Snagglebolt",loc="Stormwind Gate, Elwynn Forest"}}
d[25105]={mo=165300,o="Cut three Solid Zephyrites and give them to Isabel Jones in Stormwind. * 3 Solid Zephyrite * 3 Solid Zephyrites cut",de="Lila's pet Nibbler got into my workshop again! I was making a bracelet, to be delivered today. The work was almost done, except for the gems. I spent all night cutting them, but when I stepped out for a bit of breakfast, the little beast came into my workshop and swallowed every gem in sight! The thing can digest ANYTHING, and trust me, you'd break your back trying to pick up its leavings. I need to get replacement gems fast; the courier is coming in tonight. Help!",g={n="Isabel Jones",x=0.637,y=0.614,loc="Trade District, Stormwind City"}}
d[25154]={o="Cut three Timeless Nightstones and give them to Isabel Jones in Stormwind.",de="I'm trying to impress this trade ship captain Lila. I've been working on a necklace to match her lovely purple hair, but the gems have gone missing! They were there when I was showing them off to my good friend Bonder last evening. We were drinking moonshine and I blacked out - when I woke up the gems were gone! They must have been darn good thieves, because Bonder didn't see anything. Her ship is coming in tonight, and I really need three nightstones to get her present done. Help me out here!",g={n="Marith Lazuria",x=0.7193,y=0.3588,loc="Valley of Honor, Orgrimmar"}}
d[25155]={o="Cut three Jagged Jaspers and give them to Isabel Jones in Stormwind.",de="I was supposed to receive a shipment of jasper from Azeroth Express, but I just heard their ship crashed into some tiny island called Ogrezonia. I worry about the crew, as the giant female ogres on the island are rumored to perform horrible rituals on men who happen upon their island. My work must go on, though, and we need those gems. I've heard great things about your skill as a jewelcrafter - could you deliver three jagged jaspers by the end of the day?",g={n="Isabel Jones",x=0.637,y=0.614,loc="Trade District, Stormwind City"}}
d[25156]={o="Collect 10 Elemental Goo from any Cataclysm elemental and bring them to Isabel Jones in Stormwind.",de="Instead of using the tired old method of setting gems into rings and such, I use an innovative new method. I simply glue on the gems with Barnsworth Elemental Glue! The professor needs more elemental goo for another batch, though, and I have a whole bunch of setting to do. Can you go get me some?",g={n="Isabel Jones",x=0.637,y=0.614,loc="Trade District, Stormwind City"}}
d[25157]={o="Test Stardust No. 2 on 10 \"humanoid subjects\". *Stardust No. 2 Tested (10) *Stardust No. 2 (provided)",de="Professor Barnsworth has been working on this new stardust - what with the fashion in Stormwind this season being about all things sparkly, I'm sure if we can get it to the market it will be all the rage! The Jewelcrafter's Association, however, won't let us market it until we've completed some humanoid testing - something about tinkering with magical dust being dangerous or some such nonsense. Well, I suppose we need to humor them. Take this bag and test out Stardust No. 2 on some humanoid subjects.",g={n="Isabel Jones",x=0.637,y=0.614,loc="Trade District, Stormwind City"}}
d[25158]={mo=165300,o="Cut three Solid Zephyrites and give them to Marith Lazuria in Orgrimmar.",de="Lila's pet Nibbler got into my workshop again! I was making a bracelet, to be delivered today. The work was almost done, except for the gems. I spent all night cutting them, but when I stepped out for a bit of breakfast, the little beast came into my workshop and swallowed every gem in sight! The thing can digest ANYTHING, and trust me, you'd break your back trying to pick up its leavings. I need to get replacement gems fast; the courier is coming in tonight. Help!",g={n="Marith Lazuria",x=0.7193,y=0.3588,loc="Valley of Honor, Orgrimmar"}}
d[25159]={o="Test Stardust No. 2 on 10 \"humanoid subjects\". *Stardust No. 2 Tested (10) *Stardust No. 2 (provided)",de="Dr. Vernstrom has been working on this new stardust - what with the fashion in Orgrimmar this season being about all things sparkly, I'm sure if we can get it to the market it will be all the rage! The Jewelcrafter's Association, however, won't let us market it until we've completed some \"live testing\" - something about tinkering with magical dust being dangerous or some such nonsense. Well, I suppose we need to humor them. Take this bag and test out Stardust No. 2 on humanoid subjects.",g={n="Marith Lazuria",x=0.7193,y=0.3588,loc="Valley of Honor, Orgrimmar"}}
d[25160]={o="Cut three Timeless Nightstones and give them to Marith Lazuria in Orgrimmar.",de="I'm trying to impress this trade ship captain Lila. I've been working on a necklace to match her lovely purple hair, but the gems have gone missing! They were there when I was showing them off to my good friend Bonder last evening. We were drinking moonshine and I blacked out - when I woke up the gems were gone! They must have been darn good thieves, because Bonder didn't see anything. Her ship is coming in tonight, and I really need three nightstones to get her present done. Help me out here!",g={n="Marith Lazuria",x=0.7193,y=0.3588,loc="Valley of Honor, Orgrimmar"}}
d[25161]={o="Cut three Jagged Jaspers and give them to Marith Lazuria in Orgrimmar. *Jagged Jasper Cut (3) *Jagged Jasper (3)",de="I was supposed to receive a shipment of jasper from Azeroth Express, but I just heard their ship crashed into some tiny island called Ogrezonia. I worry about the crew, as the giant female ogres on the island are rumored to perform horrible rituals on men who happen upon their island. My work must go on, though, and we need those gems. I've heard great things about your skill as a jewelcrafter - could you deliver three jagged jaspers by the end of the day?",g={n="Marith Lazuria",x=0.7193,y=0.3588,loc="Valley of Honor, Orgrimmar"}}
d[25162]={r={{n="+"}},o="Collect 10 Elemental Goo from any Cataclysm elemental and bring them to Marith Lazuria in Orgrimmar. *Elemental Goo (10)",de="Instead of using the tired old method of setting gems into rings and such, I use an innovative new method. I simply glue on the gems with Vernstrom Elemental Glue! The doctor needs more elemental goo for another batch, though, and I have a whole bunch of setting to do. Can you go get me some?",g={n="Marith Lazuria",x=0.7193,y=0.3588,loc="Valley of Honor, Orgrimmar"}}
d[26009]={o="Slay any 20 soldiers of the Alliance in Stonetalon Mountains. *Alliance Soldier slain (20)",de="The Alliance encroaches upon our territories within Stonetalon. The forces of Northwatch have broken through our blockade in the south and occupy Windshear Valley, to our west. From the northern front comes an onslaught of night elf soldiers. All must be stopped! Venture forth into Stonetalon and destroy all Alliance soldiers that cross your path. Let their deaths serve as a message. Stonetalon belongs to the Horde!",g={n="Overlord Krom'gar",loc="Krom'gar Fortress, Cliffwalker Post, Stonetalon Mountains"}}
d[26177]={r={{n="+1 Cooking skill"},{n="+2 Epicurean's Award"}},rep="+250 Stormwind",o="Collect 10 Canal Crabs. Deliver them to Robby Flay in Stormwind City. * Canal Crab (item) (10)",de="Fresh crab legs have always been one of the King's favorite foods. We have had good luck catching fresh crabs in the canals over the past few weeks. Do you think you can lend me a hand and catch a few of them for me? Be sure to catch them alive, they are no good to me dead, the King requires the freshest catch we can muster."}
d[26183]={r={{n="+2 Cooking skill"},{n="Epicurean's Award"}},rep="+250 Stormwind",o="Obtain 12 Juicy Apples. Deliver the fruit to Robby Flay in Stormwind City. * Juicy Apple (12)",de="I am forever in debt to our King for all that he has done for us. One thing I can do for him is make his favorite drink! Lucky for us, the ingredients we need to make this wonderful drink are located right here in Stormwind City. Apple trees can be found in every district of Stormwind. These trees are too tall to pick the fruit from, but lucky for us the apples have fallen to the ground and are easy to retrieve."}
d[26190]={r={{n="+2 Cooking skill"},{n="Epicurean's Award"}},rep="+250 Stormwind",o="400px|thumb|The objective of A Fisherman's Feast are the Barrel of Canal Fish that spawn near Stormwind Fisherman Obtain 5 Gigantic Catfish. Deliver the fish to Robby Flay in Stormwind City. * Gigantic Catfish (5)",de="If there is one meal I know the King likes, it's fresh catfish. Catfish are easy to prepare but hard to catch. That's where you come in! We have a good population of Gigantic Catfish here in the waters of Stormwind but the competition to catch them is intense to say the least. I need you to figure out a way to \"acquire\" some of these fine catfish for our King. You will find fisherman at the small canal docks around town. You should be able to figure out the rest of the plan on your own."}
d[26192]={r={{n="+1 Cooking skill"},{n="Epicurean's Award"}},rep="+250 Stormwind",o="Obtain 4 sacks of Confectioners' Sugar. Deliver the sugar to Robby Flay in Stormwind City. * Confectioners' Sugar (4)",de="The orphans of Stormwind are often forgotten, but not today my friend. The king has requested a special batch of cookies be baked and sent immediately over to the orphanage. I was almost finished with the final batch when I ran out of confectioners' sugar. Can you run out and get some more for me? You should be able to find it at any of the general stores or inn's inside of Stormwind.",g={n="Robby Flay",x=0.51,y=0.72,loc="Canals, Stormwind City"}}
d[26220]={r={{n="Epicurean's Award"}},rep="+250 Orgrimmar",o="Slaughter Mature Swine south of Orgrimmar and bring me back 6 of their [http://www.wowhead.com/item=57758 Swine Bellies]. I will be waiting for you here in The Drag.",de="Feeding a hungry orc army is never an easy task. Luckily for us, we have a good supply of mature swine meat from the pig farms and surrounding areas south of Orgrimmar. Do me a favor and slaughter some of those pigs for their delicious belly meat. I will slice it up and make bacon for the troops' breakfast."}
d[26226]={r={{n="Epicurean's Award"}},mo=74000,rep="+250 Orgrimmar",o="Catch 10 Muddy Crawfish in Orgrimmar. Deliver the crustaceans to Marogg when you are done. * Muddy Crawfish (10)",de="There are a number of small lakes scattered around Orgrimmar. These lakes full up with crawfish every year. That's where you come in, . I need you to catch some of those delicious crustaceans and return to me when you are done. Assuming the catch is successful, our Horde army will feast tonight."}
d[26227]={r={{n="1xEpicurean's Award"},{n="+1 Cooking skill"}},mo=74000,rep="+250 Orgrimmar",o="Retrieve 8 pieces of Prickly Pear Fruit. Deliver the fruit to Marogg in Orgrimmar. *Prickly Pear Fruit (8)",de="Sometimes the troops want something sweet to eat. I don't always give them what they want but this time, I am going to make an exception. I am sure you have seen the local cactus that grows here in Orgrimmar. These cactus produce a tasty treat called prickly pear fruit. The trouble is the fruit are covered in spines! Watch your hands and bring be back a handful of the fruit.",g={n="Marogg",x=0.56,y=0.62,loc="Drag, Orgrimmar"}}
d[26233]={r={{n="Epicurean's Award"},{n="+1 Cooking Skill"}},mo=74000,rep="+250 Orgrimmar",o="Retrieve 6 Barrels of Darkspear Rice. Deliver the rice to Marogg in Orgrimmar. * Barrel of Darkspear Rice (6)",de="As you know , Garrosh has relegated the Trolls of Orgrimmar to the western outskirts of the city. Fortunately, that means that we have easy access to their supplies. I am working on a large batch of jambalaya for the infantry and I need as much rice as possible. Lucky for us, the Trolls keep it stored in barrels near their structures. Retrieve these barrels of Darkspear rice for me and I should be able to finish up.",g={n="Marogg",x=0.56,y=0.62,loc="Drag, Orgrimmar"}}
d[26234]={r={{n="Epicurean's Award"},{n="+1 Cooking Skill"}},mo=74000,rep="+250 Orgrimmar",o="Retrieve 6 Barrels of Kezan Rice. Deliver the rice to Marogg in Orgrimmar. Bring the Barrels of Kezan Rice to Marogg. * Barrel of Kezan Rice (6)",de="As you know , Garrosh has relegated the Goblins of Orgrimmar to the western outskirts of the city. Fortunately, that means that we have easy access to their supplies. I am working on a large batch of jambalaya for the infantry and I need as much rice as possible. Lucky for us, the Goblins keep it stored in barrels near their structures. Retrieve these barrels of Kezan rice for me and I should be able to finish up.",g={n="Marogg",x=0.56,y=0.62,loc="Drag, Orgrimmar"}}
d[26235]={r={{n="Epicurean's Award"},{n="+1 Cooking skill"}},mo=74000,rep="+250 Orgrimmar",o="Recover 3 Horde Infantry Rations. Deliver them to Marogg in Orgrimmar. *Horde Infantry Rations (3)",de="We have had a problem with thieves stealing our infantry rations here in Orgrimmar for the last couple of weeks. I recently received some intelligence of where these crimes are taking place. Anywhere you see piles of crates and supplies, there are likely to be thieves nearby. I need you to hunt these thieves down and recover the stolen rations. Return to me when you are done."}
d[26543]={r={{n="Bag of Shiny Things"},{n="+1 Fishing skill"}},mo=74000,rep="+250 Orgrimmar",o="Collect 10 Monstrous Clam Meat from the clams near the eastern shoreline, just south of Orgrimmar. Return to Razgar once you are done. *Monstrous Clam Meat (10)",de="Nothing tastes like fresh monstrous clam meat, . I have been so busy with work these past few weeks that I have not been able to make it out to the local clam spawning grounds. Think you could run down there and gather some of those tasty treats for me? The clams can be found near the shoreline on the eastern coast of Durotar. Should be plenty right around the Orgrimmar docks."}
d[26556]={rep="+250 Orgrimmar",o="Fish up 6 Toxic Puddlefish and return them to Razgar in the Valley of Honor once you are done. *Toxic Puddlefish (6)",de="Ever since those goblins took up refuge in Orgrimmar, they have been dumping all of there waste in our water supply. I have no idea what effect this is having on our local fishing supply, but I don't think it's good. I have heard reports of a new mutated fish species spawning in that toxic pool near their camp. A few specimens would really help me figure out what exactly is going on. Can you help me out?",g={n="Razgar",x=0.6571,y=0.4109,loc="Various"}}
d[26557]={rep="+250 Orgrimmar",o="Slaughter a Stag north of Orgrimmar and use it's eye as bait to catch a Sandy Carp in the Valley of Wisdom. Return to Razgar in the Valley of Honor once you are done. *Sandy Carp",de="I've fished sandy carp in Orgrimmar's local water's for years now. Recently, I have noticed my bait is not working as well as it used too. I suspect it has something to do with all the tauren that moved into the Valley of Wisdom. I spoke with one of their local fisherman and it just turns out their appetite has changed. They are biting on stag eyes these days. You should be able to find plenty of stags north of Orgrimmar, just outside the northern gate."}
d[26572]={mo=74000,rep="+250 Orgrimmar",o="Use Razgar's Fillet Knife to cut off a Drowned Thunder lizard Tail in Thunder Ridge, south of Orgrimmar. Once you have the tail, use it near a Golden Stonefish to kill it. Return to Razgar in the Valley of Honor once you are done. *Golden Stonefish (3) *Razgar's Fillet Knife (provided)",de="You heard of the golden stonefish, ? The thing with these fish is that they can't be caught by normal means. They have jaws so strong that they snap right through any hooks or lures you try to use on 'em. You can find a number of them in Thunder Ridge, south of Orgrimmar. That ridge used to be full of thunder lizards, but they all drowned in the flood. Take my knife, swim down there and cut off their tails. You should be able to use the tail to zap any stonefish you find.",g={n="Razgar",x=0.6571,y=0.4109,loc="Various"}}
d[26588]={mo=74000,rep="+250 Orgrimmar",o="Catch a Giant Furious Pike in the Southfury River. The Southfury River can be found just outside Orgrimmar's western gate. Return to Razgar in the Valley of Honor once you are done. *Giant Furious Pike",de="Are you up for a challenge, ? Good, I was hoping you would be. The southfury river flows just west of Orgrimmar and your challenge can be found within its mighty flow. We are looking for a giant furious pike. This esteemed fish used to be prevalent in these areas but ever since the floods hit, the big ones have been much harder to find. Head out to the river and let's see just how good of an angler you really are."}
d[26710]={mo=86000,rep="+250 Therazane",o="Find Pebble within the Crumbling Depths and lead him safely out of the tunnels. *Pebble brought to safety.",de="Pebble has gotten himself lost again, somewhere deep in the Crumbling Depths. He's fortunate that his size makes him unworthy of the effort for those gyreworms, but it's only a matter of time before he stumbles too close to one and gets eaten. Whatever he's so intent on down there is certainly not worth it. He seems to like you. Please, go and find him and bring him out of those tunnels to safer playing grounds."}
d[27046]={mo=86000,rep="+250 Therazane",o="Kill 10 gyreworms. * Gyreworm slain x10",de="The gyreworms infest the rock, eating away at it until our home will one day collapse. For every one that is killed, twice as many burst forth to follow, but we must carry on the fight. They must be extinguished. Go to the Crumbling Depths and slaughter any worms that you can find."}
d[27047]={mo=86000,rep="+250 Therazane",o="Recover 10 Motes of Painite. * Painite Mote x10",de="Some of the rarest crystals form in the most dangerous places. In the Crumbling Depths, you will find painite formations - much better than the gold that your races cherish so much. As a being of flesh and a being of small stature, you can enter the Crumbling Depths to retrieve motes of painite for me. Would you undergo that danger on my behalf?"}
d[27048]={mo=86000,rep="+250 Therazane",o="Use Ricket's Tickers to gather 3 Deep Alabaster Crystals, 3 Deep Celestite Crystals, 3 Deep Amethyst Crystals, and 3 Deep Garget Crystals. * Deep Alabaster Crystal x3 * Deep Celestite Crystal x3 * Deep Amethyst Crystal x3 * Deep Garnet Crystal x3 * Ricket's Tickers (provided)",de="Hey! I need some help gatherin' crystals. The elementals trade top dollar for these things... if you help me gather all the different kinds, I'll cut you in on the profits. Use these bombs to blow out chunks from the bigger formations. I've got a nasty habit of packin' the explosives a bit thick. Mind the kick.",g={n="Ricket",x=0.409,y=0.854,loc="Various"}}
d[27049]={mo=86000,rep="+250 Therazane",o="Kill 8 Fungal Behemoths. *Fungal Behemoth x8 slain",de="The corruption of the Crimson Expanse has not subsided. Destroy the Fungal Behemoths that shower their filth upon our realm. If they continue to rise, we will continue to destroy them."}
d[27050]={mo=86000,rep="+250 Therazane",o="Destroy 10 of the newly sprouted mushrooms in the Crimson Expanse. *Freshly sprouted mushroom destroyed",de="Something upon the Crimson Expanse continues to spur disgusting growths upon the rock. New fungi are rising, and they need to be crushed before they can spread."}
d[27051]={mo=86000,rep="+250 Therazane",o="Retrieve a Bag of Verlok Miracle-Grow from the Verloks upon the Crimson Expanse. * Bag of Verlok Miracle-Grow",de="The troggs did not disperse after you killed Glop. His servants recovered the growth agent that was left behind and continue to sew the seeds of corruption across the Crimson Expanse. Hunt them down and recover any of the remaining Verlock Miracle-Grow that you find. It must be disposed of."}
d[27948]={r={{n="at 85"}},rep="+250 Baradin's Wardens",o="Collect 4 Sticky Silk Glands from Darkwood Broodmother spiders in The Darkwood. The Darkwood forest is just west of here, across the bridge on the central island. * Sticky Silk Gland (4)",de="Finding supplies on the island has been difficult, to say the least. Fortunately, we have found a good supply of silk in The Darkwood, just west of here. The bad part of this story is that the silk comes from the glands on Broodmother spiders. I need you to gather 4 of these for me. That should be just enough to finish up this last set of shirts.",g={n="Camp Coordinator Brack",loc="Tol Barad Peninsula"}}
d[27967]={r={{n="at 85"}},rep="+250 with Baradin's Wardens",o="Find and kill First Lieutenant Connor at Forgotten Hill. You will find Forgotten Hill on the far west side of the island. *First Lieutenant Connor slain",de="The first time I heard about Lt. Connor, I was just a young recruit in the Stormwind stockades. None of us could believe he ended up here on Tol Barad. Sadly, he still roams these wretched islands, wreaking havoc on our troops morale. I need you to put an end to his misery... and ours.",g={n="Lieutenant Farnsworth",loc="Tol Barad Peninsula"}}
d[27971]={r={{n="at 85"}},rep="+250 with Baradin's Wardens",o="Camp Coordinator Brack has asked you to kill 8 Shipwrecked Sailors at the Cape of Lost Hope. The cape is located due northwest of here, on the beach. *Shipwrecked Sailor slain (12)",de="We have been having issues with the undead down at the Cape of Lost Hope for a while now. Every time a new ship wrecks, they end up getting more undead to join their ranks. Can you do us a favor and thin out the ranks up there? I know you won't be able to kill them all, but anything you can do will help at this point. Keep an eye out for horde, we have been getting reports of them ambushing the beach lately.",g={n="Camp Coordinator Brack",loc="Tol Barad Peninsula"}}
d[27972]={r={{n="at 85"}},o="You have been asked to recover 6 Barrels of Southsea Rum from the shipwrecks on the Cape of Lost Hope. The cape can be found north of here, along the coast. * Barrel of Southsea Rum (6)",de="Morale is low these days, . We make every effort we can to keep the troops in high spirits but we are running low on our main supply of morale booster... rum. I have been getting reports from our infantry to the south that the shipwrecks on the Cape of Lost Hope still have a good supply of southsea rum in their wrecked hulls. Can you head up there and investigate? Bring back any rum you can find.",g={n="Camp Coordinator Brack",loc="Tol Barad Peninsula"}}
d[27975]={r={{n="Tol Barad Commendation"}},mo=94000,rep="+250 Baradin's Wardens",o="Kill Foreman Wellson at the Wellson Shipyard. The shipyard can be found northwest of here, on the western coast. *Foreman Wellson slain",de="Foreman Wellson has been a pain in our side since we got here. His shipyard holds a large amount of supplies that would be extremely useful to us... if we could get to them. He keeps a close watch over his minions and makes it very difficult for us to get a foothold on the shipyard. I need you to take out Wellson for good this time. Be careful , we have been receiving reports of filthy Horde all around the area.",g={n="Sergeant Gray",loc="Tol Barad Peninsula"}}
d[27978]={r={{n="at 85"}},o="Kill 14 ghosts of any type at Largo's Overlook, just northeast of base camp. *Largo's Overlook Ghosts Slain (14)",de="See that hill just beyond our base camp? That's Largo's Overlook and it's not a fun place to setup camp next to. We have been dealing with those spirits and spectres ever since we setup base camp. Can you head up there and let them know we don't plan on leaving anytime soon? A few good kills on their ranks should put them in line. Thanks for your help on this, .",g={n="Sergeant Gray",loc="Tol Barad Peninsula"}}
d[27987]={r={{n="at 85"}},rep="+250 Baradin's Wardens",o="You need to recover 4 Stacks of Cannonballs from Largo's Overlook for Sergeant Gray. You can find Largo's Overlook just northeast of the base camp. * Stack of Cannonballs (4)",de="Largo and his minions have been stealing our supplies ever since we setup camp here. It's frustrating to say the least. We have heard reports that he is stockpiling cannonballs in the towers overlooking the water up on his overlook. Can you head up there and try to recover some of them for us? , don't forget to keep a watch out for horde too.",g={n="Sergeant Gray",loc="Tol Barad Peninsula"}}
d[27991]={r={{n="at 85"}},o="Sergeant Gray has asked you to kill Commander Largo at Largo's Overlook. The overlook is just north of the base camp. *Commander Largo slain",de="There is only one way for us to take Largo's Overlook back. I think you know what we need to do, . Largo is pretty paranoid these days so you should be able to find him on top of the tower, looking for his imaginary navy to finally arrive.",g={n="Sergeant Gray",loc="Tol Barad Peninsula"}}
d[27992]={r={{n="at 85"}},rep="+250 with Baradin's Wardens",o="You have been tasked with recovering 7 pieces of Siege Engine Scrap. Use the Magnetic Scrap Attractor in The Restless Front to find the scraps. The Restless Front is due west, just past the second bridge. * Siege Engine Scrap (7) *Magnetized Scrap Collector (provided)",de="Getting useful machine parts out here on the island has been difficult, . We have been trying to repair the broken siege engines here in camp but we keep running out of useful parts. Our second regiment reported some wrecked out siege engines in a old battlefield to the west. Maybe we could find some parts over there? You are going to have trouble finding anything in that old battlefield so take this magnetic scrap attractor and put it to some good use.",g={n="Lieutenant Farnsworth",loc="Tol Barad Peninsula"}}
d[28050]={r={{n="at 85"}},rep="+350 with Baradin's Wardens",o="You have been tasked to kill Tank, a large shark cruising the waters of the Cape of Lost Hope. The cape can be found north of here, along the northern coastline. *Tank slain *Suggested players: 3",de="I hate sharks. All of my troops hate sharks too. This is where you come in, . I need you to head up to the Cape of Lost Hope and take out a huge shark named Tank. Tank is not to be trifled with so I would bring a few friends if I were you.",g={n="Camp Coordinator Brack",loc="Tol Barad Peninsula"}}
d[28059]={r={{n="at 85"}},rep="+250 Baradin's Wardens",o="You have been asked to kill Keep Lord Farson at the Farson Hold. Farson Hold can be found on the north side of the island. *Keep Lord Farson slain",de="Have you seen the keep on the north side of the island, ? That is where Keep Lord Farson runs his operation from. Farson has a small group of dedicated followers and they have been giving us trouble since we got here. We sent a small group to investigate and they reported back on his exact position within the keep. Can you finish him off for us?",g={n="Commander Marcus Johnson",loc="Baradin Base Camp, Tol Barad Peninsula"}}
d[28065]={r={{n="at 85"}},rep="+250 Baradin's Wardens",o="Escort a Farson Hold Prisoner to safety. The hold is located on the northwestern tip of the island. *Farson Prisoner Escorted",de="We have sent at least 3 different recon groups to investigate Farson Hold in the last few weeks. Sadly, not one of them has returned back with any info. At this point, all we can hope is that they are being held alive as prisoners. I need you to infiltrate the keep and help get our soldiers back. This won't be easy , but if anyone can help us, it's you. (\"Farson Prisoner: This guy looks like he could use some help.\")",g={n="Commander Marcus Johnson",loc="Baradin Base Camp, Tol Barad Peninsula"}}
d[28250]={mo=65000,rep="+150 Ramkahen",o="thumb|A stack of Pygmies. Smash 30 Sand Pygmies with the Tehret Dynasty Mallet. *Thieving plucker smashed x30 *Tahret Dynasty Mallet (provided)",de="I don't have the most glamorous job in the world. I do not concern myself with the deep myseries of the halls of Uldum or what have you. I am in charge of these grounds... and these grounds grow dates. Now, these little date-plucking mongrels have gotten gutsy enough to stand on each other's shoulders to try and steal my precious fruit. I will not stand for this. Take this mallet, crafted by the titans, blessed by the sun-kings and who-knows-what-else and smash the runts!",g={n="Nomarch Teneth",loc="Tahret Grounds, Uldum"}}
d[28390]={mo=172000,rep="+350 Therazane",o="Speak to Earthmender Norsala, then kill Fungalmancer Glop. *Speak to *Fungalmancer Glop slain",de="Glop had a son. In his grave hubris, he named it Glop. And so the line of fungalmancers continues. I require you to slay this new fungalmancer. Your shaman ally has already returned, and awaits you at his cave in the southwest of Verlok Stand."}
d[28391]={mo=172000,rep="+350 Therazane",o="Defeat Aeosera. *Pale Resonating Crystal struck *Aeosera defeated *Stonework Mallet (provided)",de="Aeosera is restless and stubborn. She scoffs at our dominance, and she needs to be reminded of her place. I still have the mallet you retrieved for me. Return to the western edge of the Pale Roost and strike resonating crystal. I will meet you there and lend what aid I can. Put her back in her place, .",g={n="Terrath the Steady",loc="Therazane's Throne, Deepholm"}}
d[28488]={mo=86000,rep="+250 Therazane",o="Recover an Enormous Ruby Crystal Cluster. *Ruby Crystal Cluster",de="Among the other precious gemstones hidden deep out of our reach in the Crumbling Depths, there are enormous ruby crystal clusters. They are infused with terrible energy. It will not be easy to obtain such a thing, for they are well guarded. But you, you are stubborn and brave. I think this is something you can do. Within the Crumbling Depths, look to where the tunnels end abruptly in stone. The clusters are found in those passages when they are to be found at all. Should you find one, return to me."}
d[28659]={mo=94000,rep="+250 Hellscream's Reach",o="You have been instructed to kill 12 Alliance Infantry on Tol Barad. You can find the holdouts in The Slagworks, Warden's Vigil and the Ironclad Garrison, here on Tol Barad. *Alliance Infantry (12)",de="We fought hard to capture this island, . We cleared out most of the Alliance filth but I can still smell their foul stench in the air. I need you to investigate the slagworks, warden's vigil and the ironclad garrison. Kill any Alliance that you find. You know what they say, the only good Alliance is a dead Alliance!",g={n="Commander Zanoth",x=0.509,y=0.499,loc="Baradin Hold, Tol Barad"}}
d[28679]={mo=94000,rep="+250 Hellscream's Reach",o="3rd Officer Kronkar has asked you to kill 8 Shipwrecked Sailors at the Cape of Lost Hope. The cape is located due northwest of here, on the beach. *Shipwrecked Sailor (12)",de="We have been having issues with the undead down at the Cape of Lost Hope for a while now. Every time a new ship wrecks, they end up getting more undead to join their ranks. Can you do us a favor and thin out the ranks up there? I know you won't be able to kill them all, but anything you can do will help at this point. Keep an eye out for alliance, we have been getting reports of them ambushing the beach lately.",g={n="3rd Officer Kronkar",x=0.552,y=0.813,loc="Hellscream's Grasp, Tol Barad Peninsula"}}
d[28680]={r={{n="at 85"}},o="You have been asked to recover 6 Barrels of Southsea Rum from the shipwrecks on the Cape of Lost Hope. The cape can be found north of here, along the coast. * Barrel of Southsea Rum (6)",de="Morale is low these days, . We make every effort we can to keep the troops in high spirits but we are running low on our main supply of morale booster... rum. I have been getting reports from our infantry to the south that the shipwrecks on the Cape of Lost Hope still have a good supply of southsea rum in their wrecked hulls. Can you head up there and investigate? Bring back any rum you can find.",g={n="3rd Officer Kronkar",x=0.552,y=0.813,loc="Hellscream's Grasp, Tol Barad Peninsula"}}
d[28695]={r={{n="at max level"}},o="Kill Foreman Wellson at the Wellson Shipyard. The shipyard can be found north of here, on the western coast. *Foreman Wellson slain",de="Foreman Wellson has been a pain in our side since we got here. His shipyard holds a large amount of supplies that would be extremely useful to us... if we could get to them. He keeps a close watch over his minions and makes it very difficult for us to get a foothold on the shipyard. I need you to take out Wellson for good this time. Be careful , we have been receiving reports of dirty Alliance all around the area.",g={n="Private Sarlosk",x=0.558,y=0.785,loc="Hellscream's Grasp, Tol Barad Peninsula"}}
d[28696]={r={{n="at 85"}},o="Destroy 10 Ghastly Supply Boats. *Wellson Supply Boats Destroyed (10)",de="The Wellson Shipyard is constantly receiving supplies from offshore and we need to put a stop to it. They have setup cannons along the docks for defense but if you can make it to them, we can use them to destroy their supply ships. Head down there and see what you can do. Report back to me on your progress.",g={n="Private Sarlosk",x=0.558,y=0.785,loc="Hellscream's Grasp, Tol Barad Peninsula"}}
d[28697]={r={{n="at 85"}},o="Kill 14 ghosts of any type at Largo's Overlook, northeast of the Horde camp. *Largo's Overlook Ghosts Slain (14)",de="See that hill with the towers to the northeast? That's Largo's Overlook and it's not a fun place to set up camp next to. We have been dealing with those spirits and spectres ever since we setup camp. Can you head up there and let them know we don't plan on leaving anytime soon? A few good kills on their ranks should put them in line. Thanks for your help on this, .",g={n="Private Sarlosk",x=0.558,y=0.785,loc="Hellscream's Grasp, Tol Barad Peninsula"}}
d[28697]={r={{n="at 85"}},o="Release the spirits of 6 tortured souls at Forgotten Hill. Souls can be channeled by touching your hands directly to the gravestones. Forgotten Hill is due west of here, past The Restless Front.",de="Many soldiers died on this island . It is only fair that we pay our respects to them in any way that we can. I need you to travel to Forgotten Hill, due west of here and release our brothers in arms' tortured souls away from this place. Do be careful over there, reports of undead have been ongoing in the area.",g={n="Captain Prug",x=0.549,y=0.793,loc="Hellscream's Grasp, Tol Barad Peninsula"}}
d[28700]={mo=165400,rep="+250 Hellscream's Reach",o="Private Sarlosk has asked you to kill Commander Largo at Largo's Overlook. The overlook is just Northeast of the base camp. *Commander Largo slain",de="There is only one way for us to take Largo's Overlook Back. I think you know what we need to do, . Largo is pretty paranoid these days so you should be able to find him on top of the tower, looking for his imaginary navy to finally arrive.",g={n="Private Sarlosk",x=0.558,y=0.785,loc="Hellscream's Grasp, Tol Barad Peninsula"}}
d[28721]={r={{n="1x Tol Barad Commendation"}},mo=165400,o="Escort a Farson Keep Prisoner to safety. The hold is located on the northern tip of the island. *Farson Prisoner Escorted",de="We have sent at least 3 different recon groups to investigate Farson Hold in the last few weeks. Sadly, not one of them has returned back with any info. At this point, all we can hope is that they are being held alive as prisoners. I need you to infiltrate the keep and help get our soldiers back. This won't be easy , but if anyone can help us, it's you.",g={n="Commander Larmash",x=0.536,y=0.806,loc="Hellscream's Grasp, Tol Barad Peninsula"}}
d[28733]={mo=94000,o="Survive 2 Massive Waves of Zombies. * Massive Wave Defeated (2)",de="Even though we beat Warden Stillwater, his zombies still roam the countryside. Look there, another wave is approaching! Help me fight them off, old buddy! Let's go!"}
d[28736]={rep="+250 Ramkahen",o="Board the Confiscated Artillery and use it to kill 100 Schnottz Infantrymen. * Infantrymen Slain x100",de="The remnants of organization persist here on the Maker's Ascent, making the region deadly to any who draw near. There's plenty of ammunition, but without a good spotter, I'm just firing blind. Hop in and give me a hand here. Those soldiers won't know what hit them!",g={n="Weathered Nomad",loc="Uldum"}}
d[28935]={r={{n="Love Token x5"}},mo=165400,o="Kill 5 Crown Technicians and use Snagglebolt's Khorium Bomb to destroy one chemical wagon east of the Tomb of Khartut in Uldum, then return to Detective Snap Snagglebolt in Orgrimmar. * Chemical Wagon Destroyed * Crown Technician slain (5) * Snagglebolt's Khorium Bomb (provided)",de="This ledger is full of locations, and I need you to investigate and take action, pal. This has gone on long enough. Here's an entry I want you to check out: it looks like it's in Uldum, east of the Tomb of Khartut and near the entrance from Tanaris. Get out there and rough 'em up. Oh, and if you see something big and dangerous enough that it needs destroying, toss this bomb at it.",g={n="Detective Snap Snagglebolt",loc="Durotar"}}
d[28935]={r={{n="Love Token x5"}},mo=165400,o="Kill 5 Crown Technicians and use Snagglebolt's Khorium Bomb to destroy one chemical wagon east of the Tomb of Khartut in Uldum, then return to Inspector Snip Snagglebolt in Stormwind. * Chemical Wagon Destroyed * Crown Technician slain (5) * Snagglebolt's Khorium Bomb (provided)",de="This ledger is full of locations, and I need you to investigate and take action, pal. This has gone on long enough. Here's an entry I want you to check out: it looks like it's in the Uldum, just east of the Tomb of Khartut, close to the entrance from Tanaris. Get out there and rough 'em up. Oh, and if you see something big and dangerous enough that it needs destroying, toss this bomb at it.",g={n="Inspector Snip Snagglebolt",loc="Stormwind Gate, Elwynn Forest"}}
d[29035]={r={{n="Winterspring Cub Whisker"}},mo=165400,rep="+1500 Wintersaber Trainers",o="Gather 6 pieces of Shardtooth Meat from any of the Shardtooth bears in Winterspring and feed them to your Winterspring Cub (quest item). *Feed Shardtooth Meat to Cub (6)",de="Your Winterspring cub looks at you and licks its lips. The little cat must be hungry and it's up to you to find a suitable meal for your charge. Rivern Frostwind mentioned keeping some shardtooth bear meat on hand for feeding his wintersaber cubs. Perhaps your cub would enjoy some fresh shardtooth meat of its own. Various kinds of shardtooth bears can be found all over Winterspring.",g={n="Winterspring Cub (quest item)"}}
d[29037]={r={{n="Winterspring Cub Whisker"}},o="Obtain 6 pieces of Smoked Meat from either Winterfall furbolg camp in Winterspring and feed them to your Winterspring Cub (quest item). *Feed Wintersaber Cub Smoked Meat x6",de="Your cub looks at you expectantly. What could it want now? The little cat licks its lips. It must be meal time again! As the cub's surrogate you're responsible for providing meat until it can hunt on its own. But what if you let someone else do the hunting? The Winterfall furbolg of Winterspring usually have a lot of smoked meat on hand in both of their camps. Surely, they wouldn't miss a few pieces and your cub would get to try something new.",g={n="Winterspring Cub (quest item)"}}
d[29038]={r={{n="Winterspring Cub Whisker"}},mo=165400,rep="+1500 Wintersaber Trainers",o="Bring your cub near snow-covered burrows in northern Winterspring 5 times to help it learn how to hunt arctic hares. *Hunting Practice (5)",de="Your Winterspring cub paws playfully at your hands. Without any playmates, the cub has few chances to practice its hunting skills. Perhaps you should take your cub hunting for the small arctic hares that burrow in the snow of northern Winterspring. Bring your cub close to the mounds of snow covering the hare burrows and wait for the cub's instincts to take over.",g={n="Winterspring Cub (quest item)"}}
d[29040]={r={{n="Winterspring Cub Whisker"}},mo=165400,rep="+1500 Wintersaber Trainers",o="Obtain a Tough Yeti Hide from any Ice Thistle Yeti and 5 Wildkin feathers. Combine them to make a Winterspring Cat Toy and use it to play with your Winterspring Cub (quest item). *Try out Winterspring Cat Toy",de="The Winterspring cub plays with a small tuft of fur from a large animal, batting the discarded hair about. While your cub looks like it's enjoying the new game, you wonder if it might get more enjoyment from a proper cat toy. With a little bit of leather from a yeti pelt and some feathers from crazed moonkin, you could make a respectable toy. You'll need a hide from the yeti in the Ice Thistle Hills southeast of Everlook and feathers from the moonkin at the Hidden Grove or Owl Wing Thicket.",g={n="Winterspring Cub (quest item)"}}
d[29101]={r={{n="Mark of the World Tree x1"}},rep="+150 Guardians of Hyjal",o="Punt 5 Children of Tortolla into water. *Child of Tortolla punted into water (5)",de="Baby turtles can be sweet, even if they can be somewhat bitey. But they're so slow with their tiny little legs, they can't escape the fire creatures who are attacking Hyjal! PLEASE save them, ! Pick up the wee turtles and punt them into the water of the Ashen Lake. Don't worry about the kicking, they have hard shells. They also have hard teeth, so don't pick them up by the mouth.",g={n="Mylune",loc="Various"}}
d[29122]={r={{n="Mark of the World Tree x2"}},mo=94000,rep="+250 Guardians of Hyjal",o="Speak with Tooga to summon and kill Nemesis. Stand under Tooga's shell to protect you from Nemesis' Molten Fury. *Nemesis slain",de="Remember that awful fire turtle, Nemesis, from the Firelands? He's dead now (yay!) but echoes of him keep trying to break through to Mount Hyjal. Go to the shores of the Ashen Lake and speak with my friend Tooga. Let him know you're ready to fight an echo of Nemesis, and the turtles will draw him into this world. Then you can hit him! Hard! Hide inside of Tooga's shell if he starts to erupt."}
d[29125]={r={{n="Mark of the World Tree x1"}},rep="+150 Guardians of Hyjal",o="Catch three Spirits of Malorne by walking close to them. *Spirit of Malorne captured x3 *Guardian's Staff (provided)",de="Spirit fragments of Malorne - seen to us mortals as ghostly white deer - still frolic through these forests. While Malorne is no longer with us, these pieces of his spirit may be of use to us. Travel east and walk among the trees. If you are able to get close enough to one of the spirit fragments, it will bestow its power to you. Oh, and take this staff. You may need it later.",g={n="Matoclaw",x=0.19,y=0.37,loc="Various"}}
d[29126]={r={{n="Mark of the World Tree x2"}},mo=94000,rep="+250 Guardians of Hyjal",o="Use the Guardian's Staff to summon and defeat Galenges. *Galenges slain *Guardian's Staff (2) (provided)",de="The portal that opened up to our east is guarded by a powerful flamewaker by the name of Galenges. We will need all of Malorne's help in defeating him. Do you remember the staff that I gave you? Place it in the pile of ash in front of the portal. Then pray that Malorne comes to your aid."}
d[29127]={r={{n="Mark of the World Tree x1"}},mo=94000,rep="+250 Guardians of Hyjal",o="Kill any 6-9 invaders from the Firelands in the Regrowth or Sethria's Roost. *Invader from the Firelands slain (6-9)",de="Of all of our tasks here in Hyjal, the most pressing is simple: destroy these invaders. The very nature of fire is that it is all-consuming. Lower your defense for just a moment and it will destroy everything in sight. Kill any of the fiery invaders you find. Every enemy defeated purchases more time for Hyjal.",g={n="Matoclaw",x=0.19,y=0.37,loc="Various"}}
d[29128]={r={{n="Mark of the World Tree x2"}},mo=188000,rep="+350 Guardians of Hyjal",o="Slay 6 Fiery Behemoths or Seething Pyrelords. *Invader slain at Sethria's Roost x6",de="We need to place pressure on the assault camp at Sethria's Roost. Ragnaros' minions are using this area as a point to push their battlefront beyond the bounds of Hyjal. I'm putting you in charge of a small squad to deal with them. I have selected an elite group of fighters to assist you. Travel to Sethria's Roost. Your compatriots have been instructed to meet you once you arrive. Then put an end to the elementals' assault.",g={n="Captain Soren Moonfall",loc="Sanctuary of Malorne, Mount Hyjal"}}
d[29137]={r={{n="Mark of the World Tree x2"}},mo=94000,rep="+250 Guardians of Hyjal",o="Kill 5 Lava Bursters. *Lava Burster slain (5)",de="Lava worms are bursting through the ground behind our lines, breaking our formations and allowing elementals to slip through. You'll find them scattered throughout our entire front to the north, and upon the Ashen Fields further out. Stomp them back into their holes.",g={n="General Taldris Moonfall",loc="Malfurion's Breach, Molten Front"}}
d[29138]={r={{n="Mark of the World Tree x2"}},mo=94000,rep="+250 Guardians of Hyjal",o="Heal 8 Wounded Hyjal Defenders. *Wounded Hyjal Defender saved x8 *Enchanted Salve (provided)",de="We have warriors out in the field who are falling wounded, and many of our druids are too busy fighting to give them proper aid. I need you to go to the north, towards the Ashen Fields, and tend their wounds at least enough that they can make it back to safety. If you haven't any bandages or healing spells, I had Rayne put together this salve, which should prove sufficient to get them on their feet.",g={n="Captain Irontree",x=0.57,y=0.55,loc="Mount Hyjal; Molten Front"}}
d[29139]={r={{n="Mark of the World Tree x2"}},rep="+250 Guardians of Hyjal",o="Plant 5 Smothervine Seeds in the Ash Piles in the Ashen Fields. *Smothervine planted x5 *Smothervine Seeds (provided)",de="Our warriors are doing everything they can to hold back the elementals, but their numbers are endless. We need to do something to slow down the assault. Find some suitable patches of dirt or ash out on the Ashen Fields to our north and plant these seeds. They will grow deadly vines that may slow down our enemies a bit. It's not much, but every bit helps.",g={n="Rayne Feathersong",loc="Mount Hyjal; Molten Front"}}
d[29141]={r={{n="Mark of the World Tree x2"}},rep="+250 Guardians of Hyjal",o="Kill 3 Molten Behemoths. *Molten Behemoth slain (3)",de="Molten Behemoths have joined the elementals upon the battlefield. They are crushing our front lines. I need you to halt their momentum. You'll find the beasts slow and clumsy. They can easily be outmaneuvered, but they will pack a devastating punch if they hit you. Be nimble, .",g={n="General Taldris Moonfall",loc="Malfurion's Breach, Molten Front"}}
d[29142]={r={{n="Mark of the World Tree x2"}},rep="+250 Guardians of Hyjal",o="Kill 3 Druids of the Flame. *Druid of the Flame slain",de="The Druids of the Flame assault our front line, . These vile creatures have turned their backs on Elune's teachings and worship instead the Fire Lord, Ragnaros. Twisted by his insane power, they desire nothing more than to bury us in ash. We must counter their attack immediately!",g={n="General Taldris Moonfall",loc="Malfurion's Breach, Molten Front"}}
d[29143]={r={{n="Mark of the World Tree x2"}},mo=94000,rep="+250 Guardians of Hyjal",o="Lead a Hyjal Wisp to one of the fire portals in the Ashen Fields, and protect the wisp until it closes the portal. If you lose your wisp, return to Rayne Feathersong at Malfurion's Breach. *Close a Fire Portal",de="The fire elementals are pouring out of portals on the far side of the Ashen Fields. We need someone to close them. Cut off some of their reinforcements. Banishing these kinds of elemental magics is something our wisps are perfectly suited for. One will come with you. Lead it to a portal and keep it alive until it finishes.",g={n="Rayne Feathersong",loc="Mount Hyjal; Molten Front"}}
d[29147]={r={{n="Mark of the World Tree x1"}},rep="+150 Guardians of Hyjal",o="Use your Call the Flock ability to gather 12 Alpine Songbirds, 5 Forest Owls, and 2 Goldwing Hawks. *Alpine Songbird gathered (12) *Forest Owl gathered (5) *Goldwing Hawk gathered (2) *Quill of the Bird-Queen (provided)",de="Today, we have an opportunity to make another assault against one of Ragnaros' greater minions: Millagazor. However, we first need to get some assistance. Use this artifact to invoke the power of Aviana. Once you have done so, travel northwest and gather some of her flock by calling out to them. Once you have done so, we may proceed against Millagazor.",g={n="Matoclaw",x=0.19,y=0.37,loc="Various"}}
d[29148]={r={{n="Mark of the World Tree x2"}},mo=94000,rep="+250 Guardians of Hyjal",o="Use the Quill of the Bird-Queen to summon and defeat Millagazor. *Millagazor slain *Quill of the Bird-Queen (2) (provided)",de="Millagazor is a creature of flame, but in many ways, he is not unlike the birds of this land. As such, Aviana's artifacts may still have the power to summon him. The fiery portal to the west is where you will find him. Use the quill near the portal's entrance, then prepare for a fierce battle."}
d[29159]={r={{n="Mark of the World Tree x2"}},mo=94000,rep="+250 Guardians of Hyjal",o="Kill 8 Cinderweb Spinners or Cinderweb Creepers. *Cinderweb spider slain (8)",de="We've fought hard to secure this area, but our foothold is tenuous. Our scouts report that the area around us is teeming with vicious fire spiders. They are the spawn of the vicious brood widow, Beth'tilac. Help us hold our line by clearing the area of Cinderweb Spinners or Cinderweb Creepers. It will drive her mad to see her children slain.",g={n="Deldren Ravenelm",loc="Forlorn Spire, Molten Front"}}
d[29160]={r={{n="Mark of the World Tree x2"}},mo=165400,rep="+250 Guardians of Hyjal",o="Collect 20 Cinderweb Eggs from the pillars in The Widow's Clutch. *Cinderweb Egg (quest item) (20)",de="We have a real problem on our hands. Not only are the nearby spiders vicious and predatory, their numbers appear to be endless. We need to stop the growth of their army. Cut their heads off in the egg, not on the battlefield. The Cinderweb Spinners' eggs are laid among the stone pillars to the north. Collect 20 eggs and bring them back to me.",g={n="Deldren Ravenelm",loc="Forlorn Spire, Molten Front"}}
d[29161]={r={{n="Mark of the World Tree x1"}},rep="+150 Guardians of Hyjal",o="Climb up trees in the Whistling Grove, grab stranded Hyjal Bear Cubs, and then hurl them at the Soft Target from the top of the tree. This is perfectly safe. *Hyjal Bear Cubs chucked to safety *Inconspicuous Emerald (provided)",de="Oh, raspberries! Just when we had saved the last bear cub from the treetops, the fires returned and scared them again! I don't know if you know this, but baby bears are precious and soft. Go to the Whistling Grove, far to the northwest. Climb the trees, grab the bear cubs, and chuck them - gently! - to the soft target in the center of the grove. Lil' b-b-b-baby bears! Save them, !",g={n="Mylune",loc="Various"}}
d[29162]={r={{n="Mark of the World Tree x2"}},mo=94000,rep="+250 Guardians of Hyjal",o="Use the Emerald of Aessina to summon and kill Pyrachnis. *Pyrachnis slain *Emerald of Aessina (provided)",de="I love all creatures of the forest, even spiders, despite the fact that they are icky. But the spiders from the Firelands are worse than icky. They're burny, and don't belong here. Find the fire portal in the western the Regrowth, and use the gem I gave you earlier to force it open. When a fire spider emerges, step on it! Unless it's big. Then, do something y to it. Oh, and use the gem if spider venom makes you woozy!"}
d[29164]={r={{n="Mark of the World Tree x1"}},rep="+150 Guardians of Hyjal",o="Use the Fang of the Wolf atop the corpses of 10 Firelands invaders within the Regrowth. *Howl atop an invader's corpse x10 *Fang of the Wolf (provided)",de="The wolf ancient, Lo'gosh - or, if you prefer, Goldrinn - has many weapons available to him, but always the most underestimated is his howl. Today, we will use this weapon to summon and defeat Lylagar, one of the lieutenants of flame that lurk within the Firelands. Defeat any of the creatures of flame within the Regrowth, and then use the Fang of the Wolf while standing atop their corpse. Soon, your howl will echo across all of Kalimdor.",g={n="Matoclaw",x=0.19,y=0.37,loc="Various"}}
d[29165]={r={{n="Mark of the World Tree x2"}},rep="+250 Guardians of Hyjal",o="Use the Fang of the Wolf to summon and defeat Lylagar. *Lylagar slain *Fang of the Wolf (2) (provided)",de="The easternmost portal of flame is the domain of Lylagar. Stand before the portal, deliver a challenging howl, and then force the fiery beast to submit."}
d[29166]={r={{n="Mark of the World Tree x1"}},rep="+250 Guardians of Hyjal",o="Obtain 7 Blueroot Vines. *Blueroot Vine (7)",de="One of the biggest dangers that our druids face when fighting within the Firelands is simple dehydration. Our proveditors spend a significant amount of time preparing canteens for the troops on the other side. We do have other methods, however. In the greener thickets to the east, you should still find some blueroot vines which have not yet burned. These plants hold a tremendous amount of water in their roots - and also provide some energy for the weary soldier.",g={n="Matoclaw",x=0.19,y=0.37,loc="Various"}}
d[29177]={mo=78000,rep="+250 Guardians of Hyjal",o="Equip a :Twilight Firelance and fly . Kill 10 Twilight Lancers by flying into them. Press the flap button to flap your mount's wings! *Twilight Lancers slain x10",de="The agents of Twilight continue their assault within this pocket of the Firelands. We must not let our offensive fall! Take wing, and destroy as many of those lancers as you can! Do not forget to pick up and equip your lance first.",g={n="Farden Talonshrike",loc="Firelands Hatchery, Mount Hyjal"}}
d[29179]={r={{n="Mark of the World Tree x2"}},rep="+250 Guardians of Hyjal",o="Kill 8 Charred Soldiers or Charred Vanquishers. *Charred Combatant slain x8",de="The elementals continue to press on us, and I do not expect them to subside any time soon. You'll find them pouring across the Ashen Fields to the north. Thin their ranks.",g={n="General Taldris Moonfall",loc="Malfurion's Breach, Molten Front"}}
d[29189]={r={{n="Mark of the World Tree x2"}},mo=94000,rep="+250 Guardians of Hyjal",o="Free 8 victims out of Cinderweb Cocoons. *Victims freed (8)",de="Some of our scouts have not reported back for duty. We fear they have succumbed to the deadly spiders in the vicinity. Hope may not be lost, however. The spiders often wrap up their live prey in cocoons for later consumption. Go search the pillars to the north for cocooned victims. You may yet be able to save some of our brethren.",g={n="Deldren Ravenelm",loc="Forlorn Spire, Molten Front"}}
d[29205]={r={{n="Mark of the World Tree x2"}},mo=94000,rep="+250 Guardians of Hyjal",o="Protect one of the druids attempting to take the Forlorn Spire. *Druid Assault Group Protected",de="Captain Saynna Stormrunner is launching an attack against the Forlorn Spire. If you head to the northeast, you'll find her at the bottom of the ramp leading up towards that rise. Go there and escort one of her druids to the tower with any forces that she can spare. You'll have quite a fight ahead of you - make sure the druid lives to see the end of it or they'll not be able to seize the tower.",g={n="General Taldris Moonfall",loc="Malfurion's Breach, Molten Front"}}
d[29206]={r={{n="Mark of the World Tree x2"}},rep="+250 Guardians of Hyjal",o="Escort a Windcaller through the Furnace and secure the entrance to the Molten Flow. *Druid of the Talon Windcaller protected",de="Skylord Omnuron and his druids are seeking to push through the Furnace to our northwest. They've been able to fly over the dangers, but they really need someone on the ground to help them secure the territory past the fire... someone like you. If you want to aid the Druids of the Talon, wait for one of Omnuron's Windcallers to start pushing through the fire, stay close to him, and keep him safe from any attackers within the flames.",g={n="General Taldris Moonfall",loc="Malfurion's Breach, Molten Front"}}
d[29210]={r={{n="Mark of the World Tree x2"}},rep="+250 Guardians of Hyjal",o="Find your way to the Igneous Depths, then destroy all 8 of the blue runes within. *Enter the Igneous Depths *All Flame Runes Destroyed",de="Shalis has gone with one of our druids to stop a Druid of the Flame that is performing a summoning ritual in the Igneous Depths, below us. They have been tasked with killing the druid, but I need you to stop the ritual. You'll find the entrance to the cavern east of the Magma Springs. Once inside, you'll see 8 blue runes spread throughout the cavern. You can use these runes to protect you from the fiery creatures, but you need to stamp all of them out to end the ritual. You will need to be swift.",g={n="Marin Bladewing",x=0.294,y=0.26,loc="Various"}}
d[29211]={r={{n="Mark of the World Tree x2"}},mo=94000,rep="+250 Guardians of Hyjal",o="Detonate the Solar Core. *Solar Core detonated",de="The fight has taken us to Fandral's doorstep. His druids are channeling energies of the Firelands into a vessel called the Solar Core. Should this vessel detonate on Azeroth, none of us will have a home to return to. We need to strike at the Solar Core now, while it is still vulnerable. You can find the infernal device to the northeast.",g={n="Marin Bladewing",x=0.294,y=0.26,loc="Various"}}
d[29243]={r={{n="Mark of the World Tree x3"}},rep="+250 Guardians of Hyjal",o="Kill the Lieutenant of Flame. *Lieutenant of Flame slain",de="One of Ragnaros' Lieutenants has shown itself at Ragnaros' Reach. It is time to strike. Captain Sayanna has requested that you be there to help see the fight through. Witherbranch and some others will have joined the battle by the time you arrive. You should make haste to the northwest and find them.",g={n="Shalis Darkhunter",x=0.286,y=0.248,loc="Various"}}
d[29246]={r={{n="Mark of the World Tree x1"}},rep="+250 Guardians of Hyjal",o="Obtain 4 Flame-Wreathed Hearts from Seething Firelords. *Flame-Wreathed Heart (4)",de="The Arch Druid has an immense tolerance for pain. I've treated burn victims that spend twenty-two hours a day screaming in pain, and their burns weren't even half as bad as what Hamuul has suffered. Nevertheless, I can sense that he is in greater discomfort than normal today. Bring me the hearts of the large fire elementals to the southeast. I can use them to prepare a soothing salve for our patient.",g={n="Dorda'en Nightweaver",x=0.27,y=0.62,loc="Sanctuary of Malorne, Mount Hyjal"}}
d[29247]={r={{n="Mark of the World Tree x1"}},mo=71000,rep="+150 Guardians of Hyjal",o="Obtain 4 Sulfur-Laced Wrappings from Fiery Behemoths in Sethria's Roost. *Sulfur-Laced Wrapping (4)",de="We have an ample supply of medical supplies here at the Sanctuary, but we mustn't lose sight of the fact that we are at war. Hamuul isn't the only person who has need of bandages. The fiery behemoths that roam Sethria's Roost wear flame-resistant wrappings that will serve Hamuul as ably as any bandage. Bring me those wrappings, and I will prepare them for use on the Arch Druid.",g={n="Dorda'en Nightweaver",x=0.27,y=0.62,loc="Sanctuary of Malorne, Mount Hyjal"}}
d[29248]={r={{n="Mark of the World Tree x1"}},mo=94000,rep="+250 Guardians of Hyjal",o="Obtain 100 Flamewaker Scales. *Flamewaker Scale x100",de="Having been burned so badly, Arch Druid Hamuul is suffering from edema - swelling of the body's tissues. It takes a great deal of his attendants' effort to keep his swelling down enough for him to breathe. Normally, to reduce this swelling, we make cuts in his flesh, but he is weak, . I cannot cut him today. I need your help. Flamewaker scales will aid with the swelling, but you need a lot of them.",g={n="Dorda'en Nightweaver",x=0.27,y=0.62,loc="Sanctuary of Malorne, Mount Hyjal"}}
d[29263]={mo=165400,rep="+250 Guardians of Hyjal",o="Find the Subterranean Magma Worm's breath bubbles, then defeat it by making it swallow the Bitter Pill. * Subterranean Magma Worm slain * The Bitter Pill (provided)",de="As far as I'm concerned, there's no problem that can't be solved with bombs. And if a bomb doesn't solve your problem on the first try... use a bigger bomb. So there's this big worm that's been eating people near the lava pools up north. Search for breath bubbles to find it. Attack it until it prepares to bite, then place this bomb down in front of it. Then sit back and watch the fireworks. Hmm... there was one other thing I wanted to say... oh yeah! Don't get eaten.",g={n="Ricket",x=0.409,y=0.854,loc="Various"}}
d[29264]={r={{n="Mark of the World Tree x2"}},rep="+250 Guardians of Hyjal",o="Slay 8 Flamewakers within the Molten Flow. *Flamewaker slain (8)",de="Of all Ragnaros' minions, the flamewakers appear to be the most devoted. Most of them dwell within this cave, preparing for another attack. Our foothold may be strong, but we will not tolerate any surprise attacks from these worms. No, we will strike first. Tear them apart, .",g={n="Thisalee Crow",x=0.486,y=0.7584,loc="Various"}}
d[29265]={r={{n="Mark of the World Tree x2"}},rep="+250 Guardians of Hyjal",o="Obtain 5 Luciferns. *Lucifern (5)",de="My fellow druid, Choluna, has asked us to collect any specimens of plant life that we might find here in the Firelands... ...I don't know whose idea it was to bring scholars to a warfront. Nevertheless, you will already be in the cave - killing things - so be on the lookout for anything growing out of the ground.",g={n="Thisalee Crow",x=0.486,y=0.7584,loc="Various"}}
d[29273]={r={{n="Mark of the World Tree x1"}},rep="+250 Guardians of Hyjal",o="Use Tholo's Thermometer to measure the temperature of the three large lava pools on Fireplume Peak. *Northwestern Lava Pool sampled *Northeastern Lava Pool sampled *Central Lava Pool sampled *Tholo's Thermometer (provided)",de="The fire hawks of Fireplume Peak can withstand incredible temperatures. While you'll often find them circling the skies above, they're also known to swim in molten lava. Isn't that right, Anren? We'd like to know just how hot that lava can get. Fireplume Peak has three large lava pools. Use this to measure the temperature of each.",g={n="Tholo Whitehoof",loc="Various"}}
d[29274]={r={{n="Mark of the World Tree x1"}},rep="+250 Guardians of Hyjal",o="Obtain 6 small piles of Houndbone Ash. *Houndbone Ash (6)",de="On the Firelands' largest island, our troops have been having trouble against Shannox, the flamewaker hunter. Not only does he have impeccable aim, but he keeps trained hounds that give our troops no end of trouble. Tholo, in all his wisdom, thinks it would be a good idea to study the biology of these hounds. I, of course, agree with Tholo. You will find several hounds in the Molten Flow, beneath the Furnace. We will need their ashes to study.",g={n="Anren Shadowseeker",x=0.639,y=0.226,loc="Various"}}
d[29275]={r={{n="Mark of the World Tree x1"}},mo=165400,rep="+250 Guardians of Hyjal",o="Obtain a Flame Druid Staff, a Flame Druid Spellbook, a Flame Druid Reagent Pouch, and a Flame Druid Idol. *Flame Druid Staff *Flame Druid Spellbook *Flame Druid Reagent Pouch *Flame Druid Idol",de="The Druids of the Flame... an order of druids that, up until a few weeks ago, Tholo and I had never even heard of. Now, under the leadership of Fandral Staghelm, they threaten our mission's success with their mastery of fire. It would appear that they store some supplies in the Igneous Depths, to the northeast. Perhaps, if we can get some of those supplies, we will have more luck when we take the fight to Fandral.",g={n="Anren Shadowseeker",x=0.639,y=0.226,loc="Various"}}
d[29276]={r={{n="Mark of the World Tree x1"}},mo=165400,rep="+250 Guardians of Hyjal",o="Obtain 8 samples of Flame Venom and 8 samples of Searing Web Fluid. *Flame Venom (8) *Searing Web Fluid (8)",de="The Widow's Clutch, to the northeast, is named after Beth'tilac, the enormous queen of the flame spiders. Her webs and her poison are a nagging threat to our main offensive force. We believe that if we study the flame spiders here on the Molten Front, we can use that information to find success against Beth'tilac. Use whatever methods you can to gather their venom and their web fluid, then return to my trusted friend Anren.",g={n="Tholo Whitehoof",loc="Various"}}
d[29278]={r={{n="Mark of the World Tree x2"}},mo=165400,rep="+250 Guardians of Hyjal",o="Retrieve 10 Obsidium Meteorites. * Obsidium Meteorite (10)",de="Have you seen those fireballs falling out of the sky? I saw one crash in the fields to the north, and the rock that landed was made of pure Living Obsidium! I can use the material to craft ultra-sturdy heat proof armor and weapons for our troops. Can you bring me a lode? Go to the Magma Springs and touch one of the magnetic stones. Just watch where you're standing when the rain of fire hits, and gather up the rocks before they crumble from the impact.",g={n="Ricket",x=0.409,y=0.854,loc="Various"}}
d[29287]={r={{n="Mark of the World Tree x2"}},rep="+250 Guardians of Hyjal",o="Defeat the Fire Hawk Matriarch. *Fire Hawk Matriarch slain",de="Unsurprisingly, their matriarch has taken offense to us taking her young to train for our own uses. It's understandable... and a bit tragic actually. We are very much the villains in this exchange. Now is not the time for such thoughts. These creatures are beings of fire, and on more than one occasion, they've claimed the lives of our kin. With their matriarch angered, the danger has grown immensely. I need someone to quiet her rage, and I fear you may be the most capable.",g={n="Morthis Whisperwing",x=0.802,y=0.65,loc="Various"}}
d[29287]={r={{n="Mark of the World Tree x2"}},rep="+250 Guardians of Hyjal",o="Retrieve a Fire Hawk Egg from the top of Fireplume Peak. *Fire Hawk Egg",de="These fire hawks are beings of fire, but they exhibit much of the same behavior that we've seen in birds back home. It makes me wonder from where they originate. Back to the point - I think we might be able to train them. Domesticate them if you will. Use them against our enemies. I'd like you to retrieve one of their eggs from the top of Fireplume Peak. If you can bring it back to me safely, I will see to the rest.",g={n="Morthis Whisperwing",x=0.802,y=0.65,loc="Various"}}
d[29288]={r={{n="Mark of the World Tree x2"}},rep="+250 Guardians of Hyjal",o="Recover 5 Fire Hawk Hatchlings. *Fire Hawk Hatchling (5)",de="Our scouts are bringing back reports of fire hawk hatchlings all over the peak... their eggs must have hatched very recently. Better yet, it seems that they're extremely docile. I know it may sound a strange and perhaps unsavory request, but if you were able to bring some of those hatchlings back to me, I might be able to train them to aid us in our war efforts. Are you willing?",g={n="Morthis Whisperwing",x=0.802,y=0.65,loc="Various"}}
d[29293]={r={{n="Mark of the World Tree x2"}},rep="+250 Guardians of Hyjal",o="Rescue 5 Injured Druids of the Talon on Fireplume Peak. *Druids of the Talon rescued x5 *Arthorn's Injury Kit (provided)",de="Many of our Storm Crows have gone ahead to scout the peak and attempt to retrieve some of the fire hawk eggs, but to very little success I'm afraid. The thermals make it nearly impossible to fly safely, and the fire hawks aren't exactly friendly either. I need you to head over there and rescue any druids that you can. I've got splints, bandages, burn salves, smelling salts... anything you'll need to get them back on their feet, assuming they're still alive. Please hurry and help anyone you can find.",g={n="Arthorn Windsong",x=0.616,y=0.384,loc="Various"}}
d[29297]={r={{n="2x Mark of the World Tree"}},mo=94000,rep="+250 Guardians of Hyjal",o="Kill 3 Druids of the Flame, while in Fire Crow form, with the Burd Sticker. *Druids of the Flame in Fire Crow form slain (3) *Burd Sticker (provided)",de="Staghelm's druids are putting up a fierce fight at Wildflame Point to the northeast. The druids fly above us in fire crow form, then strike when we least expect it. Worst part is, they know exactly how to stay out of our reach! We would be totally helpless, except Damek lent me his trusty harpoon. He says these weapons will fly straight and true even in this super dense air. Take the dwarf's weapon and shoot some birds out of the sky!",g={n="Ricket",x=0.409,y=0.854,loc="Various"}}
d[29299]={r={{n="Mark of the World Tree"}},rep="+250 Guardians of Hyjal",o="Observe the :Crimson Lasher drinking from 6 Ember Pools. Ember Pools are created by fighting Emberspit Scorpions. *Help the Crimson Lasher Drink from Ember Pools (6)",de="I've been making progress in my research, . Based on what we've witnessed in the local flora, it's quite possible that your Lasher also accepts superheated liquids as a principal source of nutrition. I'd like you to help me with a little experiment. The Emberspit Scorpions that inhabit the Magma Springs to the north spew out burning pools of fire during combat. Take the Lasher and observe his reaction to the scorpions' Ember Pools.",g={n="Avrilla",x=0.198,y=0.377,loc="Grove of Aessina, Mount Hyjal"}}
d[29304]={r={{n="Mark of the World Tree x2"}},mo=94000,rep="+250 Guardians of Hyjal",o="Kill 5 Charhounds or Ancient Charhounds. *Ancient Charhound slain (5)",de="Our forces are falling beneath an unleashed monstrosity - Charhounds from the molten depths. These dogs fear nothing and will not stop until their lust for blood is satisfied. Our forces are barely holding them back. Go join the defenders in the Ashen Fields or in the Molten Flow. Perhaps you can make a dent in their numbers.",g={n="General Taldris Moonfall",loc="Malfurion's Breach, Molten Front"}}
d[29313]={r={{n="+2 Cooking skill"},{n="Epicurean's Award"}},mo=165400,rep="+250 Darnassus",o="Find 8 Buried Kimchi Jars in Darnassus. *Buried Kimchi Jar (8)",de="My family has been making the best kimchi in Darnassus for generations, . The secret is something simple, but it makes all the difference. We bury the jars in the ground until it's ready to serve and my latest batch has just reached that point. You can find the jars buried in earthen mounds all over the city. Would you help me gather them while the contents are just right?",g={n="Alegorn",x=0.5,y=0.366,loc="Various"}}
d[29314]={r={{n="+1 Cooking skill"},{n="Epicurean's Award"}},o="Collect the Blessed Rice Cakes from the Temple of the Moon. *Blessed Rice Cakes",de="The living are not the only ones who require sustenance. One of my duties is to prepare the rice cakes that are left for the ancestors. Normally, my senior apprentice has the honor of taking the cakes to the Temple of the Moon for blessing and then presenting them to the ancestors. Since she is out of the city today, would you mind performing the duty in her place?",g={n="Alegorn",x=0.5,y=0.366,loc="Various"}}
d[29315]={r={{n="+1 Cooking skill"},{n="Epicurean's Award"}},mo=165400,rep="+250 Undercity",o="Obtain 12 Sewer Caps. Deliver the fungus to Eunice Burch in Undercity. * Sewer Cap (12)",de="Some chefs complain that our beloved Undercity doesn't boast the ingredients to create truly fine fare. Such mewling little cretins. Delicious delights abound! Gather some of the rank, slimy Sewer Caps growing in Undercity's northwest sewer line and return them to me.",g={n="Eunice Burch",loc="Trade Quarter, Undercity"}}
d[29316]={r={{n="+1 Cooking Skill"},{n="Epicurean's Award"}},mo=165400,rep="+250 Darnassus",o="Help the inhabitants of the Craftsmen's Terrace and Tradesmen's Terrace make rice flour by pounding the contents of Rice Baskets. *Practice Making Rice Flour (6)",de="There are certain things that everybody needs, from the basic household cook to the master chef. One of the city's most important staples is rice flour. Most families keep at least one basket of rice in their houses and the residents of the Craftsmen's Terrace and Tradesmen's Terrace are no different. I often ask my students to help with the task of pounding rice into flour since it's good practice and an endless task. Why don't you give it a try?",g={n="Alegorn",x=0.5,y=0.366,loc="Various"}}
d[29317]={o="Armand Cromwell wants you to fish up a Severed Abomination Head in Undercity for Master Apothecary Faranell. *Severed Abomination Head",de="There was an... incident... with an orc guard and one of Master Apothecary Faranell's abominations. Apparently, the Kor'kron Overseer chopped its head clean off and kicked it into the slime. Faranell's apprentices searched for hours but they can't find the thing. Care to try fishing it up? I'm sure the old fellow'd be grateful.",g={n="Armand Cromwell",loc="Magic Quarter, Undercity"}}
d[29318]={r={{n="+1 Cooking skill"},{n="+2 Epicurean's Award"}},o="Use the Uncooked Ribs near a stove or campfire to cook them and then use them to feed 5 Darnassus Sentinels. *Feed Ribs to Sentinels (5) *Uncooked Ribs (provided)",de="One of my responsibilities is to feed the sentinels of Darnassus while they're on duty. It's a time-consuming task, but one I'm happy to undertake. It's also a great way to practice your skills. Would you mind helping me with today's meal? Simply take these ribs, cook them near a stove or fire, and distribute them to sentinels throughout the city.",g={n="Alegorn",x=0.5,y=0.366,loc="Various"}}
d[29319]={o="Armand Cromwell in Undercity wants you to bring him 8 Giant Flesh-Eating Tadpoles. *Giant Flesh-Eating Tadpole (8)",de="Some of our apothecaries took to dumping their more volatile waste chemicals into Stillwater Pond and... well, let's just say that no one wants to know how big mutant flesh-eating toads can grow. Would you consider fishing up some giant flesh-eating tadpoles before it gets to that? Just don't try to handle them with your bare hands.",g={n="Armand Cromwell",loc="Magic Quarter, Undercity"}}
d[29320]={o="Dig up a Corpse Worm in the Ruins of Lordaeron courtyard and use it as bait to catch a Corpse-Fed Pike. Corpse-Fed Pike can be fished up in Brightwater Lake, northeast of Undercity. *Corpse-Fed Pike",de="You've fished in Brightwater Lake, yes? The prize catch there is one of the lake's massive corpse-fed pikes. However, they only bite on a very specific type of bait... corpse worms. Search the graves in the courtyard up top and you should find some.",g={n="Armand Cromwell",loc="Magic Quarter, Undercity"}}
d[29321]={rep="+250 Darnassus",o="Gather 10 Teldrassil Clams from the shores near Rut'theran Village. *Teldrassil Clam (10)",de="It seems like everyone I know loves clams, but I can't stand them! They're smelly and slimy, and harvesting them means digging through mud. Give me a fishing pole and some bait any day. Still, I want to surprise my brother with a bucket of fresh clams. I'd reward you if you were willing to gather those clams for me. Just go through the portal to Rut'theran Village and look for the clams in the shallows near the shore.",g={n="Astaia",x=0.49,y=0.61,loc="Various"}}
d[29322]={o="Collect 10 Squirming Slime Molds. Deliver them to Armand Cromwell in Undercity. *Squirming Slime Mold (10)",de="It takes a special sort of fisherman to reap the bounty of Undercity's burbling slime troughs. Think you can handle gathering some of the squirming, sentient slime mold slithering about down there? You can try to fish them up, but they're wily; you might be better off just diving into the ooze and grabbing them. Remember, they're only useful alive and intact... who'd want to eat a dead slime mold?! Disgusting.",g={n="Armand Cromwell",loc="Magic Quarter, Undercity"}}
d[29323]={rep="+250 Darnassus",o="Catch 5 Lake Whitefish by fishing in Darnassus. * Lake Whitefish (5)",de="We've used up most of our food stores in taking care of refugees and feeding those whose homes and livelihoods were destroyed. If we don't replenish our stores, we'll all be in danger next time there's a bad storm or a Horde invasion. Perhaps you'd be willing to help me build up our stock of lake whitefish. You can catch it anywhere in Darnassus, and once it's dried, it'll keep until it's needed."}
d[29324]={rep="+250 Darnassus",o="Retrieve Aquinne's Moon Pendant from the belly of a Giant Catfish. You should be able to catch them anywhere you can fish in Darnassus. * Aquinne's Moon Pendant (1)",de="Have you met Sister Aquinne? She and I grew up together in Dolanaar, and she recently came to the city to study at the Temple of the Moon. We decided to go for a boat ride, but the clumsy oarsman managed to capsize the craft! When we got back to the shore, Aquinne's moon pendant was missing. The lakes in Darnassus are full of giant catfish who will gobble up anything shiny! I've been catching them nonstop, hoping to find the one with her pendant. I don't suppose you want to help?"}
d[29325]={r={{n="+2 Fishing Skill"},{n="Bag of Shiny Things"}},mo=165400,rep="+250 Darnassus",o="Gather 6 Baby Octopi from the shallow water near Rut'theran Village. *Baby Octopus (item) (6)",de="Have you ever eaten octopus meat? It takes some getting used to, but it's my favorite! I even know some people who like to eat the whole thing while it's alive! I don't plan on trying that anytime soon, but I am out of fresh octopi at the moment. Will you help me gather some more? They live in the shallow water off the shore near Rut'theran Village.",g={n="Astaia",x=0.49,y=0.61,loc="Various"}}
d[29332]={r={{n="+1 Cooking skill"},{n="Epicurean's Award"}},mo=165400,rep="+250 Undercity",o="Obtain 10 Stillwater Lilies. Deliver the plants to Eunice Burch in Undercity. * Stillwater Lily (10)",de="The lilies that grow around Stillwater Pond can be rendered down into a delightful broth. Well... by \"delightful,\" I mean \"won't immediately sicken any orc who drinks it.\" Why don't you go gather some for me, hmmm? Just watch out for the giant flesh-eating tadpoles.",g={n="Eunice Burch",loc="Trade Quarter, Undercity"}}
d[29333]={r={{n="+2 Cooking skill"},{n="Epicurean's Award"}},mo=165400,rep="+250 Undercity",o="Collect 8 Brightwater Snails. Deliver them to Eunice Burch in Undercity. * Brightwater Snail (item) (5)",de="The orc guards are always grumbling about bland and moldering Undercity fare - as if it's OUR fault they can't get by on a diet of mushrooms and old corpses - so I think it's time they learn just the sort of exotic delights we can cook up when we've a mind to. Gather some of the freshwater snails ambling about beneath Brightwater Lake and I'll show them what a true culinary master can create.",g={n="Eunice Burch",loc="Trade Quarter, Undercity"}}
d[29334]={r={{n="+1 Cooking skill"},{n="2x Epicurean's Award"}},mo=165400,rep="+250 Undercity",o="Obtain 20 Plump Cockroaches. Deliver the insects to Chef Audrey in Undercity. * Plump Cockroaches (20)",de="For all the grousing those Kor'kron Overseers do about Undercity food, there's ONE thing they'll eat in spades: My sister Audrey's Thrice-Spiced Crunchy Stew. Its popularity means she's always running low on ingredients. Could you gather some for her at the coach she sells them from? You'll find traps all over the city; just take their contents to Audrey and she'll handle the rest!",g={n="Eunice Burch",loc="Trade Quarter, Undercity"}}
d[29342]={r={{n="Bag of Shiny Things"}},rep="+250 Ironforge",o="Catch 5 Arctic Char by fishing in Helm's Bed Lake in Dun Morogh. *Arctic Char (5)",de="The best tastin' fish live in the cold waters o' Dun Morogh, , an' don't let anyone else tell ye otherwise! Me favorite, an' the most popular one in Ironforge is the arctic char, which only comes from our ancestral lands. I like tae think o' it as Ironforge's gift t' the world! Why don't ye try yer hand at catchin' a few yerself? The best place tae find 'em is down in Helm's Bed Lake, in the southeastern end o' Dun Morogh.",g={n="Grimnur Stonebrand",x=0.481,y=0.075,loc="Forlorn Cavern, Ironforge"}}
d[29343]={rep="+250 Ironforge",o="Catch a Young Ironjaw in Ironforge's Forlorn Cavern and display it in the Library near the Empty Plaque. *Put Young Ironjaw on Display",de="thumb|The exhibited young Ironjaw I'm sure by now ye've heard the tale o' :Old Ironjaw, the most famous and elusive fish in the waters o' Ironforge's Forlorn Cavern. Well in his many years, he's been responsible for the rise o' many young ironjaws. Don't let the name fool ye, , these young'uns are every bit as clever as their dad, but somewhat lackin' in experience. With skill an' patience, ye could probably catch one an' when ye do, bring it to the museum in Ironforge's Library an' put it on display fer all to see!",g={n="Grimnur Stonebrand",x=0.481,y=0.075,loc="Forlorn Cavern, Ironforge"}}
d[29344]={r={{n="Bag of Shiny Things"}},rep="+250 Ironforge",o="Catch 3 Blind Minnows in the pool in the Forlorn Cavern and feed them to Squrky. *Feed Squrky (3)",de="Hae I introduced ye tae me pet, Squrky? I'm teachin' him tae fish all proper-like. Fer now, I've been feedin' him minnows fished from the pool in this cavern. Maybe ye'd like tae give it a try? Just cast yer lure in the pool over there and feed Squrky any minnows ye happen tae fish up. He'll love ye ferever!",g={n="Grimnur Stonebrand",x=0.481,y=0.075,loc="Forlorn Cavern, Ironforge"}}
d[29345]={mo=94000,rep="+250 Thunder Bluff",o="Kah Mistrunner in Thunder Bluff wants 8 Azshara Snakehead fish from the Thunder Bluff pond. *Azshara Snakehead (8)",de="A well-meaning goblin visitor introduced Azshara snakeheads to our waters and now they're overrunning the pond. Please, if you can catch some of these voracious predatory fish before they eat every smallfish and mud snapper in Thunder Bluff, I'd be terribly grateful."}
d[29346]={mo=94000,rep="+250 Thunder Bluff",o="Fish up a Blind Cavefish from the Pools of Vision in Thunder Bluff. Once you catch a cavefish, fillet it and check if it swallowed the ring. *Poshken's Ring",de="One of the Forsaken from the Pools of Vision came to me and said he'd lost his ring to a blind cavefish in the waters there. Or perhaps it was his finger. It was hard to tell; his jaw did not move and his Orcish was no better than mine. In any case, I thought it would be a kind gesture towards our unusual visitors to catch and gut cavefish until the ring - or finger - was found. Would you help?"}
d[29347]={rep="+250 Ironforge",o="Use Grimnur's Bait on yourself, then jump into Helm's Bed Lake in Dun Morogh. * Catch Cold Water Crayfish * Take Crayfish to Cook Ghilm * Grimnur's Bait (provided)",de="If ye've ever fished fer crayfish, ye know they respond best to live bait, an' the more bait, the better. Would ye like to test my new bait? Simply smear this on yerself an' hop into Helm's Bed Lake in eastern Dun Morogh. After ye've got the catch, take it to me friend, Cook Ghilm at Gol'Bolar Quarry, west of the lake. He's an expert at cookin' those oversized bugs!",g={n="Grimnur Stonebrand",x=0.481,y=0.075,loc="Forlorn Cavern, Ironforge"}}
d[29348]={mo=94000,rep="+250 Thunder Bluff",o="Kah Mistrunner in Thunder Bluff wants 2 Randy Smallfish and 2 Amorous Mud Snappers from Stonebull Lake in Mulgore. *Randy Smallfish (2) *Amorous Mud Snapper (2)",de="Thunder Bluff's fishing pond is being overrun with voracious Azshara snakeheads; there are hardly any smallfish or mud snappers left. We already have fishers trying to kill as many snakeheads as they can, but can you assist us in our restocking efforts? If you could gather some fish from Stonebull Lake and bring them here to Thunder Bluff, I would be very grateful.",g={n="Kah Mistrunner",x=0.56,y=0.46,loc="Thunder Bluff"}}
d[29349]={mo=94000,rep="+250 Thunder Bluff",o="Kah Mistrunner in Thunder Bluff wants 10 Stonebull Crayfish from Stonebull Lake in Mulgore. *Stonebull Crayfish (10)",de="One of the great delicacies of Mulgore is the crayfish that dwell in our lakes and streams. They are particularly popular during weddings or the celebration of a birth. Would you help me catch some of these crafty crustaceans for the cooking pots of Thunder Bluff? You can fish them up from Stonebull Lake, or simply dive in and grab them."}
d[29350]={rep="+250 Ironforge",o="Use the Bait-o-Matic Blueprint with 5 Shiny Baubles, a Hair Trigger, and 3 Rat Traps to create the Gnomish-Bait-o-Matic. * Gnomish Bait-o-Matic * Bait-o-Matic Blueprints (provided)",de="One o' the gnomish engineerin' trainers gave me a blueprint fer a fancy lure he says'll help me catch fish faster and keep 'em from gettin' away. The whole thing sounds a mite silly if ye ask me, but I'll try anythin' once. Here are the blueprints. Ye're going to need shiny baubles, which ye can buy from my assistant inside the buildin', a hair trigger ye can buy from an engineerin' supplier in Tinker Town, and a few rat traps from the Deeprun Tram.",g={n="Grimnur Stonebrand",x=0.481,y=0.075,loc="Forlorn Cavern, Ironforge"}}
d[29351]={r={{n="+1 Cooking Skill"},{n="Epicurean's Award"}},mo=165400,rep="+250 Ironforge",o="Distribute the Ironforge Rations to 6 Ironforge Guards. * Ironforge Guards Fed (6)",de="The guards who defend Ironforge put their lives on the line against our many enemies, and it's up to us to take care of them. Today, their rations consist of two dwarven favorites, haggis and Ironforge pale ale. Would ye be so kind as to help me distribute them? That way, everyone gets his food in a timely manner and we can move on to other tasks.",g={n="Daryl Riknussun",x=0.6,y=0.36,loc="Great Forge, Ironforge"}}
d[29352]={r={{n="+1 Cooking Skill"},{n="Epicurean's Award"}},mo=165400,rep="+250 Ironforge",o="Collect 6 Dun Morogh Chickens near the entrance to Ironforge. *Dun Morogh Chicken (item) (6)",de="Oh, no, , this is going to be a disaster if we don't find some chicken soon... Ye just cannae make cock-a-leekie soup without the chicken! It's not possible! There's still time to make the soup and broth if ye can find some fresh chicken. Will ye help me? There are usually a few chickens running around outside the front entrance ot the city. If ye can get yer hands on, say, six o' them, that should save me soup.",g={n="Daryl Riknussun",x=0.6,y=0.36,loc="Great Forge, Ironforge"}}
d[29353]={r={{n="+1 Cooking Skill"},{n="+2 Epicurean's Award"}},mo=165400,rep="+250 Ironforge",o="Obtain a Bag o' Sheep Innards, 5 packets of Mild Spices, and 4 Sacks of Oatmeal. *Bag o' Sheep Innards *Sack of Oatmeal (4) *Mild Spices (5)",de="The haggis must flow. Aye, it's a figure o' speech, for haggis'll ne'er flow! Ye dinnae want to know what'll happen if the people o' Ironforge don't get their haggis. I'm working on the next batch, but I'm still missing a couple of ingredients. Sognar Cliffbeard is the meat vendor in the Military Ward, an' he'll sell you the big bag o' sheep innards I need. Ye can buy mild spices from any cooking supplier and we can find sacks o' oatmeal in any inn or among the supplies in the city.",g={n="Daryl Riknussun",x=0.6,y=0.36,loc="Great Forge, Ironforge"}}
d[29354]={mo=94000,rep="+250 Thunder Bluff",o="Nahari Cloudchaser in Thunder Bluff wants 20 Shiny Stones from around the central rise's base. *Shiny Stone (20)",de="One of a fisher's most simple and effective tools is the shiny bauble; affixed to a line, even the most novice angler has a chance at a catch. With all the fishing going on of late, though, Thunder Bluff is in woefully short supply! Might I ask you to collect shiny stones from around the base of the central rise? Bring them to Nahari Cloudchaser so that she might craft more shiny baubles with them."}
d[29355]={r={{n="+1 Cooking Skill"},{n="Epicurean's Award"}},mo=165400,rep="+250 Ironforge",o="Make or obtain 10 slices of Spice Bread. * Spice Bread (10)",de="It might seem like a basic thing, , but spice bread is a longtime favorite in Ironforge. Some days, I have trouble keeping up! Would ye like to cook some to practice yer skills an' help meet the demand? Ye can buy all the ingredients ye'll need from me brother, Emrul Riknussun, who is downstairs.",g={n="Daryl Riknussun",x=0.6,y=0.36,loc="Great Forge, Ironforge"}}
d[29356]={r={{n="+2 Cooking Skill"},{n="Epicurean's Award"}},mo=165400,rep="+250 Ironforge",o="Pick up the Cask of Drugan's IPA outside the brewery in Kharanos and run it back to Ironforge. *Deliver Cask of Drugan's IPA *Cask of Drugan's IPA",de="My stocks o' IPA, that's Ironforge Pale Ale for ye novices, are gettin' low. Luckily, the brewery isn't too far away an' they should have a new cask o' Drugan's IPA waitin' fer us. That Drugan's a genius of a brewer, I tell ye. I won't be able to get down to Kharanos meself today, but perhaps ye can dash down there, pick up the new cask an' run it back 'ere? What d'ye say?",g={n="Daryl Riknussun",x=0.6,y=0.36,loc="Great Forge, Ironforge"}}
d[29357]={r={{n="+1 Cooking skill"},{n="Epicurean's Award"}},mo=165400,rep="+250 Darnassus",o="Make or obtain 10 slices of Spice Bread. * Spice Bread (10)",de="Isn't it amazing how something as simple as spice bread is used every day in Darnassus? When I'm not seeing to my other responsibilities, I like to bake spice bread to hone my skills as a cook and practice my technique. Why don't you give it a try? You should be able to get your ingredients here in the shop. No matter how much we make, it never goes to waste. Bring me your loaves when you're done and I'll have someone share them with our friends, the Gilneans.",g={n="Alegorn",x=0.5,y=0.366,loc="Various"}}
d[29358]={r={{n="Epicurean's Award"},{n="+1 Cooking Skill"}},mo=94000,rep="+250 Thunder Bluff",o="Obtain 30 Pine Nuts by toasting Mulgore Pine Cones from Thunder Bluff. Deliver the nuts to Aska Mistrunner in Thunder Bluff. * Pine Nut (30)",de="The Shu'halo use pine nuts in so MANY dishes: meat, fish, vegetables, even baked into breads or sprinkled over sweet pastries. The Earth Mother has blessed us in that the very BEST pine nuts come from the trees upon these very mesas. Simply gather pine cones and toast them over a cooking fire to release the nuts within. Would you please be so kind as to gather some? There are hardly ever enough to go around...",g={n="Aska Mistrunner",x=0.51,y=0.53,loc="Thunder Bluff"}}
d[29359]={rep="+250 Darnassus",o="Catch 8 Kaldorei Herring by fishing in Rut'theran Village. * Kaldorei Herring (8)",de="Herring is one of the most sought-after fish in Darnassus, but not just any herring. The Kaldorei herring is native only to the waters surrounding Teldrassil. I try to keep a good supply of it because it's so versatile! I just finished smoking a batch of it, so I need to rebuild my stocks. Would you mind helping me? You can catch Kaldorei herringby fishing in Rut'theran Village."}
d[29360]={r={{n="+1 Cooking skill"},{n="Epicurean's Award"}},mo=165400,rep="+250 Undercity",o="Obtain 25 Bloated Flies from the \"meat\" near the Meat Wagons. Then return to Eunice Burch in Undercity. * Bloated Fly (25)",de="It's not always about making food for the orcs, . This time, it's about making food for what will hopefully be their replacements. We need to start small, we need to catch flies. Flies love rotting meat, and we love rotting meat... as projectile weapons! Check out the Meat Wagons for any extra bits of meat. Where you find the meat, you'll find the flies. Bring me 25 bloated flies, and then I can start on the next stage of our cooking plan.",g={n="Eunice Burch",loc="Trade Quarter, Undercity"}}
d[29361]={o="Use the :Alliance Decoy Kit to summon the Moat Monster in the Ruins of Lordaeron. Then use the Bloated Frogs to feed the monster. *Feed Bloated Frogs to the Moat Monster (10) *Moat Monster Feeding Kit (provided)",de="Sometimes fishing means throwing something back, . We've been overfeeding these frogs for just that occasion. We've fed these frogs, bloated spiders, that were fed bloated flies, and now, we are going to feed a real monster. The moat above, in the Ruins of Lordaeron, is home to our very own Moat Monster. Today is feeding day. But we must train it as well. In this bag, you will find a decoy kit and some Bloated Frogs. Use the decoy kit, then toss the frogs to the monster when it appears.",g={n="Armand Cromwell",loc="Magic Quarter, Undercity"}}
d[29362]={r={{n="+1 Cooking Skill"}},mo=94000,rep="+250 Thunder Bluff",o="Gather 6 \"Magic\" Mushrooms from the Pools of Vision in Thunder Bluff. Deliver them to Aska Mistrunner in Thunder Bluff. * \"Magic\" Mushroom (6)",de="You know of the Pools of Vision, yes? There is a sort of mushroom that grows there... not the tough, rank fungi that dominates the place, but smaller, more delicate caps that grow beneath them. They are rare and quite delicious, adding a flavor to meat dishes that one might even call magical. ...what? No, really. They just taste good. That's it.",g={n="Aska Mistrunner",x=0.51,y=0.53,loc="Thunder Bluff"}}
d[29363]={r={{n="Epicurean's Award"},{n="+1 Cooking Skill"}},mo=94000,rep="+250 Thunder Bluff",o="Use Mulgore Spices with Spice Bread to create 5 Fresh Mulgore Spice Bread (you may make your own Spice Bread or use someone else's). Deliver the bread to Aska Mistrunner in Thunder Bluff. *Fresh Mulgore Spice Bread (5) *Mulgore Spices (provided)",de="I am often asked, \"Aska, who is making all this Mulgore spice bread?!\" It is a reasonable question. Our fine and noble bread is traded in countless settlements in the most far-away lands, even by our staunchest foes. IT'S JUST THAT GOOD. And the answer...? It is \"YOU.\" Please take this packet of Mulgore spices and use it to turn bland, boring spice bread into MULGORE spice bread!",g={n="Aska Mistrunner",x=0.51,y=0.53,loc="Thunder Bluff"}}
d[29365]={r={{n="Epicurean's Award"},{n="+2 Cooking Skill"}},mo=94000,rep="+250 Thunder Bluff",o="Obtain four \"perfect portions\" from merchant stalls around Thunder Bluff. Deliver the ingredients to Aska Mistrunner in Thunder Bluff. * Succulent Sweet Potatoes * Savory Spices * Fresh-Caught Fish * Fresh-Hunted Fowl",de="Even the novice cook knows that a great dish begins with great ingredients. I have standing orders with merchants throughout Thunder Bluff, but I'd like to see how well you do at selecting the very best of what they have to offer. Please make the rounds and gather perfect portions of meat, fish, vegetables and herbs from local merchant stalls.",g={n="Aska Mistrunner",x=0.51,y=0.53,loc="Thunder Bluff"}}
d[30006]={mo=198450,rep="+250 August Celestials",o="thumb|Final Doubt. thumb|Lingering Doubt. Kill 15 sha invaders. *Sha invaders slain (15)",de="Despite our best efforts, the sha broke the seals around the main temple. If we cannot hold them back here, their darkness will spread to the rest of the Jade Forest. We need your help immediately. Kill any sha creatures that you see. They should not be difficult to find",g={n="Elder Sage Tai-Feng",loc="Jade Temple Grounds, Jade Forest"}}
d[30063]={mo=198450,rep="+250 August Celestials",o="Collect 8 Masks of Doubt. *Mask of Doubt (quest item) (8)",de="The sha may seem unstoppable, but this is not true. Their masks seem to be the source of their power. When a sha and its mask are separated, the creature's essence is banished back to its own realm. Bring me intact masks, for I wish to study them further. Do be careful. I'm sure the sha will not part with them easily.",g={n="Elder Sage Storm-Sing",loc="Jade Temple Grounds, Jade Forest"}}
d[30064]={mo=198450,rep="+250 August Celestials",o="Collect 6 Ancient Sutras. *Ancient Sutra (6)",de="My adepts had to abandon their studies when the sha invasion began. Unfortunately, they left their books scattered around the temple grounds. These priceless works of knowledge must be saved! The sutras can be found near the Training Pit and the Adept's Ring to the northeast.",g={n="Elder Sage Storm-Sing",loc="Jade Temple Grounds, Jade Forest"}}
d[30065]={mo=198450,rep="+250 August Celestials",o="Collect 8 Defender's Arrows. *Defender's Arrow (8)",de="Our war supplies grow low, but especially needed are additional arrows. Our serpent riders are skilled marksmen, but they can do little without ammunition. We need someone to brave the battlefields and retrieve any undamaged arrows to refill our stores. Every arrow you retrieve will be used wisely.",g={n="Elder Sage Tai-Feng",loc="Jade Temple Grounds, Jade Forest"}}
d[30066]={mo=198450,rep="+250 August Celestials",o="thumb|Yu'lon Guardian. thumb|Yu'lon Adept. Deliver Ancient Mantras to 6 Yu'lon Guardians or Yu'lon Adepts. *Ancient Mantras delivered x8 *Stack of Mantras (provided)",de="Our temple defenders have battled relentlessly for hours. No doubt they grow tired. I will give you mantras to deliver to our fighters. Do not be fooled by these pieces of paper. These ancient scriptures hold words of untold power.",g={n="Elder Sage Tai-Feng",loc="Jade Temple Grounds, Jade Forest"}}
d[30067]={mo=198450,rep="+350 August Celestials",o="Defeat the Shadow of Doubt. *Shadow of Doubt slain",de="A terrible manifestation of the sha has appeared to the south. It is trying to destroy an ancient relic, the Bell of a Thousand Whispers. This bell has never been rung in the temple's history, for it is rumored to be an ancient instrument of power. Please go and defeat this demon where it stands! We must save this relic!",g={n="Elder Sage Tai-Feng",loc="Jade Temple Grounds, Jade Forest"}}
d[30068]={mo=198450,rep="+350 August Celestials",o="Fly your War Serpent near Pure Water Springs, then douse 6 Void Flames with the water carried in its mouth. *Void Flames doused (6)",de="Do you see the violent black and white flames erupting all around the temple? The greater our doubt, the stronger they rage. Unchecked, they will devour the entire temple. We have but one hope. Take flight on one of our war serpents. Fly it near the pure springs of water, and then douse the fires with water from the pools.",g={n="Elder Sage Tai-Feng",loc="Jade Temple Grounds, Jade Forest"}}
d[30146]={mo=198450,rep="+125 Order of the Cloud Serpent",o="Fish 10 Sugar Minnow from any fresh or salt water in Pandaria. *Sugar Minnow (10)",de="Cloud serpents love to eat, and one of their favorite treats is the sugar minnow. These fish can be found in salt or fresh water anywhere in Pandaria. I trust you have some skill in fishing, and your own fishing pole to catch them? Bring me some a fresh catch and I'm sure the hungry beasts around here will be very grateful.",g={n="Jenova Longeye",loc="Arboretum, The Jade Forest"}}
d[30147]={mo=198450,rep="+125 Order of the Cloud Serpent",o="Visit archaeology dig sites around Pandaria and use your survey ability to retrieve 6 Serpentrider Relics. *Serpentrider Relic (6)",de="The Order of the Cloud Serpent's history stretches back thousands of years, and although we have tried to preserve the old ways, there are ancient techniques that have been lost over time. You can help us recover some of this knowledge by searching Pandaria's dig sites for clues to our past. Use your archaeology skill to survey around Pandaria and bring me whatever you find.",g={n="Jenova Longeye",loc="Arboretum, The Jade Forest"}}
d[30148]={mo=198450,rep="+125 Order of the Cloud Serpent",o="Use Windwool Bandages or Heavy Windwool Bandages to heal 8 Injured Hatchlings at Windward Isle. *Injured Hatchlings bandaged (8)",de="Many of the baby hatchlings at Windward Isle have been injured as a result of all the fighting. I have been told that you may be skilled in the art of first aid. Please go northeast and use some of your best bandages to save the injured hatchlings.",g={n="Jenova Longeye",loc="Arboretum, The Jade Forest"}}
d[30149]={mo=198450,rep="+125 Order of the Cloud Serpent",o="Collect 5 Fish Cakes. *Fish Cake (5)",de="I have heard that you know a thing or two about cooking. As it so happens, serpents love to eat Fish Cakes. If you use your culinary skills and bring me 5 of these dishes, the cloud serpents around here will be very happy.",g={n="Jenova Longeye",loc="Arboretum, The Jade Forest"}}
d[30150]={mo=198450,rep="+450 Order of the Cloud Serpent",o="thumb|Honeykeeper. Collect 30 Honeycomb from Angry Honeykeepers in The Arboretum. *Honeycomb (30)",de="From the cloud serpent's behavior, you have a hunch that it wants a sweet treat. The fragrant trees in The Arboretum are home to many honey hives. It will be a simple matter to collect combs from the nearby honeykeepers.",g={n="Your Hatchling",loc="The Arboretum, Jade Forest"}}
d[30151]={mo=198450,rep="+450 Order of the Cloud Serpent",o="Use the Bouncy Ball. Then, catch and return the ball to your hatchling 8 times. *Balls caught (8) *Bouncy Ball (provided)",de="You have a feeling the serpent is tired of being cooped up all day. How about playing a little game of catch?",g={n="Your Hatchling",loc="The Arboretum, Jade Forest"}}
d[30152]={r={{n="Winner's Reward"}},mo=198450,rep="+600 Order of the Cloud Serpent",o="Complete the Sky Race by flying through 10 checkpoints, then passing underneath the Finish Line at The Arboretum. *Checkpoints passed (10) *Pass underneath the Finish Line",de="The time for the great race is upon us! Traverse the course among the spires and pass through the checkered flags on each of the 10 balloon checkpoints. Make sure to pass underneath the finish line when you are done. The competition will be fierce, but I wish you luck. Speak to me when you are ready to begin.",g={n="Instructor Windblade",loc="Arboretum, Jade Forest"}}
d[30154]={mo=198450,rep="+450 Order of the Cloud Serpent",o="Collect 5 Tiger Flanks. *Tiger Flank (5)",de="Uh-oh, looks like someone is in a bad mood today! Luckily, you know just the thing that will cheer up the little beast. Cloud serpents love the taste of tiger meat, but the tender flanks can be... challenging... to acquire. Luckily, you recall there are some fat, juicy tigers to the northwest, on Windward Isle. Sure, you might suffer some scratches and a little mauling, but it's all worth it for your serpent, right?",g={n="Your Hatchling",loc="The Arboretum, Jade Forest"}}
d[30155]={mo=198450,rep="+450 Order of the Cloud Serpent",o="Kill 8 Slitherscale Rippers or Slitherscale Eggdrinkers. *Slitherscale saurok slain (8)",de="The situation at the islands remains dire, . The Slitherscale saurok have not responded to our attempts at peace, so only one option remains. In order to protect the wild cloud serpents, we must rid the island of their presence. Only then can the cloud serpents be left to live in peace.",g={n="Instructor Skythorn",loc="Arboretum, Jade Forest"}}
d[30156]={mo=198450,rep="+450 Order of the Cloud Serpent",o="Collect 3 Saltback Meat and feed them to your hatchling companion. *Hatchling fed (3)",de="Ouch! It seems, without a doubt, that the little beast is hungry. You recall that some meaty-looking turtles can be found on the wild cloud serpent island to the northeast. Perhaps some turtle meat will fill the hatchling's voracious appetite.",g={n="Your Hatchling",loc="The Arboretum, Jade Forest"}}
d[30157]={mo=198450,rep="+450 Order of the Cloud Serpent",o="Leash and return 6 Windward Hatchlings to their nests. *Windward Hatchlings returned x6 *Silken Rope (provided)",de="Oh, thank goodness, another cloud serpent trainer! I just received word that the wild hatchlings at Windward Isle to the northeast are in serious trouble! While the adults fight those terrible saurok, who is watching the cute little babies? No one, that's who! WE HAVE TO SAVE THEM! I'm sending every trainer I can find to go and help. If you aren't too busy, can you make sure the hatchlings are safely delivered back to their mothers' nests?",g={n="Suchi the Sweet",loc="Arboretum, Jade Forest"}}
d[30158]={mo=198450,rep="+450 Order of the Cloud Serpent",o="thumb|Slitherscale harpoon rack. Collect 5 Slitherscale Harpoons. *Slitherscale Harpoon (5)",de="If we are to stop the poachers, we need to take more aggressive action. If we can remove the enemies' primary tools for killing and capturing serpents, we may be able to stop their operation altogether. I need you to go into their territory on the eastern end of Windward Isle and steal their weapons. A cat without claws cannot strike.",g={n="Instructor Skythorn",loc="Arboretum, Jade Forest"}}
d[30159]={mo=198450,rep="+450 Order of the Cloud Serpent",o="Collect 8 Stolen Eggs. *Stolen Egg x8",de="Oh no! We must stop them! , is it? The Order needs your help! Do you know what those horrible Slitherscale saurok are doing? They have the audacity to steal cloud serpent eggs straight from the matriarch's nests! While the cloud serpents become ever rarer, those brutes are... are... ...they're eat their eggs for dinner! It's horrible! Go to Windward Isle to the northeast and recover any unbroken eggs that you can. As students of the Order, it's our duty!",g={n="Suchi the Sweet",loc="Arboretum, Jade Forest"}}
d[30190]={mo=198450,rep="+100 Golden Lotus",o="thumb|Slateskin Troublemaker. Kill 8 Slateskin Troublemakers. *Slateskin Troublemaker slain (8)",de="Sprites again! I hate these things. We need to stop them before they hurt someone or burn down half of the village! If you see any of the pests, please deal with them!",g={n="Mayor Shiyo",loc="Emperor's Approach, Vale of Eternal Blossoms"}}
d[30191]={mo=198450,rep="+100 Golden Lotus",o="thumb|Stolen Mistfall Keg. thumb|Slateskin Troublemaker. Recover 10 Stolen Mistfall Kegs. *Stolen Mistfall Keg (10)",de="Someone left some beer out up on the southern rise and now the sprites have developed a taste for our brew. They've been sneaking into town all morning, stealing whatever kegs they find. Bring back what you can. A pandaren worker without brew is just... it won't be very productive. We need the men in good spirits.",g={n="Mayor Shiyo",loc="Emperor's Approach, Vale of Eternal Blossoms"}}
d[30192]={mo=198450,rep="+100 Golden Lotus",o="Put out 30 Brazier Fires. *Put out Brazier Fires (30)",de="I don't know if you noticed, but my town is burning... The sprites have started kicking the braziers! They're going to set fire to the whole town! Please help us! Stamp out any fires you see!",g={n="Mayor Shiyo",loc="Emperor's Approach, Vale of Eternal Blossoms"}}
d[30193]={mo=198450,rep="+100 Golden Lotus",o="thumb|Fairlands Gazelle. Retrieve 10 slabs of Fairlands Gazelle Meat. *Fairlands Gazelle Meat (10)",de="Hard workers deserve hearty meals, but I'm all out of good meat! Can you head out into the forest and get me some fresh gazelle meat?",g={n="Cook Tope",loc="Mistfall Village, Vale of Eternal Blossoms"}}
d[30194]={mo=198450,rep="+100 Golden Lotus",o="thumb|Thundermaw. Kill 8 Thundermaw Wolves. *Thundermaw slain (8)",de="The villagers have lost another yak this morning to one of the thundermaw wolves from across the river. The wolves grow bold. This is a sign that they are breeding beyond the vale's ability to sustain them. It's time to thin their numbers again. If you are willing to aid me in this, you would have my sincere appreciation.",g={n="Che Wildwalker",loc="Mistfall Village, Vale of Eternal Blossoms"}}
d[30195]={mo=198450,rep="+100 Golden Lotus",o="thumb|Eternal Blossom Collect 10 Eternal Blossoms. *Eternal Blossom (item) (10)",de="Would you do a humble merchant a favor? I've been needin' to refresh my stock of eternal blossoms. They grow in the woods nearby. Could you help me out, perhaps?",g={n="Merchant Benny",loc="Mistfall Village, Vale of Eternal Blossoms"}}
d[30196]={mo=198450,rep="+100 Golden Lotus",o="Collect 12 Lushrooms. *Lushroom (item) (12)",de="Building a new village makes for hungry workers it seems! I have a hearty stew recipe prepared, but I need some lushrooms from the Tu Shen Burial Ground to the east. Apparently there are roused spirits causing trouble up there though, and I'm not very well suited for the violent life. If you're heading up the burial grounds today, could you collect some lushrooms for me?",g={n="Cook Tope",loc="Mistfall Village, Vale of Eternal Blossoms"}}
d[30200]={mo=198450,rep="+100 Golden Lotus",o="thumb|Ashweb Piercer. thumb|Ashweb Weaver. Kill 8 Ashweb Spiders. *Ashweb Spiders slain (8)",de="We used to have the trainees clear out the ruins of spiders as part of their training, but now we send them straight to the mogu front. The spiders have gotten out of control. Care to put things back in control?",g={n="Anji Autumnlight",loc="Vale of Eternal Blossoms"}}
d[30204]={mo=198450,rep="+100 Golden Lotus",o="thumb|Ashweb Hatchlings on fire. Kill 50 Ashweb Spiderlings. Use Kun's torch to burn them inside their pods. *Ashweb Hatchling slain x50 *Shado-Pan Torch (That's Not a Rock!) (provided)",de="Okay, these spiders are seriously creeping me out. Especially those egg sacs they leave lying around that I keep accidentally stepping on only to be covered in very little but very creepy spiderlings. Ug, makes me shudder just thinking about it. I say you burn them. Burn them all.",g={n="Kun Autumnlight",loc="Vale of Eternal Blossoms"}}
d[30205]={mo=198450,rep="+100 Golden Lotus",o="thumb|Runelocked runes upper level thumb|Ancient Mogu Artifact Retrieve the Ancient Mogu Artifact. *Ancient Mogu Artifact",de="Hello, friend. One of Leven's men brought word to me of a mogu artifact in the eastern ruins, but said he couldn't figure out how to retrieve it. I suspect it's guarded by one of their rune locks. If you go to the artifact, you should find four runes somewhere nearby that when activated will release the lock. If you could bring the artifact back to me, I would be very grateful.",g={n="Sinan the Dreamer",loc="Mogu'shan Palace, Vale of Eternal Blossoms"}}
d[30206]={mo=198450,rep="+100 Golden Lotus",o="Collect 12 Guo-Lai Runestones. *Guo-Lai Runestone (12)",de="In the walls of the ruins themselves, there are precious runestones that we can make use of back in the eastern vale. If you see any while you are within the ruins, would you be so kind as to bring them back to me?",g={n="Sinan the Dreamer",loc="Mogu'shan Palace, Vale of Eternal Blossoms"}}
d[30225]={r={{n="Treasures of the Vale"}},mo=247200,rep="+200 Golden Lotus",o="thumb|Bloodtip. Kill Bloodtip, the Ashweb Matriarch. *Bloodtip slain",de="My dear Kun spotted more spiders pouring out of the Guo-Lai Halls this morning, and when he went to investigate, he uncovered another spider matriarch inside. I need you to kill it.",g={n="Anji Autumnlight",loc="Vale of Eternal Blossoms"}}
d[30226]={mo=198450,rep="+100 Golden Lotus",o="Kill 8 Shao-Tien mogu on Ruins Rise. *Ruin's Rise mogu slain (8)",de="A small group of mogu have been sited on Ruin's Rise, to the north. Extinguish them.",g={n="Anji Autumnlight",loc="Vale of Eternal Blossoms"}}
d[30227]={r={{n="Treasures of the Vale"}},mo=247200,rep="+200 Golden Lotus",o="Kill Wulon, the Granite Sentinel. *Wulon slain",de="One of the quilen statues in Guo-Lai Halls came to life and nearly killed my precious Kun. I won't have it! No one threatens my Kun. I want you to go in their and smash the thing to pieces. I'd do it myself, but I need to attend to my lover's wounds first.",g={n="Anji Autumnlight",loc="Vale of Eternal Blossoms"}}
d[30228]={mo=198450,rep="+100 Golden Lotus",o="thumb|Stonebark Trickster. Kill 8 Stonebark sprites. *Stonebark sprites slain (8)",de="The wood sprites are back. I need you to kill them before they cause anymore trouble.",g={n="Anji Autumnlight",loc="Vale of Eternal Blossoms"}}
d[30231]={mo=198450,rep="+100 Golden Lotus",o="thumb|Pomfruit. Gather 12 Pomfruit. *Pomfruit (item) x12 *Pomharvest Firework (provided)",de="I need more pomfruit! Go knock some loose from the trees for me, would you? Take this, I use it when I go harvesting. Things go quicker when the fruit comes to you!",g={n="Cook Tope",loc="Mistfall Village, Vale of Eternal Blossoms"}}
d[30232]={mo=198450,rep="+100 Golden Lotus",o="Gather 80 Silken Feathers. *Silken Feather (80)",de="The hawk numbers in the vale are thriving. This is opportune for our fletchers, for we will need a great number of feathers if we are to keep the archers upon the wall stocked with arrows. If you would not mind, could you aid us in gathering these feathers?",g={n="Che Wildwalker",loc="Mistfall Village, Vale of Eternal Blossoms"}}
d[30233]={r={{n="Treasures of the Vale"}},mo=247200,rep="+200 Golden Lotus",o="thumb|Cracklefang. Kill Cracklefang. *Cracklefang slain",de="Hi! So, I have a dilemma. I've only got one good wolf name.... wait for it... Cracklefang! I know, amazing right?! But now there are TWO big nasty wolves in the forest, which is all kinds of confusing. I need you to kill one of them so I can free up the name. Should be simple enough, yeah? Especially for someone of your incredibleness. So, are you on board? I'm hoping for yes!",g={n="Ren Firetongue",loc="Ruins Rise, Vale of Eternal Blossoms"}}
d[30234]={r={{n="Treasures of the Vale"}},mo=247200,rep="+200 Golden Lotus",o="Kill Vicejaw and return Ren's Longstaff. *Vicejaw slain",de="Vicejaw! Sounds absolutely violent, does it not? I came up with it myself, and I think it's very suiting. I tried to wrestle my staff away from him for hours, but he simply would not let go! Okay, it was really more like a few seconds. I like to be truthful to my friends, even if it makes my stories significantly more boring. Anyway, would you be so kind as to release your oh-so-potent wrath upon this crocodile with a vice-like jaw, and then kindly bring my staff back? Preferably in-tact!",g={n="Ren Firetongue",loc="Ruins Rise, Vale of Eternal Blossoms"}}
d[30235]={r={{n="Treasures of the Vale"}},mo=247200,rep="+200 Golden Lotus",o="thumb|Quid. Defeat Quid, the Spirit of the Misty Falls. *Quid Defeated *Stone of the Water Strider (provided)",de="Quid is a very powerful and very ancient water spirit, though you might not know it with his child-like ways. This morning, Quid nearly killed several villagers in the bar when he jokingly caused several of the water kegs to explode. As long as the water flows, Quid will remain. He cannot be slain. But he can be reminded that we do not take his dangerous antics in jest. Would you be willing to carry this message to him on behalf of the village?",g={n="Che Wildwalker",loc="Mistfall Village, Vale of Eternal Blossoms"}}
d[30236]={r={{n="Treasures of the Vale"}},mo=247200,rep="+200 Golden Lotus",o="thumb|Aetha. Defeat Aetha, the Spirit of the Golden Winds. *Aetha Subdued",de="It seems Aetha has been levitating the livestock and dropping them into the river again. The mayor has requested that we remind her that these kinds of jokes are not welcomed. Would you be so generous as to travel to the ridge above the village and teach her this lesson? You cannot kill her, you can only send her away for a time, but this should prove a potent reminder.",g={n="Che Wildwalker",loc="Mistfall Village, Vale of Eternal Blossoms"}}
d[30237]={mo=198450,rep="+100 Golden Lotus",o="thumb|Ancient Mogu Spirit. thumb|Echo of a Pandaren Monk. Kill 8 Ancient Mogu Spirits. *Ancient Mogu Spirit slain (8)",de="In the Tu Shen Burial Ground to the east, the spirits of ancient mogu are locked in battle with the spirits of our pandaren ancestors that rose up against them. The spirits have seen no rest since the return of the mogu to the valley. If you would be willing to go to the graveyard and force the mogu to relive their defeat again, we might offer some lasting peace to the spirits of our ancestors.",g={n="Che Wildwalker",loc="Mistfall Village, Vale of Eternal Blossoms"}}
d[30238]={mo=198450,rep="+100 Golden Lotus",o="thumb|Pandaren Gravestone. Honor 6 Pandaren Gravestones. * Pandaren Gravestones Honored (6)",de="The spirits of our ancestors are reliving one of the most revered battles in our history at the Tu Shen Burial Grounds to the east. Do as I ask, , and honor their gravestones. Remind them that they are respected even these many years later, and that they are deserving of peaceful rest.",g={n="Che Wildwalker",loc="Mistfall Village, Vale of Eternal Blossoms"}}
d[30239]={r={{n="Treasures of the Vale"}},mo=247200,rep="+200 Golden Lotus",o="thumb|Spirit of Lao-Fe. Kill the Spirit of Lao-Fe, the Slavebinder. *Spirit of Lao-Fe slain",de="You can hear the spirit of Lao-Fe, the Slavebinder shouting taunts from the cave at the top of Tu Shen Burial Ground. Defeating him will surely serve to ensure victory for the spirits of the pandaren monks."}
d[30240]={mo=198450,rep="+100 Golden Lotus",o="Enter the Survival Ring and survive for 60 seconds without leaving. *Live through the Survival Ring for 60 seconds",de="This is one of the challenges I put upon my warriors during peaceful times to keep them strong and fast. Let's see how you fare. Survive the ring for 60 seconds without getting pushed out or killed. Stay on your toes.",g={n="Yumi Goldenpaw",loc="Setting Sun Garrison, Vale of Eternal Blossoms"}}
d[30242]={mo=198450,rep="+100 Golden Lotus",o="Enter the Survival Ring and survive for 60 seconds without leaving. *Live through the Survival Ring for 60 seconds",de="This is one of the challenges I put upon my warriors during peaceful times to keep them strong and fast. Let's see how you fare. Survive the ring for 60 seconds without getting pushed out or killed. Stay on your toes.",g={n="Yumi Goldenpaw",loc="Setting Sun Garrison, Vale of Eternal Blossoms"}}
d[30243]={mo=198450,rep="+100 Golden Lotus",o="thumb|Krik'thik Hiveling. Use a Shado-Pan Hot Oil Bucket to kill 80 mantid near the Gate of the Setting Sun. *Krik'thik Hiveling slain (80)",de="The mantid are attacking again, and we're a bit short-handed up on the wall. In hopes that you'd help, I saved one of the more fun posts for you: the hot oil! It's a bit more violent and a bit less scandalous than it sounds. It's simple really. Get up on the wall, find one of the oil stations, and dump it on any of the mantid pouring up against the wall. It's very effective.",g={n="Kun Autumnlight",loc="Vale of Eternal Blossoms"}}
d[30244]={mo=198450,rep="+100 Golden Lotus",o="thumb|Krik'thik Locust-Guard. thumb|Krik'thik Needler. Kill 10 Krik'thik mantid on the Gate of the Setting Sun. *Krik'thik wall attackers slain (10)",de="There are mantid on top of the wall. The defenders on the ramparts are calling for help!",g={n="Kun Autumnlight",loc="Vale of Eternal Blossoms"}}
d[30245]={mo=198450,rep="+100 Golden Lotus",o="Recover 3 Shado-Pan Scout reports. *Shado-Pan Scout information recieved (3)",de="We sent some scouts towards the Five Sisters to the north to try and find whatever mogu leader has risen up to direct their movements in the valley. Few have returned. I'd like to think they're just off downing too much ale or being irresponsible with some young pandaren, but they may actually be in some trouble. Can you scout for the scouts? And see if they've turned up any information on that leader while you're at it?",g={n="Kun Autumnlight",loc="Vale of Eternal Blossoms"}}
d[30246]={mo=198450,rep="+100 Golden Lotus",o="thumb|Krik'thik Locust-Guard. thumb|Krik'thik Needler. Kill 10 Krik'thik mantid on top of the Gate of the Setting Sun. *Krik'thik wall attackers slain (10)",de="Some of the mantid have made it on top of the wall. There's some risk they'll rout the soldiers we have posted there if their numbers are large enough. I need you to get on top of the wall and help clear out any that have broken through.",g={n="Anji Autumnlight",loc="Vale of Eternal Blossoms"}}
d[30248]={r={{n="Treasures of the Vale"}},mo=247200,rep="+200 Golden Lotus",o="Kill Bai-Jin the Butcher. *Bai-Jin the Butcher slain",de="Scouts reports place the displaced Shao-Tien Imperion at the north end of the wall. Angi Autumnlight spelled out your goal in no uncertain terms: find this leader and kill him."}
d[30249]={r={{n="Treasures of the Vale"}},mo=247200,rep="+200 Golden Lotus",o="thumb|Kri'chon. thumb|Helper NPCs? thumb|Oil Keg. Kill Kri'chon, the Corpse-Reaver. *Kri'chon slain",de="A giant beast has burrowed under the gate into the courtyard. The defenders need your help!"}
d[30251]={r={{n="Treasures of the Vale"}},mo=247200,rep="+200 Golden Lotus",o="thumb|Vyraxxis. Kill Vyraxxis, the Krik'thik Swarm-Lord. *Vyraxxis slain",de="A giant mantid is terrorizing the inside of the wall. It seems doubtful that the defenders will be able deal with it without you.",g={n="Anji Autumnlight",loc="Vale of Eternal Blossoms"}}
d[30261]={mo=247200,rep="+200 Golden Lotus",o="Complete the Serpent's Spine roll course. *Speak to Kelari Featherfoot *Serpent's Spine Roll Course Finished",de="Get to the bottom of the wall in the fastest time possible. Speak to me when you're ready to roll.",g={n="Kelari Featherfoot",loc="Setting Sun Garrison, Vale of Eternal Blossoms"}}
d[30263]={mo=198450,rep="+100 Golden Lotus",o="thumb|Shao-Tien Conqueror. thumb|Shao-Tien Painweaver. Kill 10 Shao-Tien mogu in Winterbough Glade. *Winterbough Glade mogu slain (10)",de="The Shao-Tien on are on their heels. Most of them retreated to Winterbough Glade after their last defeat. We should press the advantage. Take the fight to these mogu in the clearing to the northwest. Let us leave them no minute of rest as long as they remain in the Vale.",g={n="Che Wildwalker",loc="Mistfall Village, Vale of Eternal Blossoms"}}
d[30264]={mo=247200,rep="+200 Golden Lotus",o="thumb|War Serpent. thumb|Krik'thik Hiveling. thumb|Krik'thik War Wagon. thumb|Krik'thik Catapult. Use a Shado-Pan Sky Serpent to kill 60 Krik'thik attackers, 3 Krik'thik War Wagons, and 3 Krik'thik Catapults. *Mount a War Serpent *Krik'thik Hiveling slain (60) *Krik'thik War Wagon slain (3) *Krik'thik Catapult slain (3)",de="The mantid forces are pouring against the wall. I've arranged for some flying serpents to cut away at their forces from the air. Would you be willing to take the reigns on one of them?",g={n="Anji Autumnlight",loc="Vale of Eternal Blossoms"}}
d[30265]={mo=198450,rep="+100 Golden Lotus",o="Recover 8 Shining Rubies. *Ruby Eye (8)",de="I've been staring down into the waters of the lake, pondering life, love, and everything beautiful, and suddenly I realized that the sparkles in the water aren't just a reflection of my radiant personality, there are actually some sort of shining objects down there! Surely valuable. Would you mind taking a drip and relieving the lake's depths of its mysterious sparkles? Pretty please?",g={n="Ren Firetongue",loc="Ruins Rise, Vale of Eternal Blossoms"}}
d[30266]={mo=198450,rep="+100 Golden Lotus",o="thumb|Krik'thik Swarmer. Kill 30 Krik'thik Swarmers using a Setting Sun Turret. *Krik'thik Swarmer slain (30)",de="We have cannons set up on the top of the towers flanking the main gate. They are our best method clear the skies when the flying mantid try to pass over the wall, like they are now. You've impressed me, and I promised I'd save some of the best jobs for you. Here you go - I need you to man one of the cannons.",g={n="Kun Autumnlight",loc="Vale of Eternal Blossoms"}}
d[30277]={mo=247200,rep="+200 Golden Lotus",o="thumb|Tiles in the Guo-Lai Vault thumb|Deactivate Final Spirit Wall thumb|Ancient Guo-Lai Artifact guarded thumb|Ancient Guo-Lai Artifact Retrieve the Ancient Guo-Lai Artifact. *Deactivate Final Spirit Wall *Ancient Guo-Lai Artifact",de="An ancient mogu artifact has been uncovered in the Guo-Lai Vault, beyond the Hall of Statues. We've made repeated attempts to retrieve it, but none have been successful. We cannot let this artifact fall into the hands of the Shao-Tien. I need someone capable to retrieve it, and quickly. Are you in?",g={n="Anji Autumnlight",loc="Vale of Eternal Blossoms"}}
d[30280]={mo=247200,rep="+200 Golden Lotus",o="thumb|Hall of Tiles. thumb|Hall of the Serpent. thumb|Milau. thumb|Lightning Breath. Slay Milau. *Milau slain",de="Roars have been echoing out from inside the Guo-Lai Halls. The mogu have awakened some ancient beast, an it is not long before they attempt to release it upon my men. Find your way to the Hall of the Serpent and slay the beast before it can be unleashed upon us. I would trust no other with such a dangerous and important task.",g={n="Leven Dawnblade",loc="Golden Pagoda, Vale of Eternal Blossoms"}}
d[30281]={mo=198450,rep="+100 Golden Lotus",o="thumb|Shao-Tien Mindbender. thumb|Shao-Tien Reclaimer. Kill 10 Shao-Tien mogu at Whitepetal Lake. *Whitepetal Lake mogu slain (10)",g={n="He Softfoot",x=0.258,y=0.187,loc="Various"}}
d[30282]={mo=198450,rep="+100 Golden Lotus",o="thumb|Shao-Tien Banner alight. Burn 6 Shao-Tien Banners. *Shao-Tien Banners burned (10) *Shado-Pan Torch (Burning Away the Filth) (provided)",de="The mogu have erected their filthy banners around the lake to the west, claiming it as their own. Take this torch and show them what we think of their banners.",g={n="Anji Autumnlight",loc="Vale of Eternal Blossoms"}}
d[30283]={mo=198450,rep="+100 Golden Lotus",o="thumb|Shao-Tien Ritual Statue Destroy the Shao-Tien Ritual Statues. *Shao-Tien Ritual Statues destroyed",de="Sometimes I feel sorry for these mogu... maybe ripping out the spirits of other races is just their way of coping with family issues at home? Maybe we should be more sympathetic to where all this aggression stems from? Or we could just smash all their soul-stealing ritual objects down at the lake. That sounds more fun to me personally.",g={n="Ren Firetongue",loc="Ruins Rise, Vale of Eternal Blossoms"}}
d[30284]={mo=198450,rep="+100 Golden Lotus",o="thumb|Knifetooth Swarmer. Kill 15 Knifetooth Swarmers. *Knifetooth Swarmer slain (15)",de="The water has been frothing with danger this day! Some sort of swarming, meat-eating fishy nastiness has taken up residence in our lake! Deplorable. And just when I was considering stripping down to my nothings to take a mid-day dip! You are adept in the ways of slaughtering any manner of nasty, are you not? Would you put your skills to use this day, in the name of pandaren everywhere desiring a swim? It's a truly noble cause, especially with me among their ranks!",g={n="Ren Firetongue",loc="Ruins Rise, Vale of Eternal Blossoms"}}
d[30285]={mo=198450,rep="+100 Golden Lotus",o="thumb|Shao-Tien Pillager. Recover 3 Wu Kao Scouting Reports. *Wu Kao Scouting Report (3)",de="There were some scouting reports unaccounted for after the attack. If we're lucky, they're still out in the village, but the mogu may have gotten their hands on some of them as well. If you could bring back any scouting reports you find, it would definitely put my mind at ease. We can't afford to let the mogu in on our positions or any of the artifacts we've found, lest the men be in even more danger than they already are.",g={n="Sun Tenderheart",x=0.258,y=0.187,loc="Various"}}
d[30286]={mo=198450,rep="+100 Golden Lotus",o="thumb|Cornered Villager. thumb|Stonebound Quilen. Rescue 6 Cornered Mistfall Villagers. *Rescue Cornered Villagers (6)",de="Many villagers are cornered and scared, unable to defend themselves. You will need to defend them. Rescue them. Go quickly friend, save as many as you can!",g={n="Sun Tenderheart",x=0.258,y=0.187,loc="Various"}}
d[30288]={mo=198450,rep="+100 Golden Lotus",o="thumb|Mistfall Water Buckets Use Mistfall Water Buckets to douse 60 fires. *Mistfall Village fire doused (60)",de="I don't know if you noticed, but my town is on fire... again. We have water buckets all over town, but no one can get out to put out the fires. Please, please, help us!",g={n="Mayor Shiyo",loc="Emperor's Approach, Vale of Eternal Blossoms"}}
d[30289]={mo=198450,rep="+100 Golden Lotus",o="thumb|Shao-Tien Subjugator. thumb|Golden Lotus Guard. Free 6 Dominated Guards by killing their controllers. *Free Dominated Guards (6)",de="Mogu stealing peoples minds! Making them do evil things. Don't kill them, just kill the mogu, then they forget about all the mogu mind stealing and stop being evil. You should fix people like Rook is.",g={n="Rook Stonetoe",x=0.258,y=0.187,loc="Various"}}
d[30290]={mo=198450,rep="+100 Golden Lotus",o="Kill 8 Stonebound Quilen. *Stonebound Quilen slain (8)",de="Mogu stone dog creatures chasing villagers and hurting them. Rook try to smash some, but they too fast. You help smash some too?",g={n="Rook Stonetoe",x=0.258,y=0.187,loc="Various"}}
d[30291]={mo=198450,rep="+100 Golden Lotus",o="thumb|Stunned Whitepetal Carp Collect 12 Stunned Whitepetal Carp. *Stunned Whitepetal Carp (12)",de="'ve been talking to Tantan here... again... and he insists that fishing is some kind of fabulous. I was skeptical, but I gave it another go. I'm not a big fan of that whole holding a stick and waiting method though, so I tried something a bit more direct. Would you be a doll and go collect any of the still in-tact fish floating belly up in the lake for me?",g={n="Ren Firetongue",loc="Ruins Rise, Vale of Eternal Blossoms"}}
d[30292]={mo=198450,rep="+100 Golden Lotus",o="thumb|Paleblade Flesheater. Kill 8 Dominated Paleblade Flesheaters. *Paleblade Flesheater slain (8)",de="The mogu are taking over the minds of the saurok at the lake to our west and turning them against us! The thing is, they were already against us, so I'm not sure they really thought this thing through fully. Anyway, Anji's the fighter in this pair, I'm more the lover, so I'm looking for someone to do all the weapon swinging and spell flinging and war crying and such. Can you go kill some saurok for me?",g={n="Kun Autumnlight",loc="Vale of Eternal Blossoms"}}
d[30293]={mo=198450,rep="+100 Golden Lotus",o="thumb|Shao-Tien Mindbender. Beat 8 Possessed Whitepetal Defenders until they're freed of mogu possession. *Dominated Defenders rescued (8)",de="The Shao-Tien Mindbenders have taken over the minds of our defenders down at Whitepetal Lake to the west. Get down there and kill the mogu that are controlling them, but don't kill the defenders! Killing their captors should free them from their mind control. Sooner would be better. Anji might try to go down there to help soon, and her ability to restrain herself when in the heat of things is not one of the qualities I married her for.",g={n="Kun Autumnlight",loc="Vale of Eternal Blossoms"}}
d[30296]={r={{n="Treasures of the Vale"}},mo=247200,rep="+200 Golden Lotus",o="thumb|Gaohun the Soul-Severer. Kill Gaohun the Soul-Severer. *Gaohun the Soul-Severer slain",de="Big mogu leader is here! Up behind village. If we kill big mogu leader, Leven be happy with us for sure! You been good at helping Rook. Want to help more maybe? Please?",g={n="Rook Stonetoe",x=0.258,y=0.187,loc="Various"}}
d[30297]={r={{n="Treasures of the Vale"}},mo=247200,rep="+200 Golden Lotus",o="thumb|Baolai the Immolator. Kill Baolai the Immolator. *Baolai the Immolator slain",de="Big mogu leader is here! Up behind village. If we kill big mogu leader, Leven be happy with us for sure! You been good at helping Rook. Want to help more maybe? Please?",g={n="Rook Stonetoe",x=0.258,y=0.187,loc="Various"}}
d[30298]={mo=198450,rep="+100 Golden Lotus",o="thumb|Shao-Tien Dominator. thumb|Shao-Tien Soul-Caller. Kill 8 mogu in the Ruins of Guo-Lai. *Guo-Lai mogu slain (8)",de="The mogu think they can inhabit these ruins uncontested. Let's show them the error in their ways.",g={n="Leven Dawnblade",loc="Golden Pagoda, Vale of Eternal Blossoms"}}
d[30299]={mo=198450,rep="+100 Golden Lotus",o="thumb|Mogu Statue falling. Destroy 10 Mogu Statues. *Mogu Statue destroyed (10)",de="The mogu have forced spirits into their old statues to bring them to life, control them, and turn them against us. The only way to free the bound spirits is to destroy their vessels.",g={n="Sun Tenderheart",x=0.258,y=0.187,loc="Various"}}
d[30300]={mo=198450,rep="+100 Golden Lotus",o="thumb|Golden Lotus Captive. Find a Shao-Tien Cage Key and free 6 Golden Lotus Prisoners. *Shao-Tien Cage Key *Free Golden Lotus Prisoners (6)",de="The mogu have taken prisoners. They'll be tortured or worse. Find any way you can to free them from their cages.",g={n="Sun Tenderheart",x=0.258,y=0.187,loc="Various"}}
d[30301]={mo=198450,rep="+100 Golden Lotus",o="Burn 6 Mogu Tents in the Ruins of Guo-Lai. *Burn Shao-Tien Tents x6 *Shado-Pan Torch (Offering a Warm Welcome) (provided)",de="There is no more sure message we can send them then to burn the tents the sleep in. Scour the ruins. Destroy every tent you find.",g={n="Leven Dawnblade",loc="Golden Pagoda, Vale of Eternal Blossoms"}}
d[30302]={r={{n="Treasures of the Vale"}},mo=247200,rep="+200 Golden Lotus",o="thumb|Guo-Lai Ritual Chamber Kill the Shao-Tien Imperion. *Shao-Tien Imperion slain /",de="Scouts spotted a Shao-Tien Imperion entering the Guo-Lai Halls. I need someone I can trust to make sure he doesn't come out of there alive. I think you're the for the job.",g={n="Leven Dawnblade",loc="Golden Pagoda, Vale of Eternal Blossoms"}}
d[30304]={mo=198450,rep="+100 Golden Lotus",o="Destroy 10 Mogu Statues. *Mogu Statue destroyed (10)",de="Hey! You know what awesome thing happened to me this morning? I was strolling through the ruins with Anji, eyes on the ground so I wouldn't step on anymore of those creepy spider pods, when one of the statues came to life and tried to smash me! Anji ended up doing the smashing. But I'm not satisfied. I think that you should go out there and smash all the statues, whether they're moving or not. It's the only way to be sure.",g={n="Kun Autumnlight",loc="Vale of Eternal Blossoms"}}
d[30305]={mo=198450,rep="+100 Golden Lotus",o="Lure 8 Guo-Lai mogu into He's Poison Traps. *Lure mogu into He's Poison Traps (6)",de="You know He Softfoot? Sneaky guy, don't talk much. He put traps all over ruins for mogu. He said Rook just need to trick mogu into traps. Rook don't really know how. Maybe you do it? You find traps, you get mogu into traps? Can you not tell He though, please?",g={n="Rook Stonetoe",x=0.258,y=0.187,loc="Various"}}
d[30306]={mo=198450,rep="+100 Golden Lotus",o="Defeated 20 Shado-Pan Trainees in the Battle Ring. *Shado-Pan Trainees defeated (20)",de="We have some fresh trainees that are far from being a danger to you, but in numbers, they may prove enough of a challenge. And if not, they could use the lesson in humility. Step into the battle ring when you're ready. Don't go easy on them.",g={n="Hai-Me Heavyhands",loc="Setting Sun Garrison, Vale of Eternal Blossoms"}}
d[30307]={mo=198450,rep="+100 Golden Lotus",o="thumb|Shao-Tien Marauder. thumb|Shao-Tien Soul-Render. Kill 8 Shao-Tien mogu on the Golden Terrace. *Shao-Tien mogu slain (8)",de="Good to have you with us, . If you're joining the fight, I need more men out on the battlefield below the Golden Stair to clear out the mogu setting up base there.. Can I count on you?",g={n="Leven Dawnblade",loc="Golden Pagoda, Vale of Eternal Blossoms"}}
d[30308]={mo=198450,rep="+100 Golden Lotus",o="thumb|Granite Quilen. Kill 8 Granite Quilen. *Granite Quilen slain (8)",de="Leven always says the only good quilen is a dead quilen, and I'm inclined to agree. You here to aid the cause?",g={n="Anji Autumnlight",loc="Vale of Eternal Blossoms"}}
d[30309]={mo=198450,rep="+100 Golden Lotus",o="Destroy 6 Mogu Effigies near the Golden Pagoda. *Mogu Effigy slain (6)",de="The mogu have been sending their narcissistic stone effigies onto our battlefield today. They're bringing them to life up on the Golden Stair. The bigger they are, the harder we hit'm. You in?",g={n="Anji Autumnlight",loc="Vale of Eternal Blossoms"}}
d[30310]={mo=198450,rep="+100 Golden Lotus",o="Kill 3 Subjugated Serpents. *Subjugated Serpent slain (3)",de="The mogu have bent the will of sky serpents and turned them against us. The defenders won't fare well against them, but you would. Head northwest towards the Golden Stair and remove them from the sky.",g={n="Anji Autumnlight",loc="Vale of Eternal Blossoms"}}
d[30312]={mo=198450,rep="+100 Golden Lotus",o="thumb|Wounded Defender (Vale of Eternal Blossoms)|Wounded Defender. Heal 6 Wounded Defenders. *Wounded Defender healed (6) *Shado-Pan Bandages (provided)",de="A foolish contingent attempted to mount an offensive on the Golden Stair through the eastern pass, and were bombarded by cannons. Those that made it back are in bad shape, and there are still wounded out in the field. Here are some bandages. Use these, or any other healing spells you possess, and help get our wounded defenders back to safety. Please hurry, there is little time.",g={n="Sun Tenderheart",x=0.258,y=0.187,loc="Various"}}
d[30313]={mo=198450,rep="+100 Golden Lotus",o="thumb|Fog Walker. Kill 8 Fog Walkers. *Fog Walker slain (8)",g={n="He Softfoot",x=0.258,y=0.187,loc="Various"}}
d[30314]={mo=198450,rep="+100 Golden Lotus",o="thumb|Paleblade Flesheater. thumb|Paleblade Slithertongue. Kill 8 Paleblade Saurok. *Paleblade Saurok slain (8)",g={n="He Softfoot",x=0.258,y=0.187,loc="Various"}}
d[30317]={mo=198450,rep="+2000 Farmer Fung+150 The Tillers",o="Speak with Wing Nga to borrow a kite, then throw water onto 35 Dusty Spots in the Heartland. *Dusty Spots watered (35)",de="How'd you like to make yourself useful? The season's been awful dry lately. I need someone to water the crops out in the Heartland. Here's the thing: I need you to water ALL of the crops. I keep a few kites with Wing Nga, the flightmaster across the way. Grab one of those kites, then throw water on any areas that look dry and dusty.",g={n="Farmer Fung",loc="Halfhill Market, Valley of the Four Winds"}}
d[30318]={mo=198450,rep="+3000 Old Hillpaw+150 The Tillers",o="Pick up Hillpaw's Chickens until you find his Prize-Winning Chicken. *Old Hillpaw's Prize Chicken",de="Say, you there! , was it? I've got a problem, and I need someone with better legs than mine to help me solve it. My prize-winning chicken has flown the coop! Now she's out in the open, mingling with the other hens, wild birds, and... ill-intentioned roosters. My farm is west of here, south of the Skyrange. Could you find her, and bring her back to me?",g={n="Old Hillpaw",loc="Heartland, Valley of the Four Winds"}}
d[30319]={mo=198450,rep="+3300 Haohan Mudclaw+150 The Tillers",o="Speak with Wika-Wika, then stomp on 25 Black-Nose Marmots. *Black-Nose Marmot stomped (25)",de="One of my farmhands, Wika-Wika, has been tilling the soil in my westernmost field. I understand he's had some problems with pests. He's got plenty of pesticide to spray the bugs that eat my crops, but I'm afraid he has no way to deal with the marmots. Would you lend him a hand? With rampant hozen and virmen attacks, I can't afford to lose crops to simple pests.",g={n="Haohan Mudclaw",loc="Heartland, Valley of the Four Winds"}}
d[30320]={mo=198450,rep="+100 Golden Lotus",o="thumb|A captive spirit mourning at a body pile. thumb|Captive Pandaren Spirit. thumb|Twisted Tormentor. Enter Soul Vortexes and free 15 pandaren souls inside. *Free Captive Pandaren Spirits (15) *Shao-Tien Spirit Dagger (provided)",de="I came upon one of the Shao-Tien Soul-Render's daggers. It radiates a strong magic. I've been told it should allow you to enter their soul vortexes. The mogu use these to harvest souls and bind them to their will, but I'm hoping you can use it to free the souls. Enter any of the spirit vortexes you can find up on the Golden Stair, and free all the captive spirits you find.",g={n="Sun Tenderheart",x=0.258,y=0.187,loc="Various"}}
d[30321]={mo=198450,rep="+2000 Jogu the Drunk+150 The Tillers",o="Speak to Gai Lan, then pick 100 Weeds on his farm. You can pick Weeds while mounted. *Weeds pulled (100)",de="Ssshhay... d'you know that guy over on the farm, with the... the *hic*... the weed problem? Gai Lan, I think his name was. I love that guy, man. Anywayshh, he said that if I *hic* sent an adventurer over to go pick his weeds, he'd get me some ale. It's jusht a few weeds, not too many, probably. *hic*",g={n="Jogu the Drunk",loc="Halfhill Market, Valley of the Four Winds"}}
d[30322]={mo=198450,rep="+150 The Tillers+2600 Gina Mudclaw",o="Obtain Spicemaster Jin Jao's Payment, Trader Jambeezi's Payment, Innkeeper Lei Lan's Payment, and Lolo Lio's payment. *Spicemaster Jin Jao's Payment *Trader Jambeezi's Payment *Innkeeper Lei Lan's Payment *Lolo Lio's Payment",de="I love working in the market, although there's one aspect of this job I really dislike: collecting debts. While most pandaren debts are simply due to laziness, there are a few unsavory characters around town who simply don't want to pay, and there's some who are just too poor. A few people here in town owe me money. Could you go talk to them, and remind them about what they owe?",g={n="Gina Mudclaw",loc="Halfhill Market, Valley of the Four Winds"}}
d[30323]={mo=198450,rep="+150 The Tillers+2000 Tina Mudclaw",o="Obtain a Stolen Circlet, a Ransacked Ring, and a Burglarized Bracelet. *Stolen Circlet *Ransacked Ring *Burglarized Bracelet",de="A few weeks ago, a group of those jumpy little Springtail virmen broke into my lockbox and stole several handfuls of my jewelry. I've since found a few pieces, but they still have most of my collection. If you're headed up to the Springtail Crag, in the cliffs to the north, you should keep an eye out for them. I'd love to get my jewelry back.",g={n="Tina Mudclaw",loc="Halfhill Market, Valley of the Four Winds; Timeless Isle"}}
d[30324]={mo=198450,rep="+2000 Chee Chee+150 The Tillers",o="thumb|Kunzen Collector. thumb|Kunzen Hunter. thumb|Kunzen Ravager. thumb|Kunzen Ritualist. thumb|Kunzen Rockflinger. Kill 8 members of the Kunzen tribe in the Kunzen Village. *Kunzen tribe member slain (8)",de="Not all hozen are the same. Chee-Chee's tribe was forest hozen... came from Jade Forest. Pretty easy to get along with. The Kunzen invaders... they come from mountains, far to the north. Not nearly as nice as Chee-Chee. They come into our green land, take our things, leave big mess behind. Chee-Chee wants to kill them. You like to help?",g={n="Chee Chee",loc="Heartland, Valley of the Four Winds"}}
d[30325]={mo=198450,rep="+2000 Sho+150 The Tillers",o="thumb|Kunzen Ritual Candle. thumb|Blazing Ember. thumb|Kunzen Ritualist. Throw 8 Kunzen Ritual Candles, kick 4 Blazing Embers, and slay 1 Kunzen Ritualist. *Kuzen Ritual Candle thrown *Blazing Ember kicked *Kunzen Ritualist slain",de="I've been watching those Kunzen hozen, and I've noticed a consistent pattern. Whenever they're getting ready to attack, they participate in strange, barbaric rituals around their totem. If we can disrupt this ritual, not only will we put off any impending attacks, we can deal a huge blow to their morale! So get in there, rough them up, and make as much of a mess as possible!",g={n="Sho",x=0.295,y=0.306,loc="Skyrange, Valley of the Four Winds"}}
d[30326]={mo=198450,rep="+2000 Fish Fellreed+150 The Tillers",o="Obtain a Kunzen Legend-Book from a Kunzen Legend-Chief. *Kunzen Legend-Book",de="I've heard people talk about the hozen like they're just some tribe of barely-functional idiots... but that's not true! They have brains, too - they just don't all like to use them that much. I've heard that the Kunzen tribe has two chiefs - one in charge of fighting, and one in charge of stories, lore, and history. What I wouldn't give to see what kind of stories they tell...",g={n="Fish Fellreed",x=0.4175,y=0.3005,loc="Cattail Lake, Valley of the Four Winds"}}
d[30327]={mo=198450,rep="+2000 Ella+150 The Tillers",o="Burn 6 Kunzen Ropes. *Rope Burned (6)",de="I, umm... well... Oh, never mind. It was a stupid idea. It's just that, I was thinking that maybe we can stop the Kunzen hozen from attacking us without having to, you know... KILL anything. I noticed a few ropes on the side of the mountain. I think they're using them to climb down to our farms and... No, forget it. It was a silly idea anyways.",g={n="Ella",loc="Heartland, Valley of the Four Winds"}}
d[30328]={r={{n="+1 Cooking skill"}},mo=198450,o="Obtain 7 jars of Preserved Vegetables. *Preserved Vegetables (7)",de="One of my most popular recipes is the Thousand-Year Dumpling, which is filled with preserved vegetables. I normally let the vegetables ferment in a hole underneath my house, but when I looked for them this morning, they were gone! I blame those thieving virmen. Bring them back, and I'll let you help me cook!",g={n="Yan Ironpaw",x=0.526,y=0.516,loc="Halfhill Market, Valley of the Four Winds"}}
d[30329]={mo=198450,o="Obtain 4 Cindergut Peppers. *Cindergut Pepper (4)",de="A certain few pandaren around here prefer their dishes unbearably spicy. Unfortunately, my access to such peppers is limited. The Kunzen hozen, in the mountains to the west, often carry cindergut peppers. A few of those and I'll be set for a few days. Say, could you collect some for me? You might want to wear gloves if you'll be handling them directly.",g={n="Anthea Ironpaw",x=0.527,y=0.521,loc="Halfhill Market, Valley of the Four Winds"}}
d[30330]={r={{n="+1 Cooking skill"}},mo=198450,o="Obtain 8 Shadelight Truffles, and plant 8 Shadelight Spores. *Shadelight Spore planted (8) *Shadelight Truffle (8) *Shadelight Truffle Spores (provided)",de="I like to bake with truffles... when I can find them. They only grow up on the Skyrange, and in very, very scarce amounts. They're a fantastic ingredient, but we can't risk over-farming them. That's why we need to replace what we've taken. Bring me a handful of adult truffles, and plant some of these spores in their place.",g={n="Jian Ironpaw",x=0.533,y=0.516,loc="Halfhill Market, Valley of the Four Winds"}}
d[30331]={r={{n="+1 Cooking skill"}},mo=198450,o="thumb|Kunzen Soupmaster. Prepare 20 bowls of Mushan Tail Stew over the bonfire in the Kunzen Village. *Mushan Tail Stew x20 *Master's Pot (provided)",de="Have you ever tried Mushan Tail Stew? Chances are, if you have, that it was stringy and tasteless. You see, there's a trick to making the perfect Mushan Tail Stew: you need to cook it at high elevation. I've already gathered the ingredients. Take this pot up to the Kunzen Village, up in the mountains to the west, and prepare the stew over their bonfire.",g={n="Mei Mei Ironpaw",x=0.526,y=0.516,loc="Various"}}
d[30332]={r={{n="+1 Cooking skill"}},mo=198450,o="Obtain 4 Fatty Goatsteaks. *Fatty Goatsteak (4)",de="You know what? I think I want to grill up some goatsteak today. No, not from the puny little shaghorns they keep around here. They don't have nearly enough fat on them. You think I got to this size eating no-fat-havin' goats? Now, those shaghorns up on the Skyrange to the west... those'll do just fine.",g={n="Kol Ironpaw",x=0.53,y=0.513,loc="Halfhill Market, Valley of the Four Winds"}}
d[30333]={mo=198450,rep="+275 The Tillers",o="thumb|Springtail Warren-Mother. Slay the Springtail Warren-Mother. *Springtail Warren-Mother slain",de="Like any farming community, we have the occasional virmen troubles. The most powerful Springtail virmen live high up in the cliffs to the north, and only come down when they run out of veggies to nibble on. Frankly, I've dealt with virmen before. They're nothing but a pest that must be kept in check, and there's no better way to do that than by killing their warren-mother. Easy as that. (\"Springtail Warren-Mother: Till and kill, neighbor. Till and kill.\")",g={n="Farmer Yoon",x=0.522,y=0.488,loc="Various"}}
d[30334]={mo=198450,rep="+275 The Tillers",o="Re-steal 16 Stolen Vegetables. *Stolen Vegetable (16)",de="The hozen, up in the mountains to the west, continue to steal vegetables from my fellow farmers. Being so close to Halfhill, I very rarely suffer hozen attacks, but my friends have not been so lucky. Seems to me like they steal way more than they can eat. If you can find any intact vegetables up there in those mountains... steal them back!",g={n="Farmer Yoon",x=0.522,y=0.488,loc="Various"}}
d[30335]={mo=198450,rep="+275 The Tillers",o="Slay 12 Kunzen Hozen. *Kunzen hozen slain (12)",de="The Kunzen hozen, up in the mountains to the west, have been acting up, lighting their fires and shouting their chants. Based on what I've heard and seen around here, that means that a ravage is coming. There's not much we can do to stop the ravage, but we can at least thin their numbers before they attack.",g={n="Farmer Yoon",x=0.522,y=0.488,loc="Various"}}
d[30336]={mo=198450,rep="+275 The Tillers",o="Slay the Kunzen Hunter-Chief. *Kunzen Hunter-Chief slain",de="From what I've gathered, the Kunzen hozen have two chiefs. One is harmless - he deals with potions, medicines, and ancient fables. The other one is in charge of the Kunzen's hunters - and the only thing they've been hunting lately is our crops. The Hunter-Chief is a problem waiting to be solved. I'm sure the local farmers would be grateful if you went up there and, you know, \"took care\" of him.",g={n="Farmer Yoon",x=0.522,y=0.488,loc="Various"}}
d[30337]={mo=198450,rep="+275 The Tillers",o="thumb|Stolen tools thumb|Stolen beer thumb|Stolen grain Use the Barrel of Fireworks near the Pile of Stolen Weapons, the Pile of Stolen Tools, the Pile of Stolen Beer, and the Pile of Stolen Grain. *Stolen weapons exploded *Stolen tools exploded *Stolen beer exploded *Stolen grain exploded *Barrel of Fireworks (provided)",de="The hozen steal from us, and we keep stealing our stuff back. It has to stop sometime. Find some of our stolen supplies in their mountain camp to the west, and place these fireworks beside them. Hopefully, if they see the explosions, they'll think our supplies are defective and stop stealing altogether. It's worth a shot, right?",g={n="Farmer Yoon",x=0.522,y=0.488,loc="Various"}}
d[30338]={mo=198450,rep="+100 Golden Lotus",o="Recover 8 Mogu Artifacts. *Mogu Artifact (A Weighty Task) (8)",de="For the life of me, I can't figure out why the mogu would have built all their statues and such down in that lake. I'm sure there wasn't always water down there, but it still seems wickedly inconvenient should it ever have rained. Ah well, who's to fathom the strange intentions of the mogu... Would you be so kind to swim down there and bring back any artifacts that seem even vaguely carry-able? I'd certainly appreciate it.",g={n="Ren Firetongue",loc="Ruins Rise, Vale of Eternal Blossoms"}}
d[30339]={mo=198450,rep="+100 Golden Lotus",o="Gather 12 Fresh Whitepetal Worms. *Fresh Whitepetal Worm (12)",de="Some of the best fishin' in all of Pandaria in this lake right here. I brought enough brew to last me all day, but I didn't think to bring any bait. Who can really remember such things? If you'd be willing to gather me some bait along the shore, I'd be willin' to think on you favorably when it comes time to price my merchandise. Oh, and I'll pay you too, of course. How's that sound?",g={n="Merchant Tantan",loc="Gate of the August Celestials, Kun-Lai Summit"}}
d[30340]={mo=198450,rep="+100 Golden Lotus",o="thumb|Whitepetal Reed Gather 12 Whitepetal Reeds. *Whitepetal Reed (12)",de="I came out for a beautiful day of fishin', but I didn't think to bring a pole. There are so many things to remember for fishin', I just can't keep it all in my head. Those reeds along the river look alright for makin' a pole out of. If you'd gather me some number of them, I'd be willin' to think on you favorably when it comes time to price my merchandise. Oh, and I'll pay you too, of course. How's that sound?",g={n="Merchant Tantan",loc="Gate of the August Celestials, Kun-Lai Summit"}}
d[30341]={mo=198450,rep="+100 Golden Lotus",o="Kill 8 Shao-Tien Surveyors. *Shao-Tien Surveyor slain (8) *Shado-Pan Flare (provided)",g={n="He Softfoot",x=0.258,y=0.187,loc="Various"}}
d[30342]={mo=198450,rep="+100 Golden Lotus",o="thumb|Stillwater Crocodile. Kill 8 Stillwater Crocodiles. *Stillwater Crocodile slain (8)",de="I was kicking the water for fun again when one of those vicious crocodiles lunged out to try to bite my foot off! Rude! I have proceeded to rest my weary soles a few feet farther from the water, but I already look back on my water-kicking days longingly. Would you be so kind as to kill a crocodile or eight for me? I assure you they deserve it for frightening me though.",g={n="Ren Firetongue",loc="Ruins Rise, Vale of Eternal Blossoms"}}
d[30386]={g={n="Ella",loc="Heartland, Valley of the Four Winds"}}
d[30402]={g={n="Chee Chee",loc="Heartland, Valley of the Four Winds"}}
d[30421]={g={n="Farmer Fung",loc="Halfhill Market, Valley of the Four Winds"}}
d[30433]={g={n="Tina Mudclaw",loc="Halfhill Market, Valley of the Four Winds; Timeless Isle"}}
d[30444]={mo=198450,rep="+100 Golden Lotus",o="Kill 8 Shao-Tien mogu near the Five Sisters. *Shao-Tien mogu slain (8)",de="We've been granted a brief respite from the mogu attacks as they attempt to recoup near the Five Sisters to our north. I would like you to see to it that they not be granted a similar reprieve. Show no mercy.",g={n="Anji Autumnlight",loc="Vale of Eternal Blossoms"}}
d[30470]={mo=198450,rep="+1400 Tina Mudclaw+150 The Tillers",o="Obtain an Uncut Chrysoberyl. *Uncut Chrysoberyl",de="That Tina Mudclaw is in the Halfhill Market today, visiting her sister. She's really nice, but she's really hard to get gifts for! There's a little jewel that can be found in the cliffs to the north. It's called a chrysoberyl, and it changes color when you hold it. I'll bet she doesn't have one of THOSE! Look inside the virmen caves. I bet you'll find one really fast.",g={n="Andi",x=0.528,y=0.503,loc="Sunsong Ranch, Valley of the Four Winds"}}
d[30471]={mo=198450,rep="+150 The Tillers+1400 Chee Chee",o="Obtain an Authentic Valley Stir Fry. *Authentic Valley Stir Fry",de="That crazy Chee Chee is actually pretty neat. Mah always said that hozen were nothing but trouble, but... I guess he's just a better hozen then the rest of them. We should do something nice for him! Those mountain hozen in the west make some really fancy stir fry, and keep bowls of it inside their little hozen houses. I bet Chee Chee would love some!",g={n="Andi",x=0.528,y=0.503,loc="Sunsong Ranch, Valley of the Four Winds"}}
d[30472]={mo=198450,rep="+1400 Sho+150 The Tillers",o="Obtain a bowl of Yu-Ping Soup. *Yu-Ping Soup",de="Sho - that girl who lives up in the mountains - is in town today. I saw her walking toward the Halfhill Market. Such a long walk... she must be hungry! And I think I know just the thing that she'll like. The hozen up on the Skyrange cook a soup out of fish and apples. It sounds gross, I know... but it's awesome. You'll find it near their big, scary totem.",g={n="Andi",x=0.528,y=0.503,loc="Sunsong Ranch, Valley of the Four Winds"}}
d[30473]={mo=198450,rep="+1400 Fish Fellreed+150 The Tillers",o="Obtain a Yak Statuette from the inside of a Kunzen hozen hut. *Yak Statuette",de="That Fish Fellreed is kind of weird. First of all, her name's Fish. That's weird. Once you talk to her, though, she's really a nice lady. Did you know that she's an animal lover? I've got an idea! The Kunzen hozen, in the mountains to the west, make little animal statues and put them in their huts to scare off bad guys. I bet Fish would LOVE something weird like that!",g={n="Andi",x=0.528,y=0.503,loc="Sunsong Ranch, Valley of the Four Winds"}}
d[30474]={mo=198450,rep="+1400 Ella+150 The Tillers",o="Obtain Spicy Shrimp Dumplings. *Spicy Shrimp Dumplings",de="That poor Ella. She's so shy! I saw her standing in the Halfhill Market, looking really hungry, but afraid to talk to any of the chefs. We should bring her some food! And not any boring food - something special. The Kunzen hozen make spicy shrimp dumplings from ingredients they've stolen from our farms. I don't like spicy food, but Ella might!",g={n="Andi",x=0.528,y=0.503,loc="Sunsong Ranch, Valley of the Four Winds"}}
d[30475]={mo=198450,rep="+1400 Farmer Fung+150 The Tillers",o="Obtain a :Bloody Plainshawk Leg from a , and then bring it to in the Halfhill Market. *Grilled Plainshawk Leg",de="Farmer Fung is pretty mean, and just a little scary. Mah always said that he was one of the best farmers in the valley, though. I think I know the perfect gift for a mean, kind of scary guy like him. There's some big plainshawks that circle the hills to the west of here. You should get one, find a big piece of meat, and then ask Kol Ironpaw to grill it up!",g={n="Andi",x=0.528,y=0.503,loc="Sunsong Ranch, Valley of the Four Winds"}}
d[30476]={mo=198450,rep="+1400 Old Hillpaw+150 The Tillers",o="Find a Blue Freshwater Pearl. *Blue Freshwater Pearl",de="Old Hillpaw has about a million chickens on his farm... but that's not what he REALLY loves. I saw. He collects blue feathers. I don't realy know where to get a blue feather around here, but I do know where to find some blue pearls! Check the oysters in Cattail Lake to the northwest. I'm sure a blue pearl will look nice with his feather collection!",g={n="Andi",x=0.528,y=0.503,loc="Sunsong Ranch, Valley of the Four Winds"}}
d[30477]={mo=198450,rep="+1400 Haohan Mudclaw+150 The Tillers",o="Obtain an Enormous Cattail Grouper Tooth. *Enormous Cattail Grouper Tooth",de="Haohan Mudclaw is the big boss of the Tillers union and the richest guy in the Valley! He's been nice to let me stay here, so I want to do something nice for him. He likes expensive stuff, like ruby shards, but I don't have a lot of money, so I need to get him something else. I know! I've seen a great big fish in Cattail Lake! We should get one of its teeth as a gift!",g={n="Andi",x=0.528,y=0.503,loc="Sunsong Ranch, Valley of the Four Winds"}}
d[30478]={mo=198450,rep="+1400 Jogu the Drunk+150 The Tillers",o="Obtain 8 of Yoon's Apples and 50 of Yoon's Craneberries, then bring them to Bobo Ironpaw to brew into Apple-Berry Hooch. *Apple-Berry Hooch",de="Sometimes I feel sad for Jogu. He's the only jinyu around, and I don't think he has any friends. Other than his smelly bottle, of course. You know what? I've got an idea. Farmer Yoon has a basket of craneberries inside his house, and a few apples as well. I'm sure you could bring them to the stillmaster in the Halfhill Market and get him to brew something special for Jogu.",g={n="Andi",x=0.528,y=0.503,loc="Sunsong Ranch, Valley of the Four Winds"}}
d[30479]={mo=198450,rep="+1400 Gina Mudclaw+150 The Tillers",o="Obtain a Goldenfire Orchid. *Goldenfire Orchid",de="Have you seen Gina Mudclaw, the market girl? She has it all - looks, brains, and nice big tummy. Could you deliver a gift for me? I wanted to pick some orchids that grow on top of the big hills to the west, but I can't climb that high. Could you pick a few and bring them to Gina? Oh, and when you see her... tell her I said \"hi\".",g={n="Andi",x=0.528,y=0.503,loc="Sunsong Ranch, Valley of the Four Winds"}}
d[30481]={mo=198450,rep="+100 Golden Lotus",o="Collect 12 Guo-Lai Runestones. *Guo-Lai Runestone (12)",de="You see the shiny stones in the walls? Rook wants some. The mogu have been collecting them, so they have to take too maybe. If you find stones, you please bring them to Rook? Rook will be your friend.",g={n="Rook Stonetoe",x=0.258,y=0.187,loc="Various"}}
d[30482]={r={{n="Treasures of the Vale"}},mo=247200,rep="+200 Golden Lotus",o="thumb|Shadowmaster Sydow. Kill Shadowmaster Sydow and recover the beads from his corpse. *Soul-Gatherer's Beads",de="A single large mogu performing a ritual on the lake caught your attention while you were killing the other mogu in the area. It seems unwise to let his ritual complete."}
d[30584]={r={{n="Crispy Dojani Eel"},{n="+1 Fishing skill"}},mo=198450,rep="+500 The Anglers",o="Fish up 7 Dojani Eels from the Dojani River in Krasarang Wilds. *Dojani Eel (7)",de="Have you ever had a fresh dojani eel, ? No? Well you have not lived then! Head north up to the dojani river and fish up a few for us. Be careful, those eels can zap you if you're not careful!",g={n="Fisherman Haito",loc="Anglers Wharf, Krasarang Wilds"}}
d[30585]={r={{n="+1 Fishing skill"}},mo=114000,rep="+500 The Anglers",o="thumb|Narjon the Gulper. Find an Ancient Fishing Pool at Krasari Falls to the northwest and fish in it to lure the beast out of hiding. *Narjon the Gulper slain *Beloved Ring",de="Legend tells of a great beast in the forest to the north. My son is missing and I fear he may have wandered too near its lair.... Head northwest to Krasari Falls and look for a mysterious whirlpool - this is the key to revealing what is hidden there. Kill the wretched beast and recover any clues to my son's whereabouts.",g={n="Elder Fisherman Rassan",loc="Anglers Wharf, Krasarang Wilds"}}
d[30586]={r={{n="+1 Fishing skill"}},mo=198450,rep="+500 The Anglers",o="thumb|Jagged Abalone Harvest 9 Jagged Abalone Meat from the Jagged Abalone in Narsong Trench to the east. *Jagged Abalone Meat (9)",de="Pandaren have been harvesting jagged abalone in this area for generations. Now it's time for you to learn the ritual. The abalone can be found just west of here in narsong trench. Be careful, we have noticed increased shark activity in that area recently.",g={n="Fisherman Haito",loc="Anglers Wharf, Krasarang Wilds"}}
d[30588]={r={{n="+1 Fishing skill"}},mo=114000,rep="+500 The Anglers",o="Kill 8 Riverblade Beach Raiders at Anglers Expedition, just west of Anglers Wharf. *Riverblade Raider slain (8)",de="The riverblade saurok clan is attacking one of our local fishing expeditions! They need help right away! Thin those saurok out and help that expedition return safely!",g={n="Angler Shen",loc="Anglers Wharf, Krasarang Wilds"}}
d[30598]={r={{n="+1 Fishing skill"}},mo=114000,rep="+500 The Anglers",o="thumb|Pristine Crane Egg thumb|Crane egg pool Collect a Pristine Egg from the Narsong Spires and use it to catch a Silver Goby. *Pristine Crane Egg Gathered *Silver Goby",de="Great cranes have been nesting in this area for generations. The Narsong Spires provide a sheltered area to rear their young. Their pristine eggs are revered as bait for catching the silver goby. Retrieve a crane egg and see if you can catch a goby!",g={n="Elder Fisherman Rassan",loc="Anglers Wharf, Krasarang Wilds"}}
d[30613]={r={{n="+1 Fishing skill"}},mo=114000,rep="+500 The Anglers",o="Use the Fishing Spear to catch 5 Armored Carp in the waters south of Anglers Wharf. *Armored Carp x5 *Anglers Fishing Spear (provided)",de="Armored Carp are a delicacy around these parts. Unfortunately we can't fish them up since they snap our hooks with their powerful jaws. Take this fishing spear and see if you can catch a few for us.",g={n="Trawler Yotimo",loc="Anglers Wharf, Krasarang Wilds"}}
d[30658]={r={{n="+1 Fishing skill"}},mo=114000,rep="+500 The Anglers",o="Use the Fishing Spear to kill 5 Prickly Puffer fish in Sarjun Depths and return with their spines. *Prickly Puffer Spine x5 *Anglers Fishing Spear (provided)",de="Have you heard of the prickly puffer fish ? Of course you haven't, you're new around these parts! They can be found in the sarjun depths, due west of here. Take this fishing spear and see if you can bring me back of few of their poison tipped spines.",g={n="Trawler Yotimo",loc="Anglers Wharf, Krasarang Wilds"}}
d[30678]={r={{n="+1 Fishing skill"}},mo=114000,rep="+500 The Anglers",o="Use the Goblin Fishing Bombs to kill 3 Sting Rays and bring back their stingers to Fiznix. The Rays can be found in the shallows west of Anglers Wharf. *Stinger (3) *Goblin Fishing Bomb (provided)",de="Turns out these rays are not as easy to catch as I thought! You seem like a pretty smart guy, think you can help me out? I made the bombs but have been having trouble using the raft with my hurt leg. The rays are common in the shallows just west of here. Take the bombs and use my raft to bring me back their stingers! Oh yeah, watch out for the hammerheads!",g={n="Fiznix",loc="Anglers Wharf, Krasarang Wilds"}}
d[30698]={r={{n="+1 Fishing skill"}},mo=114000,rep="+500 The Anglers",o="Use the Goblin Fishing Raft to fish up 15 Rusty Shipwreck Parts out of the floating debris near the shipwrecks. *Rusty Shipwreck Debris (15)",de="YOU! You're just who I have been looking for! I need more parts for my goblin fishing bombs but I hurt my leg and can't collect them myself. You see those shipwrecks nearby? I bet they have just what I need if you can get to it and fish it out. Take my fishing raft and see what you can find! My buddy has been trying to help me out too so you might find some extra rafts near the wreckage, feel free to use em' too.",g={n="Fiznix",loc="Anglers Wharf, Krasarang Wilds"}}
d[30700]={r={{n="+1 Fishing skill"}},mo=114000,rep="+500 The Anglers",o="Kill Snapclaw in a cave at the bottom of Narsong Trench and return with his claw as proof. *Snapclaw's Claw",de="A giant, poisonous crab is wrecking havoc on our local abalone stores. I need you to go down into narsong trench and take it out!",g={n="Angler Shen",loc="Anglers Wharf, Krasarang Wilds"}}
d[30701]={r={{n="+1 Fishing skill"}},mo=114000,rep="+500 The Anglers",o="Kill Viseclaw Fishers on the beach and return with 16 eyes to make some yummy soup. *Viseclaw Fisher Eye (16)",de="Nothing tastes quite like viseclaw soup. It's a krasarang specialty! I was just about to start up on a new batch when I realized I am missing a key ingredient, the eyes! I need you to kill the viseclaw fishers on the beach and return with their eyes for the soup!",g={n="Fo Fook",loc="Anglers Wharf, Krasarang Wilds"}}
d[30716]={mo=198450,rep="+250 August Celestials",o="Touch 3 Spirits of the Crane. *Spirit of the Crane found x3",de="Chi-Ji is always with us. Even when he is not here in the Cradle, pieces of his spirit run through the forests and beaches of the island, watching us and testing us. Prove your dexterity in the eyes of Chi-Ji, . Find and catch the spirits of the crane.",g={n="Kuo-Na Quillpaw",loc="Cradle of Chi-Ji, Krasarang Wilds"}}
d[30717]={mo=198450,rep="+250 August Celestials",o="Obtain 10 Gifts of the Great Crane. *Gift of the Great Crane (10)",de="The cranes of Krasarang are a gift from Chi-Ji. Even the very feathers they leave behind are a gift for us to appreciate. We use these feathers to adorn our garments and to fletch arrows. But first... they must be gathered.",g={n="Yan Quillpaw",loc="Cradle of Chi-Ji, Krasarang Wilds"}}
d[30718]={mo=198450,rep="+250 August Celestials",o="Duel 10 Students of Chi-Ji. *Student of Chi-Ji dueled (10)",de="Our order prides itself on excellence in combat. We hone these combat skills by dueling one another, here on the Cradle of Chi-Ji. Prove yourself in the eyes of the Red Crane. Venture south, into the center of the island, and duel with your fellow students.",g={n="Thelonius",loc="Cradle of Chi-Ji, Krasarang Wilds"}}
d[30725]={mo=247200,rep="+350 August Celestials",o="Defeat Ellia Ravenmane at the Angkhal Pavilion. *Ellia Ravenmane defeated",de="We regularly organize one-on-one duels with trainees that we think are well-suited for one another. We have found one such trainee for you, . Her name is Ellia Ravenmane. This will be her first duel, too. She will be waiting for you at the pavilion just to the south of here.",g={n="Thelonius",loc="Cradle of Chi-Ji, Krasarang Wilds"}}
d[30726]={mo=247200,rep="+350 August Celestials",o="Defeat Minh Do-Tan. *Minh Do-Tan defeated",de="Your next challenger is another relatively new trainee. His name is Minh Do-Tan, and he has won his last two matches. He will be waiting for you near the crane statue to the south.",g={n="Thelonius",loc="Cradle of Chi-Ji, Krasarang Wilds"}}
d[30727]={mo=247200,rep="+350 August Celestials",o="thumb|Ellia Ravenmane. Defeat Ellia Ravenmane near the base of the Pedestal of Hope. *Ellia Ravenmane defeated",de="Ellia Ravenmane requested a rematch with you. She seems to identify you as her \"rival\". We discourage rivalries here within the Cradle of Chi-Ji, but we rarely decline a rematch request. You will find Ellia near the Pedestal of Hope, on the island's eastern side.",g={n="Thelonius",loc="Cradle of Chi-Ji, Krasarang Wilds"}}
d[30728]={mo=247200,rep="+350 August Celestials",o="Defeat Fat Long-Fat at the top of Angkhal Pavilion. *Fat Long-Fat defeated",de="You have been matched with a... special trainee. His name is Fat Long-Fat. Fat Long-Fat... operates outside of the normal rules of combat. He does not fight every day, and when he does, he chooses his competitor. Today, for some reason... he has selected you. You will find him atop Angkhal Pavilion.",g={n="Thelonius",loc="Cradle of Chi-Ji, Krasarang Wilds"}}
d[30729]={mo=247200,rep="+350 August Celestials",o="Defeat Julia Bates. *Julia Bates defeated",de="We welcome all kinds here within the Cradle, as long as they recognize and subscribe to the ideologies of the Red Crane. One of our new, more exotic trainees comes from the human kingdoms to the northeast. She goes by the rather foreign-sounding name of Julia Bates. She is your next challenger. You will find her on the island's western shore.",g={n="Thelonius",loc="Cradle of Chi-Ji, Krasarang Wilds"}}
d[30730]={mo=247200,rep="+350 August Celestials",o="Defeat Dextrous Izissha. *Dextrous Izissha defeated",de="Jinyu normally avoid our order, but every few years, we find one that subscribes to the way of the Crane. One such jinyu is Dextrous Izissha. Izissha is your next challenger. He waits for you on the island's southwestern shore.",g={n="Thelonius",loc="Cradle of Chi-Ji, Krasarang Wilds"}}
d[30731]={mo=247200,rep="+350 August Celestials",o="Defeat Kuo-Na Quillpaw. *Kuo-Na Quillpaw defeated",de="Most of the duels within the Cradle take place between two trainees. Rarely, when a trainee exhibits a rare amount of skill, they will have an opportunity to duel their trainer. Today you duel against Kuo-Na. She wil be waiting for you at the Pedestal of Hope.",g={n="Thelonius",loc="Cradle of Chi-Ji, Krasarang Wilds"}}
d[30732]={mo=247200,rep="+350 August Celestials",o="Defeat Ellia Ravenmane at Dome Balrissa. *Ellia Ravenmane defeated",de="Your \"rival\" has appeared again. Ellia Ravenmane has been avoiding her duities on the island, instead focusing on personal training, with the intent to defeat you in battle. \"I will destroy ,\" she said. I have honored her request for a rematch, but I will be keeping a close eye on her. Her motives may be shifting in a dangerous direction.",g={n="Thelonius",loc="Cradle of Chi-Ji, Krasarang Wilds"}}
d[30733]={mo=247200,rep="+350 August Celestials",o="Defeat Tukka-Tuk *Tukka-Tuk defeated",de="You are making a name for yourself, . I received a challenge from one of our more skilled competitors. He believes you are not as strong as you seem. His name is Tukka-Tuk, the hozen. If you've ever fought against hozen before, you know that their battle acumen belies their apparent juvenility. Good luck.",g={n="Thelonius",loc="Cradle of Chi-Ji, Krasarang Wilds"}}
d[30734]={mo=247200,rep="+350 August Celestials",o="Defeat Huck Wheelbarrow. *Huck Wheelbarrow defeated",de="Usually our trainees are adventurers like yourself, or monks from Tian Monastery, or occasionally retired Shado-Pan. Very rarely, though, we will greet trainees that have no fighting experience whatsoever. Huck Wheelbarrow is one such trainee. He has requested a duel with you. Look for him on the island's western shore.",g={n="Thelonius",loc="Cradle of Chi-Ji, Krasarang Wilds"}}
d[30735]={mo=247200,rep="+350 August Celestials",o="Defeat Mindel Sunspeaker. *Mindel Sunspeaker defeated",de="Our highest-ranked trainee is an outsider like you. It is both strange and exciting to live in a time when so many foreigners have embraced the way of the Crane. Your challenger's name is Mindel Sunspeaker, and he awaits you within Angkhal Pavilion.",g={n="Thelonius",loc="Cradle of Chi-Ji, Krasarang Wilds"}}
d[30736]={mo=247200,rep="+350 August Celestials",o="Defeat Yan Quillpaw at the Pedestal of Hope. *Yan Quillpaw defeated",de="You have already defeated Kuo-Na Quillpaw. You have not yet fought her brother, Yan. He will meet you at the Pedestal of Hope, and he will not hold back. His reputation as a trainer is at stake.",g={n="Thelonius",loc="Cradle of Chi-Ji, Krasarang Wilds"}}
d[30737]={mo=247200,rep="+350 August Celestials",o="Defeat Fat Long-Fat atop Dome Balrissa. *Fat Long-Fat defeated",de="Fat Long-Fat has requested another match with you. I find this strange. And concerning. He will be waiting atop the Dome Belrissa.",g={n="Thelonius",loc="Cradle of Chi-Ji, Krasarang Wilds"}}
d[30738]={mo=247200,rep="+350 August Celestials",o="Defeat Thelonius. *Thelonius defeated",de="When we last spoke, I promised to tell you the secret of Fat Long-Fat. I still plan to tell you that secret... after I determine your worth. I will meet you on the western shore, and we will duel.",g={n="Thelonius",loc="Cradle of Chi-Ji, Krasarang Wilds"}}
d[30739]={mo=247200,rep="+350 August Celestials",o="Defeat Ellia Ravenmane atop the Pedestal of Hope. *Ellia Ravenmane defeated",de="Ellia Ravenmane, your rival, has returned. She demands that you meet her atop the Pedestal of Hope. You need to understand, ... something horrible has happened to her. She has changed. You will see for yourself when you arrive at the pedestal. Good luck, .",g={n="Thelonius",loc="Cradle of Chi-Ji, Krasarang Wilds"}}
d[30740]={mo=247200,rep="+350 August Celestials",o="thumb|Champion of Chi-Ji. Defeat a Champion of Chi-Ji. *Champion of Chi-Ji defeated",de="While you will always hold a place of honor among our order, you are still welcome to participate in our duels. One of our current champions awaits you in the Dome Balrissa. I know that they would be honored to duel with you.",g={n="Thelonius",loc="Cradle of Chi-Ji, Krasarang Wilds"}}
d[30753]={r={{n="+1 Fishing skill"}},mo=114000,rep="+500 The Anglers",o="Kill a frenzied reef shark with your bare hands. *Frenzied Reef Shark slain",de="There is only one way to kill sharks where I come from, with your bare hands! I dumped a good amount of chum in the water just off the dock here, this place should be crawling with the local reef sharks in no time. Hop the first one you see and take it out!",g={n="John \"Big Hook\" Marsock",loc="Anglers Wharf, Krasarang Wilds"}}
d[30754]={r={{n="+1 Fishing skill"}},mo=114000,rep="+500 The Anglers",o="Collect 7 Suncrawlers in the forest north of Anglers Wharf. *Suncrawler x7",de="Certain fish are only attracted to bright lights. The forest north of here is home to a local pandaren firefly called a suncrawler. You should be able to find them on the base of the tree trunks all around that area. Bring me back a handful of them and I can use them for bait!",g={n="John \"Big Hook\" Marsock",loc="Anglers Wharf, Krasarang Wilds"}}
d[30763]={r={{n="+1 Fishing skill"}},mo=114000,rep="+500 The Anglers",o="Fish up 5 Wolf Piranha from the Krasarang River in Krasarang Wilds. *Wolf Piranha (5)",de="Certain fish are very difficult to catch. The wolf piranha falls squarely into this category. Lucky for me that you showed up! Put those fishing skills to the test and bring me back a few from the krasarang river due northwest of here.",g={n="Fo Fook",loc="Anglers Wharf, Krasarang Wilds"}}
d[30821]={mo=106000,o="Speak with Kota Kon at Kota Basecamp to ride her, then kill 100 Hozen along The Burlap Trail. *Burlap Trail Hozen Slain x100 *Flask of Kafa (provided)",de="Alright, it's time to take Kota Kon out for her \"walk.\" We brewed two fresh pots of kafa just for her and she's all fueled up!",g={n="Nephew Burrberry",loc="Kota Peak, Kun-Lai Summit"}}
d[30879]={mo=198450,rep="+250 August Celestials",o="Defeat Brewmaster Chani. *Defeat Brewmaster Chani",de="Welcome, Challenger, to my tournament of champions! Today we test the strengths of Pandaria's most dedicated heroes. Your first opponent awaits you under the eastern gazebo. Defeat her, and you may proceed to the next round. Fight with strength, fight with honor.",g={n="Xuen",loc="Various"}}
d[30880]={mo=198450,rep="+250 August Celestials",o="Defeat the Streetfighter. *Defeat The Streetfighter",de="Welcome, challenger, to my tournament of champions! Today we test the strengths of Pandaria's most dedicated heroes. Your first opponent awaits you under the eastern gazebo. Defeat her, and you may proceed to the next round. Fight with strength, fight with honor.",g={n="Xuen",loc="Various"}}
d[30881]={mo=198450,rep="+250 August Celestials",o="Defeat Clever Ashyo and Ken-Ken. *Defeat Clever Ashyo *Defeat Ken-Ken",de="You may know your next challengers. They were arguing fiercely when they arrived, so I have charged them with fighting side by side. This will teach them the strength of friendship, and possibly entertain me in the process. Go to the north eastern arena and face this jinyu and hozen. Do not be gentle, they need to learn to work together.",g={n="Xuen",loc="Various"}}
d[30882]={mo=198450,rep="+250 August Celestials",o="Defeat Kang Bramblestaff. *Defeat",de="Your next challenger is a Bramblestaff. Strength is in their blood. I remember a full century of only Bramblestaff champions. No pressure, little . Go to the eastern arena north of here and face this young challenger. See first hand if strength is earned or inherited.",g={n="Xuen",loc="Various"}}
d[30883]={mo=198450,rep="+250 August Celestials",o="Defeat The Wrestler. *Defeat The Wrestler",de="Your next challenger is a favorite of mine. He draws strength from raw force and determination. Plus he has a mask. Face him in the western arena when you are ready, and good luck.",g={n="Xuen",loc="Various"}}
d[30885]={mo=198450,rep="+250 August Celestials",o="Defeat Master Boom Boom. *Defeat",de="Your next challenger found his strength on a beach. Particularly in a box labeled \"dynamite.\" He proves however that found strength can be as deadly as personal strength. When you are ready, face this Master Boom Boom in the Western Arena.",g={n="Xuen",loc="Various"}}
d[30902]={mo=198450,rep="+250 August Celestials",o="Defeat Master Windfur. *Defeat Master Windfur",de="Well done, challenger. You have reached the final round. Your last opponent is a powerful master of the winds. He has defended his people for many years and stood as champion on more than one occasion. Face this Master Windfur in the main arena when you are ready. And challenger... good luck.",g={n="Xuen",loc="Various"}}
d[30907]={mo=198450,rep="+250 August Celestials",o="Defeat Hackiss, Healiss and Tankiss. *Defeat Hackiss *Defeat Healiss *Defeat Tankiss",de="And now the final round. I have selected three challengers for you to face. This may seem unfair... to a weakling. You are not a weakling, correct? Go to the main temple, stand in the grand arena, and face these three challengers. Prove you are stronger than their combined power! Good luck, Challenger!",g={n="Xuen",loc="Various"}}
d[30952]={mo=198450,rep="+350 August Celestials",o="Defeat 12 Sra'thik attackers at Niuzao Temple. *Sra'thik attacker slain (12)",de="The mantid continue to attack us. Their numbers ebb and flow, but they do not stop. It is no matter. The yak is stamina embodied. We will not bend to them. We will defend his home forever. Will you help us?",g={n="Ogo the Elder",loc="Niuzao Temple, Townlong Steppes"}}
d[30953]={mo=198450,rep="+250 August Celestials",o="Heal 8 Wounded Niuzao Sentinels above 50% health. You may use the Yak's Milk Flasks or your own healing spells and abilities. *Niuzao Sentinel healed x8 *Yak's Milk Flask (provided)",de="Our sentinels can fight for days on end, but even they have their limits. Since the mantid swarm began, too many of them have pushed themselves beyond their abilities. Please, aid them in whatever way you can. If you are unable to heal them yourself, you may give them some of this. A mouthful of nutritious yak's milk will give them the strength they need.",g={n="Yak-Keeper Kyana",loc="Niuzao Temple, Townlong Steppes"}}
d[30954]={mo=114000,rep="+250 August Celestials",o="thumb|Sra'thik Weapon Obtain 10 Sra'thik Weapons. *Sra'thik Weapon (10)",de="This is no time to hold to tradition. Our masons' calloused hands bleed and tremble. Our blacksmiths cannot forge weapons as quickly as our sentinels can break them. It is time to fight smart. Many of the mantid come bearing weapons, and when they die, they simply leave them on the battlefield. It would be a shame to see them go to waste.",g={n="Ogo the Younger",loc="Niuzao Temple, Townlong Steppes"}}
d[30955]={mo=198450,rep="+250 August Celestials",o="thumb|Niuzao Strongarm. thumb|Niuzao Food Supply. Obtain 6 stores of Niuzao Food. Your Niuzao Strongarm will carry the food for you. *Gather Food for Niuzao (6)",de="Our patron Niuzao is a mountain on wheels... very difficult to move, even more difficult to stop. My point: once we get him moving, the mantid will have their arms full trying to slow him down. The easiest way to get him moving is to put food in front of him. Luckily for us, food in our temple is plentiful... even in wartime. I will send one of my strongarms with you, to shoulder the load.",g={n="High Adept Paosha",loc="Niuzao Temple, Townlong Steppes"}}
d[30956]={mo=247200,rep="+350 August Celestials",o="thumb| thumb| Defeat 25 Sra'thik attackers at Niuzao Temple. *Sra'thik attacker slain x25",de="Today's mantid swarm is among the worst I've seen. We are lucky to have join us in battle. Help him, . Return to the courtyard, and join in the defense of our temple.",g={n="Ogo the Elder",loc="Niuzao Temple, Townlong Steppes"}}
d[30957]={mo=198450,rep="+250 August Celestials",o="Defeat 4 Sra'thik Kunchong. *Sra'thik Kunchong slain (4)",de="I command the sentinels of Niuzao. Every defender out there can hold his own against the mantid swarm. The kunchong, however, are something different. They are massive, violent, and without a question the biggest threat to my sentinels' lives. Only Niuzao stands a chance against them. Niuzao... and perhaps you.",g={n="Sentinel Commander Qipan",loc="Niuzao Temple, Townlong Steppes"}}
d[30958]={mo=198450,rep="+250 August Celestials",o="thumb|Loose Brick Throw 10 Loose Stones up to Niuzao Stonemasons. *Loose Brick (10)",de="Niuzao's appearance on the battlefield is a blessing... in more ways than one. With the distraction that he's caused, our stonemasons have seized the opportunity to build up our crumbling walls. They could use your help. Toss any loose bricks you find up their way. And hurry! Niuzao will not rampage forever.",g={n="High Adept Paosha",loc="Niuzao Temple, Townlong Steppes"}}
d[30959]={mo=198450,rep="+250 August Celestials",o="thumb|Sra'thik Fleshrender. Destroy 3 Sra'thik War Wagons. *Sra'thik War Wagon exploded x3 *Pot of Fire (provided)",de="The mantid now surround the Temple with their infernal war wagons. The sooner we are rid of those things, the better. You could destroy them with your own weapons and spells, but this will work much faster. Beware of retaliation from mantid that remain be inside the war wagon when it explodes. In fact, I'd stay as far away from those things as possible.",g={n="Ogo the Younger",loc="Niuzao Temple, Townlong Steppes"}}
d[31024]={mo=198450,rep="+130 The Klaxxi",o="Collect 4 Meaty Turtle Haunches. *Meaty Turtle Haunch (4)",de="As Kovok grows, he will require equal parts discipline and reward. I lack no shortage of discipline, but our supply of meat is almost empty. To the south, you will find turtles roaming north of the Lake of Stars and Kypari Zar. Hunt them. Kovok likes the taste of their flesh.",g={n="Kaz'tik the Manipulator",loc="Various"}}
d[31039]={mo=198450,rep="+250 Shado-Pan",o="thumb|Shan'ze Serpentbinder. thumb|Shan'ze Beastmaster. Kill 12 Shan'ze Serpentbinders or Shan'ze Beastmasters. *Shan'ze Serpentbinders or Beastmasters slain (12)",de="Our scouts have discovered a heavy mogu force at Shan'ze Dao to the northwest. The island was supposedly uninhabited, so their presence is disturbing news. Even more disturbing is the fact that they are performing sinister experiments on the island. I need a capable to check out the situation. The Shan'ze are likely to give you trouble, and if they do, kill them.",g={n="Ban Bearheart",loc="Various"}}
d[31040]={mo=198450,rep="+250 Shado-Pan",o="thumb|Darkwoods Pixie. thumb|Darkwoods Charmer. Kill 30 Darkwoods Pixies or Darkwoods Charmers. *Darkwoods Sprites or Darkwoods Charmers slain (30)",de="The Darkwoods sprites on Shan'ze Dao have fallen to the mogu's domination. The once sly tricksters are now the full servants of the Shan'ze. They grow bolder each day, stealing and killing to satisfy their masters. They must be eliminated, but be careful. They may look harmless, but they are actually quite vicious.",g={n="Ban Bearheart",loc="Various"}}
d[31041]={mo=198450,rep="+250 Shado-Pan",o="thumb|Shiny Egg Collect 8 Cloudrunner Eggs. *Cloudrunner Egg (8)",de="Eggs. Yes, you heard me right. I said eggs, and these aren't for eating. Have you ever seen a cloud serpent egg? These rare eggs look like jewels, and were once worth their weight in solid gold. Shan'ze Dao to the north normally teems with wild cloud serpents, but the mogu and the sprites have their eggs on lock-down. We need to save as many of these precious eggs as we can. I'm counting on YOU, .",g={n="Ban Bearheart",loc="Various"}}
d[31042]={mo=198450,rep="+250 Shado-Pan",o="Collect 4 Onyx Hearts. *Onyx Heart (4)",de="The Shan'ze Serpentbinders dominate the minds of wild cloud serpents, but they also create their own dark creatures from stone, metal, blood, and ancient sorcery. Their creations, the Onyx Stormclaws, guard the island to the northwest. I wish to study the magic binding these creatures. Bring me their hearts, so that I can better understand what sorcery we are up against.",g={n="Ban Bearheart",loc="Various"}}
d[31043]={mo=198450,rep="+250 Shado-Pan",o="Collect 8 Shan'ze Tablets. *Shan'ze Tablet (8)",de="It is said that Shan'ze Dao was once home to a great mogu temple. There, the Shan'ze studied and practiced the art of subjugating the dead or inanimate. Much of their knowledge still remains on the island to the northwest, buried among the ruins. We need to get our hands on their knowledge - both to keep it out of their hands, and to understand the nature of their experiments.",g={n="Ban Bearheart",loc="Various"}}
d[31046]={mo=198450,rep="+250 Shado-Pan",o="thumb|Cloudrunner Hatchlings. Free 20 Cloudrunner Hatchlings. *Cloudrunner Hatchlings freed (20)",de="I have seen the cruel experiments that the Shan'ze are performing on their island to the northwest. The Shan'ze raise baby serpents from the egg. They keep the young in tiny cages, surrounded by squalor and filth. The cruelest gaolers starve and torture them. We must save as many hatchlings as we can. You have my full permission to punish any mogu that gets in your way!",g={n="Ban Bearheart",loc="Various"}}
d[31047]={mo=198450,rep="+250 Shado-Pan",o="Free 6 Wild Cloudrunners from their chains. *Wild Cloudriders freed (6)",de="Do you know the story of the great cloud serpents of Pandaria, ? Someday you must hear it. Unfortunately, there is no time to tell it now. What you must know is that the wild cloudrunner serpents of Townlong are in trouble. The mogu are capturing wild serpents and corrupting their minds, bending them to their sinister will. Go to Shan'ze Dao, to the northwest. Free the adult serpents from their chains. Save them!",g={n="Ban Bearheart",loc="Various"}}
d[31049]={mo=198450,rep="+250 Shado-Pan",o="thumb|Sprite den entrance. thumb|Darkwoods Faerie. Kill the Darkwoods Faerie. *Darkwoods Faerie slain",de="The sprites of Shan'ze Dao have always been capricious tricksters, but now they have fallen under the mogu's influence. Even as we speak, they gather under a new leader. We cannot allow this to happen. Their mischievous pranks were one thing, but united, their dark magic is too powerful and too dangerous to comprehend. Take out their leader before it is too late."}
d[31058]={mo=247200,o="Defeat Captain Ook. *Captain Ook slain",de="Pirates! Our shores have been scoured by the most ill-tempered, ill-mannered, ill-hygienic, and ill-good hozen that ever was found in Pandaria. And to make matters worse, they claim to serve the legendary Captain Ook! We see them every night partying and brewing punch on their island Unga Ingoo. I say we take their brew for a change! I think I can even improve their mix. Gather up some friends and meet me on the southern side of Unga Ingoo. It is time for a Brew Run!",g={n="Brewmaster Bo",x=0.522,y=0.756,loc="Various"}}
d[31061]={mo=198450,rep="+250 Shado-Pan",o="Use the Bronze Claws to mount 8 Shan'ze Cloudrunners. Attack them to free them of their corruption. *Shan'ze Cloudrider saved (8) *Bronze Claws (provided)",de="Shan Bu, the leader of the Shan'ze, is performing some kind of dark ritual at the summit of the island to the northwest. We believe that the subjugated Shan'ze Cloudrunners are powering the spell. How, we still do not know. We believe that the Shan'ze Cloudrunners can still be saved from the corruption that taints them. Take these bronze claws. Use them to mount the back of a Shan'ze Cloudrunner. Attack them. Beat some sense back into their heads!"}
d[31109]={mo=198450,rep="+130 The Klaxxi",o="Slay 40 Shek'zeer Mantid in the Clutches of Shek'zeer. Speak with Kil'ruk the Wind-Reaver for an air-drop. *Shek'zeer Mantid Slain (40)",de="The Empress continues to amass her forces. Without intervention, they WILL overrun that wall - even if it means smothering it in the corpses of a million swarmborn. Let us find a better place for those corpses. Let me know when you are ready to depart for the clutches - I will gladly drop you in from above.",g={n="Kil'ruk the Wind-Reaver",loc="Various"}}
d[31111]={mo=198450,rep="+130 The Klaxxi",o="Kill 6 Zan'thik Impalers and 6 Zan'thik Manipulators in Zan'vess. *Zan'thik Impaler slain (6) *Zan'thik Manipulator slain (6)",de="The warriors of Zan'vess are some of the most feared and respected in the empire, for good reason. Impalers are unmatched in their mastery of the polearm - no doubt Malik trained among the Zan'thik in his time. Their manipulators command terrifying sonic power with the ease and subtlety of a breath. Both will need to be dealt with.",g={n="Kil'ruk the Wind-Reaver",loc="Various"}}
d[31113]={mo=198450,rep="+250 Shado-Pan",o="thumb|Gai-Cho Yaungol. thumb|Gai-Cho Earthtalker. thumb|Gai-Cho Pitchthrower. Kill 16 Gai-Cho Yaungol, Earthtalkers or Pitchthrowers. *Gai-Cho Yaungol, Earthtalkers, or Pitchthrowers Slain (16)",de="The Yaungol are a constant nuisance, but the group at Fire Camp Gai-Cho, to the northeast, conspired with the Osul yaungol in their recent incursion into Kun-Lai. We cannot allow such an incursion to go unpunished. Go, attack Fire Camp Gai-Cho. We need to make sure they remain occupied, so that they cannot rise up and threaten The Ox Gate again.",g={n="Master Snowdrift",loc="Townlong Steppes"}}
d[31114]={mo=198450,rep="+250 Shado-Pan",o="thumb|Deadtalker Corpsedefiler. thumb|Deadtalker Crusher. thumb|Defiled Spirit. Kill 8 Deadtalker Corpsedefilers and 1 Deadtalker Crusher. *Deadtalker Corpsedefiler slain (8) *Deadtalker Crusher slain",de="We have always left the Deadtalkers alone. For so long, they were just responsible for maintaining the sacred burial grounds of the yaungol tribes. Now, though, they are practicing dark magic, defiling the corpses of their former clanmates... I know not where the learned those dark magics, or why they no longer treat their dead with respect, but we do not have time to find out. We need to stop them.",g={n="Master Snowdrift",loc="Townlong Steppes"}}
d[31116]={mo=198450,rep="+250 Shado-Pan",o="thumb|Defiled Spirit. Return 8 spirits to their remains at the Deadtalker's Plateau in Townlong Steppes. *Spirits returned (8)",de="The spirits that the yaungol are entrapping from the remains of their ancestors still have a bit of the essence of life within them. If you defeat the spirits in battle, you can collect that essence as spirit dust, and then return it to their corpses, which will send them, finally, to the next life. This is the only way to set right what the Deadtalkers have done. It will also help keep us safe.",g={n="Master Snowdrift",loc="Townlong Steppes"}}
d[31116]={mo=198450,rep="+250 Shado-Pan",o="Collect a Scroll of Spiritbinding Rites from the yaungol at Deadtalker's Plateau. *Ciphered Scroll",de="We need to understand what went wrong with the Deadtalkers. For so many years, the Deadtalkers were simply responsible for maintaining the burial grounds and holding funerals for fallen warriors. From a recent raid, we've recovered a tablet from the grounds that is clearly written using a cipher, but it isn't one we've encountered before. If you can gather a ciphered scroll from one of the Deadtalkers, we can begin to put together the cypher and understand what's happened.",g={n="Master Snowdrift",loc="Townlong Steppes"}}
d[31117]={mo=198450,rep="+250 Shado-Pan",o="Kill Uruk at Deadtalker's Plateau in Townlong Steppes. *Uruk slain",de="Uruk is the Deadtalker of the Townlong yaungol. Your mission will not be truly complete until you defeat him. Go to it!"}
d[31119]={mo=198450,rep="+250 Shado-Pan",o="thumb|Gai-Cho Battlefield. Use Highly Explosive Yaungol Oil Barrels to kill 100 mantid or yaungol on the Gai-Cho Battlefield. *Gai-Cho Battlefield Combatants slain (100)",de="The mantid are our enemies. As are the yaungol at Fire Camp Gai-Cho. It is fortunate, then, that they are also each other's enemies. Mantid from Kri'vess constantly attack the Gai-Cho yaungol, who hold them off at their front gates. I want you to wreak havoc. \"Borrow\" some highly explosive oil barrels from camp Gai-Cho, and toss them down onto the battlefield from the air. I don't care which ones you kill, just kill a lot of them.",g={n="Master Snowdrift",loc="Townlong Steppes"}}
d[31120]={mo=198450,rep="+250 Shado-Pan",o="Kill Cheng-Bo at Fire Camp Gai-Cho in Townlong Steppes. *Cheng Bo slain",de="Cheng Bo is the Warbringer of Fire Camp Gai-Cho. While you've made a dent in their operations, you now have an opportunity to strike a major blow. Slay the Warbringer!"}
d[31131]={mo=99250,o="Speak to He Softfoot at Whitepetal Lake.",de="Reports suggest that things are quiet at Whitepetal Lake today, but I've dispatched Ren Firetongue and He Softfoot to make sure it stays they way. If you want to aid the effort further, head to the west to the lake, meet up with He, and help him keep things secure from any hostile threats.",g={n="Leven Dawnblade",loc="Golden Pagoda, Vale of Eternal Blossoms"}}
d[31136]={r={{n="Treasures of the Vale"}},mo=247200,rep="+200 Golden Lotus",o="Kill General Temuja. *General Temuja slain",de="Scouts bring me reports of a powerful Imperion that slipped through our lines in the south and is now heading for the road in the eastern vale. I need someone I can trust to stop it. Find it and kill it quickly, .",g={n="Leven Dawnblade",loc="Golden Pagoda, Vale of Eternal Blossoms"}}
d[31194]={mo=198450,rep="+600 Order of the Cloud Serpent",o="Kill the Slitherscale Lizard-Lord. *Slitherscale Lizard-Lord slain",de="The Slitherscale take orders from their leader, the Slitherscale Lizard-Lord. He can be found celebrating his victories on the southeastern corner of Windward Isle. If we can destroy this leader, we can deal their tribe a great blow. Without their lord, the Slitherscale will think twice before attacking the gentle cloud serpents of the east.",g={n="Elder Anli",x=0.577,y=0.449,loc="Arboretum, Jade Forest"}}
d[31196]={mo=198450,rep="+250 Shado-Pan",o="Kill any 15 non-elite mantid near Sra'vess. *Lesser Sra'thik mantid slain (15)",de="The mantid outnumber us quite badly. Hundreds of them for each of us. And, they surround us on two sides - at Gao-Ran in the south we're holding them off, but to the west, on the island they call Sra'vess, they continue to mass unabated. We're not stupid. We're not going to launch a full scale attack on them. We can't sustain an intense battle on multiple fronts. Instead, we're going to send you, and one of our Wu Kao, to do some dirty work. Sounds fun, doesn't it?",g={n="Ling of the Six Pools",loc="Shado-Pan Garrison, Townlong Steppes"}}
d[31197]={mo=198450,rep="+250 Shado-Pan",o="Kill any 4 elite mantid at Sra'vess. *Greater Sra'thik mantid slain (4)",de="Killing the smaller mantid works mostly as a distraction. It forces them to replenish their numbers before they consider any serious offensive. The big ones, though - we kill a few of those, and we really disrupt operations on the island. That buys ourselves a substantial amount of time. With mantid, it's like their size is directly proportional to their importance in the empire. So kill some of the big ones for me, while you're out there.",g={n="Ling of the Six Pools",loc="Shado-Pan Garrison, Townlong Steppes"}}
d[31198]={mo=198450,rep="+250 Shado-Pan",o="thumb|Central idol. thumb|Eastern idol. thumb|Western idol. Destroy the Southern, Central, Eastern and Western Idols at Sra'vess. *Southern idol *Western idol *Central idol *Eastern idol",de="The mantid have statues built on Sra'vess. We don't know exactly what they use them for. They may have some sort of religious significance, or maybe they assist with their sonic communication. When you fight your opponent, you don't just engage them physically, you also engage them mentally. Whatever they use them for, the fact is that those statues are important to them. Which is why I want you to blow them up. Losing something important will be a substantial hit to morale.",g={n="Ling of the Six Pools",loc="Shado-Pan Garrison, Townlong Steppes"}}
d[31199]={mo=198450,rep="+250 Shado-Pan",o="thumb|Large Southern Siege Weapon. thumb|Small Northern Siege Weapon. thumb|Large Northern Siege Weapon. Destroy the four mantid siege weapons at Sra'vess in Townlong Steppes. *Large Southern Siege Weapon destroyed *Small Southern Siege Weapon destroyed *Large Northern Siege Weapon destroyed *Small Northern Siege Weapon destroyed",de="The mantid don't just attack in swarms. They're smart. They use alchemy, bombs... and what's worst, they've got siege weapons. Those have the potential to be incredibly destructive if they attack with them. We've got reports that they're building up a force of siege weapons to the west at Sra'vess. Go and destroy them.",g={n="Ling of the Six Pools",loc="Shado-Pan Garrison, Townlong Steppes"}}
d[31200]={mo=198450,rep="+250 Shado-Pan",o="thumb|Amber Vault thumb|Nutriment Cell thumb|Egg Chamber thumb|Torture Cell thumb|Slaughtering Pit Plant Shado-Pan Gas Bombs within the 5 structures on Sra'vess. *Amber Vault bombed *Nutriment Cell bombed *Egg Chamber bombed *Torture Cell bombed *Slaughtering Pit bombed *Bag of Shado-Pan Gas Bombs (provided)",de="Our alchemists have cooked up a set of gas bombs that will discourage mantid from staying anywhere that we set them off. If we plant these in the critical structures of Sra'vess, they'll need to evacuate. That should sow some chaos and delay any action from the mantid there for days. Get to it, .",g={n="Ling of the Six Pools",loc="Shado-Pan Garrison, Townlong Steppes"}}
d[31201]={mo=198450,rep="+250 Shado-Pan",o="Rescue a Shado-Pan Trainee in each of the north, central and south Kunchong feeding pits. *Shado-Pan Trainee at Northern Feeding Pit freed *Shado-Pan Trainee at Central Feeding Pit freed *Shado-Pan Trainee at Southern Feeding Pit freed",de="Our scouts have sent a very troubling report. Three of our trainees have gone missing, and our scouts found them... They've been captured by the mantid and sent to their Kunchong pits. Their Kunchong FEEDING pits. We're lucky that the Kunchong don't eat that often. I need you to get in there, give them these escape kites, and get them out!",g={n="Ling of the Six Pools",loc="Shado-Pan Garrison, Townlong Steppes"}}
d[31203]={mo=198450,rep="+250 Shado-Pan",o="Kill the Sra'thik Swarmlord at Sra'vess in Townlong Steppes. *Sra'thik Swarmlord slain",de="While we're here, we should do one more thing. The Sra'thik Swarmlord is responsible for directing the mantid forces from the air. If we leave it alive, it's going to cause trouble for the garrison. So we're not going to leave it alive. Let's take it out, ."}
d[31204]={mo=114000,rep="+250 Shado-Pan",o="thumb|Sra'thik Hivelord. Defeat the Sra'thik Hivelord. *Sra'thik Hivelord slain",de="Near the ocean, on the eastern side of Sra'vess, there is a cavern that leads to a network of caves. From there, the Sra'thik Hivelord maintains Sra'vess and plots against us. If we manage to take him out, we'll disrupt their operations for days. Let's go to it."}
d[31216]={mo=198450,rep="+130 The Klaxxi",o="Kill 200 Mantid and 3 Kunchong or Dread Behemoths while flying with Xaril the Poisoned Mind. *Speak to Xaril the Poisoned Mind *Mantid slain (200) *Kunchong or Dread Behemoths slain (3)",de="The swarm begins, Wakener! The mantid amass at the Heart of Fear. Already they fill the skies with their wings and rend the earth with their claws. They shall not stop the dark march until their bodies are laid open and bleeding upon the ground. This we shall gladly do. We will attack them from above. While I fly, use my poisons to destroy their advance. Do not mix the two serums until you are ready to attack. The reaction can be quite... violent. Speak to me when you are ready to go.",g={n="Xaril the Poisoned Mind",loc="Klaxxi'vess, Dread Wastes"}}
d[31231]={mo=114000,rep="+130 The Klaxxi",o="Slay 8 Dreadspinner Tenders in the Terrace of Gurthan. Speak with for an air-drop. *Dreadspinner Tender slain (12)",de="Back in the Terrace of Gurthan where you found me, dreadspinners continue to occupy the attention of Shado-Pan marksmen who could otherwise be thinning out this wretched swarm. Eradicate those spiders and offer some relief to the archers on that wall.",g={n="Kil'ruk the Wind-Reaver",loc="Various"}}
d[31232]={mo=114000,rep="+130 The Klaxxi",o="thumb|Gurthani Tablet Collect 8 Gurthani Tablets. *Gurthani Tablet (8)",de="My brothers speak of an ancient mogu empire that once dwelled in the ruins to the east. Once, this tribe knew untold secrets of sorcery and subjugation. I have a curious mind, Wakener, and I wish to learn of the empires that ruled after my time. Knowledge of the past will determine our future. Go search the ruins for their ancient tablets. I will study their secrets and make them our own.",g={n="Korven the Prime",loc="Various"}}
d[31233]={mo=198450,rep="+130 The Klaxxi",o="thumb|Amber Tap Collect 6 Amber Sap. *Amber Sap (6)",de="I found a grove of young amber trees to the east, Wakener. I've placed tapping devices on these trees, but I have been too busy to retrieve the sap. I need someone to find the extractors. Activate them, then bring me samples of the amber.",g={n="Korven the Prime",loc="Various"}}
d[31234]={mo=198450,rep="+130 The Klaxxi",o="Collect 1 Pristine Mire Beast Eye. *Pristine Mire Beast Eye",de="Ah! Wakener! You must help me! (You will help me, or else I will help myself to you!) I need more materials for my experiments, yes yes! (Blood and guts, hearts and brains, tongues and eyes, eyes, eyes!) To the west, I have seen creatures of mist and fog. They possess such big, round, wonderful globes! Big for seeing, round and unblinking! Go now, little Wakener. Bring me back a single pristine eye!",g={n="Rik'kal the Dissector",loc="Klaxxi'vess, Dread Wastes"}}
d[31235]={mo=114000,rep="+130 The Klaxxi",o="Use the Shado-Pan Dragon Gun to destroy 20 Dreadspinner Eggs in the Terrace of Gurthan. *Dreadspinner Egg slain (20) *Shado-Pan Dragon Gun (quest item) (provided)",de="I recovered this weapon on a recent scouting run near the wall. It would seem ideal for helping your Shado-Pan with their infestation problem in Gurthani Terrace. The more they are focused on keeping spiders off the wall, the less time they are killing fear-gripped swarmborn.",g={n="Kil'ruk the Wind-Reaver",loc="Various"}}
d[31237]={mo=198450,rep="+130 The Klaxxi",o="Stomp out 6 Eyes of the Empress around the Terrace of Gurthan. Killing anything will grant you Pheromone Tracking, helping you detect them. *Eye of the Empress slain (6)",de="If this Empress is truly possessed by fear and paranoia, she will have sent scouts to every corner of the land in order to cement her control. These scout grubs are likely everywhere, but difficult to spot with the naked eye. Better to track them by the pheromone trails they leave behind. I've already... gifted you... a reactive toxin that will reveal these trails to you for a brief time after experiencing the thrill of victory. Go now to the Terrace of Gurthan and root out these spies.",g={n="Hisek the Swarmkeeper",loc="Klaxxi'vess, Dread Wastes"}}
d[31238]={mo=198450,rep="+130 The Klaxxi",o="Bring 4 Mushan Tongues to Kaz'tik the Manipulator at Klaxxi'vess. *Mushan Tongue (4)",de="Kovok is growing at an accelerated rate, but his brain may not be able to keep up. He'll require a special diet to ensure that he does not outgrow the capacity to control his own body. Mushan tongue is rich in the nutrients that promote brain growth in kunchong, but they normally eat the beasts whole and fill up quickly. If we feed Kovok only mushan tongues every couple of days or so, it should balance out his growth. Greatback mushan graze the hills east of here, near the Gurthani Terrace.",g={n="Kaz'tik the Manipulator",loc="Various"}}
d[31240]={mo=99250,o="Speak to Anji Autumnlight at the Ruins of Guo-Lai.",de="Anji came by and asked for you. Said she was heading to the northeast ruins. Oh, Anji, such a fiery spirit, that girl! Probably better for your long-term health if you not keep her waiting.",g={n="Ren Firetongue",loc="Ruins Rise, Vale of Eternal Blossoms"}}
d[31242]={mo=99250,o="Speak to Che Wildwalker at Mistfall Village.",de="My scouts have spotted no mogu near Mistfall Village today, but I've been hearing of some troubles with local wildlife and spirits in the graveyard. I dispatched Che to assess the situation, but he'll most likely need your help. Find your way southwest to the village and meet Che there. Do what you can.",g={n="Leven Dawnblade",loc="Golden Pagoda, Vale of Eternal Blossoms"}}
d[31243]={mo=99250,o="Speak to Sun Tenderheart at Mistfall Village.",de="Mogu have been sighted at Mistfall Village to the southwest. I dispatched Rook and Sun immediately, but I need another capable hand there as soon as possible. Don't delay. The villagers need you.",g={n="Leven Dawnblade",loc="Golden Pagoda, Vale of Eternal Blossoms"}}
d[31244]={mo=99250,o="Speak to Leven Dawnblade at the Ruins of Guo-Lai.",de="Leven came by in quite a huff! Said something about mogu in the ruins. Best be off to find him, I think. Angry Leven is not a fun Leven.",g={n="Ren Firetongue",loc="Ruins Rise, Vale of Eternal Blossoms"}}
d[31245]={mo=99250,o="Speak to Che Wildwalker at Mistfall Village.",de="Che stopped by on the way to the village and ask if I'd seen you. I told him no. You can go see him if you want. But now you're not obligated to see him! I am so marvelously considerate, am I not?",g={n="Ren Firetongue",loc="Ruins Rise, Vale of Eternal Blossoms"}}
d[31246]={mo=99250,o="Speak to Rook Stonetoe at Mistfall Village",de="I can see smoke from the village. And it's not my fault this time! Best go and help.",g={n="Ren Firetongue",loc="Ruins Rise, Vale of Eternal Blossoms"}}
d[31248]={mo=99250,o="Speak to Anji Autumnlight at the Ruins of Guo-Lai.",de="I've instructed Anji and Kun to resume investigation of the Ruins of Guo-Lai. We have no reports of any significant mogu presence there today, but it seems to be one of their central interests here in the Vale, and want it under thorough watch considering their attack on the lake. That's why I'm sending you as well. Head west, past the lake, to the ruins. Anji will instruct you further.",g={n="Leven Dawnblade",loc="Golden Pagoda, Vale of Eternal Blossoms"}}
d[31267]={mo=198450,rep="+130 The Klaxxi",o="Kill 6 Mistblade Rippers. *Mistblade Ripper slain (6)",de="Korven has told me of his findings. There is an enormous amber deposit sitting at the bottom of the Lake of Stars. Unfortunately, a hostile saurok tribe lives at the edge of the lake, and revere the amber as their own. They will not allow us to enter their territory easily. Go south to the lake. Kill the Mistblade saurok, so that we can more easily harvest the nearby amber.",g={n="Kil'ruk the Wind-Reaver",loc="Various"}}
d[31268]={mo=198450,rep="+130 The Klaxxi",o="Collect 3 Amber-Encrusted Brains from Ik'thik Amberstingers. *Amber-Encrusted Brain (3) *Sonic Emitter (provided)",de="Far to the south, the swarm breeds weapons of destruction - enormous, nearly unbreakable amber scorpions. Like all other creatures, they are subject to manipulation, but unlike other creatures, they have not yet submitted to my mind control. It appears that further research is necessary before I can dominate them for our own purposes. I must study their brains, and you must retrieve some specimens for me. Take this sonic emitter. I have found it to be quite effective against the beasts.",g={n="Kaz'tik the Manipulator",loc="Various"}}
d[31269]={mo=198450,rep="+130 The Klaxxi",o="Kill the Mistblade Scale-Lord. *Mistblade Scale-Lord slain",de="The saurok at the Lake of Stars take their orders from their Scale-Lord, a vicious, merciless leader who guards his territory fiercely. If we can eliminate this leader, then we can gain access to the enormous amber lode beneath the lake. Go. Their leader gives his orders from his underground dwelling, at the southern edge of the lake.",g={n="Korven the Prime",loc="Various"}}
d[31270]={mo=198450,rep="+130 The Klaxxi",o="Kill 15 Horrorscale Scorpid. *Horrorscale Scorpid slain (15)",de="When we discovered the sha influence at Kypari Zar, I had hoped the corruption could still be cleansed. Unfortunately, the Klaxxi Council has confirmed that the sha of fear's corruption is deep-seated, and continues to spread. To the south, I have observed some of the local wildlife consumed by an unnamed terror. The sha can warp and twist its victims into unimaginable horrors. We must stop the corruption before it becomes worse. Seek out the sha-infected Horrorscale Scorpids. Eliminate them.",g={n="Korven the Prime",loc="Various"}}
d[31271]={mo=198450,rep="+130 The Klaxxi",o="Kill 3 Ik'thik Genemancers and 6 Ik'thik Egg-Drones. *Ik'thik Egg-Drone slain (6) *Ik'thik Genemancer slain (3)",de="Far to the south, Wakener, the Empress's genemancers set about their dark experiments. (Dark yes, but not as dark as mine!) They dissect and mutate the nearby wildlife, breeding creatures of their own design. (Their design, which will become my design!) We must not let them succeed! (No, no! Only I am allowed such power!) Their mutations are already being unleashed for war. Go! Destroy them at any cost!",g={n="Rik'kal the Dissector",loc="Klaxxi'vess, Dread Wastes"}}
d[31272]={mo=198450,rep="+130 The Klaxxi",o="Kill 6 infected wildlife. Infected wildlife may include Bonedust Moths, Bluehide Mushan, and Mutating Scorpid. *Infected wildlife slain (6)",de="The Empress's genemancers play with dangerous toys. To the south, they are injecting local wildlife with pheromone-laden parasites, in an attempt to create monstrous mutations for war. Carelessly, they have allowed their parasitic worms to escape into the local ecosystem. Left unchecked, the infection will spread from one animal to another, until we have an outbreak. I will inject you with a mild toxin. With it, you will be able to identify infected creatures. Kill the carriers at once.",g={n="Hisek the Swarmkeeper",loc="Klaxxi'vess, Dread Wastes"}}
d[31288]={mo=198450,o="Obtain 20 Mogu Archaeology Fragments. *Mogu Archaeology Fragment (20)",de="Ah, an explorer. Just what I could use. I am on the verge of discovering the dark secrets of the mogu. Not all of the secrets, mind you. They kept a lot of dark secrets. But I am on the verge of discovering \"a\" secret at least. If, in your travels, you come across some fragments of the mogu past, bring them to me and I will happily reimburse you for them.",g={n="Master Liu",loc="Seat of Knowledge, Vale of Eternal Blossoms"}}
d[31291]={mo=198450,o="Solve 1 artifact from Pandaria. *Artifact of Pandaria Solved",de="Interested in being a Lorewalker? There is lots of digging and reading and digging and more reading. I have entire days where I stare at a broken vase trying to figure out how it goes back together. Should give it a try. Go solve one artifact of Pandaria and we will appreciate you sharing the knowledge of how you did it.",g={n="Ms. Thai",loc="Seat of Knowledge, Vale of Eternal Blossoms"}}
d[31293]={mo=198450,rep="+100 Golden Lotus",o="thumb|Shao-Tien Pillager. thumb|Shao-Tien Subjugator. Kill 8 Shao-Tien attackers in Mistfall Village. *Shao-Tien attackers slain (8)",de="Leven sent Rook here to stop mogu, but there are more than Rook can kill alone. You help? Rook will tell Leven you helped. Promise.",g={n="Rook Stonetoe",x=0.258,y=0.187,loc="Various"}}
d[31295]={mo=99250,o="Speak to Leven Dawnblade at the Ruins of Guo-Lai.",de="Thank you for your help, . I would enjoy your company for longer, but Leven is leading an attack on the mogu within the Ruins of Guo-Lai to the northwest, and awaits your capable hands. May the celestials protect you, young one.",g={n="Che Wildwalker",loc="Mistfall Village, Vale of Eternal Blossoms"}}
d[31297]={mo=99250,o="Speak to Anji Autumnlight at the Setting Sun Garrison.",de=";Ren Firetongue :Anji and Kun stopped by on the way to the garrison. Lovely pair, don't you think? So different, yet so devoted to each other... ah, it makes my heart swoon just thinking about it. :They asked for you by name. Maybe they want to put you through some of the training paces? I certainly hope they don't have something more naughty in mind... ;Sun Tenderheart :The mogu will not be able to maintain this attack much longer. We should be able to handle it here, thanks to your kind aid. :Might you be willing to find Anji at the Setting Sun Garrison to the west? She's been tasked with pr"}
d[31443]={mo=114000,rep="+600 Nat Pagle+350 The Anglers",o="Bring the Flying Tiger Gourami to Nat Pagle at Anglers Wharf. *Flying Tiger Gourami (provided)",de="You've caught a unique fish... with wings. Perhaps it deserves the expert opinion of Nat Pagle in Anglers Wharf.",g={n="Flying Tiger Gourami"}}
d[31446]={mo=114000,rep="+600 Nat Pagle+350 The Anglers",o="Bring the Mimic Octopus to Nat Pagle at Anglers Wharf. * Mimic Octopus (provided)",de="You aren't sure how, but you've caught an extraordinary cephalopod. Nat Pagle at Anglers Wharf would be very interested to see it.",g={n="Mimic Octopus"}}
d[31446]={mo=114000,rep="+600 Nat Pagle+350 The Anglers",o="Bring the Spinefish Alpha to Nat Pagle at Anglers Wharf. * Spinefish Alpha (provided)",de="You have fished up something special. It looks pretty aggressive. Maybe Nat Pagle at the Anglers Wharf might know more about it?",g={n="Spinefish Alpha"}}
d[31487]={mo=198450,rep="+130 The Klaxxi",o="Kill 4 Dread Kunchong and 6 Shek'zeer Manipulators in the Clutches of Shek'zeer. The Sonic Disruption Fork will weaken and confuse the kunchong. *Dread Kunchong slain (4) *Shek'zeer Manipulator slain (6) *Sonic Disruption Fork (provided)",de="Relying on sonic whispers to manipulate the kunchong was only the most primitive stage of my research, and yet the Empire seems to have adopted the practice wholly. The manipulators of the Shek'zeer are too impatient to form a proper bond with their kunchong. Their laziness will cost them dearly. Strike this tuning fork near the dread kunchong in the clutches - watch as they reel in confusion and lash out at their masters. Use this to your advantage and put them down.",g={n="Kaz'tik the Manipulator",loc="Various"}}
d[31491]={mo=198450,rep="+250 August Celestials",o="thumb|The two circles drawn on the ground. thumb|Tiger Temple Monk. Hold back at least 10 Tiger Temple Monks using the Ten Foot Pole. *Tiger Temple Monk Repelled (10)",de="Here is a challenge for you: stand in the center of the room and hold off waves of monks using only a ten foot pole. My record is ten. Can you beat that?",g={n="Lin Tenderpaw",loc="Various"}}
d[31492]={mo=198450,rep="+250 August Celestials",o="Carry the Torch of Strength to the gates of the Temple of the White Tiger without it extinguishing. *The Strong Brazier Lit",de="Xuen has this challenge he says helps \"refine strength.\" I am starting to think the word \"strength\" means something different to him than the rest of us. Here, take this torch to the top of the gates of the temple. If you can get it there without the torch being extinguished, you pass the challenge. Whatever you do, do not try carrying the torch on a mount. It will blow out if you do. Trust me on that one.",g={n="Lin Tenderpaw",loc="Various"}}
d[31494]={mo=198450,rep="+130 The Klaxxi",o="Break open Kunchong Cages to release 8 Kunchong Hatchlings in the Clutches of Shek'zeer. *Kunchong Hatchling released (8)",de="The Shek'zeer manipulators are corralling young kunchong into that clutch and exposing them to raw fear energies, twisting them and accelerating their growth. Disgusting! I will not allow it! Break open the cages and set those hatchlings free.",g={n="Kaz'tik the Manipulator",loc="Various"}}
d[31496]={mo=198450,rep="+130 The Klaxxi",o="thumb|Central Feeder. thumb|East Feeder. thumb|North Feeder. Use the Sap Jar at Imperial Feeders outside the Heart of Fear 4 times to fill it. *Central Feeder *East Feeder *North Feeder *Northeast Feeder *Sap Jar (provided)",de="The wonders of the kypari sap never cease to amaze me. Among its numerous properties and applications, the sap can be refined into a nutritious and extremely delectable elixir. Nowhere in the Empire will you find a finer execution of this brew than the palace itself. Surely, the homes of the loyalists have feeders brimming with this sweet nectar. Fill this jar at their feeders and return it to me. I long to sample the imperial ambrosia once more.",g={n="Korven the Prime",loc="Various"}}
d[31502]={mo=198450,rep="+130 The Klaxxi",o="Collect 24 Needler Wings from Shek'zeer Needlers in the Clutches of Shek'zeer. *Needler Wings (24)",de="The young fliers of this era are fascinating. Their exceptional agility and endurance were, in my time, the feats of incredibly skilled or mature fliers. This would seem to indicate some kind of evolution in wing structure... Or perhaps a result of advancements in training? Induced genetic mutation? Selective breeding? Gah! There's no way to know for certain without tissue samples. Bring me their wings! And try not to ruin them in the process, will you? I need them intact!",g={n="Rik'kal the Dissector",loc="Klaxxi'vess, Dread Wastes"}}
d[31503]={mo=198450,rep="+130 The Klaxxi",o="Kill Vess-Guard Na'kal outside the Heart of Fear. *Vess-Guard Na'kal slain",de="There is a champion among the loyalists, Vess-Guard Na'kal, whose strength comes not from experience or development, but from genetic modification. He was meant to be an example of the future of mantid - the sick idea that we can be born strong, without earning it. He's a mockery of my work! Gene augmentation was meant for mature, post-swarm veterans ONLY! End him. Perhaps it will serve as a lesson to Grand Empress Shek'zeer that taking shortcuts leads to ruin.",g={n="Rik'kal the Dissector",loc="Klaxxi'vess, Dread Wastes"}}
d[31504]={mo=198450,rep="+130 The Klaxxi",o="Disable 8 Pheromone Mines around the Clutches of Shek'zeer and the Heart of Fear. *Pheromone Mine Disabled (8)",de="If the Grand Empress's agents are still operating under security standards from my time, they would have hidden powerful pheromone mines all around the clutches. With mere whisper she could detonate them all simultaneously, engulfing the palace and rendering entire siege armies powerless. If we hope to have any success in a large scale standoff, we need to disable those mines. My... \"gift\" to you when we met will allow you to see the mines. Disturb them and get to a safe distance.",g={n="Hisek the Swarmkeeper",loc="Klaxxi'vess, Dread Wastes"}}
d[31505]={mo=198450,rep="+130 The Klaxxi",o="Kill Vess-Guard Vik'az in Zan'vess. *Vess-Guard Vik'az slain",de="Vess-Guard Vik'az co-ordinates the defense forces at Zan'vess. He is worth ten mantid in battle, and his presence inspires the Zan'thik who fight alongside him. Needless to say, we need him dead. He patrols the housing area at the center of the island.",g={n="Kil'ruk the Wind-Reaver",loc="Various"}}
d[31506]={mo=198450,rep="+130 The Klaxxi",o="Collect 6 Zan'thik Shackles from Thought-Bound Miners and Thought-Bound Brutes in Zan'vess. *Zan'thik Shackles (6)",de="The Zan'thik employ a sizable force of... indentured labor. Yaungol are bound in special shackles which enhance and prolong the effects of sonic manipulation. It is this technology that allows the Zan'thik manipulators to command such large quantities of thralls to endlessly toil for them in the quarries. I would like to study these shackles.",g={n="Kaz'tik the Manipulator",loc="Various"}}
d[31507]={mo=198450,rep="+130 The Klaxxi",o="Slay 6 Zan'thik Venomstings in Zan'vess. Use Korven's Experimental Grenade to counter their armor plating. *Zan'thik Amberhusk slain (6) *Korven's Experimental Grenades (provided)",de="The venomsting scorpions on Zan'vess are fed sap from a young age, causing a fascinating mutation in which their natural armor plating becomes infused with amber. Effectively, it's organic kyparite, the same substance used in forging most of the empire's weapons and armor. I think I've found a way to chemically break down kyparite, but it needs testing. Use these grenades on the Zan'thik venomstings and observe the results.",g={n="Korven the Prime",loc="Various"}}
d[31508]={mo=198450,rep="+130 The Klaxxi",o="Collect 6 Kyparite Shards from Muck Tunnelers in The Briny Muck. *Kyparite Shards (6)",de="Kyparite worms have shown extreme adaptations in order to mimic the environment around them. They can also grow to immense sizes at rates which are nearly unheard of for most creatures. Their physiology could provide valuable insight into further mutations. Bring me sample shards from the muck tunnelers in the shallows near Zan'vess.",g={n="Rik'kal the Dissector",loc="Klaxxi'vess, Dread Wastes"}}
d[31509]={mo=198450,rep="+130 The Klaxxi",o="Destroy 15 Dreadspore Bulbs in Zan'vess and The Briny Muck. *Dreadspore Bulbs destroyed (15)",de="The fallout from Shek'zeer's madness will continue long after her reign has ended. We will struggle to heal our lands for many years to come, and even then our efforts may prove fruitless. A new species of sha-twisted flora has begun taking root near Zan'vess. Destroy any that you find, but beware - there is no telling what kind of sinister defenses it may have.",g={n="Rik'kal the Dissector",loc="Klaxxi'vess, Dread Wastes"}}
d[31510]={mo=198450,rep="+130 The Klaxxi",o="Interact with the Zan'thik Resonating Crystal at the Whispering Stones in Zan'vess to incite Adjunct Sek'ot, then slay him. *Adjunct Sek'ot slain",de="On the southwestern corner of Zan'vess lie the Whispering Stones. Much like the towers here, they are critical in transmitting long-range sonic signals. An adjunct of the Empress operates the stones, keeping her in communication with the Zan'thik forces. Disrupt the signal, then silence him.",g={n="Hisek the Swarmkeeper",loc="Klaxxi'vess, Dread Wastes"}}
d[31517]={mo=198450,rep="+250 August Celestials",o="Defeat Shonuf. *Shonuf slain",de="We honor strength here, not brutality. It is unfortunate but there are some who come to my doorstep oblivious to this distinction. I have turned away one such challenger. In retaliation, he sacked the village of Yinying. Go to Yinying Village southeast of the temple, and face this \"Shonuf.\" Give him a lesson in true strength.",g={n="Xuen",loc="Various"}}
d[31520]={mo=456000,o="Complete the Temple of the Jade Serpent Challenge Mode. *Complete the Temple of the Jade Serpent Challenge Mode",de=", I need you to assemble a hearty group and lead them into the Temple of the Jade Serpent. Activate the Challenger's Orb therein, and vanquish the Sha of Doubt. Return to me when you've completed this challenge, and I shall reward you handsomely.",g={n="Challenger Wuli",loc="Shrine of Two Moons, Vale of Eternal Blossoms"}}
d[31522]={mo=456000,o="Complete the Shado-Pan Monastery Challenge Mode. *Complete the Shado-Pan Monastery Challenge Mode",de=", I need you to assemble a tranquil group and lead them into the Shado-Pan Monastery. Activate the Challenger's Orb therein, and rescue Taran Zhu from the Sha of Hatred. Return to me when you've completed this challenge, and I shall reward you handsomely.",g={n="Challenger Wuli",loc="Shrine of Two Moons, Vale of Eternal Blossoms"}}
d[31523]={mo=456000,o="Complete the Mogu'shan Palace Challenge Mode. *Complete the Mogu'shan Palace Challenge Mode",de=", I need you to assemble a nimble group and lead them into Mogu'shan Palace. Activate the Challenger's Orb therein, and put an end to Xin the Weaponmaster. Return to me when you've completed this challenge, and I shall reward you handsomely.",g={n="Challenger Wuli",loc="Shrine of Two Moons, Vale of Eternal Blossoms"}}
d[31524]={mo=456000,o="Complete the Gate of the Setting Sun Challenge Mode. *Complete the Gate of the Setting Sun Challenge Mode",de=", I need you to assemble a cracking group and lead them into the Gate of the Setting Sun. Activate the Challenger's Orb therein and lay waste to Raigonn. Return to me when you've completed this challenge, and I shall reward you handsomely.",g={n="Challenger Wuli",loc="Shrine of Two Moons, Vale of Eternal Blossoms"}}
d[31525]={mo=456000,o="Complete the Siege of Niuzao Temple Challenge Mode. *Complete the Siege of Niuzao Temple Challenge Mode",de=", I need you to assemble an eagle-eyed group and lead them into the Siege of Niuzao Temple. Activate the Challenger's Orb and ground Wing Leader Ner'onok. Return to me when you've completed this challenge, and I shall reward you handsomely.",g={n="Challenger Wuli",loc="Shrine of Two Moons, Vale of Eternal Blossoms"}}
d[31527]={mo=456000,o="Complete the Scarlet Halls Challenge Mode. *Complete the Scarlet Halls Challenge Mode",de=", I need you to assemble a cunning group and venture forth into the depths of Scarlet Halls. Activate the Challenger's Orb therein, and put a stop to Flameweaver Koegler's book-burning ways.",g={n="Challenger Wuli",loc="Shrine of Two Moons, Vale of Eternal Blossoms"}}
d[31528]={mo=396050,o="Complete the Scholomance Challenge Mode. *Complete the Scholomance Challenge Mode",de=", I need you to assemble a fearless group and lead them into the depths of Scholomance. Activate the Challenger's Orb, and cleanse Scholomance of Darkmaster Gandling's evil presence. Return to me when you've completed this challenge and I shall reward you handsomely.",g={n="Challenger Wuli",loc="Shrine of Two Moons, Vale of Eternal Blossoms"}}
d[31598]={mo=228000,rep="+130 The Klaxxi",o="Bring the Massive Kyparite Core to Ambersmith Zikk at Klaxxi'vess. *Massive Kyparite Core (provided)",g={n="Massive Kyparite Core"}}
d[31599]={mo=228000,rep="+130 The Klaxxi",o="Bring the Enormous Kunchong Mandibles to Ambersmith Zikk at Klaxxi'vess. *Enormous Kunchong Mandibles (provided)",g={n="Enormous Kunchong Mandibles"}}
d[31669]={mo=99250,rep="+350 The Tillers",o="Plant a Green Cabbage in Sunsong Ranch. You can purchase seeds from in the Halfhill Market. *Plant Green Cabbage Seeds",de="Grandpa always said that the bellweather of a true farmer lies in the quality of his cabbage. Any time a new farmer came into town, he'd buy a few heads of cabbage to see what they knew. Now, I'm the new farmer, and this is my big chance to prove myself. Could you plant some cabbage for me?",g={n="Farmer Yoon",x=0.522,y=0.488,loc="Various"}}
d[31670]={mo=99250,rep="+350 The Tillers",o="Plant a Juicycrunch Carrot in Sunsong Ranch. You can purchase seeds from Merchant Greenfield in the Halfhill Market. *Plant Juicycrunch Carrot Seeds",de="Grandpa always said, \"Carrots ain't nothin but a welcomin' mat for virmen.\" I don't think I ever saw him grow a single carrot. For once, I disagree with Grandpa. I like to live on the edge. Plus, I like to eat carrots. I like to eat carrots on the edge. Could you get some seeds and grow one for me?",g={n="Farmer Yoon",x=0.522,y=0.488,loc="Various"}}
d[31671]={mo=99250,rep="+350 The Tillers",o="Plant a Scallion in Sunsong Ranch. You can purchase seeds from Merchant Greenfield in the Halfhill Market. *Plant Scallion Seeds",de="I heard Haohan mentioning that he was going to plant scallions today. I'm not sure if today's the best day for scallions, but I'd like to hope that he knows what he's doing. He is the head of the Tillers' union, after all. Could you plant a scallion for me?",g={n="Farmer Yoon",x=0.522,y=0.488,loc="Various"}}
d[31672]={mo=99250,rep="+350 The Tillers",o="Plant a Mogu Pumpkin in Sunsong Ranch. You can purchase seeds from Merchant Greenfield in the Halfhill Market. *Plant Mogu Pumpkin Seeds",de="I heard a rumor around the market that Gina Mudclaw loves the smell of pumpkin blossoms. Maybe if I grow some pumpkins in my farm, she might come and visit a little more often. Could you plant a pumpkin for me?",g={n="Farmer Yoon",x=0.522,y=0.488,loc="Various"}}
d[31673]={mo=99250,rep="+350 The Tillers",o="Plant a Red Blossom Leek in Sunsong Ranch. You can purchase seeds from Merchant Greenfield in the Halfhill Market. *Plant Red Blossom Leek Seeds",de="Grandpa once told me that the smell of leeks will keep crocolisks off of your property. He must have had a point... he always grew leeks, and I never saw a crocolisk anywhere NEAR his farm. We're pretty far from the water... but I suppose you can never be too sure.",g={n="Farmer Yoon",x=0.522,y=0.488,loc="Various"}}
d[31674]={mo=99250,rep="+350 The Tillers",o="Plant a :Pink Turnip in Sunsong Ranch. You can purchase seeds from Merchant Greenfield in the Halfhill Market. *Plant Pink Turnip Seeds",de="Old Hillpaw bet me that my land couldn't grow a pink turnip. I'll show him. My land will grow the biggest, pinkest turnip that old coot's ever seen!",g={n="Farmer Yoon",x=0.522,y=0.488,loc="Various"}}
d[31675]={mo=99250,rep="+350 The Tillers",o="Plant a White Turnip in Sunsong Ranch. You can purchase seeds from Merchant Greenfield in the Halfhill Market. *Plant White Turnip Seeds",de="Grandpa often told me to \"Keep my drawers clean and my dirt cleaner.\" It sounds like a joke, but he makes a good point. Vegetables tend to leave behind bits of root that can contaminate your soil... but a nice, big, white turnip will clean that gunk right up. Think you could plant a white turnip for me?",g={n="Farmer Yoon",x=0.522,y=0.488,loc="Various"}}
d[31677]={mo=228000,rep="+130 The Klaxxi",o="Bring the Ashes of Warlord Gurthan to Kil'ruk the Wind-Reaver at Klaxxi'vess. *Ashes of Warlord Gurthan (provided)",g={n="Ashes of Warlord Gurthan"}}
d[31693]={o="Defeat Julia Stevens in a pet battle. * Defeat Julia Stevens",de="Think you can take me again?",g={n="Julia Stevens",x=0.417,y=0.837,loc="Maclure Vineyards, Elwynn Forest"}}
d[31698]={mo=198450,rep="+450 Order of the Cloud Serpent",o="thumb|Windward Tiger. thumb|Windward Alpha. Kill 8 Windward Tigers or Windward Alphas. *Windward Tiger slain (8)",de="The past few seasons have been plentiful, and as a result, the wild tiger population on Windward Isle has exploded. The savage creatures have hunted out all the nearby game, and are beginning to encroach upon the cloud serpent nests. As a result, as the tigers thrive, the cloud serpents decline. If we are not careful, the predatory cats could completely wipe them out. We must thin the tigers' numbers, .",g={n="Instructor Skythorn",loc="Arboretum, Jade Forest"}}
d[31699]={mo=198450,rep="+450 Order of the Cloud Serpent",o="Kill 7 Shadowfae Tricksters. *Shadowfae Trickster slain (7)",de="Oh bother, how am I supposed to get my tasks done, now? Instructor Skythorn asked me to go kill some tigers at Windward Isle, but I heard the area was overrun with sprites! Ugh! I hate sprites! They totally give me the creeps! They're so small, and... and... they jump on you and... and... they have cold, dead little stick hands! Auuugh! You have to help me, . Get rid of those things, please!",g={n="Ningna Darkwheel",loc="Arboretum, Jade Forest"}}
d[31700]={mo=198450,rep="+450 Order of the Cloud Serpent",o="thumb|Stolen Boots. thumb|Shadowfae Trickster. Re-steal 14 Stolen Boots. *Stolen Boots (14)",de="I loathe sprites! One time, one of those nasty buggers followed me all day, putting dirt in my tea and bugs in my hair. I mean, who does that!? Well, I think it's time for a little payback. Do you know what the sprites up at Windward Isle love more than anything in the world? Yeah, you guessed it. Shoes! And we're going to steal them. Won't that make them mad! Hah! Well, I'm scared to go near sprites, so you'll have to do it, .",g={n="Ningna Darkwheel",loc="Arboretum, Jade Forest"}}
d[31701]={mo=198450,rep="+600 Order of the Cloud Serpent",o="Kill the Windward Huntress. *Windward Huntress slain",de="I have learned that a vicious beast, a Windward Huntress, terrorizes the wood on the northwest side of the island. She has already slain several serpents, and injured more than one serpent rider sent to subdue her. She must be removed before she can pose a danger to anyone else. Can you perform this task?",g={n="Elder Anli",x=0.577,y=0.449,loc="Arboretum, Jade Forest"}}
d[31702]={mo=198450,rep="+600 Order of the Cloud Serpent",o="Kill the Windward Saber. *Windward Saber slain",de="I have heard report of a great white beast that stalks the wood on the northwestern side of the wild serpent island. This savage creature is mate to the Windward Huntress, and already he has taken down several of the adult cloud serpent matriarchs. We cannot have such a fearsome predator roaming the island unchecked. Go and deal with this creature. Let us see if your training has paid off.",g={n="Elder Anli",x=0.577,y=0.449,loc="Arboretum, Jade Forest"}}
d[31703]={mo=198450,rep="+600 Order of the Cloud Serpent",o="Kill the Shadowfae Madcap. *Shadowfae Madcap slain",de="There is another task I must ask of you. The leader of the woodland sprites is the Shadowfae Madcap. If there is trouble brewing, he is the mastermind pulling the puppet strings. We do not have time to deal with the sprites' tiresome pranks and insolence. Take out the Shadowfae Madcap, and be quick about it.",g={n="Elder Anli",x=0.577,y=0.449,loc="Arboretum, Jade Forest"}}
d[31704]={mo=114000,rep="+450 Order of the Cloud Serpent",o="Collect 5 Tiny Bags of Poop. *Tiny Bag of Poop (5)",de="You can tell that someone has gotten out of its pen and had \"an accident.\" Well, at the rate that the hatchling's been eating, it had to come out the other end... somewhere. You had better find the serpent's poop and clean it up before the Serpent Masters find out.",g={n="Your Hatchling",loc="The Arboretum, Jade Forest"}}
d[31705]={mo=198450,rep="+600 Order of the Cloud Serpent",o="Use the honey at the northern clearing in The Arboretum, and then kill the Orchard Needler. *Orchard Needler slain *Golden Honey (provided)",de="The Arboretum is our home, a safe haven where we raise young hatchlings and train our students. Unfortunately, there are other, more dangerous creatures who wish to make this their home as well. To the north, beyond the river, we have seen a great wasp feeding on the nectar blossoms. This creature has already stung several of our students. Use this honey to lure the wasp out of hiding. Then, destroy it before it harms anyone else.",g={n="Elder Anli",x=0.577,y=0.449,loc="Arboretum, Jade Forest"}}
d[31706]={mo=198450,rep="+450 Order of the Cloud Serpent",o="Kill 7 Weeping Widows. *Weeping Widow slain (7)",de="The spiders near Sri-La Village have grown very aggressive. They pose a severe problem to the anglers who fish along the coast. For their safety, I need you to go and eliminate the Weeping Widows in The Widow's Wail. You can find the cave along the coast to the north.",g={n="Instructor Skythorn",loc="Arboretum, Jade Forest"}}
d[31707]={mo=198450,rep="+450 Order of the Cloud Serpent",o="Destroy Widow's Webs to free 5 Sri-La Villagers. *Sri-La Villagers freed x5",de="We have had a disturbing report from the Anglers fishermen of Sri-La Village, . Many of their villagers are missing, taken by the spiders who live in The Widow's Wail, a cave along the coast to the north. The victims are dragged into the dark depths, wrapped in cocoons, and left to become the spiders' next meal. We believe that some of the people may still be alive. There is still time to save them! I need you to go and rescue as many villagers as you can find.",g={n="Instructor Skythorn",loc="Arboretum, Jade Forest"}}
d[31708]={mo=198450,rep="+450 Order of the Cloud Serpent",o="Collect 25 Serpent's Scale. *Serpent's Scale (item) (25)",de="I see you have gained your own hatchling, . Have you been feeding it, cleaning after it, and playing with it properly? Only by doing so will it become strong and healthy. Now let me tell you a trainer's secret. To the north, in The Widow's Wail, you can find a mushroom known as Serpent's Scale. It is difficult to acquire, but this mushroom has powerful properties and important nutrients. Your serpent won't like eating it, but who likes eating their vegetables?",g={n="Qua-Ro Whitebrow",loc="Arboretum, Jade Forest"}}
d[31709]={mo=198450,rep="+450 Order of the Cloud Serpent",o="Use the Sha Attunement Device at the Sha Disturbances in The Widow's Wail. The entrance to The Widow's Wail can be found to the north along the coast, south of Sri-La Village. *Northwestern Sha Disturbance measured *Northeastern Sha Disturbance measured *Southern Sha Disturbance measured *Sha Attunement Device (provided)",de="I heard that there has been some strange behavior down at The Widow's Wail to the north. Hyacinth and I went to investigate, and I am certain that some presence of the sha has found its way into the cavern. I created this device to measure sha energy levels. If you are going that way, would you mind taking measurements of any sha disturbances? The disturbances look like streams of white and black sha energy pouring from the ground.",g={n="Big Bao",loc="Arboretum, Jade Forest"}}
d[31710]={mo=198450,rep="+450 Order of the Cloud Serpent",o="Collect 100 Tiny Spider Eyes. *Tiny Spider Eye x100",de="As you near, your serpent opens its mouth and begins drooling. It looks quite hungry since you last left it. From the way it whimpers and slaps its tail, you can tell it is not looking for just any treat, but a special favorite snack. Your serpent loves to munch on tiny spider eyes, but this delicacy comes only from the Widowspawn spiders in the cave along the coast to the north. Well, what's a rider to do? Your serpent is waiting.",g={n="Your Hatchling",loc="The Arboretum, Jade Forest"}}
d[31711]={mo=198450,rep="+600 Order of the Cloud Serpent",o="Kill the Seed of Doubt. *Seed of Doubt slain",de="The problem with the sha of doubt, , is its deceitful pervasiveness. Once the seed of doubt is planted, it can grow like an unwelcome weed. Such a seed has been planted in The Widow's Wail to the north, and like a weed, we must extinguish its presence immediately. I need you to destroy the lingering fragment of doubt before it can infect any more victims.",g={n="Elder Anli",x=0.577,y=0.449,loc="Arboretum, Jade Forest"}}
d[31712]={mo=198450,rep="+450 Order of the Cloud Serpent",o="Kill 13 Oona hozen. *Oona Hozen slain (13)",de="Strange tales have reached our ears from Sri-La Village. It seems that a hozen tribe has made itself comfortable in Oona Kagu, a cave along the coast south of the fishing village. Too comfortable, in fact. The tribe members are stealing and pillaging resources all along the coast. We must teach them a lesson... one that can only be taught by force. They have already overstayed their welcome.",g={n="Instructor Skythorn",loc="Arboretum, Jade Forest"}}
d[31713]={mo=198450,rep="+450 Order of the Cloud Serpent",o="Collect 100 Sri-La Stout. *Stolen Sri-La Stout (100)",de="It's a disaster, ! When I went to visit the Dancing Serpent Inn yesterday, they were all out of brew. They said the shipment from Sri-La Village had been stolen. STOLEN! Turns out those Oona hozen have been making all kinds of trouble down at the docks, including taking all the brew to their cave at Oona Kagu along the coast. I can't handle a dry spell. A life without brew is not a life worth living! Someone needs to go and save the brew!",g={n="Ace Longpaw",loc="Arboretum, Jade Forest"}}
d[31714]={mo=198450,rep="+450 Order of the Cloud Serpent",o="Collect 10 Rescued Serpents. *Rescued Serpent (10)",de="Those Oona hozen have gone too far this time. Do you know what they are doing with wild cloud serpents? Captured hatchlings are forced to fight one another in the pits, for nothing more than the Oona's amusement. Savages! If the young hatchlings learn such aggressive behavior at a young age, they may become violent and corrupted adults. A malicious cloud serpent is not something we want to deal with. We must save the hatchlings.",g={n="Qua-Ro Whitebrow",loc="Arboretum, Jade Forest"}}
d[31715]={mo=198450,rep="+600 Order of the Cloud Serpent",o="Kill Lord Oona. *Lord Oona slain /",de="The leader of the Oona hozen is a brigand by the name of Lord Oona. I have heard fearsome tales of this roaming sea captain and his crew. Everywhere he takes his tribe, destruction follows. The Oona land their boats on fertile soil, pillage the local villages, and drain the land dry before moving on to their next conquest. We shall not allow the same to occur on our shores, not while I am still in charge. I need someone to go eradicate him now.",g={n="Elder Anli",x=0.577,y=0.449,loc="Arboretum, Jade Forest"}}
d[31717]={mo=198450,rep="+450 Order of the Cloud Serpent",o="Speak to Ace Longpaw, then defeat him. *Ace Longpaw defeated",de="You are rising up the ranks of our students, . Just as a sword must be forged through fire, so must our students test themselves against one another. Today, you will spar against one of our brightest disciples, Ace Longpaw. In order to defeat him, you will need to make use of your defensive capabilities. Speak to him in the training ring to begin the challenge. Good luck.",g={n="Elder Anli",x=0.577,y=0.449,loc="Arboretum, Jade Forest"}}
d[31718]={mo=198450,rep="+450 Order of the Cloud Serpent",o="Speak to Big Bao, then defeat him. *Big Bao defeated",de="Are you ready for another lesson, ? Today, you will spar against Big Bao. He is large of stature and of heart, and he will not give up until he is wholly beaten. If you wish to defeat him, you will need to persevere. Speak to him in the training ring to begin the challenge. Good luck.",g={n="Elder Anli",x=0.577,y=0.449,loc="Arboretum, Jade Forest"}}
d[31719]={mo=198450,rep="+450 Order of the Cloud Serpent",o="Speak to Ningna Darkwheel, then defeat her. *Ningna Darkwheel defeated",de="You show much promise, . However, talent is worth little without discipline and humility. Today, you will face Ningna Darkwheel. Her natural strength makes her one of our most talented students. If you hope to defeat her, you will need to act with the utmost control. Speak to her in the training ring to begin the challenge. Good luck.",g={n="Elder Anli",x=0.577,y=0.449,loc="Arboretum, Jade Forest"}}
d[31720]={mo=198450,rep="+450 Order of the Cloud Serpent",o="Speak to Suchi the Sweet, then defeat her. *Suchi the Sweet defeated",de="Today you will face Suchi the Sweet in the training ring. Despite her sweet exterior, she is a tough opponent. She attacks swiftly and surely, but such potent attacks can become tiring over time. If you hope to defeat her, you will need to concentrate your damage when she is weakened. Speak to Suchi to begin the duel. Good luck.",g={n="Elder Anli",x=0.577,y=0.449,loc="Arboretum, Jade Forest"}}
d[31721]={mo=198450,rep="+450 Order of the Cloud Serpent",o="Speak to Qua-Ro Whitebrow, then defeat him. *Qua-Ro Whitebrow defeated",de="Qua-Ro Whitebrow is commonly considered the best student of the Order. He seems quite without weakness. He is quick of intellect, strong of arm, hard-working, and talented. When you face him in the training ring, you will be testing yourself against our best. Speak to him to begin the duel. No matter the outcome, you will learn much from challenging him.",g={n="Elder Anli",x=0.577,y=0.449,loc="Arboretum, Jade Forest"}}
d[31752]={r={{n="Blingtron 4000 Gift Package"}},g={n="Blingtron 4000"}}
d[31754]={mo=198450,rep="+100 Golden Lotus",o="thumb|Shao-Tien Cannon. Destroy 8 Shao-Tien Cannons. *Shao-Tien Cannons destroyed x7 *Wu Kao Explosive (provided)",de="Those mogu cannons up on the Golden Stair are bombarding us from a distance. Sure would be nice if they somehow spontaneously broke, don't you think?",g={n="Kun Autumnlight",loc="Vale of Eternal Blossoms"}}
d[31755]={mo=198450,rep="+100 Golden Lotus",o="thumb|Shao-Tien Soul-Render. Rescue 5 Golden Lotus Guards or Mistfall Villagers. *Torture victims rescued (5)",de="I can hear the screams of the captured soldiers and villagers up on the Golden Stair. They're torturing them! Please, please, you have to save them!",g={n="Sun Tenderheart",x=0.258,y=0.187,loc="Various"}}
d[31756]={mo=198450,rep="+100 Golden Lotus",o="thumb|Western Stormcaller staff Destroy the Stormcaller staves. *Eastern Stormcaller destroyed *Northern Stormcaller destroyed *Southern Stormcaller destroyed *Western Stormcaller destroyed",de="The mogu are conjuring some kind of sinister storm upon the Golden Stair. Generally, mogu and lightning are not a particularly pleasant mix. I say we stop them. You should be able to find their Stormcaller staves preatty easily, considering the giant arcs of lightning extending up from them. Mind knocking them over or destroying them or something for me? I sure would sleep better.",g={n="Kun Autumnlight",loc="Vale of Eternal Blossoms"}}
d[31757]={mo=198450,rep="+100 Golden Lotus",o="thumb|Unleashed Spirit. Kill 30 Unleashed Spirits. *Unleashed Spirit slain (30)",de="The Shao-Tien have unleashed their captive tortured spirits on us. They flood down from the Golden Stair, with no end in sight. Kill as many of these unleashed spirits as you can. They are fragile, but if you are not alert, they can easily overrun you. Good luck.",g={n="Anji Autumnlight",loc="Vale of Eternal Blossoms"}}
d[31758]={mo=198450,rep="+100 Golden Lotus",o="thumb|Lao Softfoot. Rescue Lao Softfoot. *Lao Softfoot rescued",de="Lao Softfoot got himself captured again up on the Golden Stair. I'm not going to make any excuses for him, he's a lousy rogue. We probably shouldn't just leave him there though. Could you go find him?",g={n="Kun Autumnlight",loc="Vale of Eternal Blossoms"}}
d[31760]={mo=198450,rep="+100 Golden Lotus",o="thumb|Shao-Tien Behemoth. Stop the Shao-Tien Behemoth from being empowered. *Shao-Tien Behemoth ritual stopped",de="The mogu are empowering some giant stone monstrosity up on the Golden Stair with the sure intent of unleashing it upon us. How about you go and let them know our opinion on the matter? Make sure the point strikes home.",g={n="Anji Autumnlight",loc="Vale of Eternal Blossoms"}}
d[31762]={mo=198450,rep="+100 Golden Lotus",o="Destroy the Shao-Tien Behemoth. *Shao-Tien Behemoth slain",de="The mogu have succeeded in empowering an enormous statue with the intent of unleashing it upon us. In response, I would like to unleash you upon it. It approaches from the Golden Stair. Bring it to its knees...",g={n="Anji Autumnlight",loc="Vale of Eternal Blossoms"}}
d[31781]={o="Defeat Lindsay in a pet battle. * Defeat Lindsay",de="Think you can take me again? I'm always up for challenge!",g={n="Lindsay",x=0.333,y=0.526,loc="Lake Everstill, Redridge Mountains"}}
d[31808]={mo=198450,rep="+130 The Klaxxi",o="Kill 200 Mantid while controlling Kovok in the Scar. *Locate Kovok near the Clutches of Shek'zeer *Mantid slain (200)",de="Kovok has progressed at an astonishing rate. Perhaps the years in hibernation effected his growth process... Whatever the reason, this could not have come at a better time. I believe it is time to test his abilities. You have done so much to aid in his training. It is only fitting that you assist him in his first battle. I've already guided him to the edge of the scar. Find him and destroy Shek'zeer's army!",g={n="Kaz'tik the Manipulator",loc="Various"}}
d[31840]={r={{n="Enlightenment (buff)"}},o="Speak with Master Cheng in the Peak of Serenity and spar with him. *Master Cheng's Training Completed",de="Welcome Back, . I see you've returned to hone your skills. Speak with Master Cheng in the Training Grounds below us for a practice sparring session."}
d[31842]={r={{n="Enlightenment (buff)"}},o="Speak with Master Kistane in the Peak of Serenity and complete your training with her.",de="Welcome Back, . I see you've returned to hone your skills. Speak with Master Kistane in the Training Grounds below us for a practice sparring session.",g={n="Master Hight",loc="Various"}}
d[31843]={o="Speak with Master Yoon in the Peak of Serenity and complete your training with him. *Master Yoon's Training Completed",de="Welcome Back, . I see you've returned to hone your skills. Speak with Master Yoon in the Training Grounds below us for a practice sparring session.",g={n="Master Hight",loc="Various"}}
d[31844]={o="Speak with Master Cheng in the Peak of Serenity and complete your training with her. *Master Cheng's Training Completed",de="Welcome Back, . I see you've returned to hone your skills. Speak with Master Cheng in the Training Grounds below us for a practice sparring session.",g={n="Master Hight",loc="Various"}}
d[31845]={o="Speak with Master Tsang in the Peak of Serenity and complete your training with him. *Master Tsang's Training Completed",de="Welcome Back, . I see you've returned to hone your skills. Speak with Master Tsang in the Training Grounds below us for a practice sparring session.",g={n="Master Hight",loc="Various"}}
d[31846]={o="Speak with Master Hsu in the Peak of Serenity and complete your training with him. *Master Hsu's Training Completed",de="Welcome Back, . I see you've returned to hone your skills. Speak with Master Hsu in the Training Grounds below us for a practice sparring session.",g={n="Master Hight",loc="Various"}}
d[31850]={o="Defeat Eric Davidson in a pet battle. * Defeat Eric Davidson",de="Ah, so you've braved the woods again to face me in battle. I accept your brazen challenge to my vicious spawn.",g={n="Eric Davidson",x=0.198,y=0.445,loc="Raven Hill Cemetery, Duskwood"}}
d[31851]={o="Defeat Bill Buckler in a pet battle. * Defeat Bill Buckler",de="So ye've come fer another round, have ye? I'll show ya why they be callin' me the shcourge o' the vale!",g={n="Bill Buckler",x=0.515,y=0.734,loc="Wild Shore, Cape of Stranglethorn"}}
d[31852]={o="Defeat Steven Lisbane in a pet battle. * Defeat Steven Lisbane",de="You dare to challenge me again? This time, I do believe our battle is going to sway in my favor!",g={n="Steven Lisbane",x=0.46,y=0.405,loc="Northern Stranglethorn"}}
d[31909]={o="Defeat Stone Cold Trixxy in a pet battle. * Defeat Stone Cold Trixxy",de="Freeze! You've finally warmed up from our last encounter, have you? Let's change that.",g={n="Stone Cold Trixxy",x=0.656,y=0.645,loc="Ice Thistle Hills, Winterspring"}}
d[31910]={o="Defeat David Kosse in a pet battle. *Defeat David Kosse",de="My research has helped my training regimen greatly. I will defeat you this time.",g={n="David Kosse",x=0.63,y=0.546,loc="The Hinterlands"}}
d[31911]={o="Defeat Deiza Plaguehorn in a pet battle. *Defeat Deiza Plaguehorn",de="You have not yet turned to the true path of undeath. Perhaps another battle will show you the way.",g={n="Deiza Plaguehorn",x=0.666,y=0.57,loc="Pestilent Scar, Eastern Plaguelands"}}
d[31912]={o="Defeat Kortas Darkhammer in a pet battle. * Defeat Kortas Darkhammer",de="I hear that you fought my fool of a brother. He lost, eh? Looks like this is my time to shine!",g={n="Kortas Darkhammer",x=0.353,y=0.278,loc="Thorium Point, Searing Gorge"}}
d[31913]={o="Defeat Everessa in a pet battle. * Defeat Everessa",de="I believe I'm figuring out the secrets of this place. Soon I will be unstoppable!",g={n="Everessa",x=0.768,y=0.415,loc="Swamp of Sorrows"}}
d[31914]={o="Defeat Durin Darkhammer in a pet battle. * Defeat Durin Darkhammer",de="My time under the Firelord has prepared me fer anything. Nothing you can throw at me will deter me!",g={n="Durin Darkhammer",x=0.255,y=0.475,loc="Blackrock Mountain, Burning Steppes"}}
d[31916]={o="Defeat Lydia Accoste in a pet battle. * Defeat Lydia Accoste",de="You wish to face me again? You will regret this decision!",g={n="Lydia Accoste",x=0.4,y=0.765,loc="Karazhan, Deadwind Pass"}}
d[31922]={o="Defeat Nicki Tinytech in a pet battle. * Defeat Nicki Tinytech",de="According to my calculations, I have a 32.333% chance of victory. I'll take it!",g={n="Nicki Tinytech",x=0.643,y=0.493,loc="Path of Glory, Hellfire Peninsula"}}
d[31923]={o="Defeat Ras'an in a pet battle. * Defeat Ras'an",de="You want to fight again? I think I've gotten better!",g={n="Ras'an",x=0.173,y=0.505,loc="Sporewind Lake, Zangarmarsh"}}
d[31924]={o="Defeat Narrok in a pet battle. * Defeat Narrok",de="I wish to do battle once more. These young ones need to grow stronger.",g={n="Narrok",x=0.61,y=0.494,loc="Nagrand"}}
d[31925]={o="Defeat Morulu The Elder in a pet battle. * Defeat Morulu The Elder",de="I have learned much since our last encounter. Do you wish to test your skills once more?",g={n="Morulu The Elder",x=0.58,y=0.7,loc="Lower City, Shattrath City"}}
d[31926]={o="Defeat Bloodknight Antari in a pet battle. * Defeat Bloodknight Antari",de="You capitalized on my mistake last time and emerged victorious. This time, you will not be so fortunate, .",g={n="Bloodknight Antari",x=0.304,y=0.42,loc="Magma Fields, Shadowmoon Valley"}}
d[31931]={o="Defeat Beegle Blastfuse in a pet battle. * Defeat Beegle Blastfuse",de="One of my chickens flew for just a moment yesterday, I swear. We're finally hitting the big time! Oh, you'd like to battle again?",g={n="Beegle Blastfuse",x=0.286,y=0.339,loc="Howling Fjord"}}
d[31932]={o="Defeat Nearly Headless Jacob in a pet battle. * Defeat Nearly Headless Jacob",de="Time and time again you defy my wisdom. What is it that brings you back to these woods? Ah, you wish to do battle once more. Very well then.",g={n="Nearly Headless Jacob",x=0.501,y=0.59,loc="Crystalsong Forest"}}
d[31933]={o="Defeat Okrut Dragonwaste in a pet battle. * Defeat Okrut Dragonwaste",de="You dare interrupt our work? Then you must battle me again! Take out your pets, and I'll give you a taste of Hellscream's wrath!",g={n="Okrut Dragonwaste",x=0.59,y=0.77,loc="Path of the Titans, Dragonblight"}}
d[31934]={o="Defeat Gutretch in a pet battle. * Defeat Gutretch",de="Me like fighting you. You not so easy like the others. We fight again?",g={n="Gutretch",x=0.132,y=0.668,loc="Zul'Drak"}}
d[31935]={o="Defeat Major Payne in a pet battle. * Defeat Major Payne",de="The rebel comes once again to test might again that of a Grand Master. Your bravery will be your undoing this time!",g={n="Major Payne",x=0.774,y=0.196,loc="Argent Tournament Grounds, Icecrown"}}
d[31941]={mo=99250,rep="+350 The Tillers",o="Plant a Jade Squash in Sunsong Ranch. You can purchase seeds from Merchant Greenfield in the Halfhill Market. *Plant Jade Squash Seeds",de="Grandpa always said, \"A squash a week, and your tail won't reek.\" Yup. I think it's been about a week. Could you help me plant a Jade Squash?",g={n="Farmer Yoon",x=0.522,y=0.488,loc="Various"}}
d[31942]={mo=99250,rep="+350 The Tillers",o="Plant a Striped Melon in Sunsong Ranch. You can purchase seeds from Merchant Greenfield in the Halfhill Market. *Plant Striped Melon Seeds",de="Hmm... Yup. It's melon time. Could you grab some seeds and help me plant a Striped Melon?",g={n="Farmer Yoon",x=0.522,y=0.488,loc="Various"}}
d[31943]={mo=99250,rep="+350 The Tillers",o="Plant Witchberries in Sunsong Ranch. You can purchase seeds from Merchant Greenfield in the Halfhill Market. *Plant Witchberry Seeds",de="That young'un over there, Andi, is going to grow up to be a heck of a farmer some day. I can tell just by lookin' at him. I think I'll plant him some witchberries. Kids love witchberries - it'll be a nice surprise.",g={n="Farmer Yoon",x=0.522,y=0.488,loc="Various"}}
d[31953]={o="Defeat Hyuna of the Shrines in a pet battle. * Defeat Hyuna of the Shrines",de="You seek to do battle once more? Very well, it will strengthen me to better protect the sacred sites of my people.",g={n="Hyuna of the Shrines",x=0.48,y=0.541,loc="Temple of the Jade Serpent, Jade Forest"}}
d[31954]={o="Defeat Mo'ruk in a pet battle. * Defeat Mo'ruk",de="This time I'm gonna do the beating! You watch!",g={n="Mo'ruk",x=0.622,y=0.459,loc="Narsong Spires, Krasarang Wilds"}}
d[31955]={o="Defeat Farmer Nishi in a pet battle. * Defeat Farmer Nishi",de="My pets continue to grow in strength thanks to the fertile land we train on. You don't stand a chance!",g={n="Farmer Nishi",x=0.461,y=0.437,loc="Heartland, Valley of the Four Winds"}}
d[31956]={o="Defeat Courageous Yon in a pet battle. * Defeat Courageous Yon",de="If you think I am going to let you walk away with another victory in hand, you are sorely mistaken. This time, I will stand over you as the superior trainer!",g={n="Courageous Yon",x=0.359,y=0.737,loc="Kota Peak, Kun-Lai Summit"}}
d[31957]={o="Defeat Wastewalker Shu in a pet battle. * Defeat Wastewalker Shu",de="You venture into the heart of the wastes to face me again, only to suffer defeat at the hands of a true grand master. Noble, but foolish.",g={n="Wastewalker Shu",x=0.551,y=0.375,loc="Klaxxi'vess, Dread Wastes"}}
d[31958]={o="Defeat Aki the Chosen in a pet battle. * Defeat Aki the Chosen",de="You wish to test yourself against me once more? Very well, let us fight.",g={n="Aki the Chosen",x=0.314,y=0.72,loc="Mistfall Village, Vale of Eternal Blossoms"}}
d[31971]={o="Defeat Obalis in a pet battle. * Defeat Obalis",de="I see the triumphant tamer returns to again test against me. Very well. I accept your challenge.",g={n="Obalis",x=0.566,y=0.42,loc="Vir'naal Dam, Uldum"}}
d[31972]={o="Defeat Brok in a pet battle. * Defeat Brok",de="I do not yet understand the plight of these creatures well enough to help them sufficiently. Perhaps another battle would strengthen our bond?",g={n="Brok",x=0.614,y=0.327,loc="Nordrassil, Mount Hyjal"}}
d[31973]={o="Defeat Bordin Steadyfist in a pet battle. * Defeat Bordin Steadyfist",de="The natives have taught me the strength of the earth. I know it's unending endurance. Let us battle once more, and you'll see that I'm tougher than ever!",g={n="Bordin Steadyfist",x=0.5,y=0.57,loc="Jagged Wastes, Deepholm"}}
d[31974]={o="Defeat Goz Banefury in a pet battle. * Defeat Goz Banefury",de="The power of twilight flows through me. I am a god! You have no hope of defeating me!",g={n="Goz Banefury",x=0.566,y=0.568,loc="The Devouring Breach, Twilight Highlands"}}
d[31991]={o="Defeat Seeker Zusshi in a pet battle. * Defeat Seeker Zusshi",de="I knew you would return to face me once more. Let us see who is truly wiser in the ways of battle.",g={n="Seeker Zusshi",x=0.363,y=0.522,loc="Fields of Niuzao, Townlong Steppes"}}
d[31998]={mo=456000,o="Complete the Temple of the Jade Serpent Challenge Mode. *Complete the Temple of the Jade Serpent Challenge Mode",de=", I need you to assemble a hearty group and lead them into the Temple of the Jade Serpent. Activate the Challenger's Orb therein, and vanquish the Sha of Doubt. Return to me when you've completed this challenge, and I shall reward you handsomely.",g={n="Challenger Soong",loc="Summer Terrace, Shrine of Seven Stars"}}
d[32001]={mo=456000,o="Complete the Shado-Pan Monastery Challenge Mode *Complete the Shado-Pan Monastery Challenge Mode",de=", I need you to assemble a tranquil group and lead them into the Shado-Pan Monastery. Activate the Challenger's Orb therein, and rescue Taran Zhu from the Sha of Hatred. Return to me when you've completed this challenge, and I shall reward you handsomely.",g={n="Challenger Soong",loc="Summer Terrace, Shrine of Seven Stars"}}
d[32002]={mo=456000,o="Complete the Mogu'shan Palace Challenge Mode. *Complete the Mogu'shan Palace Challenge Mode",de=", I need you to assemble a nimble group and lead them into Mogu'shan Palace. Activate the Challenger's Orb therein, and put an end to Xin the Weaponmaster. Return to me when you've completed this challenge, and I shall reward you handsomely.",g={n="Challenger Soong",loc="Summer Terrace, Shrine of Seven Stars"}}
d[32003]={mo=456000,o="Complete the Gate of the Setting Sun Challenge Mode. *Complete the Gate of the Setting Sun Challenge Mode",de=", I need you to assemble a cracking group and lead them into the Gate of the Setting Sun. Activate the Challenger's Orb therein and lay waste to Raigonn. Return to me when you've completed this challenge, and I shall reward you handsomely.",g={n="Challenger Soong",loc="Summer Terrace, Shrine of Seven Stars"}}
d[32004]={mo=456000,o="Complete the Siege of Niuzao Temple Challenge Mode *Complete the Siege of Niuzao Temple Challenge Mode",de=", I need you to assemble an eagle-eyed group and lead them into the Siege of Niuzao Temple. Activate the Challenger's Orb and ground Wing Leader Ner'onok. Return to me when you've completed this challenge, and I shall reward you handsomely.",g={n="Challenger Soong",loc="Summer Terrace, Shrine of Seven Stars"}}
d[32006]={mo=456000,o="Complete the Scarlet Halls Challenge Mode. *Complete the Scarlet Halls Challenge Mode",de=", I need you to assemble a cunning group and venture forth into the depths of Scarlet Halls. Activate the Challenger's Orb therein, and put a stop to Flameweaver Koegler's book-burning ways.",g={n="Challenger Soong",loc="Summer Terrace, Shrine of Seven Stars"}}
d[32007]={mo=396050,o="Complete the Scholomance Challenge Mode. *Complete the Scholomance Challenge Mode",de=", I need you to assemble a fearless group and lead them into the depths of Scholomance. Activate the Challenger's Orb, and cleanse Scholomance of Darkmaster Gandling's evil presence. Return to me when you've completed this challenge and I shall reward you handsomely.",g={n="Challenger Soong",loc="Summer Terrace, Shrine of Seven Stars"}}
d[32115]={mo=198450,rep="+150 Operation: Shieldwall",o="Free 14 Troubled Slave Spirits. *Troubled Slave Spirits released (14)",de="The mogu are a bunch of right bastards! They enslaved the pandaren who worked these caves even after their death. Ye' gotta go free their spirits! It's just not right. Be careful though... so much trauma, they don't know what's a friend and what's an enemy. So they'll probably fight back.",g={n="Hilda Hornswaggle",x=0.598,y=0.76,loc="Various"}}
d[32116]={mo=19850,o="Meet with Hilda Hornswaggle at the Ruins of Ogudei in Krasarang Wilds.",de="When I ordered the excavation of the tunnel to the northwest, I thought we'd find something useful. Gold, iron... anything! Instead, we found mogu artifacts, and I get a bunch of dwarves from the Explorers' League to baby-sit. I hear from the soldiers that there's trouble in the mines. I have orders from Wrynn that I have to support the Explorers' League, but I can't spare any troops. Can you get down there and find out what's going on?",g={n="Marshal Troteman",x=0.287,y=0.407,loc="Various"}}
d[32118]={mo=19850,o="Use the portal at Sparkrocket Outpost to meet with Kaelis Sunsoar at the Ruins of Ogudei in Krasarang Wilds.",de="The fools in the Explorers' League have excavated an ancient mogu ruin to the northeast. And - of course - in their bumbling, they've disturbed the mogu spirits within. We are going to take advantage of their ineptitude. Take this portal and meet with Kaelis Sunsoar, my contact within the ruins.",g={n="Belloc Brightblade",x=0.49,y=0.706,loc="Various"}}
d[32119]={mo=198450,rep="+150 Operation: Shieldwall",o="Use Hilda's Anomaly Tracker to find and disperse an anomaly. *Anomaly dispersed",de="There's somethin' down there that was spookin' the workers. Some kind o' anomaly... looks like a ghost, or a magic spell... like nothing I've ever seen. I did manage to get a reading on it and put together this device to try to track it down. The display on the device will let you know roughly how close you are. Once you get close enough, you can use it to draw out the anomaly and get rid of it for good!",g={n="Hilda Hornswaggle",x=0.598,y=0.76,loc="Various"}}
d[32120]={mo=198450,rep="+150 Dominance Offensive",o="Collect 5 Ancient Mogu Essence. *Ancient Mogu Essence (5)",de="The ruins which we are occupying were built by Ogudei - an ancient mogu ruler. We know little about who he was, though the rise of the spirits in this area seems to indicate that it was related to spirit binding. When you destroy these spirits, a small amount of their essence will remain in this world. Bring it to us - we will analyze it and hopefully learn more about Ogudei's history - and his power.",g={n="Kaelis Sunsoar",loc="Ruins of Ogudei, Krasarang Wilds"}}
d[32121]={mo=198450,rep="+150 Operation: Shieldwall",o="Destroy 3 Spirit Traps. *Spirit Trap destroyed (3)",de="In the ruins there are a bunch of right nasty blue crystals. Look at 'em the wrong way and bloody angry ghosts run out at ya. I'm gonna be needing ye' to go in and clear some of them out so we can get our people back to work.",g={n="Hilda Hornswaggle",x=0.598,y=0.76,loc="Various"}}
d[32122]={mo=198450,rep="+300 Operation: Shieldwall",o="Kill Meng-do, Strength of Mountains, and Gen-li, Twister of Words. *Gen-li, Twister of Words slain *Meng-do, Strength of Mountains slain",de="When we dug through to an ancient section of the mogu ruins, that's when all this nasty business went down - and that's where the two worst o' these ghosties emerged. We need them gone, friend.",g={n="Hilda Hornswaggle",x=0.598,y=0.76,loc="Various"}}
d[32123]={mo=198450,rep="+150 Dominance Offensive",o="Defeat 10 Alliance soldiers in Domination Point. *Alliance slain (10)",de="The Alliance has made landfall. If we do not defeat them here, any hope of a Horde presence on this continent is lost. Go to the battlefield south of here and slay Alliance you find. Show them how any Horde who still stands on two legs will be the death of ten Alliance!",g={n="Shokia",x=0.102,y=0.556,loc="Various"}}
d[32126]={mo=198450,rep="+150 Dominance Offensive",o="Destroy 8 Alliance Supply Drops. *Alliance Supply Drops destroyed (8)",de="The Alliance may be cowardly, but they are not fools. Their assault would be formidable, if it were directed at lesser creatures. To sustain a siege and put pressure on our troops they are air dropping in supplies to support their ground forces. Search the beaches and docks to the south for any airdropped supplies and smash them. Let the Alliance see their food and ammunition destroyed before their eyes and despair.",g={n="Brolic",loc="Domination Point, Krasarang Wilds"}}
d[32127]={mo=198450,rep="+300 Dominance Offensive",o="Defeat Captain Brent the Black and Captain Mulkey. *Captain Brent the Black slain *Captain Mulkey slain",de="Our Warchief has dispatched me to these shores to deal with this pitiful Alliance threat. These humans and their allies have proven to be very dependant on their leaders. No initiative of their own. As you walk the battlefield today look to the Alliance ships off our southern shores. Find their captains. Slay them. For the Horde!",g={n="Brolic",loc="Domination Point, Krasarang Wilds"}}
d[32128]={mo=198450,rep="+150 Dominance Offensive",o="Detonate the explosive cargo of The Defiant and Valor's Edge. *Valor's Edge ammunition destroyed *The Defiant ammunition destroyed",de="The Alliance have planted themselves off our southern coast and continue to pepper our ground forces with cannon fire. Let us see how great their siege is without such support. Board the enemy vessels and destroy their reserve ammunition. This will take the teeth out of their bite.",g={n="Blood Guard Gro'tash",loc="Domination Point, Krasarang Wilds"}}
d[32130]={mo=198450,rep="+150 Dominance Offensive",o="Collect 10 Extra-Waxy Alliance Ears at Lion's Landing in Krasarang Wilds. *Extra-Waxy Alliance Ears (10)",de="I've got some customers lined up that wanna collect some good old fashioned ears. But not any old ears. They only want the absolute waxiest ears money can buy! Guess they think they're lucky or something'. Anyways, I need you to go get 'em for me. I don't want to hurt any animals, so you'll need to get 'em from the Alliance over at Lion's Landing. Have fun - and remember, only bring me the waxiest!",g={n="Zazzix \"Toasty\" Sparkrocket",loc="Sparkrocket Outpost, Krasarang Wilds"}}
d[32131]={mo=198450,rep="+150 Dominance Offensive",o="Collect 20 Animatable Stone chunks from the Lion's Landing quarry. Lion's Landing Engineers carry them, or you can destroy stone slabs with collateral damage to blow them into chunks you can carry. *Animatable Stone#Horde (20)",de="Gnomes are excavating a stone quarry to the northeast. They're building stuff with it! They're too stupid to realize it's special mogu stone for creating animated statues. WE can mix with a little Goblin magic juice to make some real big explosions! But the stuff is heavy. They've got some of their stupid bomb-bots there for excavating the stone. Blow 'em up near slabs and you'll get chunks small enough to carry. Or, just kill 'em and take it. Whatever works.",g={n="Zazzix \"Toasty\" Sparkrocket",loc="Sparkrocket Outpost, Krasarang Wilds"}}
d[32132]={mo=198450,rep="+150 Dominance Offensive",o="Kill 30 Lion's Landing Peasants. *Shieldwall Peasant slain (30)",de="Our goblin friends do not have the grasp of strategy necessary to win a long term engagement, I'm afraid. The key to eliminating any permanent establishment is to attack their ability to replenish their troops and to rebuild. In this case, that means taking out their Peasants. Kill them, and you weaken the foundation. The rest of the keep is bound to crumble.",g={n="Shademaster Kiryn",loc="Various"}}
d[32133]={mo=114000,rep="+150 Dominance Offensive",o="Place Sentry Wards on the Docks, in the Town Hall, and on the Second Floor of the Barracks at Lion's Landing. *Sentry Ward placed in Town Hall *Sentry Ward placed on Docks *Sentry Ward placed in Barracks, 2nd Floor",de="We've spotted heavy air support over their base, in the form of way too many dwarves on way too many griffons. Means we can't get any vision of the area from above. A troll... friend of mine gave us a set of Sentry Wards, which we can use to spy on their base and get a vantage point on what's going on in there. Bad news, friend - you're going to be the one going in there.",g={n="Shademaster Kiryn",loc="Various"}}
d[32134]={mo=198450,rep="+150 Dominance Offensive",o="Kill 8 Lion's Landing Mortar Team Engineers and destroy 2 Lion's Landing Mortar Tubes. *Dwarven Mortar Team Engineers slain (2) *Dwarven Mortar Tubes destroyed (8)",de="We've managed to get some Demolishers on the beach, but the stupid dwarves are also out there with their stupid mortar tubes, preventing the Demolishers from pushing forward and assaulting the keep itself! Get out there, kill some dwarves, and blow up some mortar tubes.",g={n="Zazzix \"Toasty\" Sparkrocket",loc="Sparkrocket Outpost, Krasarang Wilds"}}
d[32135]={mo=198450,rep="+300 Dominance Offensive",o="Kill an Alliance Hero at Lion's Landing in Krasarang Wilds. *Alliance Hero slain",de="There are some situations in which taking out one of their soldiers is more important than killing hundreds. They've deployed some of their heroes to the battlefield to help rally their defenders. Not only will killing them soften their defense, it will also leave their morale crippled. So go, take one down for me. You can handle it.",g={n="Shademaster Kiryn",loc="Various"}}
d[32136]={mo=19850,o="Find Grizzle Gearslip in Bilgewater Beach.",de="Our fuel supplies are running low. Without fuel we won't be able to operate the machinery that's building this place. They might even expect me to start helping them build! I was not built for manual labor! See these nails?! I just had them done! Get down to the refinery and get this fuel order filled! Hurry! They were fitting me for a tool-belt this morning. It didn't even match my outfit!",g={n="Boss-Lady Trixel",loc="Domination Point, Krasarang Wilds"}}
d[32137]={mo=198450,rep="+150 Dominance Offensive",o="Retrieve 9 \"Distilled\" Fuel Barrels from the Blacksand Spillway. *\"Distilled\" Fuel Barrel (9)",de="I've never seen this quality of oil! Problem is the oil needed a little extra refinin'. I heard of this system where you use ocean water to speed up the process. I don't have time to waste down here, so I just threw the barrels into the bay. Pretty good idea, I know. Problem is, I'm not sure how to pull it out of the bay... Maybe someone of your expertise could help me out.",g={n="Grizzle Gearslip",loc="Krasarang Wilds; Dagger in the Dark; Dark Heart of Pandaria"}}
d[32138]={mo=19850,o="Find Zino \"The Shredder\" Quickchop in the Lumber Farm.",de="Everyday it's the same thing! \"We're out of this!\", \"We need more of that!\", \"Why don't you ever do anything?!\" I work! I do things! They can be so hurtful! I'm doin' my best down here! Oh yeah, we need more lumber! Go down and tell that good for nothin' Zino to get his shredders in gear!",g={n="Boss-Lady Trixel",loc="Domination Point, Krasarang Wilds"}}
d[32139]={mo=198450,rep="+150 Dominance Offensive",o="Gather 9 Pieces of Domination Point Lumber from the Lumber Farm. *Domination Point Lumber collected (9)",de="We just filled an order this morning. How could they possibly need more already?! My team has been workin' double-time to get these trees chopped and processed. Problem is we have an infestation of Lion's Landing troops down here. I already risked my neck once today, I'm not goin' back out there! Goob will go with you and help you fill this order. He's not the brightest, but he can do the heavy liftin'.",g={n="Zino \"The Shredder\" Quickchop",loc="Quickchop's Lumber Farm, Krasarang Wilds"}}
d[32140]={mo=19850,o="Find Daxil \"The Gem\" Oregrind near the Deep Crawl Mine.",de="When they said they found some amazing rocks in that mine I envisioned diamonds. Everyone knows all mines have diamonds, silly! At the very least rubies! Instead, all I got was this strange iron! What am I supposed to do with this? Oh well, no one said this job would be glamorous. I just do what I can to add a little class. We just got another work order for iron. Go see Daxil down near the Deep Crawl Mine and get it filled pronto!",g={n="Boss-Lady Trixel",loc="Domination Point, Krasarang Wilds"}}
d[32141]={mo=198450,rep="+150 Dominance Offensive",o="Obtain 7 chunks of Energized Ore from Oregrind's Dig. *Energized Iron Ore Chunk (7)",de="Sometimes we dig too deep, . Sometimes, we uncover something so horrible we wish we hadn't started diggin'... Just kidding! I mean, don't get me wrong, we did find something unexpected. The ore we're finding down there is not your average run-of-the-mill iron. There is just one problem; Shale Spiders! We're struggling to keep these orders filled. Maybe you can lend us a hand?",g={n="Daxil \"The Gem\" Oregrind",loc="Daxil's Dig, Krasarang Wilds"}}
d[32142]={mo=198450,rep="+150 Operation: Shieldwall",o="thumb|Dominance Grunt. thumb|Dominance Shaman. Slay 10 Orcs at Domination Point. *Domination Orc slain (10)",de="The orcs can NOT be allowed a foothold in this land. They will defile it just as they did Kalimdor. , I need boots on the ground and horde in their graves. Get down to the coastline and bring the full force of Alliance wrath down on their heads! Slay any orcs you find. Take the wind out of their sails. For the King!",g={n="Sky Admiral Rogers",loc="Various"}}
d[32143]={mo=198450,rep="+150 Operation: Shieldwall",o="Find the three Scout-o-Matics in Domination Point. *Eliminate the Beachhead Demolishers *Eliminate the Horde Wolves *Destroy the Horde Bomb Stockpile",de="Greetings ! I have heard a lot about your success in the field. I would like to use your services to test my latest \"Siege-o-Matic\", a device of terrible and varied abilities. I promise it is mostly harmless to its users. When you are around Domination Point be on the look out for my Scout-o-Meters. They have been dispatched to get info on good siege targets. When you find one, activate it and I will pilot a Siege-o-Matic to your location. See you in the field... as it were.",g={n="Tinkmaster Overspark",x=0.706,y=0.5,loc="Various"}}
d[32144]={mo=198450,rep="+150 Operation: Shieldwall",o="Destroy 8 Horde Supply Crates. *Horde Supply Crates Destroyed",de="The Horde are consumed by pride and will fight to the death without a second thought. We need to find a way to break their will that does not involve massive loss of our numbers. Look for the Horde supplies along the coastline and near their ships. Smash their supplies. Nothing breaks the will of a defender like seeing their hope of food go up in a puff of smoke. When you are done, find Sully behind enemy lines. He has the next task for you.",g={n="Mishka",x=0.5257,y=0.7358,loc="Various"}}
d[32145]={mo=198450,rep="+300 Operation: Shieldwall",o="Defeat Stone Guard Ruk'ra, Bombgineer Snicklefritz, and Or'Dac. *Or'Dac slain *Stone Guard Ruk'Ra slain *Chief Bombgineer Snicklefritz slain",de="My probes have detected three very dangerous targets in the courtyard of Domination Keep. They have an ogre emissary, a Kor'kron officer, and an insane goblin bomb maker. My siege-o-matics are not ready for one on one combat so it is up to you to eliminate the targets. Good luck! Report back to me on the Skyfire when done."}
d[32146]={mo=198450,rep="+150 Operation: Shieldwall",o="Kill 5 Heavy Mooks. *Heavy Mook slain (5)",de="It looks like the Horde thinks they can hide behind their heavy hitting mooks. The mooks are tough, powerful, and dumber than an ogre with a hangover. Go down there and bring the hammer of the Alliance fury down on them!",g={n="Sky Admiral Rogers",loc="Various"}}
d[32148]={mo=198450,rep="+150 Operation: Shieldwall",o="thumb|Dominance Raider. thumb|Dominance Shaman. Kill 12 Dominance Shamans or Dominance Raiders. *Dominance Shaman or Raider slain (12)",de="Sure, they've got about plenty of grunts out there, pounding on our door, waiting to cut our heads off. I'm not worried about grunts. They've got shaman, and raiders, too. The shaman use their magic to empower the grunts, and the raiders are fast and specialize in taking out our buildings. I need you to get out there and kill some of those shaman and raiders. Go! Attack! Move!",g={n="Marshal Troteman",x=0.287,y=0.407,loc="Various"}}
d[32149]={mo=198450,rep="+150 Operation: Shieldwall",o="thumb|Lion's Landing Lumber Collect 12 Lion's Landing Lumber by recovering it from piles of Hastily Abandoned Lumber. *Lion's Landing Lumber (12)",de="Oh, the poor peasants... They are cowards, yes, of course. But they don't know how to fight, and they go out to collect lumber for our efforts... the Horde targets them... It's just awful all around! But, we need that lumber if we're going to hold out. Go out and collect any they've dropped.",g={n="Mishka",x=0.5257,y=0.7358,loc="Various"}}
d[32150]={mo=198450,rep="+150 Operation: Shieldwall",o="Destroy 8 Domination Point Supply Carts. *Domination Point Supplies destroyed (8)",de="The Horde decided to put goblins in charge of their logistics. And where you have goblins, you have carelessly placed explosives. Scouts have reported that they have their supplies in carts that also contain Demolisher ammunition. Look at those crates the wrong way, and they'll blow sky high. With enough Horde resources destroyed, we'll put a time limit on their attack and save lives. So go and take out those carts!",g={n="Mishka",x=0.5257,y=0.7358,loc="Various"}}
d[32151]={mo=198450,rep="+150 Operation: Shieldwall",o="Collect 20 Animatable Stone at the Lion's Landing Quarry from Bilgewater Goblins or by destroying stone slabs there with collateral damage. *Animatable Stone (20)",de="The gnomes are running our quarry operation to the northwest. The stone there is especially tough - the gnomes tell me the mogu used it to fashion their constructs. I don't know. What I do know is that we use that stone to build our towers, and the Horde has dispatched the Bilgewater goblins to steal it from us. Get out there and get some back. By the way - collateral damage may break up the stone slabs there. If so, pick that up, too.",g={n="Marshal Troteman",x=0.287,y=0.407,loc="Various"}}
d[32152]={mo=198450,rep="+150 Operation: Shieldwall",o="thumb|Bilgewater Sapper. Find a Bilgewater Blasting Cap on a Bilgewater Sapper, and then plant it on a Domination Point Demolisher. *Bilgewater Blasting Cap *Domination Point Demolisher destroyed",de="The Horde got the bright idea to send Bilgewater goblins to attack our quarry. They've been packing heavy explosives - heavy explosives that will react with the ammunition in their demolishers. Kill the Bilgewater goblins until you find an explosive, plant it on one of the demolishers... and BOOM! Siege ended.",g={n="Marshal Troteman",x=0.287,y=0.407,loc="Various"}}
d[32153]={mo=198450,rep="+300 Operation: Shieldwall",o="Kill a Horde Hero. *Horde Hero slain",de="Look, you're tough. Tougher than the rest of the men and women I've got here. Which means I need you for a special mission. The Horde is throwing their best against us. Heroes of their armies - Blademasters, Tauren Chieftains, you name it. I need you to go take one out. It'll be a huge blow, not just to their offensive but also to morale.",g={n="Marshal Troteman",x=0.287,y=0.407,loc="Various"}}
d[32154]={mo=198450,rep="+150 Operation: Shieldwall",o="thumb|Northern Fuel Tank. thumb|Northwestern Fuel Tank. Use the Unstable Explosive to destroy the Northestern Fuel Tank, Northern Fuel Tank, and the Northwestern Fuel Tank. *Northeastern Fuel Tank destroyed *Northern Fuel Tank destroyed *Northwestern Fuel Tank destroyed *Unstable Explosive (provided)",de="Those goblins are gettin' out of hand! First they level the forest and set up that abomination of a rig. Then, they start dumpin' their oil barrels into the bay! We got to put a stop to this madness! At the very least we need ta set them back. We need to take out their fuel supply! Maybe you'll even get to kill a few goblins in the process!",g={n="Sully \"The Pickle\" McLeary",loc="Various"}}
d[32156]={mo=198450,rep="+150 Operation: Shieldwall",o="Retrieve 7 Shieldwall Soldier Dog Tags from the Fallen Shieldwall Soldiers in and around Bilgewater Beach. *Shieldwall Soldier Dog Tag (7)",de="This is barbaric warfare, ! We've lost so many trying to keep the Bilgewater operation from spreading any further. Those fallen soldiers fought honorably and deserved to be given their last rights. At the very least we need to be able to notify their next of kin. Perhaps you can collect their identification tags so we can honor them in some small way.",g={n="Mishka",x=0.5257,y=0.7358,loc="Various"}}
d[32157]={mo=198450,rep="+150 Operation: Shieldwall",o="Kill 10 Bilgewater Goblins in and around Bilgewater Beach. *Bilgewater Goblins slain (10)",de="The destruction in Krasarang is unforgivable, . The only way to put an end to this is to destroy the Bilgewater operation. This is for the greater good of Pandaria and the Alliance. Go to Bilgewater Beach and cut them down! No doubt the Horde will come to their assistance.",g={n="Sky Admiral Rogers",loc="Various"}}
d[32158]={mo=198450,rep="+300 Operation: Shieldwall",o="thumb|Shredmaster Packle. Destroy Shredmaster Packle in Quickchop's Lumber Farm. *Shredmaster Packle slain",de="Shredmaster Packle is responsible for much of the devastation down there, . Rumor has it he modified the shredders to work more quickly with less regard for the collateral damage they can inflict. Imagine the agony the trees must endure being hacked at. It will be difficult to recover from this level of destruction. The first step in any recovery is acknowledging the problem. Step two is eliminating that problem.",g={n="Seraphine of the Winter",x=0.167,y=0.786,loc="The Skyfire, Krasarang Wilds"}}
d[32161]={r={{n="2x Lesser Charm of Good Fortune"}},mo=114000,o="Obtain 5 Pristine Golden Crownfeathers and a Pristine Jet Crownfeather. * Pristine Golden Crownfeather (5) * Pristine Jet Crownfeather",de="Along with the snare, you get some advice on crane hunting: The greatest cranes of the Krasarang Wilds are not tempted by simple things like food. You will need to play on the creatures' emotions if you wish to draw them from their hiding places in the jungle. Cranes abound on both the Cradle of Chi-ji and the Narsong Spires, both of which can be found east of here. Pluck those cranes' quills, then place them in a visible spot near the Crane Temple. Your quarry will come running to you.",g={n="Sturdy Crane Snare#Horde"}}
d[32162]={r={{n="2x Lesser Charm of Good Fortune"}},mo=114000,o="Obtain 25 Unbruised Yak Haunches. * Unbruised Yak Haunch (25)",de="Along with the trap, you get some advice on tiger hunting: Tigers are gluttonous creatures, and large game is hard to come by in this jungle. If you wish to tempt the most elder cats out of their hiding places, you may do so with a meal. Just on the other side of the Serpent's Spine, you will find a herd of yaks. Slay them, bring their meat to the jungle's edge, set up your trap, and wait.",g={n="Sturdy Tiger Trap (Horde)"}}
d[32163]={r={{n="2x Lesser Charm of Good Fortune"}},mo=114000,o="Obtain 30 Funky Rotten Fish from Unga Villagers in Unga Ingoo. * Funky Rotten Fish (30)",de="Along with the crate, you get some advice on crab hunting: Crabs are strange, primordial creatures, with wildly different motivations than you or I. Small crabs are easy to find and hunt, but the large ones hide beneath the sands, out of danger and out of our reach. To draw them out, we play on their sense of smell. The Unga villagers to the southeast allow their fish to ferment before they eat them. Bring enough rotten fish together, and you will catch yourself a colossal crab.",g={n="Sturdy Crab Crate#Horde"}}
d[32164]={r={{n="2x Lesser Charm of Good Fortune"}},mo=114000,o="Obtain 5 Pristine Golden Crownfeathers and a Pristine Jet Crownfeather. * Pristine Golden Crownfeather (5) * Pristine Jet Crownfeather",de="Along with the snare, you get some advice on crane hunting: The greatest cranes of the Krasarang Wilds don't care about simple things like food. You need to play on the creatures' emotions if you want to draw them out of the jungle. There's plenty of cranes on the Cradle of Chi-ji and on the Narsong Spires, both to the west of here. Pluck some of those cranes' quills, then put them in a visible spot near the Crane Temple. Your quarry will come running to you.",g={n="Sturdy Crane Snare"}}
d[32165]={r={{n="2x Lesser Charm of Good Fortune"}},mo=114000,o="Obtain 25 Unbruised Yak Haunches. * Unbruised Yak Haunch (25)",de="Along with the trap, you get some advice on tiger hunting: Tigers are gluttons, and big game is hard to come by in this jungle. If you want to tempt the elder cats out of their hiding places, you need a tempting meal. Just on the other side of the Serpent's Spine, you can find a herd of yaks. Kill them, bring their meat to the jungle's edge, set up your trap, and wait.",g={n="Sturdy Tiger Trap (Alliance)"}}
d[32166]={r={{n="2x Lesser Charm of Good Fortune"}},mo=114000,o="Obtain 30 Funky Rotten Fish from Unga Villagers in Unga Ingoo. * Funky Rotten Fish (30)",de="Along with the crate, you get some advice on crab hunting: Crabs are strange, old creatures, with different motivations than us. Small crabs are easy to find and hunt, but the big ones hide beneath the sands, out of danger and out of our reach. To draw them out, we play on their sense of smell. The Unga villagers to the southwest allow their fish to ferment before they eat them. Bring enough rotten fish together, and you will catch yourself a colossal crab.",g={n="Sturdy Crab Crate"}}
d[32197]={mo=198450,rep="+150 Dominance Offensive",o="Obtain 7 Chunks of Mystery Meat from the local wildlife. *Chunk of Mystery Meat (7)",de="We've been gettin' complaints right and left that the Boss-Lady gets all the good grub and leaves the scraps for the others. Between you and I, they may be onto somethin' here. I don't even get to eat as good as she does! We need somethin' Sezik can make a lot of that at least attempts to disguise how inedible the food is here... I got it! Mystery Meatloaf!",g={n="Duke (goblin)",loc="Domination Point, Krasarang Wilds"}}
d[32199]={mo=198450,rep="+150 Dominance Offensive",o="Obtain 5 chunks of Polluted Viseclaw Meat from the Viseclaw crabs on Bilgewater Beach. *Polluted Viseclaw Meat (5)",de="The Boss-Lady desires crabs! Why are you looking at me like that? It's not uncommon for a classy person, such as her loveliness, to want crab for dinner. What did you think I meant? There are some big crabs wandering around on Bilgewater Beach that should be suitable for her refined palate. Bring Sezik the best crab meat you can find!",g={n="Duke (goblin)",loc="Domination Point, Krasarang Wilds"}}
d[32200]={mo=198450,rep="+150 Sunreaver Onslaught",o="Slay 12 Trolls in Za'Tual. *Trolls slain in Za'Tual (12)",de=", what I ask of you is little short of genocide, but it is a task that must be done. Find trolls within their town or on the beach and slay them, for the good of us all.",g={n="Halduron Brightwing",x=0.54,y=0.206,loc="Various"}}
d[32201]={mo=198450,rep="+150 Sunreaver Onslaught",o="Kill 10 Shan'ze Gravekeepers, Shan'ze Soulrippers, or Shan'ze Thundercallers. *Shan'ze mogu slain at the Court of Bones (10)",de="The Court of Bones crawls with mogu forces. Endlessly do they perform their rituals of lightning and thunder. If our mission to take this island is to succeed, then we cannot allow them to hold such a strategic position. They must be eliminated.",g={n="Grand Magister Rommath",x=0.546,y=0.21,loc="Various"}}
d[32204]={mo=198450,rep="+150 Sunreaver Onslaught",o="Slay 10 Skumblade saurok. *Skumblade saurok slain (10)",de="Ihgaluk Crag has no end of saurok. Those beasts attack my men and spread their disease into nearby water and wildlife, interfering with our operations. Thin their numbers, . Once the Horde takes full control of this island, we can look for more permanent solutions.",g={n="Archmage Aethas Sunreaver",x=0.316,y=0.484,loc="Various"}}
d[32206]={mo=198450,rep="+150 Sunreaver Onslaught",o="Kill any 8 Zandalari trolls within Conqueror's Terrace. *Conqueror's Terrace Zandalari slain (8)",de="The Zandalari here are very powerful, . They should not be underestimated. We cannot afford to ignore them as a threat simply because they do not wield swords. More arrive every day, and with them centuries of magic knowledge. This threat must be dealt with, and quickly. Aid us in clearing this area, . Perhaps we can even learn something from them in the process.",g={n="Scout Captain Elsia",x=0.4125,y=0.8803,loc="Various"}}
d[32207]={mo=198450,rep="+150 Sunreaver Onslaught",o="Defeat 10 Zandalari trolls in the Beast Pens. *Beast Pens Trolls slain (10)",de="Inside the Beast Pens you will encounter some of the most skilled beast tamers in the Zandalari military. They are trained to kill with axe, beast, and claw. This is where they build their cavalry. We need you to kill any Zandalari you find in there before they can get their mounted monstrosities out into the open battlefield.",g={n="Magister Edien Sunhollow",loc="Various"}}
d[32208]={mo=198450,rep="+150 Sunreaver Onslaught",o="Interact with the three lightning drills in the Lightning Vein Mine to destroy them, and kill Metal Lord Mono-Han. *Western Lightning Drill destroyed *Central Lightning Drill destroyed *Eastern Lightning Drill destroyed *Metal Lord Mono-Han slain",de="The mines north of here are being used to extract Ghost Iron ore and energize it with lightning energy. We need to destroy the drills they use to extract the ore. They are impervious to normal attack, but can be overloaded using the proper methods. Oh - and while you're there, take out whoever is running the operation.",g={n="Magister Edien Sunhollow",loc="Various"}}
d[32209]={mo=198450,rep="+150 Sunreaver Onslaught",o="Rescue the three captured Sunreaver agents within the Lightning Vein Mine, and kill Metal Lord Mono-Han. *Scout Elearis rescued *Scout Merior rescued *Scout Alaine rescued *Metal Lord Mono-Han slain *Arcane Emancipator (provided)",de="The heavy mogu presence in the mines let us know it was a place of great importance - but we needed to gather more information on their activities there, so we sent agents into the mines to spy on them. Unfortunately, many were captured, and we've found that some are being tortured in the mines. You have to go rescue them - nobody deserves what they are going through... And, when you finish, kill whoever captured them. No mercy, !",g={n="Magister Edien Sunhollow",loc="Various"}}
d[32213]={mo=198450,rep="+150 Sunreaver Onslaught",o="Kill 10 Kirin Tor units or players on the Isle of Thunder. *Kirin Tor agents slain (10)",de="So the Jaina and the Kirin Tor think they can push us out again? I will not stand by and allow them to repeat the events of Dalaran! This time we fight back! This time we do the pushing... Go to Violet Rise and slay any Kirin Tor agent you find.",g={n="Lor'themar Theron",x=0.54,y=0.206,loc="Various"}}
d[32214]={mo=198450,rep="+150 Dominance Offensive",o="Kill 10 SI: 7 Saboteurs around Domination Point and Bilgewater Beach. *SI:7 Saboteur slain (10) *\"New\" and \"Improved\" Infrared Heat Focals (provided)",de="Very nice, ! I knew it! I knew there were Alliance sneaking around down there! No one messes with a Bilgewater rig and gets away with it!",g={n="Rivett Clutchpop",loc="Various"}}
d[32215]={mo=198450,rep="+150 Sunreaver Onslaught",o="Destroy the Zandalari sacrificial altars. *Cha'lat's Altar destroyed *Tec'uat's Altar destroyed *Pa'chek's Altar destroyed",de="The Zandalari perform heinous rites against our people! They must be stopped! Delve into the heart of the Za'Tual and destroy their altars.",g={n="Elina Zaralae",loc="Court of Bones, Isle of Thunder"}}
d[32216]={mo=198450,rep="+150 Sunreaver Onslaught",o="Free the Tormented Skyscreamer. *Tormented Skyscreamer freed",de="The Zandalari treat their skyscreamer pets as little more than scuttling vermin, bending them to their will with violence and torment. I can hear one writhing in pain at their hands. Find the tormented skyscreamer within Za'Tual and help it break free of its captors.",g={n="Kethiel Sunlance",x=0.764,y=0.238,loc="Various"}}
d[32217]={mo=198450,rep="+150 Sunreaver Onslaught",o="Destroy 6 Zandalari Offerings. *Zandalari Offerings destroyed (6)",de="The spirtibinders of the Zandalari perform sacrificial rites to appease the loa and their vile gods. These dark rituals involve the sacrifice of our people. Destroy any offerings you can find among their tents in Za'Tual and perhaps we can stall the sacrifices.",g={n="Elina Zaralae",loc="Court of Bones, Isle of Thunder"}}
d[32218]={mo=198450,rep="+150 Sunreaver Onslaught",o="thumb|Mummified Remains. Burn 8 Mummified Remains. *Mummified Remains burned (8) *Blessed Torch (provided)",de="The mogu here at the Court of Bones are bolstering their army by resurrecting the spirits of their dead. We cannot allow them to revive their fallen warriors. Take this torch and burn any mummified corpses that you can find. We will destroy our enemies before they have a chance to rise.",g={n="Captain Aerthas Firehawk",loc="The Firehawk, Hrothgar's Landing; Court of Bones & Dawnseeker Promontory, Isle of Thunder"}}
d[32219]={mo=198450,rep="+150 Sunreaver Onslaught",o="Destroy 8 Grave Guardians. *Grave Guardians destroyed (8)",de="Our assault on the Court of Bones continues. Our progress remains slow, but measurable. Unfortunately, we've received several reports of stone quilen statues coming to life without warning. I can't have these quilen threatening my research expedition. Venture into the Court of Bones and destroy any quilen statues that you can find.",g={n="Ryshelle Brightlock",loc="Court of Bones, Isle of Thunder"}}
d[32220]={mo=198450,rep="+150 Sunreaver Onslaught",o="thumb|Shan'ze Soulripper. thumb|Silver Covenant Scout (Isle of Thunder)|Silver Covenant Scout. thumb|Sunreaver Scout (Isle of Thunder)|Sunreaver Scout. Save 6 Sunreaver Scouts or Silver Covenant Scouts. *Scouts rescued (6)",de="We assault the mogu at the Court of Bones, but I fear we merely send them fodder for their abominable rituals. The mogu do not merely kill their prisoners - they steal their souls and imbue them in machinations of stone, or reforge the fallen into ghostly tools of war. Horde or Alliance, it matters not. We cannot allow the mogu to bolster their numbers. Go into the crypts. Free any prisoners that are still living.",g={n="Captain Aerthas Firehawk",loc="The Firehawk, Hrothgar's Landing; Court of Bones & Dawnseeker Promontory, Isle of Thunder"}}
d[32221]={mo=198450,rep="+150 Dominance Offensive",o="Kill any 10 Shieldwall Forces including SI: 7 Saboteurs in and around Bilgewater Beach. *Shieldwall forces slain (10)",de="Our lumber supply is being jeopardized by constant attacks from Lion's Landing. We've been able to keep the attackers at bay, but it's time to really show 'em some muscle! Head down to the coast and start splitting some skulls!",g={n="Rivett Clutchpop",loc="Various"}}
d[32222]={mo=198450,rep="+300 Dominance Offensive",o="Destroy Chief Engineer Cogwrench at the edge of Bilgewater Beach. *Chief Engineer Cogwrench slain",de="Wanted for crimes against the Bilgewater Operation! Chief Engineer Cogwrench was last seen building what appeared to be a giant spider tank on the edge of Bilgewater Beach. Extreme caution should be used when approaching. A large reward has been posted for Cogwrench's destruction.",g={n="Bounty Board (Krasarang Wilds)"}}
d[32223]={mo=198450,rep="+300 Dominance Offensive",o="Destroy Lieutenant Ethan Jacobson in the Southern Isles south of Quickchop's Lumber Farm. *Lieutenant Ethan Jacobson slain",de="Wanted for crimes against the Domination Point forces! Lieutenant Ethan Jacobson is responsible for leading several ground assaults against the Bilgewater lumber operation. Last spotted occupying an island south of Quickchop's Lumber Farm.",g={n="Bounty Board (Krasarang Wilds)"}}
d[32224]={mo=198450,rep="+150 Sunreaver Onslaught",o="Kill 15 Risen Ancestors. *Risen Ancestor slain (15)",de="Have you seen the ghosts wandering the graveyard? They are risen ancestors, the spirits of slain mogu who have been called back to this world. When angered, they attack swiftly and silently, and their numbers increase by the day. They do not belong here. Destroy them, and send them back beyond the grave.",g={n="Ryshelle Brightlock",loc="Court of Bones, Isle of Thunder"}}
d[32225]={mo=198450,rep="+150 Sunreaver Onslaught",o="Stop the Shan'ze Thundercallers' ritual. *Shan'ze Thundercallers' ritual stopped",de="Within the graveyard, in the deepest ruins of their western crypt, the Thunder King's most powerful sorcerers are charging a lightning rod with crackling electricity. We suspect that this weapon is meant to rain destruction on our stronghold at Dawnseeker Promontory. There is no time to delay. You must stop their ritual at once.",g={n="Grand Magister Rommath",x=0.546,y=0.21,loc="Various"}}
d[32226]={mo=198450,rep="+150 Sunreaver Onslaught",o="Use the Incantation of Gura in the Hall of the Exalted, then defeat Gura the Reclaimed. *Gura the Reclaimed slain *Incantation of Gura (provided)",de="The Reliquary is having a field day out here, literally! Every day, the researchers find more relics to study and catalog. Recently, one of our adventurers found this scroll at the Court of Bones. I believe that this incantation can be used to call beyond the grave. And if my Mogu is up to date, I'd say you should use it in the last room in the Hall of the Exalted. Would you be willing to test out my theory?",g={n="Ryshelle Brightlock",loc="Court of Bones, Isle of Thunder"}}
d[32227]={mo=198450,rep="+150 Sunreaver Onslaught",o="Frighten 12 Hatchling Skyscreamers by running near them. *Hatchling Skyscreamers frightened (12)",de="The creatures the Zandalari ride don't start out so big, nor do they start out the vicious and loyal creatures they become. If you can frighten some of the hatchling skyscreamers away from the beach, perhaps they will have a chance at a real life.",g={n="Kethiel Sunlance",x=0.764,y=0.238,loc="Various"}}
d[32228]={mo=198450,rep="+150 Sunreaver Onslaught",o="Kill the Mighty Devilsaur. *Mighty Devilsaur slain",de="There is an immense beast in the swamp. It has not yet marched upon us, but I place no stock that we will continue to be so fortunate. Strike it down before it grows hungry enough to brave our defenses.",g={n="Girana the Blooded",loc="Various"}}
d[32230]={mo=198450,rep="+150 Sunreaver Onslaught",o="Destroy the Zandalari Colossus. *Zandalari Colossus slain",de="The trolls have dispatched one of their immense constructs on the southern road, blocking our passage around the island. See to it that the road is cleared, .",g={n="Girana the Blooded",loc="Various"}}
d[32232]={mo=198450,rep="+150 Sunreaver Onslaught",o="Destroy Guardian Tak'u in Conqueror's Terrace. *Guardian Tak'u slain",de="I noticed something strange on my last scouting mission. A group of Zandalari are performing a ritual on what appears to be a very large sentry. They may be trying to re-animate it. We need that ritual stopped and the sentry destroyed. Anything that large can't be good. I've sent a scout ahead to observe their actions. Meet with her and figure out how to stop them.",g={n="Scout Captain Elsia",x=0.4125,y=0.8803,loc="Various"}}
d[32233]={mo=198450,rep="+150 Sunreaver Onslaught",o="Steal 7 Loa-Infused Blades from Conqueror's Terrace. *Loa-Infused Blade (7)",de="Look around you, . What do you see? I see an opportunity. The casters here work to imbue the Zandalari weapons with powerful magic. As if a sharp blade isn't enough to cut even the strongest foe down to size. In my scouting I've noticed the weapons are not very well guarded. This is where you come in... If we can steal a few of these weapons we may be able to use them. At the very least they are out of enemy hands.",g={n="Scout Captain Elsia",x=0.4125,y=0.8803,loc="Various"}}
d[32234]={mo=198450,rep="+150 Sunreaver Onslaught",o="Retrieve 6 Ritual Artifacts from around Conqueror's Terrace. *Ritual Artifact (6)",de="The Zandalari here practice a different kind of magic. We must understand it before we can defeat it, . Their control over the arcane and shadow is impressive. I wish to learn how they have achieved what so many others have not. I believe their ritual artifacts may hold the answers I seek. Bring me a sampling of the artifacts you find, and I will ensure you are rewarded properly.",g={n="Magister Edien Sunhollow",loc="Various"}}
d[32235]={mo=198450,o="Use the Bilgewater Molotovs to destroy 6 Skyfire Gyrocopter X2s. *Skyfire Gyrocopter X2 slain (6) *The Bilgewater Molotov (provided)",de="The gnomes have brought their flying contraptions. I want my skies CLEAR! Get up there on whatever mount you have with you and destroy those paltry devices. You may use this grog I \"acquired\" from our goblin allies. It would be better served blasting down gyrocopters than in the gullet of those little green fiends.",g={n="Blood Guard Gro'tash",loc="Domination Point, Krasarang Wilds"}}
d[32236]={mo=198450,rep="+150 Dominance Offensive",o="Spray 5 Agitated Shale Spiders with the Bug Off Sprayer and eradicate 12 Shale Shards. *Agitated Shale Spiders sprayed (5) *Shale Shards eradicated (12) *Hand-Dandy Bug Off Sprayer (provided)",de="This cave is crawlin' with nasty shale spiders! How's a girl supposed to get any work done with them gobbling up the miners AND the ore?! This seemed like a good opportunity to use my newest invention, Bug Off. See, all you have to do is spray this stuff all over the shale spiders. They hate it and it doesn't seem to have many long term side-effects for the miners! What could possibly go wrong? Take this handy sprayer and get to work!",g={n="Bixy Buzzsaw",loc="Daxil's Dig, Krasarang Wilds"}}
d[32237]={mo=198450,rep="+150 Dominance Offensive",o="Tighten 8 Faulty Valves in and around Gearslip's Gusher. *Faulty Valve tightened (8)",de="What we have here is too much of a good thing, ! Our rig just can't handle the amount of oil we're pumping out of the ground. It's literally bursting at the seams! To be more accurate, it's bursting at the valves. I've been working double-time to get the valves repaired, but every time I finish the rounds, they're all broken again. It's as if someone is following me... That's ridiculous though.... Maybe you'll have better luck. Try getting as many of those valves tightened as you can.",g={n="Bixy Buzzsaw",loc="Daxil's Dig, Krasarang Wilds"}}
d[32238]={mo=198450,rep="+150 Dominance Offensive",o="Destroy 9 Shieldwall Mecha-Pounders in and around Quickchop's Lumber Farm. *Shieldwall Mecha-Pounder exploded (9) *Universal Remote (provided)",de="The Mecha-Pounders are really making things difficult down here, but I think I may have the solution! I made this universal remote for myself, but it looks like I hit a specific frequency that has an useful result! Apparently this frequency weakens their armor! Use the remote to take them down a few notches then punch 'em in the face!",g={n="Bixy Buzzsaw",loc="Daxil's Dig, Krasarang Wilds"}}
d[32252]={mo=198450,rep="+150 Sunreaver Onslaught",o="Slay 2 Harbingers of the Loa. *Harbingers of the Loa slain (2)",de="Have you heard of the loa? We do not understand all of what it is, but it seems to be a dark magic with some degree of sentience. We do not know what power the loa might possess, but I must ask you to put a stop to their rituals, .",g={n="Halduron Brightwing",x=0.54,y=0.206,loc="Various"}}
d[32254]={mo=198450,rep="+150 Sunreaver Onslaught",o="Check in with Magister Arlan, Magister Sarien, and Magistrix Vesara. *Speak with Magister Arlan *Speak with Magister Sarien *Speak with Magistrix Vesara",de="I have three magisters entrenched in Ihgaluk Crag, monitoring the saurok and - where they can - turning them against the mogu. I need you to find them and see if they need any supplies or assistance. They will be concealed from view. Look for shimmering columns of light within the saurok village.",g={n="Archmage Aethas Sunreaver",x=0.316,y=0.484,loc="Various"}}
d[32255]={mo=198450,rep="+150 Sunreaver Onslaught",o="Recover the four stolen Sunreaver Constructs. *Recover Disabled Construct *Recover Buried Construct *Recover Distressed Construct *Recover Malfunctioning Construct",de="Saurok consistently test our borders, and our constructs usually fend them off. Some constructs, however, have been defeated and dragged back to Ihgaluk Crag. I want those constructs back. No slithering lizard will steal Sunreaver property under my watch.",g={n="Archmage Aethas Sunreaver",x=0.316,y=0.484,loc="Various"}}
d[32262]={mo=198450,rep="+150 Sunreaver Onslaught",o="Free 5 Sunreaver Captives around Violet Rise. *Free Sunreaver Captives (5)",de="The Kirin Tor have gone too far! Now they hold our fellow Sunreavers as war prisoners! There will be no discussion of prisoner exchange. We will handle this ourselves. Go to Violet Rise and free as many prisoners as you can. Do not get captured yourself. We cannot afford to lose you too.",g={n="Magister Hathorel",x=0.708,y=0.316,loc="Various"}}
d[32264]={mo=198450,rep="+150 Sunreaver Onslaught",o="Retrieve Jaina's Weathered Spellbook from Violet Rise. *Jaina's Weathered Spellbook",de="Jaina possesses several very powerful magic artifacts. These items travel with her at all times, and are never far from her grasp. I have an interest in one of these items. A tome, filled with knowledge, passed from one archmage to another. I have only ever seen glimpses of it. Now that we fight on opposite sides I see no issue in removing the tome from her possession.",g={n="High Arcanist Savor",loc="Various"}}
d[32265]={mo=114000,rep="+150 Sunreaver Onslaught",o="Recover a Charged Moganite and bring it to High Arcanist Savor. *Charged Moganite returned to Dawnseeker Promontory",de="We have been dispatching spies into the Kirin Tor base of operations on a daily basis. Some had orders to recover charged moganite from the enemy and bring it here. They have not returned, and I can confirm they have left the Kirin Tor base. Search the jungle between here and there and find any of the charged moganite that might have been lost in transit. Bring it to me and we will put it to good use.",g={n="High Arcanist Savor",loc="Various"}}
d[32266]={mo=198450,rep="+150 Sunreaver Onslaught",o="Kill 9 Kirin Tor Manafiends. *Kirin Tor Manafiend slain (9)",de="Manafiends are nasty creatures. Small and easy to underestimate, but deadly to our magic casters. The Kirin Tor have these pests crawling all over Violet Rise. We will need to handle them carefully. Alone they are easily managed, but in groups they become a different challenge altogether. Go to Violet Rise and cut down their numbers.",g={n="Girana the Blooded",loc="Various"}}
d[32268]={mo=198450,rep="+150 Sunreaver Onslaught",o="Plant a Tactical Mana Bomb on an Alliance Ship, Alliance Supply Shipment, and on the Construct Ritual. *Bomb placed on Alliance Ship *Bomb placed on Supply Shipment *Bomb placed on Construct Ritual *Case of Tactical Mana Bombs (provided)",de="Ah, , just the I was looking for. I have received another batch of tactical mana bombs that I need planted in key positions across Violet Rise to the southeast. Here, take these. I do not trust our standard soldiers with such firepower. Oh... and don't shake them, whatever you do. Plant one of the Kirin Tor ships, another one near their supplies, and the last on the construct they are building.",g={n="Girana the Blooded",loc="Various"}}
d[32269]={mo=114000,rep="+150 Sunreaver Onslaught",o="Destroy 6 Kirin Tor Perimeter Wards. *Kirin Tor Perimeter Wards destroyed (6)",de="We need to keep a close watch on the Kirin Tor and their day-to-day activities. Normally this would be easy. We would sneak in a spy and have them report back to us. However, we've run into a slight problem I believe you can help us with. The Kirin Tor perimeter wards have increased in power. It's next to impossible to get someone past their lines. If they were disabled we might be able to sneak in before they can be repaired.",g={n="Girana the Blooded",loc="Various"}}
d[32274]={mo=198450,rep="+150 Sunreaver Onslaught",o="Slay a Skumblade Brute, a Skumblade Saur-Priest, and a Skumblade Seadragon. *Skumblade Seadragon slain *Skumblade Saur-Priest slain *Skumblade Brute slain",de="The Skumblade threaten our people, but responding with all-out slaughter would be an overreaction. A more reasonable response to their threat would be to slay some of their tribal leaders. There will be less bloodshed, and they will still respect our perimeter.",g={n="Sunwalker Dezco",x=0.13,y=0.558,loc="Various"}}
d[32275]={mo=198450,rep="+150 Sunreaver Onslaught",o="Slay 3 Zandalari Spiritbinders, 3 Zandalari Beastcallers, and 3 Zandalari Jaguar Warriors. *Zandalari Beastcaller slain (3) *Zandalari Jaguar Warrior slain (3) *Zandalari Spiritbinder slain (3)",de="The Zandalari train skyscreamers to become ferocious beasts in the skies. The spiritbinders require endless sacrifices - of our people - to be brought to them. And, the jaguar warriors venture ever closer toward the heart of our camp. Find them in Za'Tual and remove the threat.",g={n="Halduron Brightwing",x=0.54,y=0.206,loc="Various"}}
d[32282]={mo=198450,rep="+150 Sunreaver Onslaught",o="Kill 5 Raptors and 10 Trained Compies in the Beast Pens. *Raptor slain (5) *Trained Compy slain (10)",de="The raptors and compies of the Zandalari represent a substantial threat to our forces here. They are superb hunting beasts that can track prey over great distances and are often lethal to encounter when caught unawares. I need you to head into the Beast Pens and cull their numbers. We need to make sure to slay them before they are fully trained.",g={n="Scout Captain Elsia",x=0.4125,y=0.8803,loc="Various"}}
d[32283]={mo=198450,rep="+150 Sunreaver Onslaught",o="Defeat a Loa Speaker. *Loa Speaker slain",de="The Zandalari have found a way to bind loa to their beasts giving them impressive and lethal powers. We need to put a stop to this. Search the Beast Pens for a loa speaker and slay him. You should be able to find them by keeping a look out for their glowing beasts. We must not allow these atrocities to continue.",g={n="Magister Edien Sunhollow",loc="Various"}}
d[32285]={mo=198450,rep="+150 Sunreaver Onslaught",o="Kill 6 Animated Warriors. *Animated Warrior slain (6)",de="The Shan'ze are animating an army from the statues in the center of the isle, an army that batters our defenses day and night. Destroy any of the walking statues you see. Our defenders will greatly appreciate it.",g={n="High Arcanist Savor",loc="Various"}}
d[32287]={mo=198450,rep="+150 Sunreaver Onslaught",o="Kill 7 Shan'ze mogu in the Diremoor. *Diremoor Shan'ze mogu slain (7)",de="There are mogu in the Diremoor animating the army of statues near the tower. Lor'themar wants them dead. I think you're the one to do it.",g={n="High Arcanist Savor",loc="Various"}}
d[32288]={mo=198450,rep="+150 Sunreaver Onslaught",o="Empower 6 Sunreaver Perimeter Wards. *Empower Sunreaver Perimeter Wards (6)",de="This island holds many dangers for us. Threats loom from every side. We must defend our hold on these shores at all costs. Perimeter wards have been placed around Dawnseeker Promontory. By default they will inflict damage, but are not fatal in their attack. Now is not the time to be merciful, . The perimeter wards need to be deadly! Go and empower the perimeter wards surrounding our camp.",g={n="Magister Hathorel",x=0.708,y=0.316,loc="Various"}}
d[32293]={mo=247200,rep="+200 Sunreaver Onslaught",o="Kill Zur'chaka the Bonecrafter. *Zur'chaka the Bonecrafter slain",de="My scouts have spotted a dangerous Zandalari among the bones west of Ihgaluk Crag. I need someone capable to see him dispatched. Are you up to the task?"}
d[32294]={mo=247200,rep="+200 Sunreaver Onslaught",o="Kill Zur'chaka the Bonecrafter. *Zur'chaka the Bonecrafter slain",de="We've spotted a Zandalari leader up the central stairs. We need to eliminate him before returning to camp. Would you be willing to do the deed?",g={n="Scout Captain Elsia",x=0.4125,y=0.8803,loc="Various"}}
d[32297]={mo=198450,rep="+150 Sunreaver Onslaught",o="Disrupt a binding ritual by killing all ritual NPCs around either a Defiant Direhorn or a Defiant Devilsaur. *Binding ritual disrupted",de="We have an opportunity to disrupt the Zandalari war machine as well as have a little fun in the process. Within these beast pens, a devilsaur and a direhorn are being outfitted with armor, their minds being enslaved to the Zandalari charms. Go into the camp and disrupt one of these binding rituals. It doesn't matter which one. Just kill those who are trying to bind the creature. This should let the fully armored beast run mad through the Zandalari camp. Then sit back and watch the hilarity ensue.",g={n="Magister Edien Sunhollow",loc="Various"}}
d[32298]={mo=198450,rep="+150 Sunreaver Onslaught",o="Find and use Saur Fetishes on 5 raptors, compies, skyscreamers or direhorns in the Beast Pens. *Saur Fetish used (5) *Saur Fetish (5)",de="The Zandalari use a series of fetishes and charms to maintain their control over their menagerie of beasts. Two can play at that game. I want you to find some of these fetishes and try them out on the various beasts in the Beast Pens. Take careful note of how each beast responds to each fetish. Then report your results to me. Maybe this will give us the edge we need against the Zandalari.",g={n="Scout Captain Elsia",x=0.4125,y=0.8803,loc="Various"}}
d[32299]={mo=198450,rep="+150 Sunreaver Onslaught",o="Disperse 75 pieces of filth by killing Quivering Filth in Ihgaluk Crag. *Filth dispersed (75)",de="This is not a glamorous job. Let me put it to you bluntly. The Skumblade saurok pile all of their filth into a pool in the middle of their village. This filth is so concentrated and so rancid that it has congealed into moving, animate matter. The saurok can keep their filth-pool, but once it starts spreading outside of the village, I'd say it's time to intervene.",g={n="Amalia Penshire",loc="Ihgaluk Crag & Dawnseeker Promontory, Isle of Thunder"}}
d[32300]={mo=198450,rep="+150 Sunreaver Onslaught",o="Disarm the Tactical Mana Bombs at the Horde Ships, the Scrying Crystals, and the Bridge within Dawnseeker Promontory. *Ships Tactical Mana Bomb disarmed *Crystal Tactical Mana Bomb disarmed *Bridge Tactical Mana Bomb disarmed",de="Well, it would seem the Lady Proudmoore has decided to use our own weaponry against us. Our perimeter wards reported several spies slipping through our defenses carrying tactical mana bombs. I would enjoy the irony if these bombs were less dangerous. Search for these bombs and disarm them. Our wards reported one near the horde ships to the north, one on a bridge to the main isle, and one near our scrying crystals on the eastern side of the Promontory.",g={n="Magister Hathorel",x=0.708,y=0.316,loc="Various"}}
d[32301]={mo=198450,rep="+150 Kirin Tor Offensive",o="Kill 10 Sunreaver agents or players on the Isle of Thunder. *Sunreaver agents slain (10)",de="To think, we were once on the same side! The Sunreavers' treachery caught us all off guard. Never again! They have shown their true natures to us. Siding with Garrosh and his madness has marked them all for death. Kill any agent of the Sunreavers that you find. We will show them no mercy here.",g={n="Vereesa Windrunner",x=0.304,y=0.486,loc="Various"}}
d[32302]={mo=198450,rep="+150 Sunreaver Onslaught",o="Destroy 3 Kirin Tor Constructs around Violet Rise. *Kirin Tor Construct slain (3)",de="The Kirin Tor constructs are primitive at best. Nevertheless, they pose a threat. Go to Violet Rise and dismantle Jaina's pitiful war machines. Show the Kirin Tor how easily they can be defeated! This will be a message the Kirin Tor cannot easily ignore.",g={n="Girana the Blooded",loc="Various"}}
d[32303]={mo=198450,rep="+150 Sunreaver Onslaught",o="Kill the Arcane Destroyer. *Arcane Destroyer slain",de="Jaina thinks this battle will be easily won. I intend to show her how wrong she is! The Kirin Tor brought a weapon with them that must be destroyed. The Arcane Destroyer is a large construct capable of turning the tides of war in their favor. Destroying this monstrosity would send a very clear message to Proudmoore.",g={n="High Arcanist Savor",loc="Various"}}
d[32304]={r={{n="Sunreaver Bounty"}},mo=247200,rep="+200 Sunreaver Onslaught",g={n="Lor'themar Theron",x=0.54,y=0.206,loc="Various"}}
d[32305]={mo=198450,rep="+150 Sunreaver Onslaught",o="Destroy 7 Mana Foci around Violet Rise. *Kirin Tor Mana Foci destroyed (7) *Sunreaver Mana Crystal (provided)",de="The Kirin Tor are using mana foci to empower their forces. We cannot allow this to continue. You'll find these foci scattered around the outskirts of Violet Rise. Use this mana crystal to destroy as many as you can. Each mana focus we destroy is another small victory for our cause.",g={n="Magister Hathorel",x=0.708,y=0.316,loc="Various"}}
d[32342]={mo=198450,rep="+150 Dominance Offensive",o="Collect 3 Spirit Traps. *Spirit Trap (item) (3)",de="Within the ruins we have identified several powerful mogu artifacts. They trapped spirits within, probably to use them in some ritual or conjuration. They are a type of device that we haven't identified and desperately need to study - they may reveal more of the secrets of the mogu's spirit binding techniques. Go, find us a few samples so that we may continue a proper study.",g={n="Kaelis Sunsoar",loc="Ruins of Ogudei, Krasarang Wilds"}}
d[32343]={mo=198450,rep="+300 Dominance Offensive",o="Collect Meng-do's Essence and Gen-li's Essence in the Ruins of Ogudei. *Meng-do's Essence *Gen-Li's Essence",de="There are two extremely powerful mogu spirits that the Alliance unearthed in their ineptitude. These are choice targets for us, . If you kill them and collect each of their essences, we could make great progress on decoding the history of this strange ruin.",g={n="Kaelis Sunsoar",loc="Ruins of Ogudei, Krasarang Wilds"}}
d[32344]={mo=198450,rep="+150 Dominance Offensive",o="Use the Arcane Bauble to find an anomaly within the Ruins of Ogudei. *Anomaly dispersed",de="We have detected several... anomalies in these mines, of an arcane or spiritual nature. They are disrupting our attempts to discern the nature of the magic used in the spirit binding rituals here. They are quite elusive, but we've managed to isolate the arcane signature of one of these anomalies, and one of our mages has enchanted this bauble with its signature. Take the bauble. It will begin to glow more brightly as you approach the anomaly. Once you reach it, you can use the bauble to draw it out.",g={n="Kaelis Sunsoar",loc="Ruins of Ogudei, Krasarang Wilds"}}
d[32345]={mo=198450,rep="+150 Dominance Offensive",o="Liberate 14 Troubled Slave Spirits. *Troubled Slave Spirit slain (14)",de="The Reliquary may have had a bad name in the past, but we're not monsters. We simply hold different views about archaeology than the Explorer's League. We do focus on performing acts of heroism from time to time. So go, liberate some of the pandaren slave spirits in the ruins.",g={n="Kaelis Sunsoar",loc="Ruins of Ogudei, Krasarang Wilds"}}
d[32346]={mo=198450,rep="+150 Operation: Shieldwall",o="thumb|Spiritbound Arcanist. thumb|Spiritbound Brutalizer. Kill 12 Spiritbound Mogu. *Spiritbound Mogu slain (12)",de="Look. We got a nasty problem here, and ol' Troteman back at Lion's Landing's gonna throw us out of here if we don't get things under control. Give us a hand, please!",g={n="Hilda Hornswaggle",x=0.598,y=0.76,loc="Various"}}
d[32347]={mo=198450,rep="+150 Operation: Shieldwall",o="Kill any 12 members of the Reliquary in the Ruins of Ogudei. *Reliquary slain (10)",de="The bloody Reliquary's snuck into the ruins. They've taken the lower section and are conducting all kinds of magical shenanigans down there. It's time we gave 'em an eviction notice, in the form of your boot in their rear!",g={n="Hilda Hornswaggle",x=0.598,y=0.76,loc="Various"}}
d[32348]={mo=198450,rep="+150 Dominance Offensive",o="Kill 12 Lion's Landing military units. *Shieldwall Rifleman *Shieldwall Footman *Lion's Landing Guard Captain",de="The Alliance may think they have a stranglehold on the ruins, given that their base of operations is close. We're going to disabuse them of that notion. Go take out some of their guards.",g={n="Kaelis Sunsoar",loc="Ruins of Ogudei, Krasarang Wilds"}}
d[32434]={o="Defeat Burning Pandaren Spirit in a pet battle. * Defeat Burning Pandaren Spirit",de="You're back! Up for another battle with me?",g={n="Burning Pandaren Spirit",x=0.57,y=0.422,loc="Underbough, Townlong Steppes"}}
d[32439]={o="Defeat Flowing Pandaren Spirit in a pet battle. * Defeat Flowing Pandaren Spirit",de="You're back! Up for another battle with me?",g={n="Flowing Pandaren Spirit",x=0.612,y=0.876,loc="Dread Wastes"}}
d[32440]={o="Defeat Whispering Pandaren Spirit in a pet battle. * Defeat Whispering Pandaren Spirit",de="You're back! Up for another battle with me?",g={n="Whispering Pandaren Spirit",x=0.288,y=0.36,loc="Jade Forest"}}
d[32441]={o="Defeat Thundering Pandaren Spirit in a pet battle. * Defeat Thundering Pandaren Spirit",de="You're back! Up for another battle with me?",g={n="Thundering Pandaren Spirit",x=0.6492,y=0.9384,loc="Kun-Lai Summit"}}
d[32446]={mo=198450,rep="+150 Operation: Shieldwall",o="thumb|Jungle Shredder. Destroy the Jungle Shredders using the Re-Configured Remote and then collect 6 pieces of Scrap Metal. *Scrap Metal (6) *Re-Configured Remote (provided)",de="Those shredders are becoming a problem down there, . We've sent in the Mecha-Pounders, but it just isn't enough. They're getting damaged faster than we can repair 'em! I happened upon this strange remote while scouting. With a little bit of re-configurin' I think we can use it. Try usin' it on the Jungle Shredders. Hopefully it will destroy them and then you can bring me the scrap metal.",g={n="Sully \"The Pickle\" McLeary",loc="Various"}}
d[32449]={mo=19850,o="Report to Belloc Brightblade in Sparkrocket Outpost.",de="Our scouts at Sparkrocket Outpost have reported some new activity near an area called the Ruins of Ogudei. We need to gather intelligence on what it is the Alliance are doing, and more importantly what it is they found. We cannot afford to have any unknowns. Meet up with Belloc Brightblade in Sparkrocket Outpost and find out what he knows.",g={n="Blood Guard Gro'tash",loc="Domination Point, Krasarang Wilds"}}
d[32450]={mo=19850,o="Report to Shademaster Kiryn in Sparkrocket Outpost.",de="Now we take the fight to them, ! Report to Shademaster Kiryn in Sparkrocket Outpost. She will have your orders. Now we'll see how they handle the full might of the Horde rushing at their precious keep!",g={n="Blood Guard Gro'tash",loc="Domination Point, Krasarang Wilds"}}
d[32451]={mo=19850,o="Report to Sky Admiral Rogers aboard the Skyfire in Krasarang Wilds.",de="It's time we show these Horde mongrels the full strength of the Alliance! Today we bring the battle to their door. Report to Admiral Rogers aboard the Skyfire. She will have further instructions. Good luck out there, . Do the Alliance proud!",g={n="Amber Kearnen",x=0.682,y=0.704,loc="Various"}}
d[32452]={mo=19850,o="Report to Sky Admiral Rogers aboard the Skyfire in Krasarang Wilds.",de="We're fighting a war on all fronts, . Even Pandaria itself needs our protection. The Bilgewater goblins are destroying land that doesn't belong to them. They must be stopped! Report to Sky Admiral Rogers aboard the Skyfire. From her vantage point she should have a good idea of where their weak spots are.",g={n="Amber Kearnen",x=0.682,y=0.704,loc="Various"}}
d[32485]={mo=198450,rep="+150 Kirin Tor Offensive",o="Empower 6 Kirin Tor Perimeter Wards around Violet Rise. *Empower Kirin Tor Perimeter Wards (6)",de="This island is a dangerous place, . We have to worry about attacks from the Zandalari, mogu, saurok, and worst of all the Sunreavers. I had perimeter wards placed on the outskirts of our camp for additional protection. In their current state they will only injure an attacker, but I'm done with warnings! With your help we can super-charge the wards into a more deadly defense system.",g={n="Lady Jaina Proudmoore",x=0.662,y=0.49,loc="Various"}}
d[32489]={mo=198450,rep="+150 Sunreaver Onslaught",o="Crush 150 Ihgaluk Roaches. *Ihgaluk Roach crushed (150)",de="Ah, roaches! I once bought a pet roach in the Undercity. Roaches will soak up disease like a sponge, and then spread it as far as they can run. Which is pretty far. Ihgaluk Crag is crawling with the things, and they carry Skumblade filth all over of this island. Crush as many of them as you can while you're there.",g={n="Amalia Penshire",loc="Ihgaluk Crag & Dawnseeker Promontory, Isle of Thunder"}}
d[32491]={mo=198450,rep="+150 Sunreaver Onslaught",o="Destroy 3 Fetid Meat Piles. *Fetid Meat Pile destroyed (3)",de="The Skumblade saurok do not eat all of the meat they hunt. They reserve large portions of it to rot in piles near their homes, attracting pests and spreading disease. We can't have the saurok spreading their disease beyond the borders of Ihgaluk Crag. Dispose of any excess meat that you find.",g={n="Amalia Penshire",loc="Ihgaluk Crag & Dawnseeker Promontory, Isle of Thunder"}}
d[32493]={mo=198450,rep="+150 Sunreaver Onslaught",o="Kill 5 Spirit-Bound Sentries and then use the Resonance Crystal to capture the Zandalari Spirits trapped within. *Zandalari Spirits captured (5) *Resonance Siphon (provided)",de="The Zandalari do not tolerate weakness in their ranks, . Those that are deemed weak are often sacrificed in barbaric ceremonies. The victims' spirits are captured and entombed within the sentries you see guarding the grounds. I wish to study their essence. For this I will need your help. Take this resonance crystal and siphon the spirits from the sentry corpses. Do not allow them to escape!",g={n="Magister Edien Sunhollow",loc="Various"}}
d[32494]={mo=198450,rep="+150 Sunreaver Onslaught",o="Retrieve the Mask of the Dark Mystic and the Mask of the Spirit-Caller from Spiritbinder Tu'chek and Arcanital Ra'kul within Conqueror's Terrace. *Mask of the Spirit-Caller *Mask of the Dark Mystic",de="The Zandalari have found a way to infuse items of great power with the essence of their loa. These items are often passed from one generation to another, each recipient adding to the item's power. Two such items exist here. To be specific, two masks, worn by two brothers. Spiritbinder Tu'chek and Arcanital Ra'kul must be stopped and their masks destroyed. Kill them and return their masks to me. I will make sure the masks are disposed of.",g={n="Magister Edien Sunhollow",loc="Various"}}
d[32495]={mo=198450,rep="+150 Sunreaver Onslaught",o="Kill Kaida the Bloodletter. *Kaida the Bloodletter slain",de="I have heard a disturbing report, . Just beyond our position, in the Court of Bones, the mogu bring captives to a general named Kaida the Bloodletter. I will spare you the details, but he thrives on torturing his victims. This monster must be stopped. If you fall to his blade, I wish you a swift death.",g={n="Grand Magister Rommath",x=0.546,y=0.21,loc="Various"}}
d[32506]={mo=198450,rep="+150 Sunreaver Onslaught",o="Recover a Wild Ptrerrorwing Hatchling. *Wild Pterrorwing Hatchling (item)",de="I've just received a report that another young pterrorwing has been spotted in the Diremoor. We need to recover as many of these as we can find. They may be the key to flying on this island.",g={n="Magister Hathorel",x=0.708,y=0.316,loc="Various"}}
d[32517]={mo=198450,rep="+150 Sunreaver Onslaught",o="Stop the Ancient Stone Conqueror ritual in the main temple at the Court of Bones. *Stop the Ancient Stone Conqueror ritual",de="In the Court of Bones, the Thunder King's sorcerers perform dark rituals. To bolster their numbers, the Shan'ze soulrippers are imbuing ancient stone statues with stolen spirits from the living. After these stone conquerors are brought to life, they will be formidable opponents on the battlefield. We must stop their ritual before these statues can be revived.",g={n="Ryshelle Brightlock",loc="Court of Bones, Isle of Thunder"}}
d[32520]={r={{n="Sunreaver Bounty"}},mo=247200,rep="+200 Sunreaver Onslaught",o="Kill Arcweaver Jor'guva. *Arcweaver Jor'guva slain",de="My scouts have spotted a dangerous Zandalari just this side of Za'Tual. I need someone capable to see him dispatched. Are you up to the task?"}
d[32521]={r={{n="Sunreaver Bounty"}},mo=198450,rep="+200 Sunreaver Onslaught",o="Kill Nurkala, the Zandalari War Leader. *Nurkala slain",de="My scouts have spotted a Zandalari war party on the northern beach. I need someone capable to see him dispatched. Are you up to the task?",g={n="Lor'themar Theron",x=0.54,y=0.206,loc="Various"}}
d[32523]={mo=49600,o="Find Scout Captain Elsia at the Beast Pens. *Find Scout Captain Elsia at the Beast Pens",de="We need to counter the beasts the Zandalari are using to strike at our camp. I have dispatched Scout Captain Elsia to the Beast Pens along with some war mages to provide cover. Go and find her east of here near the breaches in the wall and help her trim down the cavalry and siege beasts being levied against us. They are masked, so look for the shimmers of their magical cloaking spells."}
d[32524]={mo=49600,o="Locate Scout Captain Elsia within Conqueror's Terrace.",de="Do you hear that, ? The beating of war drums in the distance. The Zandalari are preparing for us. Let's not give them the luxury of time to organize their defenses. We need to push the attack now! Report to Scout Captain Elsia within Conqueror's Terrace. She will have further orders for you."}
d[32525]={mo=198450,rep="+150 Kirin Tor Offensive",o="thumb|Mummified Remains. Burn 8 Mummified Remains. *Mummified Remains burned (8) *Blessed Torch (provided)",de="The mogu at the Court of Bones are bolstering their army by resurrecting the spirits of the dead. We cannot allow them to revive their fallen warriors. Take this torch and burn any mummified corpses that you find. We will destroy our enemies before they have a chance to rise.",g={n="Danara Silverglass",loc="Seabolt & Violet Rise, Isle of Thunder"}}
d[32526]={mo=198450,rep="+150 Kirin Tor Offensive",o="thumb|Shan'ze Soulripper. thumb|Silver Covenant Scout (Isle of Thunder)|Silver Covenant Scout. thumb|Sunreaver Scout (Isle of Thunder)|Sunreaver Scout. Save 8 Silver Covenant Scouts. *Scouts rescued (8)",de="We assault the mogu at the Court of Bones, but I fear we merely send them fodder for their abominable rituals. The mogu do not merely kill their prisoners - they steal their souls and imbue them in machinations of stone, or reforge the fallen into ghostly tools of war. Alliance or Horde, it matters not. We cannot allow the mogu to bolster their numbers. Go into the crypts. Free any prisoners that are still living.",g={n="Narasi Snowdawn",x=0.762,y=0.196,loc="Various"}}
d[32527]={mo=198450,rep="+150 Kirin Tor Offensive",o="Kill 10 Shan'ze Gravekeepers, Shan'ze Soulrippers, or Shan'ze Thundercallers. *Shan'ze mogu slain at the Court of Bones (10)",de="The Court of Bones crawls with mogu forces. Endlessly do they perform their rituals of lightning and thunder. If our mission to take this island is to succeed, then we cannot allow them to hold such a strategic position. They must be eliminated.",g={n="Narasi Snowdawn",x=0.762,y=0.196,loc="Various"}}
d[32528]={mo=198450,rep="+150 Kirin Tor Offensive",o="thumb|Gura the Reclaimed. Use the Incantation of Gura in the Hall of the Exalted, then defeat Gura the Reclaimed. *Gura the Reclaimed slain *Incantation of Gura (provided)",de="Every day, we uncover additional relics from the Court of Bones. Recently, we discovered this scroll amongst the gravestones in one of the deepest crypts. I believe that this incantation can be used to call beyond the grave. And if my Mogu is up to date, I'd say you should use it in the last room in the Hall of the Exalted. Would you be willing to test out my theory?",g={n="Danara Silverglass",loc="Seabolt & Violet Rise, Isle of Thunder"}}
d[32529]={mo=198450,rep="+150 Kirin Tor Offensive",o="Stop the Shan'ze Thundercallers' ritual. *Shan'ze Thundercallers' ritual stopped",de="At the Court of Bones, in the deepest ruins of their western crypt, the Thunder King's most powerful sorcerers are charging a lightning rod with crackling electricity. We suspect that this weapon is meant to rain destruction on our stronghold at Violet Rise. There is no time to delay. You must stop their ritual at once.",g={n="Vylene Amaranth",loc="Seabolt & Violet Rise, Isle of Thunder"}}
d[32530]={mo=198450,rep="+150 Kirin Tor Offensive",o="Kill Kaida the Bloodletter. *Kaida the Bloodletter slain",de="I have heard a disturbing report, . Just beyond our position, in the Court of Bones, the mogu bring captives to a general named Kaida the Bloodletter. He thrives on torturing his victims. This monster must be stopped. If you fall to his blade, I wish you a swift death.",g={n="Vylene Amaranth",loc="Seabolt & Violet Rise, Isle of Thunder"}}
d[32531]={mo=198450,rep="+150 Kirin Tor Offensive",o="Disrupt the Ancient Stone Conqueror ritual in the main temple at the Court of Bones. *Disrupt the Ancient Stone Conqueror ritual",de="In the Court of Bones, the Thunder King's sorcerers perform dark rituals. To bolster their numbers, the Shan'ze soulrippers are imbuing ancient stone statues with stolen spirits from the living. After these stone conquerors are brought to life, they will be formidable opponents on the battlefield. We must stop their ritual before these statues can be revived.",g={n="Vylene Amaranth",loc="Seabolt & Violet Rise, Isle of Thunder"}}
d[32532]={mo=198450,rep="+150 Kirin Tor Offensive",o="thumb|Risen Ancestor. Kill 15 Risen Ancestors. *Risen Ancestor slain (15)",de="Have you seen the ghosts wandering the graveyard? They are risen ancestors, the spirits of slain mogu who have been called back to this world. When angered, they attack swiftly and silently, and their numbers increase by the day. They do not belong here. Destroy them, and send them back beyond the grave.",g={n="Danara Silverglass",loc="Seabolt & Violet Rise, Isle of Thunder"}}
d[32533]={mo=198450,rep="+150 Kirin Tor Offensive",o="Destroy 8 Grave Guardians. *Grave Guardians destroyed (8)",de="Our assault on the Court of Bones continues. Our progress remains slow, but measurable. Unfortunately, we've received several reports of stone quilen statues coming to life without warning. These quilen are too dangerous to ignore. Venture into the Court of Bones and destroy any quilen statues that you can find.",g={n="Danara Silverglass",loc="Seabolt & Violet Rise, Isle of Thunder"}}
d[32535]={mo=198450,rep="+150 Kirin Tor Offensive",o="Slay 10 Skumblade saurok. *Skumblade saurok slain (10)",de="Ihgaluk Crag has no end of saurok. Those beasts attack my men and spread their disease into nearby water and wildlife, interfering with our operations. Thin their numbers, . Once the Alliance takes full control of this island, we can look for more permanent solutions.",g={n="Archmage Modera",loc="Various"}}
d[32536]={mo=198450,rep="+150 Kirin Tor Offensive",o="thumb|Magister Yalis. thumb|Magister Lyanis. thumb|Magistrix Sanal. Check in with Magister Yalis, Magister Lyanis, and Magistrix Sanal. *Speak with Magister Yalis *Speak with Magister Lyanis *Speak with Magistrix Sanal",de="I have three magisters entrenched in Ihgaluk Crag, monitoring the saurok and - where they can - turning them against the mogu. I need you to find them and see if they need any supplies or assistance. They will be concealed from view. Look for shimmering columns of light within the saurok village.",g={n="Archmage Modera",loc="Various"}}
d[32537]={mo=198450,rep="+150 Kirin Tor Offensive",o="thumb|Disabled Silver Covenant Construct. thumb|Buried Silver Covenant Construct. thumb|Distressed Silver Covenant Construct. thumb|Malfunctioning Silver Covenant Construct. Recover the four stolen Silver Covenant Constructs. *Recover Disabled Construct *Recover Buried Construct *Recover Distressed Construct *Recover Malfunctioning Construct",de="Saurok consistently test our borders, and our constructs usually fend them off. Some constructs, however, have been defeated and dragged back to Ihgaluk Crag. I want those constructs back. No slithering lizard will steal Silver Covenant property under my watch.",g={n="Archmage Modera",loc="Various"}}
d[32538]={mo=198450,rep="+150 Kirin Tor Offensive",o="Destroy the Zandalari sacrificial altars. *Cha'lat's Altar destroyed *Tec'uat's Altar destroyed *Pa'chek's Altar destroyed",de="Some of the strongest of the spiritbinders perform heinous rites to their wretched gods. We've devised a method to destroy their altars, so the difficult task will be getting to each altar alive. Venture into the depths of Za'Tual and destroy their altars.",g={n="Dalvin Jaacor",loc="Seabolt & Violet Rise, Isle of Thunder"}}
d[32539]={mo=198450,rep="+150 Kirin Tor Offensive",o="Destroy 6 Zandalari Offerings. *Zandalari Offerings destroyed (6)",de="The Zandalari's spiritbinders perform dark sacrifices to appease their gods, killing our people in the process. Destroy any Zandalari offerings you can find to help slow the pace of their dark sacrifices.",g={n="Dalvin Jaacor",loc="Seabolt & Violet Rise, Isle of Thunder"}}
d[32540]={mo=198450,rep="+150 Kirin Tor Offensive",o="Slay 2 Harbingers of the Loa *Defeat Harbingers of the Loa (2)",de="If you spend some time in Za'Tual, you will likely see one of their large tents emanating a pure form of evil. Please, venture into the troll camp and put a stop to these rituals.",g={n="Archmage Lan'dalock",x=0.576,y=0.666,loc="Various"}}
d[32541]={mo=198450,rep="+150 Kirin Tor Offensive",o="thumb|Hatchling Skyscreamer. Frighten 12 Hatchling Skyscreamers by running near them. *Hatchling Skyscreamers frightened (12)",de="It pains me to think of the torture the poor skyscreamers must endure as the trolls train them to become implements of war. The hatchlings are quite fearful, and will fly away if you even get close them. Please, frighten some away before the Zandalari corrupt them.",g={n="Ako",loc="Seabolt & Violet Rise, Isle of Thunder"}}
d[32542]={mo=198450,rep="+150 Kirin Tor Offensive",o="Slay 3 Zandalari Spiritbinders, 3 Zandalari Beastcallers, and 3 Zandalari Jaguar Warriors. *Zandalari Beastcaller slain (3) *Zandalari Jaguar Warrior slain (3) *Zandalari Spiritbinder slain (3)",de="Zandalari spiritbinders peform sacrifices to their gods, the beastcallers bend innocent skyscreamers to their will, and the jaguar warriors venture closer to us by the day. Dispose of these threats in Za'Tual, , and watch the might of the trolls weaken.",g={n="Archmage Lan'dalock",x=0.576,y=0.666,loc="Various"}}
d[32543]={mo=198450,rep="+150 Kirin Tor Offensive",o="Slay 12 Trolls in Za'Tual. *Trolls slain in Za'Tual (12)",de="The Zandalari are a formidable foe - more so than many foes we've encountered in the past. But you are a formidable foe as well, . Enter Za'Tual and show them the risks associated with opposing the likes of you.",g={n="Archmage Lan'dalock",x=0.576,y=0.666,loc="Various"}}
d[32544]={mo=198450,rep="+150 Kirin Tor Offensive",o="Free the Tormented Skyscreamer. *Tormented Skyscreamer freed",de="One of the trolls' skyscreamers in Za'Tual is undergoing a ritual of torture, its will being bent forever to serve its masters. Kill those that inflict such torment on the creature and we can only hope that it will return to the skies.",g={n="Ako",loc="Seabolt & Violet Rise, Isle of Thunder"}}
d[32545]={mo=198450,rep="+150 Kirin Tor Offensive",o="Slay a Skumblade Brute, a Skumblade Saur-Priest, and a Skumblade Seadragon. *Skumblade Brute slain *Skumblade Saur-Priest slain *Skumblade Seadragon slain",de="The Skumblade threaten our people, but responding with all-out slaughter would be an overreaction. A more reasonable response to their threat would be to slay some of their tribal leaders. There will be less bloodshed, and they will still respect our perimeter.",g={n="Lyalia",x=0.15,y=0.502,loc="Various"}}
d[32546]={mo=198450,rep="+150 Kirin Tor Offensive",o="Disperse 75 pieces of filth by killing Quivering Filth in Ihgaluk Crag. *Filth dispersed (75)",de="This is not a glamorous job. Let me put it to you bluntly. The Skumblade saurok pile all of their filth into a pool in the middle of their village. This filth is so concentrated and so rancid that it has congealed into moving, animate matter. The saurok can keep their filth-pool, but once it starts spreading outside of the village, I'd say it's time to intervene.",g={n="Sanitation Sorcerer Stephen Litmatch",loc="Seabolt, Isle of Thunder"}}
d[32547]={mo=198450,rep="+150 Kirin Tor Offensive",o="thumb|Ihgaluk Roach. Crush 150 Ihgaluk Roaches. *Ihgaluk Roach crushed (150)",de="Ah, roaches! I once bought a pet roach in Booty Bay. Roaches will soak up disease like a sponge, and then spread it as far as they can run. Which is pretty far. Ihgaluk Crag is crawling with the things, and they carry Skumblade filth all over of this island. Crush as many of them as you can while you're there.",g={n="Sanitation Sorcerer Stephen Litmatch",loc="Seabolt, Isle of Thunder"}}
d[32548]={mo=198450,rep="+150 Kirin Tor Offensive",o="Destroy 3 Fetid Meat Piles. *Fetid Meat Pile destroyed (3)",de="The Skumblade saurok do not eat all of the meat they hunt. They reserve large portions of it to rot in piles near their homes, attracting pests and spreading disease. We can't have the saurok spreading their disease beyond the borders of Ihgaluk Crag. Dispose of any excess meat that you find.",g={n="Sanitation Sorcerer Stephen Litmatch",loc="Seabolt, Isle of Thunder"}}
d[32550]={mo=198450,rep="+150 Kirin Tor Offensive",o="Defeat 10 Zandalari trolls in the Beast Pens. *Beast Pens Trolls slain (10)",de="Inside the Beast Pens you will encounter some of the most skilled beast tamers in the Zandalari military. They are trained to kill with axe, beast, and claw. This is where they build their cavalry. We need you to kill any Zandalari you find in the Bestiary before they can get their mounted monstrosities out into the open battlefield.",g={n="Scout Captain Daelin",x=0.742,y=0.796,loc="Various"}}
d[32551]={mo=198450,rep="+150 Kirin Tor Offensive",o="Kill 5 Raptors and 10 Trained Compies in the Beast Pens. *Raptor slain (5) *Trained Compy slain (10)",de="The raptors and compies of the Zandalari represent a substantial threat to our forces here. They are superb hunting beasts that can track prey over great distances and are often lethal to encounter when caught unawares. I need you to head into the Beast Pens and cull their numbers. We need to make sure to slay them before they are fully trained.",g={n="Scout Captain Daelin",x=0.742,y=0.796,loc="Various"}}
d[32552]={mo=198450,rep="+150 Kirin Tor Offensive",o="Defeat a Loa Speaker. *Loa Speaker slain",de="The Zandalari have found a way to bind loa to their beasts giving them impressive and lethal powers. We need to put a stop to this. Search the Beast Pens for a loa speaker and slay him. You should be able to find them by keeping a look out for their glowing beasts. We must not allow these atrocities to continue.",g={n="Miura Brightweaver",x=0.75,y=0.788,loc="Various"}}
d[32553]={mo=198450,rep="+150 Kirin Tor Offensive",o="Disrupt a binding ritual by killing all ritual NPCs around either a Defiant Direhorn or a Defiant Devilsaur. *Binding ritual disrupted",de="We have an opportunity to disrupt the Zandalari war machine as well as have a little fun in the process. Within these beast pens, a devilsaur and a direhorn are being outfitted with armor, their minds being enslaved to the Zandalari charms. Go into the camp and disrupt one of these binding rituals. It doesn't matter which one. Just kill those who are trying to bind the creature. This should let the fully armored beast run mad through the Zandalari camp. Then sit back and watch the hilarity ensue.",g={n="Miura Brightweaver",x=0.75,y=0.788,loc="Various"}}
d[32554]={mo=198450,rep="+150 Kirin Tor Offensive",o="Find and use Saur Fetishes on 5 raptors, compies, skyscreamers or direhorns in the Beast Pens. *Saur Fetish used (5) *Saur Fetish (5)",de="The Zandalari use a series of fetishes and charms to maintain their control over their menagerie of beasts. Two can play at that game. I want you to find some of these fetishes and try them out on the various beasts in the Beast Pens. Take careful note of how each beast responds to each fetish. Then report your results to me. Maybe this will give us the edge we need against the Zandalari.",g={n="Scout Captain Daelin",x=0.742,y=0.796,loc="Various"}}
d[32555]={mo=198450,rep="+150 Kirin Tor Offensive",o="Kill 5 Spirit-Bound Sentries and then use the Resonance Crystal to capture the Zandalari spirits trapped within. *Zandalari Spirits captured (5) *Resonance Siphon (provided)",de="Sacrifices are common place in Zandalari society. There is however one oddity among these barbaric rituals; volunteers. They treat it as a great honor! The weak still seek to contribute, even if that means giving their lives to be bound to the sentries you see walking around. Locked away in service to their people. Take this resonating crystal. Once destroyed, drain the sentry of its Zandalari inhabitant. Return the crystal to me when your task is complete.",g={n="Miura Brightweaver",x=0.75,y=0.788,loc="Various"}}
d[32556]={mo=198450,rep="+150 Kirin Tor Offensive",o="Retrieve 6 Ritual Artifacts from around Conqueror's Terrace. *Ritual Artifact (6)",de="This whole area is littered with Zandalari artifacts. I would be lying if I said studying them didn't interest me. I am fascinated by the significance of these objects to their rituals. The more we understand our enemies, the better prepared we are to defeat them. If I am to study them, I will need to see them up close. Bring me as many artifacts as you can find.",g={n="Miura Brightweaver",x=0.75,y=0.788,loc="Various"}}
d[32557]={mo=198450,rep="+150 Kirin Tor Offensive",o="Steal 7 Loa-Infused Blades from Conqueror's Terrace *Loa-Infused Blade (7)",de="Magic is a frightening opponent when wielded by an experienced caster. A blade however, is terrifying in even the most inexperienced hands. The Zandalari have some impressive weapons, made even more deadly by the magic they are enhanced with. We should relieve them of this advantage. Steal as many of the weapons as you can find.",g={n="Scout Captain Daelin",x=0.742,y=0.796,loc="Various"}}
d[32558]={mo=198450,rep="+150 Kirin Tor Offensive",o="Retrieve the Mask of the Dark Mystic and the Mask of the Spirit-Caller from Spiritbinder Tu'chek and Arcanital Ra'kul. *Mask of the Spirit-Caller *Mask of the Dark Mystic",de="Conqueror's Terrace is watched over by two brothers; Spiritbinder Tu'chek and Arcanital Rak'ul. They are powerful magic users and should not be underestimated. Their power seems to stem from the ornate masks they wear; relics passed down from one generation to the next. Each owner imbuing it with their own magic before passing it on. We must deal with the brothers and destroy their masks before they fall into the wrong hands.",g={n="Miura Brightweaver",x=0.75,y=0.788,loc="Various"}}
d[32559]={mo=198450,rep="+150 Kirin Tor Offensive",o="thumb|Guardian Tak'u. Destroy Guardian Tak'u within Conqueror's Terrace. *Guardian Tak'u slain",de="The Zandalari worship the Loa; animal spirits they often call to their aid. They may be trying to bind these spirits into a huge golem. The outcome would be disastrous. I've sent ahead a scout to gather more information, but I think this task may require your expertise. Stop that ritual at all costs!",g={n="Scout Captain Daelin",x=0.742,y=0.796,loc="Various"}}
d[32560]={mo=198450,rep="+150 Kirin Tor Offensive",o="Kill any 8 Zandalari trolls within Conqueror's Terrace. *Conqueror's Terrace Zandalari slain (8)",de="The Zandalari here are a threat to our campaign, . Their use of magic is an abomination. They mix the power of arcane with the darkness of shadow with little care to consequence. We cannot afford for them to find their full strength here or for the Horde to learn of their twisted magic. Their numbers must be thinned. I will leave this task to you.",g={n="Scout Captain Daelin",x=0.742,y=0.796,loc="Various"}}
d[32562]={r={{n="Sunreaver Bounty"}},mo=247200,rep="+200 Sunreaver Onslaught",o="Kill Horgak the Enslaver. *Horgak the Enslaver slain",de="One of my scouts has returned with word of a mogu leader under the central tower. He needs to be removed. Would you be willing to do this for me, ?",g={n="Lor'themar Theron",x=0.54,y=0.206,loc="Various"}}
d[32564]={r={{n="Sunreaver Bounty"}},mo=247200,rep="+200 Sunreaver Onslaught",o="Kill Arcweaver Jor'guva. *Arcweaver Jor'guva slain",de="We've spotted a Zandalari leader up the central stairs. We need to eliminate him before returning to camp. Can you handle this one?",g={n="Scout Captain Elsia",x=0.4125,y=0.8803,loc="Various"}}
d[32567]={mo=49600,o="Find Scout Captain Daelin at the Beast Pens. *Find Scout Captain Daelin at the Beast Pens",de="I do not want to see another Zandalari beast rider breach our defenses! I have dispatched Scout Captain Daelin and some war mages to the Beast Pens northwest of here. Their mission is to infiltrate and harass the Zandalari siege and cavalry units. I want you to join them and lend your expertise. Keep an eye out for the tell tale shimmer of their magical cloaking spell."}
d[32568]={mo=49600,o="Locate Scout Captain Daelin within Conqueror's Terrace.",de="We have accomplished much since arriving here, but now is not the time to rest. Your efforts have helped us breach the upper level of the Thunder King's stronghold. Now, I call on you to continue our campaign. Report to Scout Captain Daelin within Conqueror's Terrace. He will have further orders for you."}
d[32571]={mo=198450,rep="+150 Kirin Tor Offensive",o="Recover a Wild Pterrorwing Hatchling. *Wild Pterrorwing Hatchling (item)",de="I've just received a report that another young pterrorwing has been spotted in the Diremoor. We need to recover as many of these as we can find. They may be the key to flying on this island.",g={n="Warmage Yurias",x=0.158,y=0.418,loc="Various"}}
d[32572]={mo=198450,rep="+150 Kirin Tor Offensive",o="thumb|Animated Warrior. Kill 6 Animated Warriors. *Animated Warrior slain (6)",de="The Shan'ze are animating an army from the statues in the center of the isle, an army that batters our defenses day and night. Destroy any of the walking statues you see. Our defenders will greatly appreciate it.",g={n="Captain Elleane Wavecrest",x=0.514,y=0.492,loc="Various"}}
d[32573]={mo=198450,rep="+150 Kirin Tor Offensive",o="Kill 7 Shan'ze mogu in the Diremoor. *Diremoor Shan'ze mogu slain (7)",de="There are mogu in the diremoor animating the army of statues near the tower. Vereesa wants them dead. I think you're the one to do it.",g={n="Captain Elleane Wavecrest",x=0.514,y=0.492,loc="Various"}}
d[32574]={mo=198450,rep="+150 Kirin Tor Offensive",o="Kill the Mighty Devilsaur. *Mighty Devilsaur slain",de="There is an immense beast in the swamp. It has not yet marched upon us, but I place no stock that we will continue to be so fortunate. Strike it down before it grows hungry enough to brave our defenses.",g={n="Vereesa Windrunner",x=0.304,y=0.486,loc="Various"}}
d[32575]={mo=198450,rep="+150 Kirin Tor Offensive",o="thumb|Zandalari Colossus. Destroy the Zandalari Colossus. *Zandalari Colossus slain",de="The trolls have dispatched one of their immense constructs on the southern road, blocking our passage around the island. See to it that the road is cleared, .",g={n="Vereesa Windrunner",x=0.304,y=0.486,loc="Various"}}
d[32576]={r={{n="Arcane Trove"}},mo=247200,rep="+200 Kirin Tor Offensive",o="Kill Arcweaver Jor'guva. *Arcweaver Jor'guva slain",de=";Lan'dalock, Modera, Narasi :One of the scryers has identified a Zandalari leader near the central tower. He needs to be removed. :Would you be willing to do this for me, ? ;Jaina :The scouts have spotted a dangerous Zandalari just this side of Za'Tual. We need someone capable to see him dispatched. Are you up to the task?"}
d[32578]={r={{n="Arcane Trove"}},mo=247200,rep="+200 Kirin Tor Offensive",o="thumb| Kill Zur'chaka the Bonecrafter. *Zur'chaka the Bonecrafter slain",de="The scouts have spotted a dangerous Zandalari among the bones west of Ihgaluk Crag. We need someone capable to see him dispatched. Are you up to the task?"}
d[32580]={r={{n="Arcane Trove"}},mo=198450,rep="+200 Kirin Tor Offensive",o="Kill Nurkala, the Zandalari War Leader. *Nurkala slain",de="We've received word of a Zandalari war party up the beach, north of our foothold. We need them hunted down and killed. Are you willing to do this thing for us, ?"}
d[32581]={r={{n="Arcane Trove"}},mo=247200,rep="+200 Kirin Tor Offensive",o="Kill Horgak the Enslaver. *Horgak the Enslaver slain",de=";Jaina :The scryers have spotted a mogu leader at the central tower. He needs to be killed before he can mount an offensive on our position. :Can you take care of this for us? ;Others :One of Vereesa's scouts has returned with word of a mogu leader under the central tower. He needs to be removed. :Would you be willing to handle this?"}
d[32582]={r={{n="Arcane Trove"}},mo=247200,rep="+200 Kirin Tor Offensive",o="Kill Zur'chaka the Bonecrafter. *Zur'chaka the Bonecrafter slain",de="We've spotted a Zandalari leader up the central stairs. We need to eliminate him before returning to camp. Would you be willing to do the deed?",g={n="Scout Captain Daelin",x=0.742,y=0.796,loc="Various"}}
d[32583]={r={{n="Arcane Trove"}},mo=198450,rep="+200 Kirin Tor Offensive",o="Kill Arcweaver Jor'guva. *Arcweaver Jor'guva slain",de="We've spotted a Zandalari leader up the central stairs. We need to eliminate him before returning to camp. Can you handle this one?",g={n="Scout Captain Daelin",x=0.742,y=0.796,loc="Various"}}
d[32586]={mo=198450,rep="+100 Kirin Tor Offensive",o="Destroy the 3 lightning drills in the Lightning Vein Mine, and kill Metal Lord Mono-Han. *Western Lightning Drill destroyed / *Central Lightning Drill destroyed / *Eastern Lightning Drill destroyed / *Metal Lord Mono-Han slain",de="The mines north of here are critical to the mogu supply line. They are using giant lightning enchanted drills to extract the ore. If you can disrupt the drills, they'll be destroyed, greatly slowing their ability to make weapons. Oh, also, kill whoever is in charge, will you?",g={n="Miura Brightweaver",x=0.75,y=0.788,loc="Various"}}
d[32587]={r={{n="Arcane Trove"}},mo=247200,rep="+200 Kirin Tor Offensive",o="thumb|Itoka. thumb|Fleshcrafter Hoku. Kill the Master of the Forge and Collect a Codex Fragment from Fleshcrafter Hoku in the Isle of Thunder. *Itoka slain *Mogu Codex Fragment",de="The forge lies ahead of you, and with it the heart of the Mogu's weaponsmithing ability. And beyond that, the Mogu gatekeeper, who holds the key to unlocking the gate to the next part of the city. It's time to move out!"}
d[32588]={mo=198450,rep="+150 Kirin Tor Offensive",o="thumb|Agent Grisel. thumb|Agent Crowley. Rescue the three captured Kirin Tor Agents within the Ghost Iron Mines, and kill Metal Lord Mono-Han. *Agent Reginald rescued / *Agent Grisel rescued / *Agent Crowley rescued / *Metal Lord Mono-Han slain *Arcane Emancipator (provided)",de="Under orders from Jaina herself, some of our agents attempted to sneak past mogu lines to find out what was going on in the Mines. They were captured, and are being subjected to who-knows-what kind of awful tortures. You must free them and kill whoever captured them. We don't leave anyone behind!",g={n="Miura Brightweaver",x=0.75,y=0.788,loc="Various"}}
d[32604]={o="Defeat Ka'wi the Gorger, Nitun, Kafi, and Dos-Ryga. * Ka'wi the Gorger * Nitun * Kafi * Dos-Ryga",de="The stories of Ka'wi the Gorger, Nitun, Kafi, and Dos-Ryga will exist in this land, always. Do you wish to meet them in battle once more?",g={n="Sara Finkleswitch",loc="Shrine of Seven Stars"}}
d[32605]={mo=198450,rep="+150 Sunreaver Onslaught",o="Plant Mogu Weapons into the corpses of 9 Skumblade saurok. *Use Mogu Weapon on Skumblade corpse (9)",de="The saurok are vile, but we share an enemy: the mogu. And I'd rather send saurok to kill mogu than send my own men. We've been collecting mogu weaponry. Bury these polearms into the skulls of the saurok. Feed our enemies' rivalry, and you may save Horde lives.",g={n="Archmage Aethas Sunreaver",x=0.316,y=0.484,loc="Various"}}
d[32606]={mo=198450,rep="+150 Kirin Tor Offensive",o="Plant Mogu Weapons into the corpses of 9 Skumblade saurok. *Use Mogu Weapon on Skumblade corpse (9)",de="The saurok are vile, but we share an enemy: the mogu. And I'd rather send saurok to kill mogu than send my own men. We've been collecting mogu weaponry. Bury these polearms into the skulls of the saurok. Feed our enemies' rivalry, and you may save Alliance lives.",g={n="Archmage Modera",loc="Various"}}
d[32607]={mo=456000,rep="+400 Kirin Tor Offensive",o="Steal the Workshop Orders and slay the new captain of the Zandalari warship. *Warship Captain slain *Workshop Orders",de="The Zandalari have already begun repairing that warship, but we can keep it crippled with minimal effort. Simply relieve the new captain of his post, and steal the ship's damage report from that workshop just outside the vault. No captain. No repairs. No warship.",g={n="Taoshi",x=0.406,y=0.472,loc="Various"}}
d[32608]={mo=456000,rep="+400 Kirin Tor Offensive",o="Steal the Choker of Storms from The Swollen Vault. *Choker of Storms",de="The Swollen Vault is a repository for some of Lei Shen's nastiest weaponry and most prized trinkets - not surprisingly, these are often one and the same. One artifact in particular, an amulet known as the Choker of Storms, could help us to understand his apparent mastery over lightning. Break into the vault and slay the hoard-keeper. Take his key and use it to recover the amulet from a cache at the back of the vault.",g={n="Taoshi",x=0.406,y=0.472,loc="Various"}}
d[32613]={mo=19850,g={n="Ku'ma",x=0.328,y=0.539,loc="Isle of Giants"}}
d[32614]={r={{n="Mote of Harmony"}},mo=19850,g={n="Ku'ma",x=0.328,y=0.539,loc="Isle of Giants"}}
d[32615]={r={{n="Spirit of Harmony"}},mo=19850,g={n="Ku'ma",x=0.328,y=0.539,loc="Isle of Giants"}}
d[32627]={mo=114000,rep="+150 Kirin Tor Offensive",o="Recover a Charged Moganite and bring it to Warmage Yurias. *Charged Moganite returned to Violet Rise",de="We have been dispatching spies into the Sunreaver base of operations on a daily basis. Some had orders to recover charged moganite from the enemy and bring it here. They have not returned, and I can confirm they have left the Sunreaver base. Search the jungle between here and there and find any of the charged moganite that might have been lost in transit. Bring it to me and we will put it to good use.",g={n="Warmage Yurias",x=0.158,y=0.418,loc="Various"}}
d[32628]={mo=198450,rep="+150 Kirin Tor Offensive",o="Plant a Tactical Mana Bomb on a Sunreaver ship, the Scrying Crystals, and on the most inland bridge of Dawnseeker Promontory. *Bomb placed on Sunreaver Ship *Bomb placed on Bridge *Bomb placed on Scrying Crystals *Case of Tactical Mana Bombs (provided)",de="Ah, , just the I was looking for. I have received another batch of tactical mana bombs that I need planted in key positions across Dawnseeker Promontory to the northwest. Here, take these. It is time to give the Sunreavers a taste of their own medicine. Plant one on the Sunreaver ships, another one on their scrying crystals, and the last on the bridge that connects to their forward base.",g={n="Captain Elleane Wavecrest",x=0.514,y=0.492,loc="Various"}}
d[32631]={r={{n="Arcane Trove"}},mo=247200,rep="+200 Kirin Tor Offensive",g={n="Lady Jaina Proudmoore",x=0.662,y=0.49,loc="Various"}}
d[32632]={mo=198450,rep="+150 Kirin Tor Offensive",o="Kill the Pyrestar Demolisher. *Pyrestar Demolisher slain",de="Some things are built with multiple purposes in mind. Some things are built with the sole purpose of destruction. A massive construct called the Pyrestar Demolisher sits guarding Dawnseeker Promontory. Its purpose is solely to destroy. It must be dismantled.",g={n="Warmage Yurias",x=0.158,y=0.418,loc="Various"}}
d[32633]={mo=198450,rep="+150 Kirin Tor Offensive",o="Retrieve Rommath's Book of Incantations from Dawnseeker Promontory. *Rommath's Book of Incantations",de="Grand Magister Rommath has something in his possession that I want. He brought a very powerful tome with him. It would be better for our cause if it were no longer in Sunreaver hands. Locate Rommath's book of incantations and bring it to me.",g={n="Warmage Yurias",x=0.158,y=0.418,loc="Various"}}
d[32634]={mo=114000,rep="+150 Kirin Tor Offensive",o="Destroy 6 Sunreaver Perimeter Wards around Dawnseeker Promontory. *Destroy Sunreaver Perimeter Wards (6)",de="Even the strongest defense can still have a weakness, . We just need to find the weakness in the Sunreaver's defense and then exploit it as much as possible. Scouts have reported the use of perimeter wards around Dawnseeker Promontory. They're powerful, but not deadly. Disabling them would allow us to keep closer watch on their activities.",g={n="Captain Elleane Wavecrest",x=0.514,y=0.492,loc="Various"}}
d[32635]={mo=198450,rep="+150 Kirin Tor Offensive",o="Disarm the Tactical Mana Bombs at the Alliance Ships, the Construct Ritual, and the Supplies within Violet Rise. *Ships Tactical Mana Bomb disarmed *Supplies Tactical Mana Bomb disarmed *Construct Ritual Tactical Mana Bomb disarmed",de="The Sunreavers have planted tactical mana bombs around our camp. These must be dismantled before they are detonated. Look for them in areas of high importance such as our supplies. Make sure you find and disable them all. We cannot afford to lose any ground here.",g={n="Lady Jaina Proudmoore",x=0.662,y=0.49,loc="Various"}}
d[32636]={mo=198450,rep="+150 Kirin Tor Offensive",o="thumb|Kirin Tor Captive. Free 5 Kirin Tor Captives near Dawnseeker Promontory. *Free Kirin Tor Captives (5)",de="The Sunreavers will stoop to even the lowest levels to get what they want, . I received reports earlier that several Kirin Tor have gone missing. I suspect the Sunreavers may have something to do with this. Hopefully they have not been harmed, or my wrath will be swift and terrible. I trust you to bring them back in one piece, but please hurry.",g={n="Lady Jaina Proudmoore",x=0.662,y=0.49,loc="Various"}}
d[32637]={mo=198450,rep="+150 Kirin Tor Offensive",o="Destroy 7 Sunreaver Mana Collectors around Dawnseeker Promontory. *Sunreaver Mana Collectors destroyed (7) *Kirin Tor Mana Crystal (provided)",de="The Sunreaver forces have grown more powerful recently. I suspect magic to be at play here, but I can't be certain. I think it would be wise to investigate their camp to see if you can find the source of this extra power. Once you find it, use this crystal to overload and destroy it.",g={n="Lady Jaina Proudmoore",x=0.662,y=0.49,loc="Various"}}
d[32638]={mo=198450,rep="+150 Kirin Tor Offensive",o="Kill 9 Sunreaver Mana Wyrms. *Sunreaver Mana Wyrm slain (9)",de="Sometimes, even the smallest creatures can be the biggest threat. The Sunreavers brought mana wyrms with them. Though small in size they have the ability to cripple our casters in combat. Many have learned the hard way not to underestimate them. They must be dealt with and quickly.",g={n="Captain Elleane Wavecrest",x=0.514,y=0.492,loc="Various"}}
d[32639]={mo=198450,rep="+150 Kirin Tor Offensive",o="Destroy 3 Sunreaver Constructs outside of Dawnseeker Promontory. *Sunreaver Construct slain (6)",de="Scouts are reporting a large number of constructs patrolling outside of Dawnseeker Promontory. If left unchecked they will pose a considerable threat should the Sunreavers mount an attack. The only answer is a preemptive strike. We'll destroy them before they can attack us!",g={n="Captain Elleane Wavecrest",x=0.514,y=0.492,loc="Various"}}
d[32643]={mo=198450,rep="+400 Dominance Offensive",o="Harvest 8 Ripe Red Blossom Leek plants and provide 40 Red Blossom Leeks for the Dominance Offensive. *Harvest Ripe Red Blossom Leeks (8) *Red Blossom Leek (40)",de="Once your Red Blossom Leeks are ready to be picked, you'll need only to package them for pick-up. Just think; your Red Blossom Leeks will be a part of your factions efforts in Pandaria!"}
d[32646]={mo=198450,rep="+400 Operation: Shieldwall",o="thumb|Empty Crate. Harvest 8 Ripe Witchberry plants and provide 40 Witchberries for the Operation: Shieldwall. *Harvest Ripe Witchberries (8) *Witchberries (40)",de="Once your witchberries are ready to be picked, you'll need only to package them for pick-up. Just think; your witchberries will be a part of your factions efforts in Pandaria!"}
d[32648]={mo=198450,rep="+400 Golden Lotus",o="thumb|Empty Crate. Harvest 8 Ripe White Turnip plants and provide 40 White Turnips for the Golden Lotus. *Harvest Ripe Ripe White Turnips (8) *White Turnip (40)",de="Well, hopefully these crops will be suitable! Once your White Turnips are ready to be picked, you'll need only to package them for pick-up."}
d[32650]={mo=198450,rep="+400 Shado-Pan",o="Harvest 8 Ripe Green Cabbage plants and provide 40 Green Cabbages for the Shado-Pan. *Harvest Ripe Green Cabbages (8) *Green Cabbage (40)",de="Well, your work is done for the day! Now to wait for the harvest tomorrow. Once your Green Cabbages are ready to be picked, you'll need only to package them for pick-up. Only the finest cabbage will do for the Shado-Pan!"}
d[32657]={mo=198450,rep="+400 August Celestials",o="Harvest 8 Ripe Striped Melon plants and provide 40 Striped Melons for the August Celestials. *Harvest Ripe Striped Melon (8) *Striped Melon (40)",de="Once your Striped Melons are ready to be picked, you'll need only to package them for pick-up. A trainee from the Cradle of Chi-Ji will be along shortly to collect their order."}
d[32659]={mo=198450,rep="+400 The Klaxxi",o="Harvest 8 Ripe Mogu Pumpkin plants and provide 40 Mogu Pumpkins for the Klaxxi. *Harvest Ripe Mogu Pumpkin (8) *Mogu Pumpkin (40)",de="Once your Mogu Pumpkins are ready to be picked, you'll need only to package them for pick-up. I wouldn't dilly-dally if I were you. The Klaxxi aren't known for their patience!"}
d[32676]={mo=198450,rep="+150 Sunreaver Onslaught",o="Steal the Workshop Orders and slay the new captain of the Zandalari warship. *Warship Captain slain *Workshop Orders",de="The Zandalari have already begun repairing that warship, but we can keep it crippled with minimal effort. Simply relieve the new captain of his post, and steal the ship's damage report from that workshop just outside the vault. No captain. No repairs. No warship.",g={n="Taoshi",x=0.406,y=0.472,loc="Various"}}
d[32677]={mo=456000,rep="+200 Sunreaver Onslaught",o="Steal the Choker of Storms from The Swollen Vault. *Choker of Storms",de="The Swollen Vault is a repository for some of Lei Shen's nastiest weaponry and most prized trinkets - not surprisingly, these are often one and the same. One artifact in particular, an amulet known as the Choker of Storms, could help us to understand his apparent mastery over lightning. Break into the vault and slay the hoard-keeper. Take his key and use it to recover the amulet from a cache at the back of the vault.",g={n="Taoshi",x=0.406,y=0.472,loc="Various"}}
d[32722]={r={{n="Sunreaver Bounty"}},mo=198450,rep="+200 Sunreaver Onslaught",o="thumb|Itoka. thumb|Fleshcrafter Hoku. Kill the Master of the Forge and collect a Codex Fragment from Fleshcrafter Hoku in the Isle of Thunder. *Itoka slain *Mogu Codex Fragment",de="There's more you must do. Kill Itoka, master of the forge, and find a codex fragment from Fleshcrafter Hoku, gatekeeper of the Thunder King."}
d[32728]={mo=49600,rep="+150 Sunreaver Onslaught",o="Find Grand Magister Rommath outside the Court of Bones.",de="The mogu within the nearby Court of Bones pose a constant threat to our foothold on this island. Grand Magister Rommath has been entrusted with halting their efforts, but I am certain he could use a capable to see this task through. Go to him. Aid in whatever ways that you are able.",g={n="Girana the Blooded",loc="Various"}}
d[32729]={mo=49600,o="Find Halduron Brightwing outside of Za'Tual.",de="The Zandalari have been a constant nuisance since we arrived on this island. I've assigned Hauldron Brightwing to take charge of dismantling their presence at Za'Tual, in the south. Report to Halduron when you are best able. He will have work for you.",g={n="Lor'themar Theron",x=0.54,y=0.206,loc="Various"}}
d[32730]={mo=49600,o="Find Archmage Aethas Sunreaver outside of Ihgaluk Crag.",de="Aethas has taken over at Ihgaluk Crag, to the southeast, continuing his effort to turn the Saurok against the Zandalari and mogu. Go to him, and help in any way that you can.",g={n="Magister Hathorel",x=0.708,y=0.316,loc="Various"}}
d[32731]={mo=49600,o="Find Narasi Snowdawn outside the Court of Bones.",de="The mogu within the nearby Court of Bones comprise of of the greatest threats to our presence on this island. Narasi Snowdawn has been entrusted with halting their efforts, but I am certain she could use a capable to see this task through. Go to her. Aid in whatever ways that you are able.",g={n="Vereesa Windrunner",x=0.304,y=0.486,loc="Various"}}
d[32732]={mo=49600,o="thumb|Modera's other position outside Ihgaluk Crag Find Archmage Modera outside of Ihgaluk Crag.",de="Archmage Modera has taken over at Ihgaluk Crag, to the southeast, continuing her efforts to turn the saurok against the Zandalari and the mogu. Go to her, and help in any way that you can.",g={n="Captain Elleane Wavecrest",x=0.514,y=0.492,loc="Various"}}
d[32733]={mo=49600,o="thumb|Lan'dalock's position in the Diremoor Find Archmage Lan'dalock outside of Za'Tual.",de="The Zandalari have been a constant nuisance since we arrived on this island. I've assigned Archmage Lan'dalock to take charge of dismantling their presence at Za'Tual, in the south. Report to him when you are best able. He will have work for you.",g={n="Lady Jaina Proudmoore",x=0.662,y=0.49,loc="Various"}}
d[32868]={o="Defeat Lucky Yi, Greyhoof, and Skitterer Xi'a. * Lucky Yi * Greyhoof * Skitterer Xi'a",de="The stories of Lucky Yi, Greyhoof, and Skitterer Xi'a will exist in this land, always. Do you wish to meet them in battle once more?",g={n="Sara Finkleswitch",loc="Shrine of Seven Stars"}}
d[32869]={o="Defeat No-No, Ti'un the Wanderer, and Gorespine. * No-No * Ti'un the Wanderer * Gorespine",de="The stories of No-No, Ti'un the Wanderer, and Gorespine will exist in this land, always. Do you wish to meet them in battle once more?",g={n="Sara Finkleswitch",loc="Shrine of Seven Stars"}}
d[32943]={r={{n="Lesser Charm of Good Fortune"}},mo=114000,rep="+400 Sunreaver Onslaught",o="Harvest 8 Ripe Scallion plants and provide 40 Scallions for the Sunreaver Onslaught. *Harvest Ripe Scallions (8) *Scallions (40)",de="Once your scallions are ready to be picked, you'll need only to package them for pick-up. Just think; your scallions will feed so many hungry soldiers on the front lines!",g={n="Empty Crate",x=0.516,y=0.487}}
d[32945]={r={{n="Lesser Charm of Good Fortune"}},mo=114000,rep="+400 Kirin Tor Offensive",o="Harvest 8 Ripe Juicycrunch Carrot plants and provide 40 Juicycrunch Carrots for the Kirin Tor Offensive. * Harvest Ripe Juicycrunch Carrots (8) * Juicycrunch Carrot (40)",de="Once your juicycrunch carrots are ready to be picked, you'll need only to package them for pick-up. Just think; your juicycrunch carrots will feed so many hungry soldiers on the front lines!",g={n="Empty Crate",x=0.516,y=0.487}}
d[33211]={mo=456000,o="Correctly answer one of Evelyna's questions about the history of Azeroth. *Answered Evelyna's question",de="Destiny. Fate. Karma. Words like these imply that the timeways are unassailable. Would that were the case. To this day, many of Azeroth's inhabitants yearn to change the past. Yet just as our experiences shape us, they also shape the world around us. Consider how those threads have woven the fabric of today's reality. Cut enough threads, and causation inevitably fails, unraveling that fabric. Indeed, cutting even a single thread short can result in disaster, provided it is the right thread.",g={n="Senior Historian Evelyna",x=0.655,y=0.491,loc="Whispershade Hollow, Timeless Isle"}}
d[33222]={mo=114000,o="Defeat Little Tommy Newcomer in a pet battle. *Defeat Little Tommy Newcomer",de="I've got a battle pet, too! Want to battle? It'll be fun, I promise!",g={n="Little Tommy Newcomer",x=0.346,y=0.604,loc="Celestial Court, Timeless Isle"}}
d[33690]={mo=462000,o="Assault the hostile creatures at Lost Veil Anzu in Spires of Arak. *Assault the hostile creatures at Lost Veil Anzu",de="Some of our best scouts have gone missing in the vicinity of the lost ruins of Veil Anzu. Rokhan has requested any available resources be dispatched to identify the threat and see if any of our men yet remain alive within the ruins.",g={n="War Planning Map"}}
d[35066]={r={{n="+1 Draenor Fishing"},{n="Pack of Fishing Supplies"}},mo=194000,o="Mak'jin wants you to collect 10 Fire Ammonite Eggs from Frostfire Ridge. *Fire Ammonite Egg × 10",de="We need to stock the garrison pond with local fish. I need you to search the waters in Frostfire Ridge for fish that we can stock up with. Once you have the fish, you will need to slice them up and look for eggs inside.",g={n="Mak'jin",loc="Frostwall, Frostfire Ridge"}}
